class PyTorchDataLoaderOptimizer:
    """Optimized DataLoader configurations for PyTorch."""
    
    @staticmethod
    def get_optimal_workers():
        """Get optimal number of workers based on system."""
        cpu_count = os.cpu_count()
        if cpu_count is None:
            return 0
        # Use 75% of CPU cores, but max 8 workers
        return min(int(cpu_count * 0.75), 8)
    
    @staticmethod
    def create_optimized_dataloader(dataset, batch_size=32, is_training=True, 
                                  device=None, **kwargs):
        """Create an optimized DataLoader with PyTorch best practices."""
        
        if device is None:
            device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        
        # Determine optimal configuration
        num_workers = kwargs.get('num_workers', PyTorchDataLoaderOptimizer.get_optimal_workers())
        pin_memory = kwargs.get('pin_memory', device.type == 'cuda')
        persistent_workers = kwargs.get('persistent_workers', num_workers > 0)
        prefetch_factor = kwargs.get('prefetch_factor', 2)
        
        # Create DataLoader
        dataloader = DataLoader(
            dataset,
            batch_size=batch_size,
            shuffle=is_training,
            num_workers=num_workers,
            pin_memory=pin_memory,
            persistent_workers=persistent_workers,
            prefetch_factor=prefetch_factor,
            drop_last=is_training,
            **kwargs
        )
        
        return dataloader
    
    @staticmethod
    def create_multi_gpu_dataloader(dataset, batch_size=32, world_size=1, rank=0):
        """Create DataLoader for distributed training."""
        from torch.utils.data.distributed import DistributedSampler
        
        sampler = DistributedSampler(
            dataset,
            num_replicas=world_size,
            rank=rank,
            shuffle=True
        )
        
        dataloader = DataLoader(
            dataset,
            batch_size=batch_size,
            sampler=sampler,
            num_workers=PyTorchDataLoaderOptimizer.get_optimal_workers(),
            pin_memory=True,
            persistent_workers=True,
            prefetch_factor=2
        )
        
        return dataloader, sampler

class MemoryEfficientCollate:
    """Memory-efficient collate functions for PyTorch."""
    
    @staticmethod
    def dynamic_padding_collate(batch):
        """Collate function with dynamic padding for variable-length sequences."""
        # Find max length in batch
        max_len = max(len(item[0]) if isinstance(item, (list, tuple)) else item.shape[0] 
                     for item in batch)
        
        # Pad sequences to max length
        padded_batch = []
        for item in batch:
            if isinstance(item, (list, tuple)):
                # Handle (input, target) pairs
                input_seq, target = item
                if len(input_seq) < max_len:
                    # Pad with zeros (adjust based on your data type)
                    padding = [0] * (max_len - len(input_seq))
                    padded_input = input_seq + padding
                else:
                    padded_input = input_seq
                padded_batch.append((padded_input, target))
            else:
                # Handle single tensors
                if item.shape[0] < max_len:
                    padding = torch.zeros(max_len - item.shape[0], *item.shape[1:])
                    padded_item = torch.cat([item, padding], dim=0)
                else:
                    padded_item = item
                padded_batch.append(padded_item)
        
        return padded_batch
    
    @staticmethod
    def tensor_collate(batch):
        """Efficient tensor collation."""
        if isinstance(batch[0], torch.Tensor):
            return torch.stack(batch, dim=0)
        elif isinstance(batch[0], (list, tuple)):
            return [torch.stack([item[i] for item in batch], dim=0) 
                   for i in range(len(batch[0]))]
        else:
            return batch

class DataLoadingProfiler:
    """Profile and optimize data loading performance."""
    
    def __init__(self):
        self.metrics = {}
        self.start_time = None
    
    def start_profiling(self):
        """Start profiling session."""
        self.start_time = time.time()
        if torch.cuda.is_available():
            torch.cuda.reset_peak_memory_stats()
    
    def end_profiling(self):
        """End profiling session and collect metrics."""
        if self.start_time is None:
            return
        
        end_time = time.time()
        self.metrics['total_time'] = end_time - self.start_time
        
        if torch.cuda.is_available():
            self.metrics['peak_memory'] = torch.cuda.max_memory_allocated() / 1024**3
            self.metrics['current_memory'] = torch.cuda.memory_allocated() / 1024**3
        
        self.start_time = None
    
    def profile_dataloader(self, dataloader, num_batches=100):
        """Profile DataLoader performance."""
        self.start_profiling()
        
        batch_count = 0
        total_samples = 0
        
        for batch in dataloader:
            if batch_count >= num_batches:
                break
            
            # Simulate processing
            if isinstance(batch, (list, tuple)):
                batch_size = batch[0].shape[0]
            else:
                batch_size = batch.shape[0]
            
            total_samples += batch_size
            batch_count += 1
        
        self.end_profiling()
        
        # Calculate metrics
        self.metrics['batches_processed'] = batch_count
        self.metrics['total_samples'] = total_samples
        self.metrics['throughput'] = total_samples / self.metrics['total_time']
        self.metrics['avg_batch_time'] = self.metrics['total_time'] / batch_count
        
        return self.metrics
    
    def print_report(self):
        """Print profiling report."""
        print("\n📊 Data Loading Performance Report:")
        print("-" * 40)
        for key, value in self.metrics.items():
            if isinstance(value, float):
                if 'time' in key:
                    print(f"  {key}: {value:.4f}s")
                elif 'memory' in key:
                    print(f"  {key}: {value:.2f} GB")
                elif 'throughput' in key:
                    print(f"  {key}: {value:.1f} samples/s")
                else:
                    print(f"  {key}: {value:.4f}")
            else:
                print(f"  {key}: {value}")
