class PerformanceOptimizer:
    """Centralized performance optimization manager."""
    
    def __init__(self, config: PerformanceConfig = None):
        self.config = config or PERFORMANCE_CONFIG
        self.optimization_history = []
        self.performance_metrics = {}
        self._setup_optimizations()
    
    def _setup_optimizations(self):
        """Setup PyTorch performance optimizations."""
        try:
            # Enable CUDNN benchmark for faster convolutions
            if self.config.enable_cudnn_benchmark and torch.cuda.is_available():
                torch.backends.cudnn.benchmark = True
                logger.info("CUDNN benchmark enabled")
            
            # Enable TF32 for faster matrix multiplications on Ampere GPUs
            if self.config.enable_tf32 and torch.cuda.is_available():
                torch.backends.cuda.matmul.allow_tf32 = True
                torch.backends.cudnn.allow_tf32 = True
                logger.info("TF32 enabled for faster matrix operations")
            
            # Enable deterministic mode if requested
            if self.config.enable_deterministic:
                torch.backends.cudnn.deterministic = True
                torch.use_deterministic_algorithms(True)
                logger.info("Deterministic mode enabled")
                
        except Exception as e:
            logger.warning(f"Failed to setup some optimizations: {e}")
    
    def optimize_model(self, model: nn.Module) -> nn.Module:
        """Apply comprehensive model optimizations."""
        try:
            # Enable gradient checkpointing for memory efficiency
            if self.config.enable_gradient_checkpointing:
                model.gradient_checkpointing_enable()
                logger.info("Gradient checkpointing enabled")
            
            # Enable activation checkpointing
            if self.config.enable_activation_checkpointing:
                self._enable_activation_checkpointing(model)
            
            # Convert to channels last memory format for better GPU utilization
            if self.config.enable_channels_last and torch.cuda.is_available():
                model = model.to(memory_format=torch.channels_last)
                logger.info("Model converted to channels last memory format")
            
            # Apply Torch Compile for graph optimization (PyTorch 2.0+)
            if self.config.enable_torch_compile and hasattr(torch, 'compile'):
                try:
                    model = torch.compile(model, mode="max-autotune")
                    logger.info("Torch Compile applied successfully")
                except Exception as e:
                    logger.warning(f"Torch Compile failed: {e}")
            
            return model
            
        except Exception as e:
            logger.error(f"Model optimization failed: {e}")
            return model
    
    def _enable_activation_checkpointing(self, model: nn.Module):
        """Enable activation checkpointing for memory efficiency."""
        try:
            # Apply activation checkpointing to transformer blocks
            for module in model.modules():
                if hasattr(module, 'checkpoint_grad_fn'):
                    module.checkpoint_grad_fn = True
                elif hasattr(module, 'gradient_checkpointing'):
                    module.gradient_checkpointing = True
        except Exception as e:
            logger.warning(f"Activation checkpointing setup failed: {e}")
    
    def optimize_attention(self, model: nn.Module) -> nn.Module:
        """Optimize attention mechanisms for memory efficiency."""
        try:
            if self.config.enable_memory_efficient_attention:
                if self.config.enable_flash_attention and FLASH_ATTENTION_AVAILABLE:
                    self._replace_attention_with_flash(model)
                elif self.config.enable_xformers and XFORMERS_AVAILABLE:
                    self._replace_attention_with_xformers(model)
            
            return model
            
        except Exception as e:
            logger.error(f"Attention optimization failed: {e}")
            return model
    
    def _replace_attention_with_flash(self, model: nn.Module):
        """Replace standard attention with Flash Attention."""
        try:
            for name, module in model.named_modules():
                if hasattr(module, 'attention') and hasattr(module.attention, 'to_qkv'):
                    # Replace with Flash Attention
                    module.attention = FlashAttention(
                        softmax_scale=1.0,
                        attention_dropout=0.0
                    )
                    logger.info(f"Replaced attention in {name} with Flash Attention")
        except Exception as e:
            logger.warning(f"Flash Attention replacement failed: {e}")
    
    def _replace_attention_with_xformers(self, model: nn.Module):
        """Replace standard attention with XFormers memory-efficient attention."""
        try:
            for name, module in model.named_modules():
                if hasattr(module, 'attention') and hasattr(module.attention, 'to_qkv'):
                    # Replace with XFormers attention
                    module.attention = xformers.ops.MemoryEfficientAttention()
                    logger.info(f"Replaced attention in {name} with XFormers")
        except Exception as e:
            logger.warning(f"XFormers attention replacement failed: {e}")
    
    def optimize_data_loading(self, dataloader: DataLoader) -> DataLoader:
        """Optimize data loading for performance."""
        try:
            if self.config.enable_advanced_prefetching:
                # Enable pin memory for faster GPU transfer
                dataloader.pin_memory = True
                
                # Optimize number of workers
                if dataloader.num_workers == 0:
                    dataloader.num_workers = min(4, mp.cpu_count())
                
                # Enable persistent workers
                if hasattr(dataloader, 'persistent_workers'):
                    dataloader.persistent_workers = True
                
                # Optimize prefetch factor
                if hasattr(dataloader, 'prefetch_factor'):
                    dataloader.prefetch_factor = 2
                
                logger.info("Data loading optimizations applied")
            
            return dataloader
            
        except Exception as e:
            logger.error(f"Data loading optimization failed: {e}")
            return dataloader
    
    def get_performance_summary(self) -> Dict[str, Any]:
        """Get comprehensive performance optimization summary."""
        return {
            "optimizations_applied": len(self.optimization_history),
            "performance_metrics": self.performance_metrics,
            "configuration": {
                "memory_optimizations": {
                    "gradient_checkpointing": self.config.enable_gradient_checkpointing,
                    "activation_checkpointing": self.config.enable_activation_checkpointing,
                    "memory_efficient_attention": self.config.enable_memory_efficient_attention,
                    "flash_attention": self.config.enable_flash_attention,
                    "xformers": self.config.enable_xformers
                },
                "computation_optimizations": {
                    "torch_compile": self.config.enable_torch_compile,
                    "tf32": self.config.enable_tf32,
                    "channels_last": self.config.enable_channels_last,
                    "cudnn_benchmark": self.config.enable_cudnn_benchmark
                },
                "training_optimizations": {
                    "amp": self.config.enable_amp,
                    "grad_scaling": self.config.enable_grad_scaling,
                    "gradient_accumulation": self.config.enable_gradient_accumulation,
                    "dynamic_batching": self.config.enable_dynamic_batching
                }
            }
        }

