class MemoryManager:
    """Advanced memory management and monitoring."""
    
    def __init__(self, enable_monitoring: bool = True):
        self.enable_monitoring = enable_monitoring
        self.memory_history = []
        self.peak_memory = 0
        
        if enable_monitoring and MEMORY_MONITORING_AVAILABLE:
            self._setup_monitoring()
    
    def _setup_monitoring(self):
        """Setup memory monitoring."""
        try:
            if torch.cuda.is_available():
                torch.cuda.empty_cache()
                self.peak_memory = torch.cuda.max_memory_allocated()
        except Exception as e:
            logger.warning(f"Memory monitoring setup failed: {e}")
    
    def get_memory_info(self) -> Dict[str, Any]:
        """Get comprehensive memory information."""
        memory_info = {}
        
        try:
            # System memory
            if MEMORY_MONITORING_AVAILABLE:
                memory_info["system"] = {
                    "total": psutil.virtual_memory().total,
                    "available": psutil.virtual_memory().available,
                    "used": psutil.virtual_memory().used,
                    "percent": psutil.virtual_memory().percent
                }
            
            # GPU memory
            if torch.cuda.is_available():
                memory_info["gpu"] = {
                    "allocated": torch.cuda.memory_allocated(),
                    "cached": torch.cuda.memory_reserved(),
                    "peak_allocated": torch.cuda.max_memory_allocated(),
                    "device_count": torch.cuda.device_count()
                }
                
                # Per-device memory info
                memory_info["gpu_devices"] = []
                for i in range(torch.cuda.device_count()):
                    device_info = {
                        "device": i,
                        "name": torch.cuda.get_device_name(i),
                        "allocated": torch.cuda.memory_allocated(i),
                        "cached": torch.cuda.memory_reserved(i)
                    }
                    memory_info["gpu_devices"].append(device_info)
            
            # NVML detailed GPU info
            if NVML_AVAILABLE and torch.cuda.is_available():
                try:
                    nvml.nvmlInit()
                    for i in range(torch.cuda.device_count()):
                        handle = nvml.nvmlDeviceGetHandleByIndex(i)
                        memory_info["gpu_devices"][i].update({
                            "total_memory": nvml.nvmlDeviceGetMemoryInfo(handle).total,
                            "free_memory": nvml.nvmlDeviceGetMemoryInfo(handle).free,
                            "utilization": nvml.nvmlDeviceGetUtilizationRates(handle).gpu
                        })
                except Exception as e:
                    logger.warning(f"NVML monitoring failed: {e}")
            
        except Exception as e:
            logger.error(f"Memory info collection failed: {e}")
        
        return memory_info
    
    def optimize_memory(self):
        """Apply memory optimization techniques."""
        try:
            if torch.cuda.is_available():
                # Clear CUDA cache
                torch.cuda.empty_cache()
                
                # Reset peak memory stats
                torch.cuda.reset_peak_memory_stats()
                
                logger.info("Memory optimization applied")
                
        except Exception as e:
            logger.error(f"Memory optimization failed: {e}")
    
    def monitor_memory_usage(self, operation_name: str = "operation"):
        """Context manager for monitoring memory usage during operations."""
        return MemoryMonitor(self, operation_name)

class MemoryMonitor:
    """Context manager for memory monitoring."""
    
    def __init__(self, memory_manager: MemoryManager, operation_name: str):
        self.memory_manager = memory_manager
        self.operation_name = operation_name
        self.start_memory = None
        self.end_memory = None
    
    def __enter__(self):
        if self.memory_manager.enable_monitoring:
            self.start_memory = self.memory_manager.get_memory_info()
        return self
    
    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.memory_manager.enable_monitoring:
            self.end_memory = self.memory_manager.get_memory_info()
            
            # Calculate memory delta
            if self.start_memory and self.end_memory:
                delta = self._calculate_memory_delta()
                logger.info(f"Memory usage for {self.operation_name}: {delta}")
    
    def _calculate_memory_delta(self) -> Dict[str, Any]:
        """Calculate memory usage delta."""
        delta = {}
        
        if "gpu" in self.start_memory and "gpu" in self.end_memory:
            delta["gpu_allocated"] = (
                self.end_memory["gpu"]["allocated"] - 
                self.start_memory["gpu"]["allocated"]
            )
            delta["gpu_cached"] = (
                self.end_memory["gpu"]["cached"] - 
                self.start_memory["gpu"]["cached"]
            )
        
        return delta

# =============================================================================
# ADVANCED TRAINING OPTIMIZATIONS
# =============================================================================

class AdvancedTrainingOptimizer:
    """Advanced training optimization techniques."""
    
    def __init__(self, config: PerformanceConfig = None):
        self.config = config or PERFORMANCE_CONFIG
        self.optimization_stats = {}
    
    def setup_mixed_precision(self, model: nn.Module, optimizer: torch.optim.Optimizer):
        """Setup advanced mixed precision training."""
        try:
            if self.config.enable_amp and torch.cuda.is_available():
                # Enable automatic mixed precision
                scaler = GradScaler()
                
                # Configure model for mixed precision
                if hasattr(model, 'half'):
                    model = model.half()
                
                logger.info("Advanced mixed precision training enabled")
                return scaler
            else:
                return None
                
        except Exception as e:
            logger.error(f"Mixed precision setup failed: {e}")
            return None
    
    def setup_gradient_accumulation(self, accumulation_steps: int = 1):
        """Setup gradient accumulation for effective larger batch sizes."""
        try:
            if self.config.enable_gradient_accumulation and accumulation_steps > 1:
                logger.info(f"Gradient accumulation enabled with {accumulation_steps} steps")
                return accumulation_steps
            else:
                return 1
                
        except Exception as e:
            logger.error(f"Gradient accumulation setup failed: {e}")
            return 1
    
    def setup_dynamic_batching(self, base_batch_size: int, max_batch_size: int = None):
        """Setup dynamic batching for optimal memory utilization."""
        try:
            if self.config.enable_dynamic_batching:
                if max_batch_size is None:
                    max_batch_size = base_batch_size * 2
                
                logger.info(f"Dynamic batching enabled: {base_batch_size} -> {max_batch_size}")
                return {"base": base_batch_size, "max": max_batch_size}
            else:
                return {"base": base_batch_size, "max": base_batch_size}
                
        except Exception as e:
            logger.error(f"Dynamic batching setup failed: {e}")
            return {"base": base_batch_size, "max": base_batch_size}
    
    def optimize_learning_rate_scheduling(self, optimizer: torch.optim.Optimizer, 
                                        total_steps: int, warmup_steps: int = 0):
        """Setup optimized learning rate scheduling."""
        try:
            if warmup_steps > 0:
                # Cosine annealing with warmup
                scheduler = torch.optim.lr_scheduler.OneCycleLR(
                    optimizer,
                    max_lr=optimizer.param_groups[0]['lr'],
                    total_steps=total_steps,
                    pct_start=warmup_steps/total_steps,
                    anneal_strategy='cos'
                )
                logger.info("OneCycleLR scheduler with warmup enabled")
            else:
                # Standard cosine annealing
                scheduler = torch.optim.lr_scheduler.CosineAnnealingLR(
                    optimizer,
                    T_max=total_steps
                )
                logger.info("Cosine annealing scheduler enabled")
            
            return scheduler
            
        except Exception as e:
            logger.error(f"Learning rate scheduling optimization failed: {e}")
            return None
    
    def setup_multi_gpu_training(self, model: nn.Module, device_ids: List[int] = None):
        """Setup optimized multi-GPU training."""
        try:
            if not self.config.enable_multi_gpu or not torch.cuda.is_available():
                return model
            
            if device_ids is None:
                device_ids = list(range(torch.cuda.device_count()))
            
            if len(device_ids) > 1:
                if self.config.enable_ddp:
                    # Distributed Data Parallel for better performance
                    model = DistributedDataParallel(model, device_ids=device_ids)
                    logger.info(f"DDP enabled for {len(device_ids)} GPUs")
                else:
                    # Data Parallel for simpler multi-GPU
                    model = DataParallel(model, device_ids=device_ids)
                    logger.info(f"DataParallel enabled for {len(device_ids)} GPUs")
            
            return model
            
        except Exception as e:
            logger.error(f"Multi-GPU training setup failed: {e}")
            return model

