class PerformanceMonitor:
    """Comprehensive performance monitoring and profiling."""
    
    def __init__(self, config: PerformanceConfig = None):
        self.config = config or PERFORMANCE_CONFIG
        self.metrics_history = []
        self.profiler = None
        
        if self.config.enable_profiling:
            self._setup_profiler()
    
    def _setup_profiler(self):
        """Setup PyTorch profiler."""
        try:
            if torch.cuda.is_available():
                self.profiler = profile(
                    activities=[ProfilerActivity.CPU, ProfilerActivity.CUDA],
                    record_shapes=True,
                    with_stack=True,
                    profile_memory=True
                )
                logger.info("PyTorch profiler enabled")
        except Exception as e:
            logger.warning(f"Profiler setup failed: {e}")
    
    def start_profiling(self):
        """Start performance profiling."""
        if self.profiler:
            self.profiler.start()
    
    def stop_profiling(self):
        """Stop performance profiling and get results."""
        if self.profiler:
            self.profiler.stop()
            return self.profiler.key_averages().table(sort_by="cuda_time_total")
        return None
    
    def record_metric(self, name: str, value: float, step: int = None):
        """Record performance metric."""
        metric = {
            "name": name,
            "value": value,
            "step": step,
            "timestamp": time.time()
        }
        self.metrics_history.append(metric)
    
    def get_performance_report(self) -> Dict[str, Any]:
        """Get comprehensive performance report."""
        return {
            "metrics_count": len(self.metrics_history),
            "recent_metrics": self.metrics_history[-10:] if self.metrics_history else [],
            "profiler_enabled": self.profiler is not None,
            "configuration": {
                "monitoring": self.config.enable_performance_monitoring,
                "memory_monitoring": self.config.enable_memory_monitoring,
                "gpu_monitoring": self.config.enable_gpu_monitoring,
                "profiling": self.config.enable_profiling
            }
        }

