# ADVANCED QUANTIZATION AND PRUNING
# =============================================================================

class ModelQuantizer:
    """Advanced model quantization for inference optimization."""
    
    def __init__(self, config: PerformanceConfig = None):
        self.config = config or PERFORMANCE_CONFIG
        self.quantization_stats = {}
    
    def quantize_model(self, model: nn.Module, quantization_type: str = "dynamic") -> nn.Module:
        """Apply model quantization for faster inference."""
        try:
            if not self.config.enable_quantization:
                return model
            
            if quantization_type == "dynamic":
                # Dynamic quantization (weights quantized, activations quantized at runtime)
                quantized_model = torch.quantization.quantize_dynamic(
                    model, {nn.Linear, nn.Conv2d}, dtype=torch.qint8
                )
                logger.info("Dynamic quantization applied successfully")
                
            elif quantization_type == "static":
                # Static quantization (requires calibration data)
                quantized_model = self._apply_static_quantization(model)
                
            elif quantization_type == "qat":
                # Quantization-aware training
                quantized_model = self._apply_qat_quantization(model)
                
            else:
                logger.warning(f"Unknown quantization type: {quantization_type}")
                return model
            
            self.quantization_stats["type"] = quantization_type
            self.quantization_stats["success"] = True
            
            return quantized_model
            
        except Exception as e:
            logger.error(f"Model quantization failed: {e}")
            self.quantization_stats["success"] = False
            self.quantization_stats["error"] = str(e)
            return model
    
    def _apply_static_quantization(self, model: nn.Module) -> nn.Module:
        """Apply static quantization with calibration."""
        try:
            # Prepare model for static quantization
            model.eval()
            
            # Fuse operations for better quantization
            model_fused = torch.quantization.fuse_modules(
                model, [['conv', 'bn', 'relu']]
            )
            
            # Set quantization configuration
            model_fused.qconfig = torch.quantization.get_default_qconfig('fbgemm')
            
            # Prepare for quantization
            model_prepared = torch.quantization.prepare(model_fused)
            
            # Note: In practice, you would need calibration data here
            # For now, we'll return the prepared model
            logger.info("Static quantization preparation completed")
            return model_prepared
            
        except Exception as e:
            logger.warning(f"Static quantization failed: {e}")
            return model
    
    def _apply_qat_quantization(self, model: nn.Module) -> nn.Module:
        """Apply quantization-aware training."""
        try:
            # Set quantization configuration for QAT
            model.qconfig = torch.quantization.get_default_qat_qconfig('fbgemm')
            
            # Prepare for QAT
            model_prepared = torch.quantization.prepare_qat(model)
            
            logger.info("Quantization-aware training preparation completed")
            return model_prepared
            
        except Exception as e:
            logger.warning(f"QAT quantization failed: {e}")
            return model
    
    def get_quantization_summary(self) -> Dict[str, Any]:
        """Get quantization statistics and summary."""
        return {
            "quantization_stats": self.quantization_stats,
            "model_size_reduction": self._calculate_size_reduction(),
            "performance_improvement": self._estimate_performance_improvement()
        }
    
    def _calculate_size_reduction(self) -> float:
        """Calculate estimated model size reduction from quantization."""
        if self.quantization_stats.get("success"):
            # Typical size reduction from int8 quantization
            return 0.75  # 75% size reduction
        return 0.0
    
    def _estimate_performance_improvement(self) -> float:
        """Estimate performance improvement from quantization."""
        if self.quantization_stats.get("success"):
            # Typical speedup from int8 quantization
            return 2.0  # 2x speedup
        return 1.0

class ModelPruner:
    """Advanced model pruning for model compression."""
    
    def __init__(self, config: PerformanceConfig = None):
        self.config = config or PERFORMANCE_CONFIG
        self.pruning_stats = {}
    
    def prune_model(self, model: nn.Module, pruning_ratio: float = 0.3,
                   pruning_type: str = "structured") -> nn.Module:
        """Apply model pruning for model compression."""
        try:
            if not self.config.enable_pruning:
                return model
            
            if pruning_type == "structured":
                # Structured pruning (remove entire channels/filters)
                pruned_model = self._apply_structured_pruning(model, pruning_ratio)
                
            elif pruning_type == "unstructured":
                # Unstructured pruning (remove individual weights)
                pruned_model = self._apply_unstructured_pruning(model, pruning_ratio)
                
            elif pruning_type == "global":
                # Global pruning (remove weights across all layers)
                pruned_model = self._apply_global_pruning(model, pruning_ratio)
                
            else:
                logger.warning(f"Unknown pruning type: {pruning_type}")
                return model
            
            self.pruning_stats["type"] = pruning_type
            self.pruning_stats["ratio"] = pruning_ratio
            self.pruning_stats["success"] = True
            
            return pruned_model
            
        except Exception as e:
            logger.error(f"Model pruning failed: {e}")
            self.pruning_stats["success"] = False
            self.pruning_stats["error"] = str(e)
            return model
    
    def _apply_structured_pruning(self, model: nn.Module, pruning_ratio: float) -> nn.Module:
        """Apply structured pruning to convolutional layers."""
        try:
            for name, module in model.named_modules():
                if isinstance(module, nn.Conv2d):
                    # Apply structured pruning to Conv2d layers
                    torch.nn.utils.prune.ln_structured(
                        module, name='weight', amount=pruning_ratio, n=2, dim=0
                    )
                    logger.info(f"Structured pruning applied to {name}")
            
            return model
            
        except Exception as e:
            logger.warning(f"Structured pruning failed: {e}")
            return model
    
    def _apply_unstructured_pruning(self, model: nn.Module, pruning_ratio: float) -> nn.Module:
        """Apply unstructured pruning to linear layers."""
        try:
            for name, module in model.named_modules():
                if isinstance(module, nn.Linear):
                    # Apply unstructured pruning to Linear layers
                    torch.nn.utils.prune.l1_unstructured(
                        module, name='weight', amount=pruning_ratio
                    )
                    logger.info(f"Unstructured pruning applied to {name}")
            
            return model
            
        except Exception as e:
            logger.warning(f"Unstructured pruning failed: {e}")
            return model
    
    def _apply_global_pruning(self, model: nn.Module, pruning_ratio: float) -> nn.Module:
        """Apply global pruning across all prunable parameters."""
        try:
            # Collect all prunable parameters
            parameters_to_prune = []
            for name, module in model.named_modules():
                if isinstance(module, (nn.Linear, nn.Conv2d)):
                    parameters_to_prune.append((module, 'weight'))
            
            # Apply global pruning
            torch.nn.utils.prune.global_unstructured(
                parameters_to_prune,
                pruning_method=torch.nn.utils.prune.L1Unstructured,
                amount=pruning_ratio
            )
            
            logger.info(f"Global pruning applied with ratio {pruning_ratio}")
            return model
            
        except Exception as e:
            logger.warning(f"Global pruning failed: {e}")
            return model
    
    def get_pruning_summary(self) -> Dict[str, Any]:
        """Get pruning statistics and summary."""
        return {
            "pruning_stats": self.pruning_stats,
            "parameter_count_reduction": self._calculate_parameter_reduction(),
            "model_size_reduction": self._calculate_size_reduction()
        }
    
    def _calculate_parameter_reduction(self) -> float:
        """Calculate parameter count reduction from pruning."""
        if self.pruning_stats.get("success"):
            return self.pruning_stats.get("ratio", 0.0)
        return 0.0
    
    def _calculate_size_reduction(self) -> float:
        """Calculate model size reduction from pruning."""
        if self.pruning_stats.get("success"):
            # Size reduction is approximately equal to pruning ratio
            return self.pruning_stats.get("ratio", 0.0)
        return 0.0

# =============================================================================
# COMPREHENSIVE PERFORMANCE OPTIMIZATION MANAGER
# =============================================================================

class ComprehensivePerformanceManager:
    """Comprehensive performance optimization manager that integrates all optimization techniques."""
    
    def __init__(self, config: PerformanceConfig = None):
        self.config = config or PERFORMANCE_CONFIG
        
        # Initialize all optimization components
        self.performance_optimizer = PerformanceOptimizer(config)
        self.memory_manager = MemoryManager(config.enable_memory_monitoring)
        self.training_optimizer = AdvancedTrainingOptimizer(config)
        self.data_pipeline_optimizer = DataPipelineOptimizer(config)
        self.model_quantizer = ModelQuantizer(config)
        self.model_pruner = ModelPruner(config)
        self.performance_monitor = PerformanceMonitor(config)
        
        # Performance tracking
        self.optimization_history = []
        self.performance_metrics = {}
        self.baseline_metrics = {}
        
        logger.info("Comprehensive Performance Manager initialized")
    
    def optimize_training_pipeline(self, model: nn.Module, dataset: Dataset,
                                 dataloader: DataLoader = None, **kwargs) -> Dict[str, Any]:
        """Apply comprehensive optimization to the entire training pipeline."""
        try:
            optimization_results = {}
            
            # 1. Model optimizations
            logger.info("Applying model optimizations...")
            optimized_model = self.performance_optimizer.optimize_model(model)
            optimized_model = self.performance_optimizer.optimize_attention(optimized_model)
            optimization_results["model"] = "optimized"
            
            # 2. Memory optimizations
            logger.info("Applying memory optimizations...")
            self.memory_manager.optimize_memory()
            optimization_results["memory"] = "optimized"
            
            # 3. Data pipeline optimizations
            logger.info("Applying data pipeline optimizations...")
            if dataloader is None:
                dataloader = self.data_pipeline_optimizer.create_optimized_dataloader(
                    dataset, **kwargs
                )
            else:
                dataloader = self.performance_optimizer.optimize_data_loading(dataloader)
            optimization_results["data_pipeline"] = "optimized"
            
            # 4. Training optimizations
            logger.info("Applying training optimizations...")
            training_optimizations = self._setup_training_optimizations(optimized_model)
            optimization_results["training"] = training_optimizations
            
            # 5. Performance monitoring
            logger.info("Setting up performance monitoring...")
            self.performance_monitor.start_profiling()
            optimization_results["monitoring"] = "enabled"
            
            # Record optimization
            self.optimization_history.append({
                "timestamp": time.time(),
                "optimizations": optimization_results,
                "model_parameters": sum(p.numel() for p in optimized_model.parameters())
            })
            
            return {
                "optimized_model": optimized_model,
                "optimized_dataloader": dataloader,
                "training_optimizations": training_optimizations,
                "optimization_results": optimization_results
            }
            
        except Exception as e:
            logger.error(f"Comprehensive optimization failed: {e}")
            return {
                "optimized_model": model,
                "optimized_dataloader": dataloader or DataLoader(dataset, **kwargs),
                "training_optimizations": {},
                "optimization_results": {"error": str(e)}
            }
    
    def _setup_training_optimizations(self, model: nn.Module) -> Dict[str, Any]:
        """Setup comprehensive training optimizations."""
        try:
            optimizations = {}
            
            # Mixed precision setup
            if self.config.enable_amp:
                scaler = self.training_optimizer.setup_mixed_precision(model, None)
                if scaler:
                    optimizations["mixed_precision"] = {"scaler": scaler, "status": "enabled"}
            
            # Gradient accumulation setup
            if self.config.enable_gradient_accumulation:
                accumulation_steps = self.training_optimizer.setup_gradient_accumulation(4)
                optimizations["gradient_accumulation"] = {"steps": accumulation_steps, "status": "enabled"}
            
            # Dynamic batching setup
            if self.config.enable_dynamic_batching:
                batching_config = self.training_optimizer.setup_dynamic_batching(32, 64)
                optimizations["dynamic_batching"] = {"config": batching_config, "status": "enabled"}
            
            # Multi-GPU setup
            if self.config.enable_multi_gpu:
                multi_gpu_model = self.training_optimizer.setup_multi_gpu_training(model)
                if multi_gpu_model != model:
                    optimizations["multi_gpu"] = {"status": "enabled", "device_count": torch.cuda.device_count()}
                    model = multi_gpu_model
            
            return optimizations
            
        except Exception as e:
            logger.error(f"Training optimization setup failed: {e}")
            return {"error": str(e)}
    
    def apply_inference_optimizations(self, model: nn.Module) -> nn.Module:
        """Apply optimizations specifically for inference."""
        try:
            logger.info("Applying inference optimizations...")
            
            # 1. Model quantization
            if self.config.enable_quantization:
                model = self.model_quantizer.quantize_model(model, "dynamic")
            
            # 2. Model pruning
            if self.config.enable_pruning:
                model = self.model_pruner.prune_model(model, 0.2, "structured")
            
            # 3. Model compilation (if available)
            if self.config.enable_torch_compile and hasattr(torch, 'compile'):
                try:
                    model = torch.compile(model, mode="reduce-overhead")
                    logger.info("Model compiled for inference optimization")
                except Exception as e:
                    logger.warning(f"Model compilation failed: {e}")
            
            return model
            
        except Exception as e:
            logger.error(f"Inference optimization failed: {e}")
            return model
    
    def benchmark_performance(self, model: nn.Module, dataloader: DataLoader,
                            num_iterations: int = 100) -> Dict[str, Any]:
        """Benchmark model performance with comprehensive metrics."""
        try:
            logger.info(f"Starting performance benchmark with {num_iterations} iterations...")
            
            # Setup for benchmarking
            model.eval()
            device = next(model.parameters()).device
            
            # Performance metrics
            inference_times = []
            memory_usage = []
            throughput_metrics = []
            
            # Start monitoring
            with self.memory_manager.monitor_memory_usage("benchmark"):
                for i, batch in enumerate(dataloader):
                    if i >= num_iterations:
                        break
                    
                    # Move batch to device
                    if isinstance(batch, (list, tuple)):
                        batch = [b.to(device) if torch.is_tensor(b) else b for b in batch]
                    elif torch.is_tensor(batch):
                        batch = batch.to(device)
                    
                    # Measure inference time
                    start_time = time.time()
                    with torch.no_grad():
                        outputs = model(batch)
                    end_time = time.time()
                    
                    inference_time = end_time - start_time
                    inference_times.append(inference_time)
                    
                    # Measure memory usage
                    if torch.cuda.is_available():
                        memory_usage.append(torch.cuda.memory_allocated())
                    
                    # Calculate throughput
                    if hasattr(batch, 'shape') and len(batch.shape) > 0:
                        batch_size = batch.shape[0]
                        throughput = batch_size / inference_time
                        throughput_metrics.append(throughput)
                    
                    # Progress update
                    if (i + 1) % 10 == 0:
                        logger.info(f"Benchmark progress: {i + 1}/{num_iterations}")
            
            # Calculate comprehensive metrics
            benchmark_results = self._calculate_benchmark_metrics(
                inference_times, memory_usage, throughput_metrics
            )
            
            # Record benchmark
            self.performance_metrics["benchmark"] = benchmark_results
            
            logger.info("Performance benchmark completed successfully")
            return benchmark_results
            
        except Exception as e:
            logger.error(f"Performance benchmark failed: {e}")
            return {"error": str(e)}
    
    def _calculate_benchmark_metrics(self, inference_times: List[float],
                                   memory_usage: List[int],
                                   throughput_metrics: List[float]) -> Dict[str, Any]:
        """Calculate comprehensive benchmark metrics."""
        try:
            metrics = {}
            
            # Inference time statistics
            if inference_times:
                metrics["inference_time"] = {
                    "mean": np.mean(inference_times),
                    "median": np.median(inference_times),
                    "std": np.std(inference_times),
                    "min": np.min(inference_times),
                    "max": np.max(inference_times),
                    "p95": np.percentile(inference_times, 95),
                    "p99": np.percentile(inference_times, 99)
                }
            
            # Memory usage statistics
            if memory_usage:
                metrics["memory_usage"] = {
                    "mean": np.mean(memory_usage),
                    "peak": np.max(memory_usage),
                    "min": np.min(memory_usage),
                    "std": np.std(memory_usage)
                }
            
            # Throughput statistics
            if throughput_metrics:
                metrics["throughput"] = {
                    "mean": np.mean(throughput_metrics),
                    "median": np.median(throughput_metrics),
                    "max": np.max(throughput_metrics),
                    "std": np.std(throughput_metrics)
                }
            
            # Performance summary
            metrics["summary"] = {
                "total_iterations": len(inference_times),
                "average_latency_ms": metrics.get("inference_time", {}).get("mean", 0) * 1000,
                "throughput_samples_per_sec": metrics.get("throughput", {}).get("mean", 0),
                "memory_efficiency_mb": metrics.get("memory_usage", {}).get("mean", 0) / (1024 * 1024)
            }
            
            return metrics
            
        except Exception as e:
            logger.error(f"Benchmark metrics calculation failed: {e}")
            return {"error": str(e)}
    
    def get_optimization_report(self) -> Dict[str, Any]:
        """Get comprehensive optimization and performance report."""
        try:
            # Stop profiling if active
            profiler_results = None
            if self.performance_monitor.profiler:
                profiler_results = self.performance_monitor.stop_profiling()
            
            # Get memory information
            memory_info = self.memory_manager.get_memory_info()
            
            # Get performance report
            performance_report = self.performance_monitor.get_performance_report()
            
            # Compile comprehensive report
            report = {
                "optimization_summary": {
                    "total_optimizations": len(self.optimization_history),
                    "last_optimization": self.optimization_history[-1] if self.optimization_history else None,
                    "performance_metrics": self.performance_metrics
                },
                "memory_analysis": memory_info,
                "performance_analysis": performance_report,
                "profiler_results": profiler_results,
                "quantization_summary": self.model_quantizer.get_quantization_summary(),
                "pruning_summary": self.model_pruner.get_pruning_summary(),
                "configuration": {
                    "performance_config": {
                        "memory_optimizations": {
                            "gradient_checkpointing": self.config.enable_gradient_checkpointing,
                            "activation_checkpointing": self.config.enable_activation_checkpointing,
                            "memory_efficient_attention": self.config.enable_memory_efficient_attention
                        },
                        "computation_optimizations": {
                            "torch_compile": self.config.enable_torch_compile,
                            "tf32": self.config.enable_tf32,
                            "channels_last": self.config.enable_channels_last
                        },
                        "training_optimizations": {
                            "amp": self.config.enable_amp,
                            "gradient_accumulation": self.config.enable_gradient_accumulation,
                            "dynamic_batching": self.config.enable_dynamic_batching
                        }
                    }
                }
            }
            
            return report
            
        except Exception as e:
            logger.error(f"Optimization report generation failed: {e}")
            return {"error": str(e)}
    
    def reset_optimizations(self):
        """Reset all optimizations to baseline."""
        try:
            logger.info("Resetting all optimizations...")
            
            # Clear optimization history
            self.optimization_history.clear()
            self.performance_metrics.clear()
            
            # Reset memory manager
            self.memory_manager.optimize_memory()
            
            # Reset performance monitor
            if self.performance_monitor.profiler:
                self.performance_monitor.profiler = None
            
            logger.info("All optimizations reset successfully")
            
        except Exception as e:
            logger.error(f"Optimization reset failed: {e}")

# =============================================================================
# COMPREHENSIVE MULTI-GPU TRAINING SYSTEM
# =============================================================================

class MultiGPUTrainer:
    """Comprehensive multi-GPU training system with DataParallel and DistributedDataParallel."""
    
    def __init__(self, config: PerformanceConfig = None):
        self.config = config or PERFORMANCE_CONFIG
        self.device_count = torch.cuda.device_count() if torch.cuda.is_available() else 0
        self.current_strategy = None
        self.model = None
        self.optimizer = None
        self.scheduler = None
        self.scaler = None
        
        # Multi-GPU configuration
        self.multi_gpu_config = {
            'strategy': 'auto',  # 'auto', 'DataParallel', 'DistributedDataParallel'
            'device_ids': None,  # Specific device IDs to use
            'ddp_backend': 'nccl',  # DDP backend
            'ddp_init_method': 'env://',  # DDP initialization method
            'ddp_world_size': None,  # DDP world size
            'ddp_rank': None,  # DDP rank
            'ddp_local_rank': None,  # DDP local rank
            'ddp_master_addr': 'localhost',  # DDP master address
            'ddp_master_port': '12355',  # DDP master port
            'ddp_find_unused_parameters': False,  # DDP find unused parameters
            'ddp_gradient_as_bucket_view': True,  # DDP gradient as bucket view
            'ddp_broadcast_buffers': True,  # DDP broadcast buffers
            'ddp_bucket_cap_mb': 25,  # DDP bucket capacity in MB
            'ddp_static_graph': False,  # DDP static graph
            'ddp_forward_prefetch': False,  # DDP forward prefetch
        }
        
        # Performance tracking
        self.training_metrics = {
            'gpu_utilization': [],
            'memory_usage': [],
            'throughput': [],
            'scaling_efficiency': []
        }
        
        logger.info(f"Multi-GPU Trainer initialized with {self.device_count} GPUs")
    
    def configure_multi_gpu(self, strategy: str = 'auto', **kwargs):
        """Configure multi-GPU training strategy."""
        try:
            # Update configuration
            self.multi_gpu_config.update(kwargs)
            
            # Auto-select strategy if not specified
            if strategy == 'auto':
                strategy = self._auto_select_strategy()
            
            self.multi_gpu_config['strategy'] = strategy
            
            # Validate configuration
            self._validate_multi_gpu_config()
            
            logger.info(f"Multi-GPU configuration: {strategy} with {self.device_count} GPUs")
            return True
            
        except Exception as e:
            logger.error(f"Multi-GPU configuration failed: {e}")
            return False
    
    def _auto_select_strategy(self) -> str:
        """Automatically select the best multi-GPU strategy."""
        if self.device_count < 2:
            return 'single_gpu'
        elif self.device_count <= 4:
            return 'DataParallel'  # Better for small number of GPUs
        else:
            return 'DistributedDataParallel'  # Better for large number of GPUs
    
    def _validate_multi_gpu_config(self):
        """Validate multi-GPU configuration."""
        if self.device_count < 2:
            raise ValueError(f"Multi-GPU training requires at least 2 GPUs, found {self.device_count}")
        
        strategy = self.multi_gpu_config['strategy']
        if strategy not in ['DataParallel', 'DistributedDataParallel', 'single_gpu']:
            raise ValueError(f"Invalid strategy: {strategy}")
        
        if strategy == 'DistributedDataParallel':
            # Validate DDP-specific configuration
            if not self.multi_gpu_config['ddp_world_size']:
                self.multi_gpu_config['ddp_world_size'] = self.device_count
    
    def setup_model(self, model: nn.Module, optimizer: torch.optim.Optimizer = None,
                   scheduler: torch.optim.lr_scheduler._LRScheduler = None,
                   scaler: GradScaler = None) -> nn.Module:
        """Setup model for multi-GPU training."""
        try:
            self.model = model
            self.optimizer = optimizer
            self.scheduler = scheduler
            self.scaler = scaler
            
            strategy = self.multi_gpu_config['strategy']
            
            if strategy == 'DataParallel':
                return self._setup_dataparallel(model)
            elif strategy == 'DistributedDataParallel':
                return self._setup_distributed_dataparallel(model)
            else:
                return model  # Single GPU
                
        except Exception as e:
            logger.error(f"Multi-GPU model setup failed: {e}")
            return model
    
    def _setup_dataparallel(self, model: nn.Module) -> nn.Module:
        """Setup DataParallel for multi-GPU training."""
        try:
            device_ids = self.multi_gpu_config['device_ids']
            if device_ids is None:
                device_ids = list(range(self.device_count))
            
            # Validate device IDs
            valid_device_ids = [i for i in device_ids if i < self.device_count]
            if len(valid_device_ids) < 2:
                raise ValueError(f"DataParallel requires at least 2 valid GPUs, found {len(valid_device_ids)}")
            
            # Wrap model with DataParallel
            wrapped_model = DataParallel(
                model,
                device_ids=valid_device_ids,
                output_device=valid_device_ids[0]  # Primary device
            )
            
            self.current_strategy = 'DataParallel'
            logger.info(f"DataParallel setup completed with devices: {valid_device_ids}")
            
            return wrapped_model
            
        except Exception as e:
            logger.error(f"DataParallel setup failed: {e}")
            raise
    
    def _setup_distributed_dataparallel(self, model: nn.Module) -> nn.Module:
        """Setup DistributedDataParallel for multi-GPU training."""
        try:
            device_ids = self.multi_gpu_config['device_ids']
            if device_ids is None:
                device_ids = list(range(self.device_count))
            
            # Validate device IDs
            valid_device_ids = [i for i in device_ids if i < self.device_count]
            if len(valid_device_ids) < 2:
                raise ValueError(f"DistributedDataParallel requires at least 2 valid GPUs, found {len(valid_device_ids)}")
            
            # Set environment variables for DDP
            os.environ['MASTER_ADDR'] = self.multi_gpu_config['ddp_master_addr']
            os.environ['MASTER_PORT'] = self.multi_gpu_config['ddp_master_port']
            os.environ['WORLD_SIZE'] = str(self.multi_gpu_config['ddp_world_size'])
            os.environ['RANK'] = str(self.multi_gpu_config['ddp_rank'] or 0)
            os.environ['LOCAL_RANK'] = str(self.multi_gpu_config['ddp_local_rank'] or 0)
            
            # Initialize process group
            torch.distributed.init_process_group(
                backend=self.multi_gpu_config['ddp_backend'],
                init_method=self.multi_gpu_config['ddp_init_method'],
                world_size=self.multi_gpu_config['ddp_world_size'],
                rank=self.multi_gpu_config['ddp_rank'] or 0
            )
            
            # Move model to primary device
            primary_device = valid_device_ids[0]
            model = model.to(primary_device)
            
            # Wrap model with DistributedDataParallel
            wrapped_model = DistributedDataParallel(
                model,
                device_ids=[primary_device],
                output_device=primary_device,
                find_unused_parameters=self.multi_gpu_config['ddp_find_unused_parameters'],
                gradient_as_bucket_view=self.multi_gpu_config['ddp_gradient_as_bucket_view'],
                broadcast_buffers=self.multi_gpu_config['ddp_broadcast_buffers'],
                bucket_cap_mb=self.multi_gpu_config['ddp_bucket_cap_mb'],
                static_graph=self.multi_gpu_config['ddp_static_graph'],
                forward_prefetch=self.multi_gpu_config['ddp_forward_prefetch']
            )
            
            self.current_strategy = 'DistributedDataParallel'
            logger.info(f"DistributedDataParallel setup completed with devices: {valid_device_ids}")
            
            return wrapped_model
            
        except Exception as e:
            logger.error(f"DistributedDataParallel setup failed: {e}")
            raise
    
    def setup_dataloader(self, dataloader: DataLoader) -> DataLoader:
        """Setup dataloader for multi-GPU training."""
        try:
            if self.current_strategy == 'DistributedDataParallel':
                # Use DistributedSampler for DDP
                sampler = DistributedSampler(
                    dataloader.dataset,
                    num_replicas=self.multi_gpu_config['ddp_world_size'],
                    rank=self.multi_gpu_config['ddp_rank'] or 0,
                    shuffle=dataloader.shuffle
                )
                
                # Create new dataloader with distributed sampler
                distributed_dataloader = DataLoader(
                    dataloader.dataset,
                    batch_size=dataloader.batch_size,
                    num_workers=dataloader.num_workers,
                    sampler=sampler,
                    pin_memory=dataloader.pin_memory,
                    drop_last=dataloader.drop_last
                )
                
                logger.info("DistributedDataParallel dataloader setup completed")
                return distributed_dataloader
            
            elif self.current_strategy == 'DataParallel':
                # DataParallel automatically handles data distribution
                # Just ensure proper batch size scaling
                effective_batch_size = dataloader.batch_size * self.device_count
                logger.info(f"DataParallel dataloader: effective batch size = {effective_batch_size}")
                return dataloader
            
            else:
                return dataloader
                
        except Exception as e:
            logger.error(f"Multi-GPU dataloader setup failed: {e}")
            return dataloader
    
    def train_step(self, batch, model: nn.Module, criterion, optimizer: torch.optim.Optimizer,
                   scaler: GradScaler = None, accumulation_steps: int = 1) -> Dict[str, Any]:
        """Execute a single training step with multi-GPU support."""
        try:
            start_time = time.time()
            
            # Move batch to primary device
            if self.current_strategy == 'DistributedDataParallel':
                primary_device = next(model.parameters()).device
            else:
                primary_device = next(model.parameters()).device
            
            batch = self._move_batch_to_device(batch, primary_device)
            
            # Forward pass
            with autocast() if scaler else nullcontext():
                outputs = model(batch)
                if isinstance(outputs, dict):
                    loss = outputs.get('loss', outputs.get('logits', outputs))
                else:
                    loss = outputs
                
                # Scale loss for gradient accumulation
                loss = loss / accumulation_steps
            
            # Backward pass
            if scaler:
                scaler.scale(loss).backward()
            else:
                loss.backward()
            
            # Gradient accumulation
            if accumulation_steps == 1 or (hasattr(self, '_step_count') and 
                                        (self._step_count + 1) % accumulation_steps == 0):
                if scaler:
                    scaler.step(optimizer)
                    scaler.update()
                else:
                    optimizer.step()
                
                if self.scheduler:
                    self.scheduler.step()
                
                optimizer.zero_grad(set_to_none=True)
            
            # Update step count
            if not hasattr(self, '_step_count'):
                self._step_count = 0
            self._step_count += 1
            
            # Calculate metrics
            training_time = time.time() - start_time
            batch_size = self._get_batch_size(batch)
            
            metrics = {
                'loss': loss.item(),
                'training_time': training_time,
                'batch_size': batch_size,
                'strategy': self.current_strategy,
                'device_count': self.device_count
            }
            
            # Update performance metrics
            self._update_training_metrics(metrics)
            
            return metrics
            
        except Exception as e:
            logger.error(f"Multi-GPU training step failed: {e}")
            raise
    
    def _move_batch_to_device(self, batch, device: torch.device):
        """Move batch data to specified device."""
        if isinstance(batch, torch.Tensor):
            return batch.to(device, non_blocking=True)
        elif isinstance(batch, (list, tuple)):
            return [self._move_batch_to_device(item, device) for item in batch]
        elif isinstance(batch, dict):
            return {key: self._move_batch_to_device(value, device) for key, value in batch.items()}
        else:
            return batch
    
    def _get_batch_size(self, batch) -> int:
        """Get batch size from batch data."""
        if isinstance(batch, torch.Tensor):
            return batch.size(0)
        elif isinstance(batch, (list, tuple)) and batch:
            return self._get_batch_size(batch[0])
        elif isinstance(batch, dict) and batch:
            return self._get_batch_size(next(iter(batch.values())))
        else:
            return 1
    
    def _update_training_metrics(self, metrics: Dict[str, Any]):
        """Update training performance metrics."""
        try:
            # GPU utilization
            if torch.cuda.is_available():
                gpu_util = []
                for i in range(self.device_count):
                    try:
                        util = torch.cuda.utilization(i)
                        gpu_util.append(util)
                    except:
                        gpu_util.append(0)
                
                avg_gpu_util = sum(gpu_util) / len(gpu_util) if gpu_util else 0
                self.training_metrics['gpu_utilization'].append(avg_gpu_util)
            
            # Memory usage
            if torch.cuda.is_available():
                total_memory = sum(torch.cuda.memory_allocated(i) for i in range(self.device_count))
                self.training_metrics['memory_usage'].append(total_memory)
            
            # Throughput (samples per second)
            if metrics['training_time'] > 0:
                throughput = metrics['batch_size'] / metrics['training_time']
                self.training_metrics['throughput'].append(throughput)
            
            # Scaling efficiency (actual vs. theoretical speedup)
            if len(self.training_metrics['throughput']) > 1:
                baseline_throughput = self.training_metrics['throughput'][0]
                current_throughput = self.training_metrics['throughput'][-1]
                theoretical_speedup = self.device_count
                actual_speedup = current_throughput / baseline_throughput if baseline_throughput > 0 else 0
                scaling_efficiency = actual_speedup / theoretical_speedup
                self.training_metrics['scaling_efficiency'].append(scaling_efficiency)
            
            # Keep metrics history manageable
            max_history = 1000
            for key in self.training_metrics:
                if len(self.training_metrics[key]) > max_history:
                    self.training_metrics[key] = self.training_metrics[key][-max_history:]
                    
        except Exception as e:
            logger.warning(f"Failed to update training metrics: {e}")
    
    def get_performance_summary(self) -> Dict[str, Any]:
        """Get comprehensive multi-GPU performance summary."""
        try:
            summary = {
                'strategy': self.current_strategy,
                'device_count': self.device_count,
                'configuration': self.multi_gpu_config,
                'metrics': {}
            }
            
            # Calculate performance statistics
            for metric_name, values in self.training_metrics.items():
                if values:
                    summary['metrics'][metric_name] = {
                        'count': len(values),
                        'mean': np.mean(values),
                        'std': np.std(values),
                        'min': np.min(values),
                        'max': np.max(values),
                        'latest': values[-1] if values else None
                    }
            
            # Calculate scaling efficiency
            if 'scaling_efficiency' in summary['metrics'] and summary['metrics']['scaling_efficiency']['count'] > 0:
                avg_efficiency = summary['metrics']['scaling_efficiency']['mean']
                summary['scaling_analysis'] = {
                    'average_efficiency': avg_efficiency,
                    'efficiency_percentage': avg_efficiency * 100,
                    'theoretical_speedup': self.device_count,
                    'actual_speedup': avg_efficiency * self.device_count
                }
            
            return summary
            
        except Exception as e:
            logger.error(f"Failed to get performance summary: {e}")
            return {'error': str(e)}
    
    def benchmark_multi_gpu_performance(self, model: nn.Module, dataloader: DataLoader,
                                      num_iterations: int = 100) -> Dict[str, Any]:
        """Benchmark multi-GPU training performance."""
        try:
            logger.info(f"Starting multi-GPU performance benchmark with {num_iterations} iterations...")
            
            # Setup for benchmarking
            model.train()
            criterion = nn.CrossEntropyLoss()
            optimizer = torch.optim.Adam(model.parameters(), lr=0.001)
            
            # Benchmark single GPU first
            single_gpu_metrics = self._benchmark_single_gpu(model, dataloader, num_iterations)
            
            # Benchmark multi-GPU
            multi_gpu_metrics = self._benchmark_multi_gpu(model, dataloader, num_iterations)
            
            # Calculate scaling analysis
            scaling_analysis = self._calculate_scaling_analysis(single_gpu_metrics, multi_gpu_metrics)
            
            benchmark_results = {
                'single_gpu': single_gpu_metrics,
                'multi_gpu': multi_gpu_metrics,
                'scaling_analysis': scaling_analysis,
                'configuration': self.multi_gpu_config
            }
            
            logger.info("Multi-GPU performance benchmark completed successfully")
            return benchmark_results
            
        except Exception as e:
            logger.error(f"Multi-GPU performance benchmark failed: {e}")
            return {'error': str(e)}
    
    def _benchmark_single_gpu(self, model: nn.Module, dataloader: DataLoader,
                             num_iterations: int) -> Dict[str, Any]:
        """Benchmark single GPU performance."""
        try:
            # Temporarily move model to single GPU
            original_device = next(model.parameters()).device
            single_gpu_model = model.to('cuda:0' if torch.cuda.is_available() else 'cpu')
            
            # Benchmark
            start_time = time.time()
            total_loss = 0
            batch_times = []
            
            for i, batch in enumerate(dataloader):
                if i >= num_iterations:
                    break
                
                batch_start = time.time()
                
                # Forward pass
                outputs = single_gpu_model(batch)
                if isinstance(outputs, dict):
                    loss = outputs.get('loss', outputs.get('logits', outputs))
                else:
                    loss = outputs
                
                total_loss += loss.item()
                batch_time = time.time() - batch_start
                batch_times.append(batch_time)
            
            total_time = time.time() - start_time
            
            # Restore original device
            single_gpu_model.to(original_device)
            
            return {
                'total_time': total_time,
                'average_loss': total_loss / len(batch_times) if batch_times else 0,
                'batch_times': batch_times,
                'throughput': len(batch_times) / total_time if total_time > 0 else 0
            }
            
        except Exception as e:
            logger.error(f"Single GPU benchmark failed: {e}")
            return {'error': str(e)}
    
    def _benchmark_multi_gpu(self, model: nn.Module, dataloader: DataLoader,
                            num_iterations: int) -> Dict[str, Any]:
        """Benchmark multi-GPU performance."""
        try:
            # Use current multi-GPU setup
            if not self.current_strategy:
                raise ValueError("Multi-GPU strategy not configured")
            
            # Benchmark
            start_time = time.time()
            total_loss = 0
            batch_times = []
            
            for i, batch in enumerate(dataloader):
                if i >= num_iterations:
                    break
                
                batch_start = time.time()
                
                # Training step
                metrics = self.train_step(batch, model, nn.CrossEntropyLoss(), 
                                       torch.optim.Adam(model.parameters(), lr=0.001))
                
                total_loss += metrics['loss']
                batch_time = metrics['training_time']
                batch_times.append(batch_time)
            
            total_time = time.time() - start_time
            
            return {
                'total_time': total_time,
                'average_loss': total_loss / len(batch_times) if batch_times else 0,
                'batch_times': batch_times,
                'throughput': len(batch_times) / total_time if total_time > 0 else 0,
                'strategy': self.current_strategy
            }
            
        except Exception as e:
            logger.error(f"Multi-GPU benchmark failed: {e}")
            return {'error': str(e)}
    
    def _calculate_scaling_analysis(self, single_gpu_metrics: Dict[str, Any],
                                  multi_gpu_metrics: Dict[str, Any]) -> Dict[str, Any]:
        """Calculate scaling efficiency analysis."""
        try:
            if 'error' in single_gpu_metrics or 'error' in multi_gpu_metrics:
                return {'error': 'Benchmark failed'}
            
            single_throughput = single_gpu_metrics.get('throughput', 0)
            multi_throughput = multi_gpu_metrics.get('throughput', 0)
            
            if single_throughput <= 0:
                return {'error': 'Invalid single GPU throughput'}
            
            # Calculate scaling metrics
            speedup = multi_throughput / single_throughput
            theoretical_speedup = self.device_count
            efficiency = speedup / theoretical_speedup if theoretical_speedup > 0 else 0
            
            return {
                'speedup': speedup,
                'theoretical_speedup': theoretical_speedup,
                'efficiency': efficiency,
                'efficiency_percentage': efficiency * 100,
                'single_gpu_throughput': single_throughput,
                'multi_gpu_throughput': multi_gpu_throughput
            }
            
        except Exception as e:
            logger.error(f"Scaling analysis calculation failed: {e}")
            return {'error': str(e)}
    
    def cleanup(self):
        """Cleanup multi-GPU resources."""
        try:
            if self.current_strategy == 'DistributedDataParallel':
                torch.distributed.destroy_process_group()
                logger.info("DistributedDataParallel process group destroyed")
            
            # Clear metrics
            for key in self.training_metrics:
                self.training_metrics[key].clear()
            
            logger.info("Multi-GPU trainer cleanup completed")
            
        except Exception as e:
            logger.error(f"Multi-GPU cleanup failed: {e}")

# =============================================================================
# COMPREHENSIVE GRADIENT ACCUMULATION SYSTEM
# =============================================================================

class GradientAccumulationConfig:
    """Configuration for gradient accumulation system."""
    
    def __init__(self, 
                 enable_gradient_accumulation: bool = True,
                 accumulation_steps: int = 4,
                 target_batch_size: int = None,
                 base_batch_size: int = 32,
                 memory_efficient: bool = True,
                 sync_batch_norm: bool = True,
                 scale_loss: bool = True,
                 accumulation_mode: str = 'standard',  # 'standard', 'memory_efficient', 'adaptive'
                 max_memory_usage: float = 0.9,  # Maximum GPU memory usage (90%)
                 adaptive_threshold: float = 0.8,  # Threshold for adaptive accumulation
                 warmup_steps: int = 0,  # Warmup steps for accumulation
                 decay_steps: int = None,  # Decay steps for accumulation
                 min_accumulation_steps: int = 1,  # Minimum accumulation steps
                 max_accumulation_steps: int = 16,  # Maximum accumulation steps
                 monitor_memory: bool = True,  # Monitor memory usage
                 auto_adjust: bool = True,  # Auto-adjust accumulation steps
                 verbose: bool = True):
        
        self.enable_gradient_accumulation = enable_gradient_accumulation
        self.accumulation_steps = accumulation_steps
        self.target_batch_size = target_batch_size
        self.base_batch_size = base_batch_size
        self.memory_efficient = memory_efficient
        self.sync_batch_norm = sync_batch_norm
        self.scale_loss = scale_loss
        self.accumulation_mode = accumulation_mode
        self.max_memory_usage = max_memory_usage
        self.adaptive_threshold = adaptive_threshold
        self.warmup_steps = warmup_steps
        self.decay_steps = decay_steps
        self.min_accumulation_steps = min_accumulation_steps
        self.max_accumulation_steps = max_accumulation_steps
        self.monitor_memory = monitor_memory
        self.auto_adjust = auto_adjust
        self.verbose = verbose
        
        # Calculate effective batch size
        if self.enable_gradient_accumulation:
            self.effective_batch_size = self.base_batch_size * self.accumulation_steps
        else:
            self.effective_batch_size = self.base_batch_size
        
        # Validate configuration
        self._validate_config()
    
    def _validate_config(self):
        """Validate gradient accumulation configuration."""
        if self.accumulation_steps < 1:
            raise ValueError(f"Accumulation steps must be >= 1, got {self.accumulation_steps}")
        
        if self.accumulation_steps > self.max_accumulation_steps:
            raise ValueError(f"Accumulation steps {self.accumulation_steps} exceeds maximum {self.max_accumulation_steps}")
        
        if self.accumulation_steps < self.min_accumulation_steps:
            raise ValueError(f"Accumulation steps {self.accumulation_steps} below minimum {self.min_accumulation_steps}")
        
        if self.max_memory_usage <= 0 or self.max_memory_usage >= 1:
            raise ValueError(f"Max memory usage must be between 0 and 1, got {self.max_memory_usage}")
        
        if self.adaptive_threshold <= 0 or self.adaptive_threshold >= 1:
            raise ValueError(f"Adaptive threshold must be between 0 and 1, got {self.adaptive_threshold}")
    
    def update_accumulation_steps(self, new_steps: int):
        """Update accumulation steps and recalculate effective batch size."""
        if new_steps < self.min_accumulation_steps or new_steps > self.max_accumulation_steps:
            raise ValueError(f"New accumulation steps {new_steps} outside valid range [{self.min_accumulation_steps}, {self.max_accumulation_steps}]")
        
        self.accumulation_steps = new_steps
        self.effective_batch_size = self.base_batch_size * self.accumulation_steps
        
        if self.verbose:
            logger.info(f"Updated accumulation steps to {new_steps}, effective batch size: {self.effective_batch_size}")
    
    def get_learning_rate_scale_factor(self) -> float:
        """Get learning rate scale factor for effective batch size."""
        if self.enable_gradient_accumulation and self.scale_loss:
            return self.accumulation_steps
        return 1.0
    
    def to_dict(self) -> Dict[str, Any]:
        """Convert configuration to dictionary."""
        return {
            'enable_gradient_accumulation': self.enable_gradient_accumulation,
            'accumulation_steps': self.accumulation_steps,
            'target_batch_size': self.target_batch_size,
            'base_batch_size': self.base_batch_size,
            'effective_batch_size': self.effective_batch_size,
            'memory_efficient': self.memory_efficient,
            'sync_batch_norm': self.sync_batch_norm,
            'scale_loss': self.scale_loss,
            'accumulation_mode': self.accumulation_mode,
            'max_memory_usage': self.max_memory_usage,
            'adaptive_threshold': self.adaptive_threshold,
            'warmup_steps': self.warmup_steps,
            'decay_steps': self.decay_steps,
            'min_accumulation_steps': self.min_accumulation_steps,
            'max_accumulation_steps': self.max_accumulation_steps,
            'monitor_memory': self.monitor_memory,
            'auto_adjust': self.auto_adjust,
            'verbose': self.verbose
        }


class GradientAccumulationManager:
    """Advanced gradient accumulation manager for large batch sizes."""
    
    def __init__(self, config: GradientAccumulationConfig = None):
        self.config = config or GradientAccumulationConfig()
        self.current_step = 0
        self.accumulated_gradients = {}
        self.accumulation_count = 0
        self.memory_history = []
        self.performance_history = []
        
        # Performance tracking
        self.step_times = []
        self.memory_usage = []
        self.gradient_norms = []
        
        # Adaptive accumulation
        self.adaptive_accumulation_steps = self.config.accumulation_steps
        self.adaptation_history = []
        
        logger.info(f"Gradient Accumulation Manager initialized with {self.config.accumulation_steps} steps")
        logger.info(f"Effective batch size: {self.config.effective_batch_size}")
    
    def setup_accumulation(self, model: nn.Module, optimizer: torch.optim.Optimizer) -> bool:
        """Setup gradient accumulation for the model and optimizer."""
        try:
            if not self.config.enable_gradient_accumulation:
                logger.info("Gradient accumulation disabled")
                return False
            
            # Initialize accumulated gradients
            self._initialize_accumulated_gradients(model)
            
            # Setup hooks for gradient accumulation
            if self.config.memory_efficient:
                self._setup_memory_efficient_accumulation(model)
            else:
                self._setup_standard_accumulation(model)
            
            # Setup batch norm synchronization if enabled
            if self.config.sync_batch_norm:
                self._setup_batch_norm_sync(model)
            
            logger.info(f"Gradient accumulation setup completed with {self.config.accumulation_steps} steps")
            return True
            
        except Exception as e:
            logger.error(f"Gradient accumulation setup failed: {e}")
            return False
    
    def _initialize_accumulated_gradients(self, model: nn.Module):
        """Initialize accumulated gradients dictionary."""
        self.accumulated_gradients.clear()
        for name, param in model.named_parameters():
            if param.requires_grad:
                self.accumulated_gradients[name] = torch.zeros_like(param.grad) if param.grad is not None else torch.zeros_like(param.data)
    
    def _setup_standard_accumulation(self, model: nn.Module):
        """Setup standard gradient accumulation with hooks."""
        def gradient_hook(name):
            def hook(grad):
                if grad is not None:
                    self.accumulated_gradients[name] += grad / self.config.accumulation_steps
            return hook
        
        # Register hooks for all parameters
        for name, param in model.named_parameters():
            if param.requires_grad:
                param.register_hook(gradient_hook(name))
    
    def _setup_memory_efficient_accumulation(self, model: nn.Module):
        """Setup memory-efficient gradient accumulation."""
        # For memory-efficient accumulation, we'll handle gradients manually
        # This reduces memory overhead but requires manual gradient handling
        logger.info("Memory-efficient gradient accumulation enabled")
    
    def _setup_batch_norm_sync(self, model: nn.Module):
        """Setup batch normalization synchronization for accumulated batches."""
        # Convert BatchNorm to SyncBatchNorm if available
        if hasattr(torch.nn, 'SyncBatchNorm'):
            for name, module in model.named_modules():
                if isinstance(module, nn.BatchNorm1d):
                    setattr(model, name, nn.SyncBatchNorm(module.num_features))
                elif isinstance(module, nn.BatchNorm2d):
                    setattr(model, name, nn.SyncBatchNorm(module.num_features))
                elif isinstance(module, nn.BatchNorm3d):
                    setattr(model, name, nn.SyncBatchNorm(module.num_features))
            
            logger.info("BatchNorm synchronization enabled")
    
    def accumulate_gradients(self, loss: torch.Tensor, model: nn.Module, 
                           optimizer: torch.optim.Optimizer, scaler: GradScaler = None) -> Dict[str, Any]:
        """Accumulate gradients for the current step."""
        try:
            start_time = time.time()
            
            # Scale loss for gradient accumulation
            if self.config.scale_loss:
                scaled_loss = loss / self.config.accumulation_steps
            else:
                scaled_loss = loss
            
            # Backward pass
            if scaler:
                scaler.scale(scaled_loss).backward()
            else:
                scaled_loss.backward()
            
            # Accumulate gradients
            self.accumulation_count += 1
            
            # Record performance metrics
            step_time = time.time() - start_time
            self.step_times.append(step_time)
            
            # Monitor memory usage
            if self.config.monitor_memory and torch.cuda.is_available():
                memory_used = torch.cuda.memory_allocated() / (1024**3)  # GB
                self.memory_usage.append(memory_used)
                
                # Auto-adjust accumulation steps if enabled
                if self.config.auto_adjust:
                    self._auto_adjust_accumulation_steps(memory_used)
            
            # Check if it's time to update weights
            should_update = self.accumulation_count % self.config.accumulation_steps == 0
            
            metrics = {
                'step': self.current_step,
                'accumulation_count': self.accumulation_count,
                'accumulation_steps': self.config.accumulation_steps,
                'should_update': should_update,
                'step_time': step_time,
                'memory_usage': self.memory_usage[-1] if self.memory_usage else 0,
                'effective_batch_size': self.config.effective_batch_size,
                'scaled_loss': scaled_loss.item() if hasattr(scaled_loss, 'item') else scaled_loss
            }
            
            self.current_step += 1
            return metrics
            
        except Exception as e:
            logger.error(f"Gradient accumulation failed: {e}")
            raise
    
    def update_weights(self, model: nn.Module, optimizer: torch.optim.Optimizer, 
                      scaler: GradScaler = None) -> bool:
        """Update weights after gradient accumulation."""
        try:
            if self.accumulation_count % self.config.accumulation_steps != 0:
                logger.warning("Attempting to update weights before accumulation complete")
                return False
            
            # Update weights
            if scaler:
                scaler.step(optimizer)
                scaler.update()
            else:
                optimizer.step()
            
            # Zero gradients
            optimizer.zero_grad(set_to_none=True)
            
            # Reset accumulation count
            self.accumulation_count = 0
            
            # Clear accumulated gradients
            self._clear_accumulated_gradients()
            
            logger.debug(f"Weights updated after {self.config.accumulation_steps} accumulation steps")
            return True
            
        except Exception as e:
            logger.error(f"Weight update failed: {e}")
            return False
    
    def _clear_accumulated_gradients(self):
        """Clear accumulated gradients."""
        for name in self.accumulated_gradients:
            self.accumulated_gradients[name].zero_()
    
    def _auto_adjust_accumulation_steps(self, current_memory: float):
        """Automatically adjust accumulation steps based on memory usage."""
        try:
            if not self.config.auto_adjust:
                return
            
            # Calculate memory usage ratio
            if torch.cuda.is_available():
                total_memory = torch.cuda.get_device_properties(0).total_memory / (1024**3)  # GB
                memory_ratio = current_memory / total_memory
            else:
                return
            
            # Adjust accumulation steps based on memory usage
            if memory_ratio > self.config.max_memory_usage:
                # Memory usage too high, increase accumulation steps
                new_steps = min(self.config.accumulation_steps + 1, self.config.max_accumulation_steps)
                if new_steps != self.config.accumulation_steps:
                    self._adapt_accumulation_steps(new_steps, 'memory_high', memory_ratio)
            
            elif memory_ratio < self.config.adaptive_threshold:
                # Memory usage low, can decrease accumulation steps
                new_steps = max(self.config.accumulation_steps - 1, self.config.min_accumulation_steps)
                if new_steps != self.config.accumulation_steps:
                    self._adapt_accumulation_steps(new_steps, 'memory_low', memory_ratio)
                    
        except Exception as e:
            logger.warning(f"Auto-adjustment of accumulation steps failed: {e}")
    
    def _adapt_accumulation_steps(self, new_steps: int, reason: str, memory_ratio: float):
        """Adapt accumulation steps and record adaptation."""
        old_steps = self.config.accumulation_steps
        self.config.update_accumulation_steps(new_steps)
        
        adaptation_record = {
            'step': self.current_step,
            'old_steps': old_steps,
            'new_steps': new_steps,
            'reason': reason,
            'memory_ratio': memory_ratio,
            'timestamp': time.time()
        }
        
        self.adaptation_history.append(adaptation_record)
        
        if self.config.verbose:
            logger.info(f"Adapted accumulation steps: {old_steps} -> {new_steps} ({reason})")
    
    def get_accumulation_stats(self) -> Dict[str, Any]:
        """Get comprehensive accumulation statistics."""
        try:
            stats = {
                'configuration': self.config.to_dict(),
                'current_state': {
                    'current_step': self.current_step,
                    'accumulation_count': self.accumulation_count,
                    'should_update': self.accumulation_count % self.config.accumulation_steps == 0
                },
                'performance': {
                    'average_step_time': np.mean(self.step_times) if self.step_times else 0,
                    'total_steps': len(self.step_times),
                    'average_memory_usage': np.mean(self.memory_usage) if self.memory_usage else 0,
                    'peak_memory_usage': np.max(self.memory_usage) if self.memory_usage else 0
                },
                'adaptations': {
                    'total_adaptations': len(self.adaptation_history),
                    'adaptation_history': self.adaptation_history[-10:] if self.adaptation_history else []  # Last 10
                },
                'effective_batch_size': self.config.effective_batch_size,
                'learning_rate_scale_factor': self.config.get_learning_rate_scale_factor()
            }
            
            return stats
            
        except Exception as e:
            logger.error(f"Failed to get accumulation stats: {e}")
            return {'error': str(e)}
    
    def reset_accumulation(self):
        """Reset accumulation state."""
        self.current_step = 0
        self.accumulation_count = 0
        self.step_times.clear()
        self.memory_usage.clear()
        self.gradient_norms.clear()
        self.adaptation_history.clear()
        self._clear_accumulated_gradients()
        
        logger.info("Gradient accumulation state reset")
    
    def calculate_optimal_accumulation_steps(self, target_batch_size: int, 
                                          available_memory: float = None) -> int:
        """Calculate optimal accumulation steps for target batch size."""
        try:
            if target_batch_size <= self.config.base_batch_size:
                return 1
            
            # Calculate required accumulation steps
            required_steps = target_batch_size // self.config.base_batch_size
            
            # Consider memory constraints
            if available_memory is not None and self.config.monitor_memory:
                # Estimate memory per step and adjust
                estimated_memory_per_step = available_memory * 0.8  # Conservative estimate
                max_steps_by_memory = int(estimated_memory_per_step / (self.config.base_batch_size * 0.1))  # Rough estimate
                required_steps = min(required_steps, max_steps_by_memory)
            
            # Ensure within bounds
            optimal_steps = max(self.config.min_accumulation_steps, 
                              min(required_steps, self.config.max_accumulation_steps))
            
            return optimal_steps
            
        except Exception as e:
            logger.error(f"Failed to calculate optimal accumulation steps: {e}")
            return self.config.accumulation_steps
    
    def warmup_accumulation(self, warmup_steps: int = None):
        """Warmup accumulation with gradually increasing steps."""
        try:
            warmup_steps = warmup_steps or self.config.warmup_steps
            if warmup_steps <= 0:
                return
            
            logger.info(f"Starting accumulation warmup for {warmup_steps} steps")
            
            # Gradually increase accumulation steps
            for step in range(warmup_steps):
                progress = step / warmup_steps
                target_steps = int(1 + progress * (self.config.accumulation_steps - 1))
                
                self.config.update_accumulation_steps(target_steps)
                
                if self.config.verbose:
                    logger.info(f"Warmup step {step + 1}/{warmup_steps}: {target_steps} accumulation steps")
                
                # Wait for next step
                time.sleep(0.1)  # Small delay for demonstration
            
            # Restore original accumulation steps
            self.config.update_accumulation_steps(self.config.accumulation_steps)
            logger.info("Accumulation warmup completed")
            
        except Exception as e:
            logger.error(f"Accumulation warmup failed: {e}")
    
    def cleanup(self):
        """Cleanup gradient accumulation resources."""
        try:
            self._clear_accumulated_gradients()
            self.accumulated_gradients.clear()
            self.reset_accumulation()
            logger.info("Gradient accumulation cleanup completed")
            
        except Exception as e:
            logger.error(f"Gradient accumulation cleanup failed: {e}")


class AdvancedGradientAccumulationTrainer:
    """Advanced trainer with comprehensive gradient accumulation support."""
    
    def __init__(self, model: nn.Module, optimizer: torch.optim.Optimizer,
                 config: GradientAccumulationConfig = None):
        self.model = model
        self.optimizer = optimizer
        self.config = config or GradientAccumulationConfig()
        self.accumulation_manager = GradientAccumulationManager(config)
        
        # Training state
        self.current_epoch = 0
        self.global_step = 0
        self.epoch_losses = []
        self.epoch_metrics = []
        
        # Setup accumulation
        self.accumulation_manager.setup_accumulation(model, optimizer)
        
        logger.info(f"Advanced Gradient Accumulation Trainer initialized")
    
    def train_step(self, batch, criterion, scaler: GradScaler = None) -> Dict[str, Any]:
        """Execute a single training step with gradient accumulation."""
        try:
            # Forward pass
            outputs = self.model(batch)
            if isinstance(outputs, dict):
                loss = outputs.get('loss', outputs.get('logits', outputs))
            else:
                loss = outputs
            
            # Accumulate gradients
            accumulation_metrics = self.accumulation_manager.accumulate_gradients(
                loss, self.model, self.optimizer, scaler
            )
            
            # Update weights if accumulation complete
            if accumulation_metrics['should_update']:
                self.accumulation_manager.update_weights(self.model, self.optimizer, scaler)
                self.global_step += 1
            
            # Record metrics
            step_metrics = {
                'loss': loss.item(),
                'accumulation_step': accumulation_metrics['accumulation_count'],
                'should_update': accumulation_metrics['should_update'],
                'effective_batch_size': accumulation_metrics['effective_batch_size'],
                'step_time': accumulation_metrics['step_time'],
                'memory_usage': accumulation_metrics['memory_usage']
            }
            
            return step_metrics
            
        except Exception as e:
            logger.error(f"Training step failed: {e}")
            raise
    
    def train_epoch(self, dataloader: DataLoader, criterion, scaler: GradScaler = None) -> Dict[str, Any]:
        """Train for one epoch with gradient accumulation."""
        try:
            self.model.train()
            epoch_loss = 0
            epoch_metrics = []
            
            for batch_idx, batch in enumerate(dataloader):
                # Training step
                step_metrics = self.train_step(batch, criterion, scaler)
                epoch_metrics.append(step_metrics)
                epoch_loss += step_metrics['loss']
                
                # Log progress
                if batch_idx % 100 == 0:
                    logger.info(f"Epoch {self.current_epoch}, Batch {batch_idx}: "
                              f"Loss: {step_metrics['loss']:.4f}, "
                              f"Accumulation: {step_metrics['accumulation_step']}/{self.config.accumulation_steps}")
            
            # Final weight update if needed
            if self.accumulation_manager.accumulation_count > 0:
                self.accumulation_manager.update_weights(self.model, self.optimizer, scaler)
                self.global_step += 1
            
            # Calculate epoch statistics
            avg_loss = epoch_loss / len(dataloader)
            self.epoch_losses.append(avg_loss)
            
            epoch_summary = {
                'epoch': self.current_epoch,
                'avg_loss': avg_loss,
                'total_steps': len(dataloader),
                'global_step': self.global_step,
                'accumulation_stats': self.accumulation_manager.get_accumulation_stats()
            }
            
            self.epoch_metrics.append(epoch_summary)
            self.current_epoch += 1
            
            return epoch_summary
            
        except Exception as e:
            logger.error(f"Training epoch failed: {e}")
            raise
    
    def get_training_summary(self) -> Dict[str, Any]:
        """Get comprehensive training summary."""
        try:
            summary = {
                'current_epoch': self.current_epoch,
                'global_step': self.global_step,
                'epoch_losses': self.epoch_losses,
                'epoch_metrics': self.epoch_metrics,
                'accumulation_stats': self.accumulation_manager.get_accumulation_stats(),
                'configuration': self.config.to_dict()
            }
            
            return summary
            
        except Exception as e:
            logger.error(f"Failed to get training summary: {e}")
            return {'error': str(e)}
    
    def cleanup(self):
        """Cleanup training resources."""
        try:
            self.accumulation_manager.cleanup()
            logger.info("Advanced Gradient Accumulation Trainer cleanup completed")
            
        except Exception as e:
            logger.error(f"Advanced Gradient Accumulation Trainer cleanup failed: {e}")


