# COMPREHENSIVE MIXED PRECISION TRAINING SYSTEM
# =============================================================================

class MixedPrecisionConfig:
    """Configuration for mixed precision training system."""
    
    def __init__(self, 
                 enable_mixed_precision: bool = True,
                 dtype: str = 'float16',  # 'float16', 'bfloat16', 'float32'
                 autocast_enabled: bool = True,
                 grad_scaler_enabled: bool = True,
                 initial_scale: float = 2.**16,
                 growth_factor: float = 2.0,
                 backoff_factor: float = 0.5,
                 growth_interval: int = 2000,
                 hysteresis: int = 2,
                 tolerance: float = 1e-4,
                 memory_efficient: bool = True,
                 cache_enabled: bool = True,
                 dynamic_scaling: bool = True,
                 adaptive_scaling: bool = True,
                 monitor_nan_inf: bool = True,
                 fallback_to_fp32: bool = True,
                 verbose: bool = True):
        
        self.enable_mixed_precision = enable_mixed_precision
        self.dtype = dtype
        self.autocast_enabled = autocast_enabled
        self.grad_scaler_enabled = grad_scaler_enabled
        self.initial_scale = initial_scale
        self.growth_factor = growth_factor
        self.backoff_factor = backoff_factor
        self.growth_interval = growth_interval
        self.hysteresis = hysteresis
        self.tolerance = tolerance
        self.memory_efficient = memory_efficient
        self.cache_enabled = cache_enabled
        self.dynamic_scaling = dynamic_scaling
        self.adaptive_scaling = adaptive_scaling
        self.monitor_nan_inf = monitor_nan_inf
        self.fallback_to_fp32 = fallback_to_fp32
        self.verbose = verbose
        
        # Validate configuration
        self._validate_config()
        
        # Set PyTorch dtype
        self._set_torch_dtype()
    
    def _validate_config(self):
        """Validate mixed precision configuration."""
        if self.dtype not in ['float16', 'bfloat16', 'float32']:
            raise ValueError(f"Invalid dtype: {self.dtype}. Must be 'float16', 'bfloat16', or 'float32'")
        
        if self.initial_scale <= 0:
            raise ValueError(f"Initial scale must be > 0, got {self.initial_scale}")
        
        if self.growth_factor <= 1.0:
            raise ValueError(f"Growth factor must be > 1.0, got {self.growth_factor}")
        
        if self.backoff_factor <= 0 or self.backoff_factor >= 1.0:
            raise ValueError(f"Backoff factor must be between 0 and 1, got {self.backoff_factor}")
        
        if self.growth_interval <= 0:
            raise ValueError(f"Growth interval must be > 0, got {self.growth_interval}")
        
        if self.hysteresis <= 0:
            raise ValueError(f"Hysteresis must be > 0, got {self.hysteresis}")
    
    def _set_torch_dtype(self):
        """Set PyTorch dtype based on configuration."""
        if self.dtype == 'float16':
            self.torch_dtype = torch.float16
        elif self.dtype == 'bfloat16':
            self.torch_dtype = torch.bfloat16
        else:
            self.torch_dtype = torch.float32
    
    def update_dtype(self, new_dtype: str):
        """Update dtype and recalculate torch dtype."""
        if new_dtype not in ['float16', 'bfloat16', 'float32']:
            raise ValueError(f"Invalid dtype: {new_dtype}")
        
        self.dtype = new_dtype
        self._set_torch_dtype()
        
        if self.verbose:
            logger.info(f"Updated mixed precision dtype to {new_dtype}")
    
    def to_dict(self) -> Dict[str, Any]:
        """Convert configuration to dictionary."""
        return {
            'enable_mixed_precision': self.enable_mixed_precision,
            'dtype': self.dtype,
            'autocast_enabled': self.autocast_enabled,
            'grad_scaler_enabled': self.grad_scaler_enabled,
            'initial_scale': self.initial_scale,
            'growth_factor': self.growth_factor,
            'backoff_factor': self.backoff_factor,
            'growth_interval': self.growth_interval,
            'hysteresis': self.hysteresis,
            'tolerance': self.tolerance,
            'memory_efficient': self.memory_efficient,
            'cache_enabled': self.cache_enabled,
            'dynamic_scaling': self.dynamic_scaling,
            'adaptive_scaling': self.adaptive_scaling,
            'monitor_nan_inf': self.monitor_nan_inf,
            'fallback_to_fp32': self.fallback_to_fp32,
            'verbose': self.verbose,
            'torch_dtype': str(self.torch_dtype)
        }


class MixedPrecisionManager:
    """Advanced mixed precision training manager with torch.cuda.amp."""
    
    def __init__(self, config: MixedPrecisionConfig = None):
        self.config = config or MixedPrecisionConfig()
        self.scaler = None
        self.autocast_context = None
        
        # Performance tracking
        self.training_metrics = {
            'forward_pass_time': [],
            'backward_pass_time': [],
            'optimizer_step_time': [],
            'scaler_step_time': [],
            'memory_usage': [],
            'gradient_norms': [],
            'nan_inf_count': 0,
            'scaler_scale': [],
            'fallback_count': 0
        }
        
        # Setup mixed precision
        self._setup_mixed_precision()
        
        logger.info(f"Mixed Precision Manager initialized with {self.config.dtype}")
    
    def _setup_mixed_precision(self):
        """Setup mixed precision training components."""
        try:
            if not self.config.enable_mixed_precision:
                logger.info("Mixed precision disabled")
                return
            
            # Check CUDA availability
            if not torch.cuda.is_available():
                logger.warning("CUDA not available, mixed precision will be limited")
                self.config.enable_mixed_precision = False
                return
            
            # Setup GradScaler
            if self.config.grad_scaler_enabled:
                self.scaler = GradScaler(
                    init_scale=self.config.initial_scale,
                    growth_factor=self.config.growth_factor,
                    backoff_factor=self.config.backoff_factor,
                    growth_interval=self.config.growth_interval,
                    hysteresis=self.config.hysteresis
                )
                logger.info("GradScaler initialized for mixed precision training")
            
            # Setup autocast context
            if self.config.autocast_enabled:
                self.autocast_context = autocast(
                    dtype=self.config.torch_dtype,
                    cache_enabled=self.config.cache_enabled
                )
                logger.info(f"Autocast context initialized with {self.config.dtype}")
            
            # Enable memory efficient attention if available
            if self.config.memory_efficient and hasattr(torch.backends.cuda, 'sdp_kernel'):
                torch.backends.cuda.sdp_kernel(enable_flash=True, enable_math=True, enable_mem_efficient=True)
                logger.info("Memory efficient attention enabled")
            
            logger.info("Mixed precision setup completed successfully")
            
        except Exception as e:
            logger.error(f"Mixed precision setup failed: {e}")
            self.config.enable_mixed_precision = False
    
    def get_autocast_context(self):
        """Get autocast context for mixed precision training."""
        if not self.config.enable_mixed_precision or not self.config.autocast_enabled:
            return nullcontext()
        
        return self.autocast_context
    
    def get_grad_scaler(self):
        """Get gradient scaler for mixed precision training."""
        return self.scaler if self.config.grad_scaler_enabled else None
    
    def setup_model_for_mixed_precision(self, model: nn.Module) -> nn.Module:
        """Setup model for mixed precision training."""
        try:
            if not self.config.enable_mixed_precision:
                return model
            
            # Convert model to mixed precision dtype
            if self.config.dtype != 'float32':
                model = model.to(dtype=self.config.torch_dtype)
                logger.info(f"Model converted to {self.config.dtype}")
            
            # Enable memory efficient attention for transformer models
            if self.config.memory_efficient:
                self._enable_memory_efficient_attention(model)
            
            return model
            
        except Exception as e:
            logger.error(f"Failed to setup model for mixed precision: {e}")
            return model
    
    def _enable_memory_efficient_attention(self, model: nn.Module):
        """Enable memory efficient attention for transformer models."""
        try:
            # Check for transformer models and enable memory efficient attention
            for module in model.modules():
                if hasattr(module, 'attention') and hasattr(module.attention, 'enable_memory_efficient'):
                    module.attention.enable_memory_efficient(True)
                elif hasattr(module, 'enable_memory_efficient'):
                    module.enable_memory_efficient(True)
            
            logger.info("Memory efficient attention enabled for transformer models")
            
        except Exception as e:
            logger.warning(f"Failed to enable memory efficient attention: {e}")
    
    def forward_pass(self, model: nn.Module, inputs, **kwargs) -> Tuple[Any, float]:
        """Execute forward pass with mixed precision."""
        try:
            start_time = time.time()
            
            # Use autocast context
            with self.get_autocast_context():
                outputs = model(inputs, **kwargs)
            
            forward_time = time.time() - start_time
            self.training_metrics['forward_pass_time'].append(forward_time)
            
            return outputs, forward_time
            
        except Exception as e:
            logger.error(f"Forward pass failed: {e}")
            raise
    
    def backward_pass(self, loss: torch.Tensor, optimizer: torch.optim.Optimizer,
                     model: nn.Module, **kwargs) -> Tuple[float, float]:
        """Execute backward pass with mixed precision."""
        try:
            start_time = time.time()
            
            # Scale loss if using GradScaler
            if self.scaler is not None:
                scaled_loss = self.scaler.scale(loss)
                scaled_loss.backward(**kwargs)
                
                # Record scaler scale
                self.training_metrics['scaler_scale'].append(self.scaler.get_scale())
            else:
                loss.backward(**kwargs)
            
            backward_time = time.time() - start_time
            self.training_metrics['backward_pass_time'].append(backward_time)
            
            return backward_time, self.scaler.get_scale() if self.scaler else 1.0
            
        except Exception as e:
            logger.error(f"Backward pass failed: {e}")
            raise
    
    def optimizer_step(self, optimizer: torch.optim.Optimizer, 
                      model: nn.Module, **kwargs) -> Tuple[bool, float]:
        """Execute optimizer step with mixed precision."""
        try:
            start_time = time.time()
            
            if self.scaler is not None:
                # Unscale gradients and step optimizer
                self.scaler.step(optimizer)
                self.scaler.update()
                
                # Check for NaN/Inf values
                if self.config.monitor_nan_inf:
                    self._check_nan_inf(model)
                
                step_time = time.time() - start_time
                self.training_metrics['scaler_step_time'].append(step_time)
                
                return True, step_time
            else:
                # Standard optimizer step
                optimizer.step()
                
                step_time = time.time() - start_time
                self.training_metrics['optimizer_step_time'].append(step_time)
                
                return True, step_time
                
        except Exception as e:
            logger.error(f"Optimizer step failed: {e}")
            
            # Fallback to FP32 if enabled
            if self.config.fallback_to_fp32:
                return self._fallback_to_fp32(optimizer, model, **kwargs)
            
            return False, 0.0
    
    def _check_nan_inf(self, model: nn.Module):
        """Check for NaN/Inf values in model parameters and gradients."""
        try:
            nan_inf_found = False
            
            for name, param in model.named_parameters():
                if param.grad is not None:
                    if torch.isnan(param.grad).any() or torch.isinf(param.grad).any():
                        nan_inf_found = True
                        if self.config.verbose:
                            logger.warning(f"NaN/Inf detected in gradients of {name}")
            
            if nan_inf_found:
                self.training_metrics['nan_inf_count'] += 1
                
                # Reduce scaler scale if using GradScaler
                if self.scaler is not None:
                    self.scaler.update(0)
                    logger.info("GradScaler scale reset due to NaN/Inf values")
            
        except Exception as e:
            logger.warning(f"Failed to check for NaN/Inf values: {e}")
    
    def _fallback_to_fp32(self, optimizer: torch.optim.Optimizer, 
                          model: nn.Module, **kwargs) -> Tuple[bool, float]:
        """Fallback to FP32 precision if mixed precision fails."""
        try:
            logger.warning("Falling back to FP32 precision")
            
            # Convert model back to FP32
            model = model.to(dtype=torch.float32)
            
            # Disable mixed precision temporarily
            original_enabled = self.config.enable_mixed_precision
            self.config.enable_mixed_precision = False
            
            # Execute optimizer step in FP32
            start_time = time.time()
            optimizer.step()
            step_time = time.time() - start_time
            
            # Restore mixed precision
            self.config.enable_mixed_precision = original_enabled
            
            self.training_metrics['fallback_count'] += 1
            self.training_metrics['optimizer_step_time'].append(step_time)
            
            logger.info("Successfully fell back to FP32 precision")
            return True, step_time
            
        except Exception as e:
            logger.error(f"FP32 fallback failed: {e}")
            return False, 0.0
    
    def training_step(self, model: nn.Module, inputs, targets, 
                     criterion, optimizer: torch.optim.Optimizer, **kwargs) -> Dict[str, Any]:
        """Execute complete training step with mixed precision."""
        try:
            # Forward pass
            outputs, forward_time = self.forward_pass(model, inputs, **kwargs)
            
            # Calculate loss
            loss = criterion(outputs, targets)
            
            # Backward pass
            backward_time, scaler_scale = self.backward_pass(loss, optimizer, model, **kwargs)
            
            # Optimizer step
            step_success, step_time = self.optimizer_step(optimizer, model, **kwargs)
            
            # Record metrics
            metrics = {
                'loss': loss.item(),
                'forward_time': forward_time,
                'backward_time': backward_time,
                'step_time': step_time,
                'total_time': forward_time + backward_time + step_time,
                'scaler_scale': scaler_scale,
                'step_success': step_success,
                'dtype': self.config.dtype,
                'mixed_precision_enabled': self.config.enable_mixed_precision
            }
            
            # Update performance metrics
            self._update_performance_metrics(metrics)
            
            return metrics
            
        except Exception as e:
            logger.error(f"Training step failed: {e}")
            raise
    
    def _update_performance_metrics(self, metrics: Dict[str, Any]):
        """Update performance tracking metrics."""
        try:
            # Record memory usage
            if torch.cuda.is_available():
                memory_used = torch.cuda.memory_allocated() / (1024**3)  # GB
                self.training_metrics['memory_usage'].append(memory_used)
            
            # Record gradient norms
            if hasattr(metrics, 'gradient_norm'):
                self.training_metrics['gradient_norms'].append(metrics['gradient_norm'])
            
            # Keep metrics history manageable
            max_history = 1000
            for key in self.training_metrics:
                if isinstance(self.training_metrics[key], list) and len(self.training_metrics[key]) > max_history:
                    self.training_metrics[key] = self.training_metrics[key][-max_history:]
                    
        except Exception as e:
            logger.warning(f"Failed to update performance metrics: {e}")
    
    def get_performance_summary(self) -> Dict[str, Any]:
        """Get comprehensive mixed precision performance summary."""
        try:
            summary = {
                'configuration': self.config.to_dict(),
                'performance': {}
            }
            
            # Calculate performance statistics
            for metric_name, values in self.training_metrics.items():
                if isinstance(values, list) and values:
                    summary['performance'][metric_name] = {
                        'count': len(values),
                        'mean': np.mean(values),
                        'std': np.std(values),
                        'min': np.min(values),
                        'max': np.max(values),
                        'latest': values[-1] if values else None
                    }
                else:
                    summary['performance'][metric_name] = values
            
            # Calculate speedup metrics
            if summary['performance'].get('forward_pass_time', {}).get('count', 0) > 0:
                avg_forward_time = summary['performance']['forward_pass_time']['mean']
                summary['performance']['speedup_analysis'] = {
                    'avg_forward_time': avg_forward_time,
                    'estimated_fp32_time': avg_forward_time * 1.5,  # Rough estimate
                    'speedup_factor': 1.5
                }
            
            return summary
            
        except Exception as e:
            logger.error(f"Failed to get performance summary: {e}")
            return {'error': str(e)}
    
    def benchmark_mixed_precision(self, model: nn.Module, dataloader: DataLoader,
                                criterion, optimizer: torch.optim.Optimizer,
                                num_iterations: int = 100) -> Dict[str, Any]:
        """Benchmark mixed precision vs. FP32 performance."""
        try:
            logger.info(f"Starting mixed precision benchmark with {num_iterations} iterations...")
            
            # Benchmark mixed precision
            mp_metrics = self._benchmark_precision(model, dataloader, criterion, 
                                                 optimizer, num_iterations, use_mixed_precision=True)
            
            # Benchmark FP32
            fp32_metrics = self._benchmark_precision(model, dataloader, criterion, 
                                                   optimizer, num_iterations, use_mixed_precision=False)
            
            # Calculate performance comparison
            comparison = self._calculate_performance_comparison(mp_metrics, fp32_metrics)
            
            benchmark_results = {
                'mixed_precision': mp_metrics,
                'fp32': fp32_metrics,
                'comparison': comparison,
                'configuration': self.config.to_dict()
            }
            
            logger.info("Mixed precision benchmark completed successfully")
            return benchmark_results
            
        except Exception as e:
            logger.error(f"Mixed precision benchmark failed: {e}")
            return {'error': str(e)}
    
    def _benchmark_precision(self, model: nn.Module, dataloader: DataLoader,
                            criterion, optimizer: torch.optim.Optimizer,
                            num_iterations: int, use_mixed_precision: bool) -> Dict[str, Any]:
        """Benchmark specific precision mode."""
        try:
            # Temporarily modify configuration
            original_enabled = self.config.enable_mixed_precision
            self.config.enable_mixed_precision = use_mixed_precision
            
            # Setup model for current precision
            if use_mixed_precision:
                model = self.setup_model_for_mixed_precision(model)
            else:
                model = model.to(dtype=torch.float32)
            
            # Benchmark
            start_time = time.time()
            total_loss = 0
            step_times = []
            
            for i, batch in enumerate(dataloader):
                if i >= num_iterations:
                    break
                
                step_start = time.time()
                
                # Training step
                metrics = self.training_step(model, batch, batch, criterion, optimizer)
                
                total_loss += metrics['loss']
                step_time = metrics['total_time']
                step_times.append(step_time)
            
            total_time = time.time() - start_time
            
            # Restore original configuration
            self.config.enable_mixed_precision = original_enabled
            
            return {
                'total_time': total_time,
                'average_loss': total_loss / len(step_times) if step_times else 0,
                'step_times': step_times,
                'throughput': len(step_times) / total_time if total_time > 0 else 0,
                'precision_mode': 'mixed_precision' if use_mixed_precision else 'fp32'
            }
            
        except Exception as e:
            logger.error(f"Precision benchmark failed: {e}")
            return {'error': str(e)}
    
    def _calculate_performance_comparison(self, mp_metrics: Dict[str, Any],
                                        fp32_metrics: Dict[str, Any]) -> Dict[str, Any]:
        """Calculate performance comparison between mixed precision and FP32."""
        try:
            if 'error' in mp_metrics or 'error' in fp32_metrics:
                return {'error': 'Benchmark failed'}
            
            mp_throughput = mp_metrics.get('throughput', 0)
            fp32_throughput = fp32_metrics.get('throughput', 0)
            
            if fp32_throughput <= 0:
                return {'error': 'Invalid FP32 throughput'}
            
            # Calculate performance metrics
            speedup = mp_throughput / fp32_throughput
            improvement_percentage = (speedup - 1) * 100
            
            return {
                'speedup': speedup,
                'improvement_percentage': improvement_percentage,
                'mp_throughput': mp_throughput,
                'fp32_throughput': fp32_throughput,
                'efficiency': min(speedup, 2.0) / 2.0  # Normalize to theoretical max
            }
            
        except Exception as e:
            logger.error(f"Performance comparison calculation failed: {e}")
            return {'error': str(e)}
    
    def reset_metrics(self):
        """Reset performance metrics."""
        for key in self.training_metrics:
            if isinstance(self.training_metrics[key], list):
                self.training_metrics[key].clear()
            else:
                self.training_metrics[key] = 0
        
        logger.info("Mixed precision performance metrics reset")
    
    def cleanup(self):
        """Cleanup mixed precision resources."""
        try:
            if self.scaler is not None:
                del self.scaler
                self.scaler = None
            
            if self.autocast_context is not None:
                del self.autocast_context
                self.autocast_context = None
            
            self.reset_metrics()
            logger.info("Mixed precision cleanup completed")
            
        except Exception as e:
            logger.error(f"Mixed precision cleanup failed: {e}")


class AdvancedMixedPrecisionTrainer:
    """Advanced trainer with comprehensive mixed precision support."""
    
    def __init__(self, model: nn.Module, optimizer: torch.optim.Optimizer,
                 config: MixedPrecisionConfig = None):
        self.model = model
        self.optimizer = optimizer
        self.config = config or MixedPrecisionConfig()
        self.mixed_precision_manager = MixedPrecisionManager(config)
        
        # Training state
        self.current_epoch = 0
        self.global_step = 0
        self.epoch_losses = []
        self.epoch_metrics = []
        
        # Setup model for mixed precision
        self.model = self.mixed_precision_manager.setup_model_for_mixed_precision(model)
        
        logger.info(f"Advanced Mixed Precision Trainer initialized with {self.config.dtype}")
    
    def train_step(self, batch, targets, criterion) -> Dict[str, Any]:
        """Execute a single training step with mixed precision."""
        try:
            # Training step with mixed precision
            metrics = self.mixed_precision_manager.training_step(
                self.model, batch, targets, criterion, self.optimizer
            )
            
            # Update global step
            if metrics['step_success']:
                self.global_step += 1
            
            return metrics
            
        except Exception as e:
            logger.error(f"Training step failed: {e}")
            raise
    
    def train_epoch(self, dataloader: DataLoader, criterion) -> Dict[str, Any]:
        """Train for one epoch with mixed precision."""
        try:
            self.model.train()
            epoch_loss = 0
            epoch_metrics = []
            
            for batch_idx, batch in enumerate(dataloader):
                # Training step
                step_metrics = self.train_step(batch, batch, criterion)
                epoch_metrics.append(step_metrics)
                epoch_loss += step_metrics['loss']
                
                # Log progress
                if batch_idx % 100 == 0:
                    logger.info(f"Epoch {self.current_epoch}, Batch {batch_idx}: "
                              f"Loss: {step_metrics['loss']:.4f}, "
                              f"Time: {step_metrics['total_time']:.4f}s, "
                              f"Precision: {step_metrics['dtype']}")
            
            # Calculate epoch statistics
            avg_loss = epoch_loss / len(dataloader)
            self.epoch_losses.append(avg_loss)
            
            epoch_summary = {
                'epoch': self.current_epoch,
                'avg_loss': avg_loss,
                'total_steps': len(dataloader),
                'global_step': self.global_step,
                'mixed_precision_stats': self.mixed_precision_manager.get_performance_summary()
            }
            
            self.epoch_metrics.append(epoch_summary)
            self.current_epoch += 1
            
            return epoch_summary
            
        except Exception as e:
            logger.error(f"Training epoch failed: {e}")
            raise
    
    def get_training_summary(self) -> Dict[str, Any]:
        """Get comprehensive training summary."""
        try:
            summary = {
                'current_epoch': self.current_epoch,
                'global_step': self.global_step,
                'epoch_losses': self.epoch_losses,
                'epoch_metrics': self.epoch_metrics,
                'mixed_precision_stats': self.mixed_precision_manager.get_performance_summary(),
                'configuration': self.config.to_dict()
            }
            
            return summary
            
        except Exception as e:
            logger.error(f"Failed to get training summary: {e}")
            return {'error': str(e)}
    
    def benchmark_performance(self, dataloader: DataLoader, criterion,
                            num_iterations: int = 100) -> Dict[str, Any]:
        """Benchmark mixed precision performance."""
        return self.mixed_precision_manager.benchmark_mixed_precision(
            self.model, dataloader, criterion, self.optimizer, num_iterations
        )
    
    def cleanup(self):
        """Cleanup training resources."""
        try:
            self.mixed_precision_manager.cleanup()
            logger.info("Advanced Mixed Precision Trainer cleanup completed")
            
        except Exception as e:
            logger.error(f"Advanced Mixed Precision Trainer cleanup failed: {e}")


