class DeepLearningErrorHandler:
    """Comprehensive error handling and debugging system for deep learning operations."""
    
    def __init__(self, enable_debugging: bool = False, log_level: str = "INFO"):
        """
        Initialize error handler.
        
        Args:
            enable_debugging: Enable PyTorch debugging tools
            log_level: Logging level (DEBUG, INFO, WARNING, ERROR)
        """
        self.enable_debugging = enable_debugging
        self.log_level = log_level
        self.error_count = 0
        self.warning_count = 0
        self.debug_info = {}
        
        # Setup PyTorch debugging if enabled
        if self.enable_debugging:
            self._setup_pytorch_debugging()
        
        logger.info(f"Deep Learning Error Handler initialized with debugging: {enable_debugging}")
    
    def _setup_pytorch_debugging(self):
        """Setup PyTorch debugging tools."""
        try:
            # Enable autograd anomaly detection
            torch.autograd.set_detect_anomaly(True)
            logger.info("PyTorch autograd anomaly detection enabled")
            
            # Set memory fraction for debugging
            if torch.cuda.is_available():
                torch.cuda.set_per_process_memory_fraction(0.8)
                logger.info("CUDA memory fraction set to 0.8 for debugging")
            
            # Enable detailed error messages
            torch.set_default_dtype(torch.float32)
            logger.info("PyTorch default dtype set to float32 for debugging")
            
        except Exception as e:
            logger.warning(f"Failed to setup PyTorch debugging: {e}")
    
    def handle_error(self, error: Exception, context: str = "unknown", 
                    operation: str = "unknown", **kwargs) -> Dict[str, Any]:
        """
        Handle errors with comprehensive logging and recovery suggestions.
        
        Args:
            error: The exception that occurred
            context: Context where error occurred
            operation: Specific operation that failed
            **kwargs: Additional error context
            
        Returns:
            Dictionary with error information and recovery suggestions
        """
        try:
            self.error_count += 1
            error_type = type(error).__name__
            
            # Log error details
            logger.error(f"Error in {context} during {operation}: {error}")
            logger.error(f"Error type: {error_type}")
            logger.error(f"Additional context: {kwargs}")
            
            # Get error context
            error_context = self._get_error_context(error, context, operation)
            
            # Generate recovery suggestions
            recovery_suggestions = self._generate_recovery_suggestions(error, context, operation)
            
            # Store debug information
            self.debug_info[f"error_{self.error_count}"] = {
                'timestamp': time.time(),
                'error_type': error_type,
                'error_message': str(error),
                'context': context,
                'operation': operation,
                'additional_context': kwargs,
                'recovery_suggestions': recovery_suggestions
            }
            
            return {
                'error': True,
                'error_type': error_type,
                'message': str(error),
                'context': context,
                'operation': operation,
                'recovery_suggestions': recovery_suggestions,
                'error_id': self.error_count,
                'timestamp': time.time()
            }
            
        except Exception as e:
            logger.error(f"Error in error handler: {e}")
            return {
                'error': True,
                'error_type': 'ErrorHandlerError',
                'message': f"Failed to handle error: {str(e)}",
                'context': context,
                'operation': operation
            }
    
    def _get_error_context(self, error: Exception, context: str, operation: str) -> Dict[str, Any]:
        """Extract relevant context information from error."""
        context_info = {
            'context': context,
            'operation': operation,
            'error_type': type(error).__name__,
            'timestamp': time.time()
        }
        
        # Add PyTorch-specific context
        if hasattr(torch, 'cuda') and torch.cuda.is_available():
            context_info.update({
                'cuda_memory_allocated': torch.cuda.memory_allocated(),
                'cuda_memory_reserved': torch.cuda.memory_reserved(),
                'cuda_device_count': torch.cuda.device_count(),
                'current_device': torch.cuda.current_device()
            })
        
        # Add system context
        context_info.update({
            'python_version': sys.version,
            'pytorch_version': torch.__version__,
            'platform': sys.platform
        })
        
        return context_info
    
    def _generate_recovery_suggestions(self, error: Exception, context: str, operation: str) -> List[str]:
        """Generate recovery suggestions based on error type and context."""
        suggestions = []
        error_type = type(error).__name__
        
        # CUDA/GPU errors
        if "CUDA" in str(error) or "GPU" in str(error):
            suggestions.extend([
                "Check GPU memory availability",
                "Reduce batch size or input size",
                "Clear GPU cache: torch.cuda.empty_cache()",
                "Check GPU drivers and PyTorch compatibility"
            ])
        
        # Memory errors
        if "out of memory" in str(error).lower() or "MemoryError" in error_type:
            suggestions.extend([
                "Reduce batch size",
                "Use gradient accumulation",
                "Enable mixed precision training",
                "Check for memory leaks in data loading"
            ])
        
        # Data loading errors
        if "data" in context.lower() or "dataloader" in operation.lower():
            suggestions.extend([
                "Check data file paths and permissions",
                "Verify data format and preprocessing",
                "Reduce number of workers in DataLoader",
                "Check for corrupted data files"
            ])
        
        # Model errors
        if "model" in context.lower() or "forward" in operation.lower():
            suggestions.extend([
                "Check model architecture and input dimensions",
                "Verify model weights and state dict",
                "Check for NaN/Inf values in inputs",
                "Enable gradient anomaly detection"
            ])
        
        # Training errors
        if "training" in context.lower() or "optimizer" in operation.lower():
            suggestions.extend([
                "Check learning rate and optimizer parameters",
                "Verify loss function inputs",
                "Check for gradient explosion/vanishing",
                "Enable gradient clipping"
            ])
        
        # Generic suggestions
        suggestions.extend([
            "Check input data types and shapes",
            "Verify all required dependencies are installed",
            "Check system resources (CPU, RAM, GPU)",
            "Review error logs for additional context"
        ])
        
        return suggestions
    
    def enable_debug_mode(self):
        """Enable comprehensive debugging mode."""
        try:
            self.enable_debugging = True
            self._setup_pytorch_debugging()
            
            # Enable additional debugging
            torch.set_default_tensor_type(torch.DoubleTensor)
            logger.info("Comprehensive debugging mode enabled")
            
        except Exception as e:
            logger.error(f"Failed to enable debug mode: {e}")
    
    def disable_debug_mode(self):
        """Disable debugging mode."""
        try:
            self.enable_debugging = False
            torch.autograd.set_detect_anomaly(False)
            logger.info("Debugging mode disabled")
            
        except Exception as e:
            logger.error(f"Failed to disable debug mode: {e}")
    
    def get_debug_summary(self) -> Dict[str, Any]:
        """Get summary of debugging information."""
        return {
            'error_count': self.error_count,
            'warning_count': self.warning_count,
            'debug_enabled': self.enable_debugging,
            'recent_errors': list(self.debug_info.values())[-5:],  # Last 5 errors
            'pytorch_debug_info': self._get_pytorch_debug_info()
        }
    
    def _get_pytorch_debug_info(self) -> Dict[str, Any]:
        """Get PyTorch debugging information."""
        debug_info = {}
        
        try:
            # Autograd info
            debug_info['autograd_anomaly_detection'] = torch.autograd.is_anomaly_enabled()
            debug_info['autograd_grad_mode'] = torch.is_grad_enabled()
            
            # Memory info
            if torch.cuda.is_available():
                debug_info['cuda_memory_allocated'] = torch.cuda.memory_allocated()
                debug_info['cuda_memory_reserved'] = torch.cuda.memory_reserved()
                debug_info['cuda_memory_cached'] = torch.cuda.memory_reserved()
            
            # Device info
            debug_info['current_device'] = torch.cuda.current_device() if torch.cuda.is_available() else 'CPU'
            debug_info['device_count'] = torch.cuda.device_count() if torch.cuda.is_available() else 0
            
        except Exception as e:
            debug_info['error'] = str(e)
        
        return debug_info
    
    def clear_debug_info(self):
        """Clear stored debug information."""
        self.debug_info.clear()
        self.error_count = 0
        self.warning_count = 0
        logger.info("Debug information cleared")


class RobustDataLoader:
    """DataLoader with comprehensive error handling and debugging."""
    
    def __init__(self, dataset, batch_size: int = 1, shuffle: bool = False, 
                 num_workers: int = 0, error_handler: DeepLearningErrorHandler = None):
        """
        Initialize robust DataLoader.
        
        Args:
            dataset: PyTorch dataset
            batch_size: Batch size
            shuffle: Whether to shuffle data
            num_workers: Number of worker processes
            error_handler: Error handler instance
        """
        self.dataset = dataset
        self.batch_size = batch_size
        self.shuffle = shuffle
        self.num_workers = num_workers
        self.error_handler = error_handler or DeepLearningErrorHandler()
        
        # Create DataLoader with error handling
        self.dataloader = self._create_dataloader()
        
        logger.info(f"Robust DataLoader initialized with {len(dataset)} samples")
    
    def _create_dataloader(self):
        """Create DataLoader with error handling."""
        try:
            # Configure DataLoader with safe defaults
            dataloader = DataLoader(
                dataset=self.dataset,
                batch_size=self.batch_size,
                shuffle=self.shuffle,
                num_workers=min(self.num_workers, 4),  # Limit workers for stability
                pin_memory=torch.cuda.is_available(),
                drop_last=False,
                timeout=60,  # 60 second timeout
                persistent_workers=True if self.num_workers > 0 else False
            )
            
            return dataloader
            
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "DataLoader creation", "dataloader_init"
            )
            logger.error(f"Failed to create DataLoader: {error_info}")
            
            # Fallback to basic DataLoader
            return DataLoader(
                dataset=self.dataset,
                batch_size=self.batch_size,
                shuffle=self.shuffle,
                num_workers=0,  # No multiprocessing
                pin_memory=False
            )
    
    def __iter__(self):
        """Iterate over data with error handling."""
        return self._robust_iterator()
    
    def _robust_iterator(self):
        """Robust iterator with error handling."""
        iterator = iter(self.dataloader)
        
        while True:
            try:
                batch = next(iterator)
                yield batch
                
            except StopIteration:
                break
                
            except Exception as e:
                error_info = self.error_handler.handle_error(
                    e, "data iteration", "batch_loading",
                    batch_index=getattr(self, '_batch_count', 0)
                )
                
                logger.error(f"Batch loading error: {error_info}")
                
                # Try to recover or skip batch
                if self._should_skip_batch(error_info):
                    logger.warning("Skipping problematic batch")
                    continue
                else:
                    # Re-raise if critical
                    raise e
    
    def _should_skip_batch(self, error_info: Dict[str, Any]) -> bool:
        """Determine if batch should be skipped based on error."""
        # Skip for non-critical errors
        skip_errors = ['OSError', 'FileNotFoundError', 'PermissionError']
        return error_info.get('error_type') in skip_errors
    
    def __len__(self):
        """Get length of dataloader."""
        return len(self.dataloader)


class RobustModelInference:
    """Model inference with comprehensive error handling and debugging."""
    
    def __init__(self, model: nn.Module, error_handler: DeepLearningErrorHandler = None):
        """
        Initialize robust model inference.
        
        Args:
            model: PyTorch model
            error_handler: Error handler instance
        """
        self.model = model
        self.error_handler = error_handler or DeepLearningErrorHandler()
        self.inference_count = 0
        self.error_count = 0
        
        # Setup model for inference
        self._setup_model()
        
        logger.info("Robust Model Inference initialized")
    
    def _setup_model(self):
        """Setup model for inference with error handling."""
        try:
            self.model.eval()
            
            # Move to GPU if available
            if torch.cuda.is_available():
                self.model = self.model.cuda()
                logger.info("Model moved to GPU")
            
            # Enable anomaly detection if debugging
            if self.error_handler.enable_debugging:
                torch.autograd.set_detect_anomaly(True)
                logger.info("Anomaly detection enabled for inference")
            
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "model setup", "model_initialization"
            )
            logger.error(f"Model setup failed: {error_info}")
    
    def predict(self, inputs, **kwargs):
        """
        Perform model inference with error handling.
        
        Args:
            inputs: Model inputs
            **kwargs: Additional inference parameters
            
        Returns:
            Model predictions or error information
        """
        try:
            self.inference_count += 1
            
            # Validate inputs
            self._validate_inputs(inputs)
            
            # Perform inference
            with torch.no_grad():
                if self.error_handler.enable_debugging:
                    # Enable anomaly detection for this inference
                    with torch.autograd.detect_anomaly():
                        outputs = self.model(inputs, **kwargs)
                else:
                    outputs = self.model(inputs, **kwargs)
            
            # Validate outputs
            self._validate_outputs(outputs)
            
            return outputs
            
        except Exception as e:
            self.error_count += 1
            error_info = self.error_handler.handle_error(
                e, "model inference", "prediction",
                input_shape=inputs.shape if hasattr(inputs, 'shape') else str(type(inputs)),
                inference_count=self.inference_count
            )
            
            logger.error(f"Inference error: {error_info}")
            return error_info
    
    def _validate_inputs(self, inputs):
        """Validate model inputs."""
        try:
            if inputs is None:
                raise ValueError("Inputs cannot be None")
            
            # Check for NaN/Inf values
            if torch.is_tensor(inputs):
                if torch.isnan(inputs).any():
                    raise ValueError("Input contains NaN values")
                if torch.isinf(inputs).any():
                    raise ValueError("Input contains Inf values")
                
                # Check input dimensions
                if inputs.dim() == 0:
                    raise ValueError("Input tensor must have at least 1 dimension")
            
        except Exception as e:
            raise ValueError(f"Input validation failed: {str(e)}")
    
    def _validate_outputs(self, outputs):
        """Validate model outputs."""
        try:
            if outputs is None:
                raise ValueError("Model outputs cannot be None")
            
            # Check for NaN/Inf values
            if torch.is_tensor(outputs):
                if torch.isnan(outputs).any():
                    raise ValueError("Model outputs contain NaN values")
                if torch.isinf(outputs).any():
                    raise ValueError("Model outputs contain Inf values")
            
        except Exception as e:
            raise ValueError(f"Output validation failed: {str(e)}")
    
    def get_inference_stats(self) -> Dict[str, Any]:
        """Get inference statistics."""
        return {
            'total_inferences': self.inference_count,
            'successful_inferences': self.inference_count - self.error_count,
            'error_count': self.error_count,
            'success_rate': (self.inference_count - self.error_count) / max(1, self.inference_count),
            'debug_info': self.error_handler.get_debug_summary()
        }


