# COMPREHENSIVE ERROR HANDLING AND DEBUGGING SYSTEM
# =============================================================================

class DeepLearningErrorHandler:
    """Comprehensive error handling and debugging system for deep learning operations."""
    
    def __init__(self, enable_debug_mode: bool = False, log_level: str = "INFO"):
        """
        Initialize error handler.
        
        Args:
            enable_debug_mode: Enable PyTorch debugging tools
            log_level: Logging level for error tracking
        """
        self.enable_debug_mode = enable_debug_mode
        self.error_log = []
        self.debug_info = {}
        self.performance_metrics = {}
        
        # Setup PyTorch debugging if enabled
        if self.enable_debug_mode:
            self._setup_pytorch_debugging()
        
        logger.info(f"Deep Learning Error Handler initialized (debug_mode: {enable_debug_mode})")
    
    def _setup_pytorch_debugging(self):
        """Setup PyTorch debugging tools."""
        try:
            # Enable anomaly detection for debugging
            torch.autograd.set_detect_anomaly(True)
            logger.info("PyTorch anomaly detection enabled")
            
            # Set memory fraction for debugging
            if torch.cuda.is_available():
                torch.cuda.set_per_process_memory_fraction(0.8)
                logger.info("CUDA memory fraction set to 0.8 for debugging")
                
        except Exception as e:
            logger.warning(f"Failed to setup PyTorch debugging: {e}")
    
    def safe_execute(self, operation_name: str, operation_func, *args, **kwargs):
        """
        Safely execute operations with comprehensive error handling.
        
        Args:
            operation_name: Name of the operation for logging
            operation_func: Function to execute
            *args: Positional arguments for the function
            **kwargs: Keyword arguments for the function
            
        Returns:
            Tuple of (success, result, error_info)
        """
        start_time = time.time()
        error_info = None
        
        try:
            # Pre-execution checks
            self._pre_execution_checks(operation_name, *args, **kwargs)
            
            # Execute operation
            result = operation_func(*args, **kwargs)
            
            # Post-execution validation
            success = self._post_execution_validation(operation_name, result)
            
            if success:
                execution_time = time.time() - start_time
                self._log_success(operation_name, execution_time, result)
                return True, result, None
            else:
                raise ValueError(f"Post-execution validation failed for {operation_name}")
                
        except Exception as e:
            execution_time = time.time() - start_time
            error_info = self._handle_error(operation_name, e, execution_time, *args, **kwargs)
            return False, None, error_info
    
    def _pre_execution_checks(self, operation_name: str, *args, **kwargs):
        """Perform pre-execution validation checks."""
        try:
            # Check CUDA memory if available
            if torch.cuda.is_available():
                memory_allocated = torch.cuda.memory_allocated() / 1024**3  # GB
                memory_reserved = torch.cuda.memory_reserved() / 1024**3    # GB
                
                if memory_allocated > 0.9:  # 90% threshold
                    logger.warning(f"High CUDA memory usage before {operation_name}: {memory_allocated:.2f}GB")
                
                self.debug_info[f"{operation_name}_pre_memory"] = {
                    'allocated': memory_allocated,
                    'reserved': memory_reserved
                }
            
            # Check input validity
            self._validate_inputs(operation_name, *args, **kwargs)
            
        except Exception as e:
            logger.warning(f"Pre-execution check failed for {operation_name}: {e}")
    
    def _validate_inputs(self, operation_name: str, *args, **kwargs):
        """Validate input parameters."""
        try:
            for i, arg in enumerate(args):
                if isinstance(arg, torch.Tensor):
                    # Check for NaN/Inf in tensors
                    if torch.isnan(arg).any():
                        raise ValueError(f"NaN values detected in argument {i}")
                    if torch.isinf(arg).any():
                        raise ValueError(f"Inf values detected in argument {i}")
                    
                    # Check tensor device consistency
                    if hasattr(self, 'expected_device') and arg.device != self.expected_device:
                        logger.warning(f"Tensor device mismatch in {operation_name}: expected {self.expected_device}, got {arg.device}")
                
                elif isinstance(arg, (list, tuple)) and len(arg) > 0:
                    # Check list/tuple contents
                    if all(isinstance(item, torch.Tensor) for item in arg):
                        for j, tensor in enumerate(arg):
                            if torch.isnan(tensor).any() or torch.isinf(tensor).any():
                                raise ValueError(f"Invalid values in tensor list at position {j}")
            
            # Validate keyword arguments
            for key, value in kwargs.items():
                if isinstance(value, torch.Tensor):
                    if torch.isnan(value).any() or torch.isinf(value).any():
                        raise ValueError(f"Invalid values in keyword argument {key}")
                        
        except Exception as e:
            logger.error(f"Input validation failed for {operation_name}: {e}")
            raise
    
    def _post_execution_validation(self, operation_name: str, result) -> bool:
        """Validate operation results."""
        try:
            if result is None:
                logger.warning(f"Operation {operation_name} returned None")
                return False
            
            # Validate tensor outputs
            if isinstance(result, torch.Tensor):
                if torch.isnan(result).any():
                    logger.error(f"NaN values in result of {operation_name}")
                    return False
                if torch.isinf(result).any():
                    logger.error(f"Inf values in result of {operation_name}")
                    return False
            
            # Validate dictionary outputs
            elif isinstance(result, dict):
                for key, value in result.items():
                    if isinstance(value, torch.Tensor):
                        if torch.isnan(value).any() or torch.isinf(value).any():
                            logger.error(f"Invalid values in result key '{key}' of {operation_name}")
                            return False
            
            return True
            
        except Exception as e:
            logger.error(f"Post-execution validation failed for {operation_name}: {e}")
            return False
    
    def _handle_error(self, operation_name: str, error: Exception, execution_time: float, *args, **kwargs) -> Dict[str, Any]:
        """Handle errors with comprehensive logging and recovery suggestions."""
        try:
            error_type = type(error).__name__
            error_message = str(error)
            
            # Create detailed error info
            error_info = {
                'operation': operation_name,
                'error_type': error_type,
                'error_message': error_message,
                'execution_time': execution_time,
                'timestamp': time.time(),
                'args_info': self._get_args_info(*args, **kwargs),
                'stack_trace': self._get_stack_trace(),
                'system_info': self._get_system_info(),
                'recovery_suggestions': self._get_recovery_suggestions(error_type, error_message)
            }
            
            # Log error
            self.error_log.append(error_info)
            logger.error(f"Operation '{operation_name}' failed: {error_type} - {error_message}")
            
            # Handle specific error types
            if isinstance(error, torch.cuda.OutOfMemoryError):
                self._handle_cuda_oom_error(operation_name)
            elif isinstance(error, RuntimeError) and "CUDA" in error_message:
                self._handle_cuda_runtime_error(operation_name, error_message)
            elif isinstance(error, ValueError):
                self._handle_value_error(operation_name, error_message)
            
            return error_info
            
        except Exception as e:
            logger.error(f"Error in error handler: {e}")
            return {
                'operation': operation_name,
                'error_type': 'ErrorHandlerFailure',
                'error_message': str(e),
                'timestamp': time.time()
            }
    
    def _handle_cuda_oom_error(self, operation_name: str):
        """Handle CUDA out of memory errors."""
        try:
            if torch.cuda.is_available():
                # Clear CUDA cache
                torch.cuda.empty_cache()
                
                # Log memory info
                memory_allocated = torch.cuda.memory_allocated() / 1024**3
                memory_reserved = torch.cuda.memory_reserved() / 1024**3
                
                logger.info(f"CUDA cache cleared after OOM in {operation_name}")
                logger.info(f"Memory after cleanup: {memory_allocated:.2f}GB allocated, {memory_reserved:.2f}GB reserved")
                
        except Exception as e:
            logger.warning(f"Failed to handle CUDA OOM error: {e}")
    
    def _handle_cuda_runtime_error(self, operation_name: str, error_message: str):
        """Handle CUDA runtime errors."""
        try:
            if "CUDA driver version is insufficient" in error_message:
                logger.error(f"CUDA driver version issue in {operation_name}. Please update CUDA drivers.")
            elif "CUDA out of memory" in error_message:
                logger.error(f"CUDA memory issue in {operation_name}. Consider reducing batch size or model size.")
            else:
                logger.error(f"CUDA runtime error in {operation_name}: {error_message}")
                
        except Exception as e:
            logger.warning(f"Failed to handle CUDA runtime error: {e}")
    
    def _handle_value_error(self, operation_name: str, error_message: str):
        """Handle value errors."""
        try:
            if "size mismatch" in error_message.lower():
                logger.error(f"Tensor size mismatch in {operation_name}. Check input dimensions.")
            elif "invalid argument" in error_message.lower():
                logger.error(f"Invalid argument in {operation_name}. Check input parameters.")
            else:
                logger.error(f"Value error in {operation_name}: {error_message}")
                
        except Exception as e:
            logger.warning(f"Failed to handle value error: {e}")
    
    def _get_args_info(self, *args, **kwargs) -> Dict[str, Any]:
        """Get information about function arguments."""
        try:
            args_info = {
                'num_args': len(args),
                'arg_types': [type(arg).__name__ for arg in args],
                'kwargs_keys': list(kwargs.keys()),
                'kwargs_types': {key: type(value).__name__ for key, value in kwargs.items()}
            }
            
            # Add tensor-specific info
            for i, arg in enumerate(args):
                if isinstance(arg, torch.Tensor):
                    args_info[f'arg_{i}_tensor_info'] = {
                        'shape': list(arg.shape),
                        'dtype': str(arg.dtype),
                        'device': str(arg.device),
                        'requires_grad': arg.requires_grad
                    }
            
            return args_info
            
        except Exception as e:
            logger.warning(f"Failed to get args info: {e}")
            return {'error': str(e)}
    
    def _get_stack_trace(self) -> str:
        """Get current stack trace."""
        try:
            import traceback
            return traceback.format_exc()
        except:
            return "Stack trace not available"
    
    def _get_system_info(self) -> Dict[str, Any]:
        """Get system information for debugging."""
        try:
            system_info = {
                'python_version': sys.version,
                'pytorch_version': torch.__version__,
                'cuda_available': torch.cuda.is_available(),
                'cuda_version': torch.version.cuda if torch.cuda.is_available() else None,
                'device_count': torch.cuda.device_count() if torch.cuda.is_available() else 0
            }
            
            if torch.cuda.is_available():
                system_info.update({
                    'current_device': torch.cuda.current_device(),
                    'device_name': torch.cuda.get_device_name(),
                    'memory_info': {
                        'allocated': torch.cuda.memory_allocated() / 1024**3,
                        'reserved': torch.cuda.memory_reserved() / 1024**3,
                        'max_allocated': torch.cuda.max_memory_allocated() / 1024**3
                    }
                })
            
            return system_info
            
        except Exception as e:
            logger.warning(f"Failed to get system info: {e}")
            return {'error': str(e)}
    
    def _get_recovery_suggestions(self, error_type: str, error_message: str) -> List[str]:
        """Get recovery suggestions based on error type."""
        suggestions = []
        
        if error_type == "RuntimeError":
            if "CUDA out of memory" in error_message:
                suggestions.extend([
                    "Reduce batch size",
                    "Use gradient checkpointing",
                    "Clear CUDA cache with torch.cuda.empty_cache()",
                    "Consider using CPU if GPU memory is insufficient"
                ])
            elif "CUDA" in error_message:
                suggestions.extend([
                    "Check CUDA driver compatibility",
                    "Verify PyTorch CUDA version",
                    "Restart Python kernel to reset CUDA state"
                ])
        
        elif error_type == "ValueError":
            if "size mismatch" in error_message.lower():
                suggestions.extend([
                    "Check input tensor dimensions",
                    "Verify model architecture matches input",
                    "Use tensor.shape to debug dimensions"
                ])
            else:
                suggestions.extend([
                    "Validate input parameters",
                    "Check data types and formats",
                    "Use debug mode to trace execution"
                ])
        
        elif error_type == "TypeError":
            suggestions.extend([
                "Check input types match expected types",
                "Verify function signatures",
                "Use type hints for debugging"
            ])
        
        # General suggestions
        suggestions.extend([
            "Enable debug mode with enable_debug_mode=True",
            "Check error logs for detailed information",
            "Use smaller inputs for testing",
            "Verify model state and weights"
        ])
        
        return suggestions
    
    def _log_success(self, operation_name: str, execution_time: float, result):
        """Log successful operation execution."""
        try:
            success_info = {
                'operation': operation_name,
                'execution_time': execution_time,
                'timestamp': time.time(),
                'result_type': type(result).__name__,
                'success': True
            }
            
            # Add result-specific info
            if isinstance(result, torch.Tensor):
                success_info['result_info'] = {
                    'shape': list(result.shape),
                    'dtype': str(result.dtype),
                    'device': str(result.device)
                }
            
            # Update performance metrics
            if operation_name not in self.performance_metrics:
                self.performance_metrics[operation_name] = []
            
            self.performance_metrics[operation_name].append(execution_time)
            
            # Keep only last 100 measurements
            if len(self.performance_metrics[operation_name]) > 100:
                self.performance_metrics[operation_name] = self.performance_metrics[operation_name][-100:]
            
            logger.info(f"Operation '{operation_name}' completed successfully in {execution_time:.4f}s")
            
        except Exception as e:
            logger.warning(f"Failed to log success for {operation_name}: {e}")
    
    def get_error_summary(self) -> Dict[str, Any]:
        """Get comprehensive error summary."""
        try:
            if not self.error_log:
                return {'total_errors': 0, 'error_types': {}, 'recent_errors': []}
            
            # Count error types
            error_types = {}
            for error in self.error_log:
                error_type = error['error_type']
                error_types[error_type] = error_types.get(error_type, 0) + 1
            
            # Get recent errors
            recent_errors = self.error_log[-10:]  # Last 10 errors
            
            # Calculate error rate
            if len(self.error_log) > 1:
                time_span = self.error_log[-1]['timestamp'] - self.error_log[0]['timestamp']
                error_rate = len(self.error_log) / max(time_span, 1) * 3600  # errors per hour
            else:
                error_rate = 0
            
            # Performance statistics
            performance_stats = {}
            for operation, times in self.performance_metrics.items():
                if times:
                    performance_stats[operation] = {
                        'avg_time': np.mean(times),
                        'min_time': np.min(times),
                        'max_time': np.max(times),
                        'std_time': np.std(times),
                        'total_calls': len(times)
                    }
            
            return {
                'total_errors': len(self.error_log),
                'error_types': error_types,
                'recent_errors': recent_errors,
                'error_rate': error_rate,
                'performance_stats': performance_stats,
                'debug_mode': self.enable_debug_mode,
                'system_info': self._get_system_info()
            }
            
        except Exception as e:
            logger.error(f"Failed to get error summary: {e}")
            return {'error': str(e)}
    
    def clear_error_log(self):
        """Clear error log."""
        self.error_log.clear()
        logger.info("Error log cleared")
    
    def enable_debug_mode(self):
        """Enable debug mode."""
        self.enable_debug_mode = True
        self._setup_pytorch_debugging()
        logger.info("Debug mode enabled")
    
    def disable_debug_mode(self):
        """Disable debug mode."""
        self.enable_debug_mode = False
        torch.autograd.set_detect_anomaly(False)
        logger.info("Debug mode disabled")


# =============================================================================
# PyTorch Best Practices - Context Managers
# =============================================================================

@contextmanager
def nullcontext():
    """Null context manager for conditional autocast."""
    yield


@contextmanager
def torch_profiler_context(config, enabled=True):
    """Context manager for PyTorch profiling."""
    if enabled and config.use_profiling:
        with profile(
            activities=[ProfilerActivity.CPU, ProfilerActivity.CUDA],
            record_shapes=True,
            with_stack=True,
            profile_memory=True
        ) as prof:
            yield prof
    else:
        yield None


@contextmanager
def memory_tracking_context():
    """Context manager for memory tracking."""
    if torch.cuda.is_available():
        torch.cuda.reset_peak_memory_stats()
        torch.cuda.empty_cache()
    
    yield
    
    if torch.cuda.is_available():
        peak_memory = torch.cuda.max_memory_allocated() / 1024**3  # GB
        logger.info(f"Peak GPU memory usage: {peak_memory:.2f} GB")


# =============================================================================
# Ultra-Optimized Configuration
# =============================================================================

@dataclass
class UltraTrainingConfig:
    """Ultra-optimized training configuration with PyTorch best practices."""
    
    # Model settings
    model_name: str = "gpt2"
    max_length: int = 512
    batch_size: int = 8
    gradient_accumulation_steps: int = 4
    max_grad_norm: float = 1.0
    
    # Training settings
    learning_rate: float = 2e-5
    num_epochs: int = 3
    warmup_steps: int = 100
    weight_decay: float = 0.01
    lr_scheduler_type: str = "cosine"
    
    # Optimization settings
    use_mixed_precision: bool = True
    use_gradient_clipping: bool = True
    use_flash_attention: bool = True
    use_gradient_checkpointing: bool = True
    use_xformers: bool = True
    
    # PyTorch specific optimizations
    use_torch_compile: bool = False  # PyTorch 2.0+ feature
    use_channels_last: bool = True   # Memory format optimization
    use_amp: bool = True             # Automatic mixed precision
    use_profiling: bool = False      # Enable PyTorch profiler
    
    # Hardware settings
    device: str = "cuda" if torch.cuda.is_available() else "cpu"
    num_gpus: int = torch.cuda.device_count()
    ddp_backend: str = "nccl"
    
    # Logging settings
    logging_steps: int = 100
    save_steps: int = 1000
    eval_steps: int = 500
    save_total_limit: int = 3
    
    # Paths
    output_dir: str = "./outputs"
    cache_dir: str = "./cache"
    log_dir: str = "./logs"
    
    # Advanced settings
    dataloader_num_workers: int = 4
    dataloader_pin_memory: bool = True
    dataloader_prefetch_factor: int = 2
    
    # PyTorch memory optimization
    enable_memory_efficient_attention: bool = True
    enable_gradient_checkpointing: bool = True
    enable_activation_checkpointing: bool = False

# =============================================================================
# PyTorch Best Practices - Model Initialization
# =============================================================================

def initialize_pytorch_environment(config: UltraTrainingConfig):
    """Initialize PyTorch environment with best practices."""
    # Set PyTorch to use deterministic algorithms
    torch.backends.cudnn.deterministic = True
    torch.backends.cudnn.benchmark = False
    
    # Enable memory efficient attention if available
    if config.enable_memory_efficient_attention:
        try:
            torch.backends.cuda.enable_flash_sdp(True)
            logger.info("Flash attention enabled")
        except AttributeError:
            logger.warning("Flash attention not available in this PyTorch version")
    
    # Set memory format for optimization
    if config.use_channels_last and torch.cuda.is_available():
        torch.backends.cuda.matmul.allow_tf32 = True
        torch.backends.cudnn.allow_tf32 = True
        logger.info("TF32 enabled for better performance")
    
    # Log PyTorch version and CUDA info
    logger.info(
        "PyTorch environment initialized",
        pytorch_version=torch.__version__,
        cuda_available=torch.cuda.is_available(),
        cuda_version=torch.version.cuda if torch.cuda.is_available() else None,
        device_count=torch.cuda.device_count() if torch.cuda.is_available() else 0
    )


def get_optimal_device(config: UltraTrainingConfig) -> torch.device:
    """Get optimal device with PyTorch best practices."""
    if config.device == "cuda" and torch.cuda.is_available():
        # Select GPU with most free memory
        if torch.cuda.device_count() > 1:
            free_memory = []
            for i in range(torch.cuda.device_count()):
                torch.cuda.set_device(i)
                free_memory.append(torch.cuda.get_device_properties(i).total_memory)
            
            optimal_gpu = free_memory.index(max(free_memory))
            torch.cuda.set_device(optimal_gpu)
            logger.info(f"Selected GPU {optimal_gpu} with most free memory")
        
        return torch.device("cuda")
    else:
        return torch.device("cpu")


# =============================================================================
# Ultra-Optimized Model Architectures
# =============================================================================

class UltraOptimizedTransformerModel(nn.Module):
    """Ultra-optimized transformer model with PyTorch best practices."""
    
    def __init__(self, model_name: str, num_labels: int = 2, config: UltraTrainingConfig = None):
        super().__init__()
        self.config = config or UltraTrainingConfig()
        
        # Initialize PyTorch environment
        initialize_pytorch_environment(self.config)
        
        # Load pre-trained model with optimizations
        model_kwargs = {
            "cache_dir": self.config.cache_dir,
            "torch_dtype": torch.float16 if self.config.use_mixed_precision else torch.float32,
            "low_cpu_mem_usage": True,
        }
        
        if self.config.use_gradient_checkpointing:
            model_kwargs["use_gradient_checkpointing"] = True
            
        self.transformer = AutoModel.from_pretrained(model_name, **model_kwargs)
        
        # Add classification head
        self.classifier = nn.Linear(self.transformer.config.hidden_size, num_labels)
        
        # Initialize weights with PyTorch best practices
        self._init_weights()
        
        # Apply PyTorch optimizations
        self._apply_pytorch_optimizations()
        
    def _init_weights(self):
        """Initialize weights with PyTorch best practices."""
        for module in self.modules():
            if isinstance(module, nn.Linear):
                # Use proper initialization methods
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
            elif isinstance(module, nn.LayerNorm):
                nn.init.ones_(module.weight)
                nn.init.zeros_(module.bias)
            elif isinstance(module, nn.Embedding):
                nn.init.normal_(module.weight, mean=0.0, std=0.02)
    
    def _apply_pytorch_optimizations(self):
        """Apply PyTorch-specific optimizations."""
        # Enable gradient checkpointing for memory efficiency
        if self.config.enable_gradient_checkpointing:
            self.transformer.gradient_checkpointing_enable()
            logger.info("Gradient checkpointing enabled")
        
        # Use channels last memory format for optimization
        if self.config.use_channels_last and torch.cuda.is_available():
            self.transformer = self.transformer.to(memory_format=torch.channels_last)
            logger.info("Channels last memory format applied")
        
        # Compile model if enabled (PyTorch 2.0+)
        if self.config.use_torch_compile and hasattr(torch, 'compile'):
            try:
                self.transformer = torch.compile(self.transformer)
                logger.info("Model compiled with torch.compile")
            except Exception as e:
                logger.warning(f"torch.compile failed: {e}")
    
    def forward(self, input_ids, attention_mask=None, labels=None):
        """Forward pass with PyTorch optimizations."""
        try:
            # Use proper context managers
            with autocast() if self.config.use_mixed_precision else nullcontext():
                outputs = self.transformer(
                    input_ids=input_ids,
                    attention_mask=attention_mask,
                    return_dict=True
                )
                
                logits = self.classifier(outputs.last_hidden_state[:, 0, :])
                
                loss = None
                if labels is not None:
                    loss_fct = nn.CrossEntropyLoss()
                    loss = loss_fct(logits.view(-1, logits.size(-1)), labels.view(-1))
                
                return {"loss": loss, "logits": logits} if loss is not None else {"logits": logits}
                
        except Exception as e:
            logger.error("Forward pass failed", error=str(e), model_name=self.config.model_name)
            raise

