class DiffusionConfig:
    """Comprehensive configuration for diffusion models using Diffusers library."""
    
    def __init__(self, 
                 # Basic diffusion parameters
                 num_timesteps: int = 1000,
                 beta_start: float = 0.0001,
                 beta_end: float = 0.02,
                 beta_schedule: str = "linear",
                 guidance_scale: float = 7.5,
                 num_inference_steps: int = 50,
                 
                 # Scheduler configuration
                 scheduler_type: str = "ddpm",
                 scheduler_kwargs: Dict[str, Any] = None,
                 
                 # Pipeline configuration
                 pipeline_type: str = "stable_diffusion",
                 model_id: str = "runwayml/stable-diffusion-v1-5",
                 
                 # Performance and optimization
                 use_classifier_free_guidance: bool = True,
                 use_mixed_precision: bool = True,
                 use_xformers: bool = True,
                 use_gradient_checkpointing: bool = False,
                 enable_cpu_offload: bool = False,
                 enable_sequential_cpu_offload: bool = False,
                 enable_model_cpu_offload: bool = False,
                 enable_vae_slicing: bool = False,
                 enable_vae_tiling: bool = False,
                 enable_attention_slicing: str = None,  # "auto", "max", or int
                 
                 # Safety and content filtering
                 safety_checker: bool = True,
                 requires_safety_checker: bool = True,
                 nsfw_filter: bool = True,
                 
                 # Generation parameters
                 height: int = 512,
                 width: int = 512,
                 seed: int = None,
                 eta: float = 0.0,
                 
                 # Device and memory
                 device: str = "cuda" if torch.cuda.is_available() else "cpu",
                 torch_dtype: str = "float16",
                 cache_dir: str = "./cache",
                 
                 # Advanced features
                 use_karras_sigmas: bool = False,
                 clip_skip: int = None,
                 cross_attention_kwargs: Dict[str, Any] = None):
        
        # Basic parameters
        self.num_timesteps = num_timesteps
        self.beta_start = beta_start
        self.beta_end = beta_end
        self.beta_schedule = beta_schedule
        self.guidance_scale = guidance_scale
        self.num_inference_steps = num_inference_steps
        
        # Scheduler
        self.scheduler_type = scheduler_type
        self.scheduler_kwargs = scheduler_kwargs or {}
        
        # Pipeline
        self.pipeline_type = pipeline_type
        self.model_id = model_id
        
        # Performance
        self.use_classifier_free_guidance = use_classifier_free_guidance
        self.use_mixed_precision = use_mixed_precision
        self.use_xformers = use_xformers
        self.use_gradient_checkpointing = use_gradient_checkpointing
        self.enable_cpu_offload = enable_cpu_offload
        self.enable_sequential_cpu_offload = enable_sequential_cpu_offload
        self.enable_model_cpu_offload = enable_model_cpu_offload
        self.enable_vae_slicing = enable_vae_slicing
        self.enable_vae_tiling = enable_vae_tiling
        self.enable_attention_slicing = enable_attention_slicing
        
        # Safety
        self.safety_checker = safety_checker
        self.requires_safety_checker = requires_safety_checker
        self.nsfw_filter = nsfw_filter
        
        # Generation
        self.height = height
        self.width = width
        self.seed = seed
        self.eta = eta
        
        # Device
        self.device = device
        self.torch_dtype = getattr(torch, torch_dtype) if isinstance(torch_dtype, str) else torch_dtype
        self.cache_dir = cache_dir
        
        # Advanced
        self.use_karras_sigmas = use_karras_sigmas
        self.clip_skip = clip_skip
        self.cross_attention_kwargs = cross_attention_kwargs or {}


class CustomDiffusionScheduler:
    """Enhanced custom diffusion scheduler with mathematical rigor and multiple algorithms."""
    
    def __init__(self, config: DiffusionConfig):
        self.config = config
        self.betas = self._create_beta_schedule()
        self.alphas = 1.0 - self.betas
        self.alphas_cumprod = torch.cumprod(self.alphas, dim=0)
        self.alphas_cumprod_prev = torch.cat([torch.tensor([1.0]), self.alphas_cumprod[:-1]])
        
        # Precompute values for efficiency
        self.sqrt_alphas_cumprod = torch.sqrt(self.alphas_cumprod)
        self.sqrt_one_minus_alphas_cumprod = torch.sqrt(1.0 - self.alphas_cumprod)
        self.log_one_minus_alphas_cumprod = torch.log(1.0 - self.alphas_cumprod)
        self.sqrt_recip_alphas_cumprod = torch.sqrt(1.0 / self.alphas_cumprod)
        self.sqrt_recipm1_alphas_cumprod = torch.sqrt(1.0 / self.alphas_cumprod - 1)
        
        # Additional precomputed values for variance calculation
        self.posterior_variance = (
            self.betas * (1.0 - self.alphas_cumprod_prev) / (1.0 - self.alphas_cumprod)
        )
        self.posterior_log_variance_clipped = torch.log(
            torch.cat([self.posterior_variance[1:2], self.posterior_variance[1:]])
        )
        self.posterior_mean_coef1 = (
            self.betas * torch.sqrt(self.alphas_cumprod_prev) / (1.0 - self.alphas_cumprod)
        )
        self.posterior_mean_coef2 = (
            (1.0 - self.alphas_cumprod_prev) * torch.sqrt(self.alphas) / (1.0 - self.alphas_cumprod)
        )
        
        # Move to device
        self._move_to_device(config.device)
    
    def _move_to_device(self, device):
        """Move all tensors to the specified device."""
        tensors_to_move = [
            'betas', 'alphas', 'alphas_cumprod', 'alphas_cumprod_prev',
            'sqrt_alphas_cumprod', 'sqrt_one_minus_alphas_cumprod',
            'log_one_minus_alphas_cumprod', 'sqrt_recip_alphas_cumprod',
            'sqrt_recipm1_alphas_cumprod', 'posterior_variance',
            'posterior_log_variance_clipped', 'posterior_mean_coef1',
            'posterior_mean_coef2'
        ]
        
        for tensor_name in tensors_to_move:
            tensor = getattr(self, tensor_name)
            setattr(self, tensor_name, tensor.to(device))
    
    def _create_beta_schedule(self) -> torch.Tensor:
        """Create beta schedule for diffusion with multiple algorithms."""
        if self.config.scheduler_type == "linear":
            return self._linear_beta_schedule()
        elif self.config.scheduler_type == "cosine":
            return self._cosine_beta_schedule()
        elif self.config.scheduler_type == "quadratic":
            return self._quadratic_beta_schedule()
        elif self.config.scheduler_type == "sigmoid":
            return self._sigmoid_beta_schedule()
        elif self.config.scheduler_type == "exponential":
            return self._exponential_beta_schedule()
        elif self.config.scheduler_type == "karras":
            return self._karras_beta_schedule()
        elif self.config.scheduler_type == "vp":
            return self._vp_beta_schedule()
        else:  # Default to linear
            return self._linear_beta_schedule()
    
    def _linear_beta_schedule(self) -> torch.Tensor:
        """Linear beta schedule: β_t = β_start + (β_end - β_start) * t / T."""
        return torch.linspace(self.config.beta_start, self.config.beta_end, self.config.num_timesteps)
    
    def _cosine_beta_schedule(self) -> torch.Tensor:
        """Cosine beta schedule as proposed in Improved DDPM."""
        steps = self.config.num_timesteps + 1
        x = torch.linspace(0, self.config.num_timesteps, steps)
        alphas_cumprod = torch.cos(((x / self.config.num_timesteps) + 0.008) / 1.008 * math.pi * 0.5) ** 2
        alphas_cumprod = alphas_cumprod / alphas_cumprod[0]
        betas = 1 - (alphas_cumprod[1:] / alphas_cumprod[:-1])
        return torch.clip(betas, 0.0001, 0.9999)
    
    def _quadratic_beta_schedule(self) -> torch.Tensor:
        """Quadratic beta schedule: β_t = (β_start^0.5 + (β_end^0.5 - β_start^0.5) * t / T)^2."""
        return torch.linspace(self.config.beta_start ** 0.5, self.config.beta_end ** 0.5, self.config.num_timesteps) ** 2
    
    def _sigmoid_beta_schedule(self) -> torch.Tensor:
        """Sigmoid beta schedule for smooth transitions."""
        x = torch.linspace(-6, 6, self.config.num_timesteps)
        sigmoid = torch.sigmoid(x)
        betas = self.config.beta_start + (self.config.beta_end - self.config.beta_start) * sigmoid
        return betas
    
    def _exponential_beta_schedule(self) -> torch.Tensor:
        """Exponential beta schedule: β_t = β_start * (β_end / β_start)^(t / T)."""
        return self.config.beta_start * (self.config.beta_end / self.config.beta_start) ** (torch.arange(self.config.num_timesteps) / self.config.num_timesteps)
    
    def _karras_beta_schedule(self) -> torch.Tensor:
        """Karras beta schedule for high-quality generation."""
        # Karras et al. "Elucidating the Design Space of Diffusion-Based Generative Models"
        sigma_min = 0.002
        sigma_max = 80.0
        rho = 7.0
        
        # Convert to noise schedule
        sigmas = sigma_min ** (1 - rho) + torch.arange(self.config.num_timesteps) / (self.config.num_timesteps - 1) * (sigma_max ** (1 - rho) - sigma_min ** (1 - rho))
        sigmas = sigmas ** (1 / (1 - rho))
        
        # Convert sigmas to betas
        alphas_cumprod = 1 / (1 + sigmas ** 2)
        betas = 1 - (alphas_cumprod[1:] / alphas_cumprod[:-1])
        return torch.clip(betas, 0.0001, 0.9999)
    
    def _vp_beta_schedule(self) -> torch.Tensor:
        """Variance Preserving (VP) beta schedule."""
        # VP-SDE from "Score-Based Generative Modeling through Stochastic Differential Equations"
        t = torch.arange(self.config.num_timesteps) / self.config.num_timesteps
        beta_t = 1 - torch.exp(-0.5 * t * (self.config.beta_end - self.config.beta_start) - self.config.beta_start * t)
        return beta_t
    
    def q_sample(self, x_start: torch.Tensor, t: torch.Tensor, noise: torch.Tensor = None) -> torch.Tensor:
        """
        Forward diffusion process: q(x_t | x_0).
        
        Args:
            x_start: Original images [B, C, H, W]
            t: Timesteps [B]
            noise: Optional noise tensor [B, C, H, W]
        
        Returns:
            Noisy images [B, C, H, W]
        """
        if noise is None:
            noise = torch.randn_like(x_start)
        
        # Ensure t is properly shaped for broadcasting
        t = t.view(-1, 1, 1, 1)
        
        # q(x_t | x_0) = N(x_t; √(ᾱ_t) * x_0, (1 - ᾱ_t) * I)
        sqrt_alphas_cumprod_t = self.sqrt_alphas_cumprod[t].view(-1, 1, 1, 1)
        sqrt_one_minus_alphas_cumprod_t = self.sqrt_one_minus_alphas_cumprod[t].view(-1, 1, 1, 1)
        
        return sqrt_alphas_cumprod_t * x_start + sqrt_one_minus_alphas_cumprod_t * noise
    
    def p_sample(self, model: nn.Module, x: torch.Tensor, t: torch.Tensor, t_index: int, 
                clip_denoised: bool = True, return_dict: bool = True) -> Union[torch.Tensor, Dict]:
        """
        Reverse diffusion process: p(x_{t-1} | x_t).
        
        Args:
            model: Noise prediction model
            x: Current noisy image [B, C, H, W]
            t: Current timestep [B]
            t_index: Current timestep index (scalar)
            clip_denoised: Whether to clip denoised images to [-1, 1]
            return_dict: Whether to return a dictionary with additional info
        
        Returns:
            Denoised image [B, C, H, W] or dictionary
        """
        betas_t = self.betas[t_index]
        sqrt_one_minus_alphas_cumprod_t = self.sqrt_one_minus_alphas_cumprod[t_index]
        sqrt_recip_alphas_t = self.sqrt_recip_alphas_cumprod[t_index]
        
        # Predict noise using the model
        model_output = model(x, t)
        
        # Calculate predicted x_0 using the reparameterization trick
        pred_original = (x - sqrt_one_minus_alphas_cumprod_t * model_output) * sqrt_recip_alphas_t
        
        if clip_denoised:
            pred_original = torch.clamp(pred_original, -1.0, 1.0)
        
        # Calculate the mean of q(x_{t-1} | x_t, x_0)
        pred_epsilon_coef = (1 - betas_t) / sqrt_one_minus_alphas_cumprod_t
        pred_mean = pred_original + pred_epsilon_coef * model_output
        
        if t_index == 0:
            # No noise at the final step
            noise = torch.zeros_like(x)
        else:
            # Add noise for stochastic sampling
            noise = torch.randn_like(x)
        
        # Calculate variance
        if t_index == 0:
            variance = torch.zeros_like(x)
        else:
            variance = (1 - self.alphas_cumprod[t_index - 1]) / (1 - self.alphas_cumprod[t_index]) * betas_t
            variance = variance.view(-1, 1, 1, 1)
        
        pred_sample = pred_mean + torch.sqrt(variance) * noise
        
        if not return_dict:
            return pred_sample
        
        return {
            "prev_sample": pred_sample,
            "pred_original": pred_original,
            "pred_mean": pred_mean,
            "pred_variance": variance,
        }
    
    def q_posterior_mean_variance(self, x_start: torch.Tensor, x_t: torch.Tensor, t: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
        """
        Compute the mean and variance of q(x_{t-1} | x_t, x_0).
        
        Args:
            x_start: Original images [B, C, H, W]
            x_t: Noisy images at timestep t [B, C, H, W]
            t: Timesteps [B]
        
        Returns:
            posterior_mean, posterior_variance, posterior_log_variance_clipped
        """
        t = t.view(-1, 1, 1, 1)
        
        posterior_mean = (
            self.posterior_mean_coef1[t] * x_start +
            self.posterior_mean_coef2[t] * x_t
        )
        posterior_variance = self.posterior_variance[t]
        posterior_log_variance_clipped = self.posterior_log_variance_clipped[t]
        
        return posterior_mean, posterior_variance, posterior_log_variance_clipped
    
    def p_sample_loop(self, model: nn.Module, shape: Tuple[int, ...], 
                     noise: torch.Tensor = None, clip_denoised: bool = True,
                     return_dict: bool = True, sampling_method: str = "ddpm",
                     **kwargs) -> Union[torch.Tensor, Dict]:
        """
        Generate samples by running the reverse diffusion process.
        
        Args:
            model: Noise prediction model
            shape: Shape of the samples to generate [B, C, H, W]
            noise: Optional initial noise
            clip_denoised: Whether to clip denoised images
            return_dict: Whether to return additional information
            sampling_method: Sampling method to use
            **kwargs: Additional arguments for the sampling method
        
        Returns:
            Generated samples [B, C, H, W] or dictionary
        """
        device = next(model.parameters()).device
        batch_size = shape[0]
        
        if noise is None:
            noise = torch.randn(shape, device=device)
        
        x = noise
        
        # Reverse sampling loop
        for i in tqdm(reversed(range(0, self.config.num_timesteps)), desc=f"Sampling ({sampling_method})"):
            t = torch.full((batch_size,), i, device=device, dtype=torch.long)
            
            with torch.no_grad():
                result = self.sample_with_method(sampling_method, model, x, t, i, 
                                              clip_denoised=clip_denoised, 
                                              return_dict=return_dict, **kwargs)
                if return_dict:
                    x = result["prev_sample"]
                else:
                    x = result
        
        if return_dict:
            return {"sample": x}
        return x
    
    def p_sample_loop_adaptive(self, model: nn.Module, shape: Tuple[int, ...],
                              noise: torch.Tensor = None, clip_denoised: bool = True,
                              return_dict: bool = True, adaptive_steps: bool = True,
                              min_steps: int = 10, max_steps: int = None) -> Union[torch.Tensor, Dict]:
        """
        Adaptive sampling loop that adjusts the number of steps based on convergence.
        
        Args:
            model: Noise prediction model
            shape: Shape of the samples to generate [B, C, H, W]
            noise: Optional initial noise
            clip_denoised: Whether to clip denoised images
            return_dict: Whether to return additional information
            adaptive_steps: Whether to use adaptive step sizing
            min_steps: Minimum number of sampling steps
            max_steps: Maximum number of sampling steps (default: num_timesteps)
        
        Returns:
            Generated samples [B, C, H, W] or dictionary
        """
        device = next(model.parameters()).device
        batch_size = shape[0]
        max_steps = max_steps or self.config.num_timesteps
        
        if noise is None:
            noise = torch.randn(shape, device=device)
        
        x = noise
        convergence_history = []
        
        # Adaptive sampling loop
        for i in tqdm(reversed(range(0, max_steps)), desc="Adaptive Sampling"):
            t = torch.full((batch_size,), i, device=device, dtype=torch.long)
            
            with torch.no_grad():
                result = self.p_sample(model, x, t, i, clip_denoised, return_dict)
                if return_dict:
                    x_new = result["prev_sample"]
                else:
                    x_new = result
                
                # Check convergence
                if adaptive_steps and i > min_steps:
                    change = torch.abs(x_new - x).mean().item()
                    convergence_history.append(change)
                    
                    # Early stopping if converged
                    if len(convergence_history) >= 3 and all(c < 1e-4 for c in convergence_history[-3:]):
                        logger.info(f"Early stopping at step {i} due to convergence")
                        break
                
                x = x_new
        
        if return_dict:
            return {"sample": x, "convergence_history": convergence_history}
        return x
    
    def p_sample_loop_guided(self, model: nn.Module, shape: Tuple[int, ...],
                            guidance_scale: float = 7.5, classifier_free_guidance: bool = True,
                            noise: torch.Tensor = None, clip_denoised: bool = True,
                            return_dict: bool = True) -> Union[torch.Tensor, Dict]:
        """
        Guided sampling loop with classifier-free guidance.
        
        Args:
            model: Noise prediction model
            shape: Shape of the samples to generate [B, C, H, W]
            guidance_scale: Guidance scale for classifier-free guidance
            classifier_free_guidance: Whether to use classifier-free guidance
            noise: Optional initial noise
            clip_denoised: Whether to clip denoised images
            return_dict: Whether to return additional information
        
        Returns:
            Generated samples [B, C, H, W] or dictionary
        """
        device = next(model.parameters()).device
        batch_size = shape[0]
        
        if noise is None:
            noise = torch.randn(shape, device=device)
        
        x = noise
        
        # Guided sampling loop
        for i in tqdm(reversed(range(0, self.config.num_timesteps)), desc="Guided Sampling"):
            t = torch.full((batch_size,), i, device=device, dtype=torch.long)
            
            with torch.no_grad():
                if classifier_free_guidance:
                    # Classifier-free guidance: run model with and without conditioning
                    # This is a simplified version - in practice, you'd need a conditional model
                    result_cond = self.p_sample(model, x, t, i, clip_denoised, return_dict)
                    result_uncond = self.p_sample(model, x, t, i, clip_denoised, return_dict)
                    
                    if return_dict:
                        pred_cond = result_cond["prev_sample"]
                        pred_uncond = result_uncond["prev_sample"]
                    else:
                        pred_cond = result_cond
                        pred_uncond = result_uncond
                    
                    # Apply guidance
                    x = pred_uncond + guidance_scale * (pred_cond - pred_uncond)
                else:
                    result = self.p_sample(model, x, t, i, clip_denoised, return_dict)
                    if return_dict:
                        x = result["prev_sample"]
                    else:
                        x = result
        
        if return_dict:
            return {"sample": x, "guidance_scale": guidance_scale}
        return x
    
    def add_noise(self, original_samples: torch.Tensor, timesteps: torch.Tensor) -> torch.Tensor:
        """
        Add noise to the original samples according to the forward process.
        
        Args:
            original_samples: Original samples [B, C, H, W]
            timesteps: Timesteps to add noise at [B]
        
        Returns:
            Noisy samples [B, C, H, W]
        """
        return self.q_sample(original_samples, timesteps)
    
    def get_velocity(self, sample: torch.Tensor, noise: torch.Tensor, timesteps: torch.Tensor) -> torch.Tensor:
        """
        Get the velocity (v) prediction for v-prediction models.
        
        Args:
            sample: Current sample [B, C, H, W]
            noise: Noise [B, C, H, W]
            timesteps: Timesteps [B]
        
        Returns:
            Velocity prediction [B, C, H, W]
        """
        timesteps = timesteps.view(-1, 1, 1, 1)
        sqrt_alphas_cumprod_t = self.sqrt_alphas_cumprod[timesteps]
        sqrt_one_minus_alphas_cumprod_t = self.sqrt_one_minus_alphas_cumprod[timesteps]
        
        # v = ᾱ_t * ε - √(1 - ᾱ_t) * x_0
        velocity = sqrt_alphas_cumprod_t * noise - sqrt_one_minus_alphas_cumprod_t * sample
        return velocity
    
    def ddim_sample(self, model: nn.Module, x: torch.Tensor, t: torch.Tensor, t_index: int,
                   eta: float = 0.0, clip_denoised: bool = True, return_dict: bool = True) -> Union[torch.Tensor, Dict]:
        """
        DDIM sampling: deterministic sampling with η parameter.
        
        Args:
            model: Noise prediction model
            x: Current noisy image [B, C, H, W]
            t: Current timestep [B]
            t_index: Current timestep index (scalar)
            eta: DDIM eta parameter (0 = deterministic, 1 = stochastic)
            clip_denoised: Whether to clip denoised images
            return_dict: Whether to return additional information
        
        Returns:
            Denoised image [B, C, H, W] or dictionary
        """
        betas_t = self.betas[t_index]
        sqrt_one_minus_alphas_cumprod_t = self.sqrt_one_minus_alphas_cumprod[t_index]
        sqrt_recip_alphas_t = self.sqrt_recip_alphas_cumprod[t_index]
        
        # Predict noise using the model
        model_output = model(x, t)
        
        # Calculate predicted x_0
        pred_original = (x - sqrt_one_minus_alphas_cumprod_t * model_output) * sqrt_recip_alphas_t
        
        if clip_denoised:
            pred_original = torch.clamp(pred_original, -1.0, 1.0)
        
        # DDIM formula: x_{t-1} = √(ᾱ_{t-1}) * x_0_pred + √(1 - ᾱ_{t-1} - η² * σ_t²) * ε_pred
        if t_index == 0:
            # No noise at the final step
            pred_sample = pred_original
        else:
            # Calculate variance for DDIM
            sigma_t = eta * torch.sqrt((1 - self.alphas_cumprod[t_index - 1]) / (1 - self.alphas_cumprod[t_index]) * betas_t)
            sigma_t = sigma_t.view(-1, 1, 1, 1)
            
            # DDIM sampling
            pred_sample = (
                self.sqrt_alphas_cumprod[t_index - 1].view(-1, 1, 1, 1) * pred_original +
                torch.sqrt(1 - self.alphas_cumprod[t_index - 1] - sigma_t ** 2).view(-1, 1, 1, 1) * model_output
            )
        
        if not return_dict:
            return pred_sample
        
        return {
            "prev_sample": pred_sample,
            "pred_original": pred_original,
            "sigma": sigma_t if t_index > 0 else torch.zeros_like(x),
        }
    
    def dpm_solver_sample(self, model: nn.Module, x: torch.Tensor, t: torch.Tensor, t_index: int,
                         algorithm_type: str = "dpmsolver++", return_dict: bool = True) -> Union[torch.Tensor, Dict]:
        """
        DPM-Solver sampling: fast ODE-based sampling.
        
        Args:
            model: Noise prediction model
            x: Current noisy image [B, C, H, W]
            t: Current timestep [B]
            t_index: Current timestep index (scalar)
            algorithm_type: "dpmsolver" or "dpmsolver++"
            return_dict: Whether to return additional information
        
        Returns:
            Denoised image [B, C, H, W] or dictionary
        """
        # DPM-Solver uses a different approach based on ODE solving
        # This is a simplified implementation
        betas_t = self.betas[t_index]
        sqrt_one_minus_alphas_cumprod_t = self.sqrt_one_minus_alphas_cumprod[t_index]
        sqrt_recip_alphas_t = self.sqrt_recip_alphas_cumprod[t_index]
        
        # Predict noise using the model
        model_output = model(x, t)
        
        # Calculate predicted x_0
        pred_original = (x - sqrt_one_minus_alphas_cumprod_t * model_output) * sqrt_recip_alphas_t
        
        # DPM-Solver step
        if t_index == 0:
            pred_sample = pred_original
        else:
            # Simplified DPM-Solver step
            alpha_t = self.alphas[t_index]
            alpha_prev = self.alphas[t_index - 1] if t_index > 0 else 1.0
            
            # DPM-Solver formula
            pred_sample = (
                alpha_prev.sqrt() * pred_original +
                (1 - alpha_prev).sqrt() * model_output
            )
        
        if not return_dict:
            return pred_sample
        
        return {
            "prev_sample": pred_sample,
            "pred_original": pred_original,
            "algorithm_type": algorithm_type,
        }
    
    def euler_sample(self, model: nn.Module, x: torch.Tensor, t: torch.Tensor, t_index: int,
                    return_dict: bool = True) -> Union[torch.Tensor, Dict]:
        """
        Euler sampling: simple ODE-based sampling.
        
        Args:
            model: Noise prediction model
            x: Current noisy image [B, C, H, W]
            t: Current timestep [B]
            t_index: Current timestep index (scalar)
            return_dict: Whether to return additional information
        
        Returns:
            Denoised image [B, C, H, W] or dictionary
        """
        # Euler method: simple first-order ODE solver
        betas_t = self.betas[t_index]
        sqrt_one_minus_alphas_cumprod_t = self.sqrt_one_minus_alphas_cumprod[t_index]
        sqrt_recip_alphas_t = self.sqrt_recip_alphas_cumprod[t_index]
        
        # Predict noise using the model
        model_output = model(x, t)
        
        # Calculate predicted x_0
        pred_original = (x - sqrt_one_minus_alphas_cumprod_t * model_output) * sqrt_recip_alphas_t
        
        # Euler step
        if t_index == 0:
            pred_sample = pred_original
        else:
            # Simple Euler step
            dt = 1.0 / self.config.num_timesteps
            pred_sample = x + dt * model_output
        
        if not return_dict:
            return pred_sample
        
        return {
            "prev_sample": pred_sample,
            "pred_original": pred_original,
            "method": "euler",
        }
    
    def ancestral_sample(self, model: nn.Module, x: torch.Tensor, t: torch.Tensor, t_index: int,
                        return_dict: bool = True) -> Union[torch.Tensor, Dict]:
        """
        Ancestral sampling: stochastic sampling with ancestral steps.
        
        Args:
            model: Noise prediction model
            x: Current noisy image [B, C, H, W]
            t: Current timestep [B]
            t_index: Current timestep index (scalar)
            return_dict: Whether to return additional information
        
        Returns:
            Denoised image [B, C, H, W] or dictionary
        """
        betas_t = self.betas[t_index]
        sqrt_one_minus_alphas_cumprod_t = self.sqrt_one_minus_alphas_cumprod[t_index]
        sqrt_recip_alphas_t = self.sqrt_recip_alphas_cumprod[t_index]
        
        # Predict noise using the model
        model_output = model(x, t)
        
        # Calculate predicted x_0
        pred_original = (x - sqrt_one_minus_alphas_cumprod_t * model_output) * sqrt_recip_alphas_t
        
        if t_index == 0:
            pred_sample = pred_original
        else:
            # Ancestral sampling adds noise at each step
            noise = torch.randn_like(x)
            pred_sample = pred_original + torch.sqrt(betas_t).view(-1, 1, 1, 1) * noise
        
        if not return_dict:
            return pred_sample
        
        return {
            "prev_sample": pred_sample,
            "pred_original": pred_original,
            "method": "ancestral",
        }
    
    def sample_with_method(self, method: str, model: nn.Module, x: torch.Tensor, t: torch.Tensor, 
                          t_index: int, **kwargs) -> Union[torch.Tensor, Dict]:
        """
        Sample using the specified method.
        
        Args:
            method: Sampling method ("ddpm", "ddim", "dpm_solver", "euler", "ancestral")
            model: Noise prediction model
            x: Current noisy image
            t: Current timestep
            t_index: Current timestep index
            **kwargs: Additional arguments for the sampling method
        
        Returns:
            Denoised image or dictionary
        """
        method_mapping = {
            "ddpm": self.p_sample,
            "ddim": self.ddim_sample,
            "dpm_solver": self.dpm_solver_sample,
            "euler": self.euler_sample,
            "ancestral": self.ancestral_sample,
        }
        
        if method not in method_mapping:
            logger.warning(f"Unknown sampling method: {method}. Falling back to DDPM.")
            method = "ddpm"
        
        return method_mapping[method](model, x, t, t_index, **kwargs)
    
    def get_sampling_methods(self):
        """Get list of available sampling methods."""
        return ["ddpm", "ddim", "dpm_solver", "euler", "ancestral"]


class DiffusersSchedulerFactory:
    """Factory for creating Diffusers schedulers."""
    
    SCHEDULER_MAPPING = {
        "ddpm": DDPMScheduler,
        "ddim": DDIMScheduler,
        "euler": EulerDiscreteScheduler,
        "euler_a": EulerAncestralDiscreteScheduler,
        "dpm_solver": DPMSolverMultistepScheduler,
        "dpm_solver++": DPMSolverMultistepScheduler,
        "unipc": UniPCMultistepScheduler,
        "lms": LMSDiscreteScheduler,
        "pndm": PNDMScheduler,
        "kdpm2": KDPM2DiscreteScheduler,
        "heun": HeunDiscreteScheduler,
    }
    
    @classmethod
    def create_scheduler(cls, scheduler_type: str, config: DiffusionConfig, **kwargs):
        """Create a scheduler from the Diffusers library."""
        if scheduler_type not in cls.SCHEDULER_MAPPING:
            raise ValueError(f"Unsupported scheduler type: {scheduler_type}. Supported: {list(cls.SCHEDULER_MAPPING.keys())}")
        
        scheduler_class = cls.SCHEDULER_MAPPING[scheduler_type]
        
        # Base scheduler arguments
        scheduler_kwargs = {
            "num_train_timesteps": config.num_timesteps,
            "beta_start": config.beta_start,
            "beta_end": config.beta_end,
            "beta_schedule": config.beta_schedule,
            **config.scheduler_kwargs,
            **kwargs
        }
        
        # Scheduler-specific configurations
        if scheduler_type in ["dpm_solver", "dpm_solver++"]:
            scheduler_kwargs.update({
                "algorithm_type": "dpmsolver++" if scheduler_type == "dpm_solver++" else "dpmsolver",
                "use_karras_sigmas": config.use_karras_sigmas,
            })
        elif scheduler_type in ["euler", "euler_a"]:
            scheduler_kwargs.update({
                "use_karras_sigmas": config.use_karras_sigmas,
            })
        elif scheduler_type == "ddim":
            scheduler_kwargs.update({
                "eta": config.eta,
                "clip_sample": False,
            })
        
        try:
            return scheduler_class(**scheduler_kwargs)
        except Exception as e:
            logger.warning(f"Failed to create {scheduler_type} scheduler with custom args: {e}")
            # Fallback to basic configuration
            basic_kwargs = {
                "num_train_timesteps": config.num_timesteps,
                "beta_start": config.beta_start,
                "beta_end": config.beta_end,
                "beta_schedule": config.beta_schedule,
            }
            return scheduler_class(**basic_kwargs)
    
    @classmethod
    def get_available_schedulers(cls):
        """Get list of available schedulers."""
        return list(cls.SCHEDULER_MAPPING.keys())


class DiffusersPipelineFactory:
    """
    Comprehensive factory for creating Diffusers pipelines.
    
    This factory supports all major pipeline types from the Diffusers library:
    
    **Text-to-Image Pipelines:**
    - stable_diffusion: Standard Stable Diffusion for text-to-image generation
    - stable_diffusion_xl: High-quality XL model with better resolution and quality
    
    **Image Transformation Pipelines:**
    - img2img: Transform existing images based on text prompts
    - inpaint: Fill in masked areas of images
    - controlnet: Control generation with additional conditions (edges, depth, etc.)
    - upscale: Increase image resolution
    - latent_upscale: Upscale in latent space for better quality
    - depth2img: Generate images from depth maps
    - pix2pix_zero: InstructPix2Pix-style image editing
    
    **Video Generation Pipelines:**
    - text_to_video_zero: Generate videos from text with zero-shot capabilities
    - text_to_video_sd: Stable Diffusion-based video generation
    - text_to_video_xl: High-quality XL video generation
    
    **Basic Diffusion Pipelines:**
    - ddpm: Basic DDPM pipeline for unconditional generation
    - ddim: DDIM pipeline for faster sampling
    
    **Specialized Pipelines:**
    - instruct_pix2pix: Instruction-based image editing
    - kandinsky: Alternative text-to-image model
    - wuerstchen: Fast text-to-image generation
    """
    
    PIPELINE_MAPPING = {
        # Text-to-Image Pipelines
        "stable_diffusion": StableDiffusionPipeline,
        "stable_diffusion_xl": StableDiffusionXLPipeline,
        
        # Image Transformation Pipelines
        "img2img": StableDiffusionImg2ImgPipeline,
        "inpaint": StableDiffusionInpaintPipeline,
        "controlnet": StableDiffusionControlNetPipeline,
        "upscale": StableDiffusionUpscalePipeline,
        "latent_upscale": StableDiffusionLatentUpscalePipeline,
        "depth2img": StableDiffusionDepth2ImgPipeline,
        "pix2pix_zero": StableDiffusionPix2PixZeroPipeline,
        
        # Additional pipelines that will be conditionally imported
        # These are added dynamically to avoid import errors
    }
    
    @classmethod
    def register_pipeline(cls, name: str, pipeline_class):
        """Dynamically register a new pipeline type."""
        cls.PIPELINE_MAPPING[name] = pipeline_class
        logger.info(f"Registered new pipeline type: {name}")
    
    @classmethod
    def get_available_pipelines(cls):
        """Get list of all available pipeline types."""
        return list(cls.PIPELINE_MAPPING.keys())
    
    @classmethod
    def get_pipeline_info(cls, pipeline_type: str):
        """Get detailed information about a specific pipeline type."""
        if pipeline_type not in cls.PIPELINE_MAPPING:
            return None
        
        pipeline_class = cls.PIPELINE_MAPPING[pipeline_type]
        return {
            "name": pipeline_type,
            "class": pipeline_class.__name__,
            "module": pipeline_class.__module__,
            "description": cls._get_pipeline_description(pipeline_type)
        }
    
    @classmethod
    def _get_pipeline_description(cls, pipeline_type: str):
        """Get description for a pipeline type."""
        descriptions = {
            "stable_diffusion": "Standard Stable Diffusion for text-to-image generation with 512x512 resolution",
            "stable_diffusion_xl": "High-quality XL model with better resolution (1024x1024) and improved quality",
            "img2img": "Transform existing images based on text prompts while preserving structure",
            "inpaint": "Fill in masked areas of images with context-aware generation",
            "controlnet": "Control generation with additional conditions like edges, depth, or pose",
            "upscale": "Increase image resolution using specialized upscaling models",
            "latent_upscale": "Upscale in latent space for better quality and consistency",
            "depth2img": "Generate images from depth maps for 3D-aware generation",
            "pix2pix_zero": "Instruction-based image editing with zero-shot capabilities",
            "text_to_video_zero": "Generate videos from text with zero-shot video generation",
            "text_to_video_sd": "Stable Diffusion-based video generation with temporal consistency",
            "text_to_video_xl": "High-quality XL video generation with improved temporal modeling",
            "ddpm": "Basic DDPM pipeline for unconditional image generation",
            "ddim": "DDIM pipeline for faster sampling with deterministic generation",
            "instruct_pix2pix": "Instruction-based image editing with natural language commands",
            "kandinsky": "Alternative text-to-image model with different architecture",
            "wuerstchen": "Fast text-to-image generation with efficient sampling"
        }
        return descriptions.get(pipeline_type, "Pipeline for AI-powered content generation")
    
    @classmethod
    def create_pipeline(cls, config: DiffusionConfig, **kwargs):
        """Create a pipeline from the Diffusers library."""
        pipeline_type = config.pipeline_type
        
        if pipeline_type not in cls.PIPELINE_MAPPING:
            raise ValueError(f"Unsupported pipeline type: {pipeline_type}. Supported: {list(cls.PIPELINE_MAPPING.keys())}")
        
        pipeline_class = cls.PIPELINE_MAPPING[pipeline_type]
        
        # Base pipeline arguments
        pipeline_kwargs = {
            "cache_dir": config.cache_dir,
            "torch_dtype": config.torch_dtype,
            **kwargs
        }
        
        # Safety checker configuration
        if not config.safety_checker:
            pipeline_kwargs.update({
                "safety_checker": None,
                "requires_safety_checker": False,
            })
        
        # Load the pipeline
        try:
            pipeline = pipeline_class.from_pretrained(config.model_id, **pipeline_kwargs)
        except Exception as e:
            logger.error(f"Failed to load pipeline {pipeline_type} with model {config.model_id}: {e}")
            raise
        
        # Apply optimizations
        cls._apply_optimizations(pipeline, config)
        
        # Move to device
        pipeline = pipeline.to(config.device)
        
        logger.info(f"Successfully created {pipeline_type} pipeline with model {config.model_id}")
        return pipeline
    
    @classmethod
    def register_additional_pipelines(cls):
        """Dynamically register additional pipeline types that might not be available by default."""
        try:
            # Try to import and register text-to-video pipelines
            from diffusers import TextToVideoZeroPipeline
            cls.register_pipeline("text_to_video_zero", TextToVideoZeroPipeline)
        except ImportError:
            logger.debug("TextToVideoZeroPipeline not available")
        
        try:
            from diffusers import TextToVideoSDPipeline
            cls.register_pipeline("text_to_video_sd", TextToVideoSDPipeline)
        except ImportError:
            logger.debug("TextToVideoSDPipeline not available")
        
        try:
            from diffusers import TextToVideoXLPipeline
            cls.register_pipeline("text_to_video_xl", TextToVideoXLPipeline)
        except ImportError:
            logger.debug("TextToVideoXLPipeline not available")
        
        try:
            from diffusers import DDIMPipeline
            cls.register_pipeline("ddim", DDIMPipeline)
        except ImportError:
            logger.debug("DDIMPipeline not available")
        
        try:
            from diffusers import DDPMPipeline
            cls.register_pipeline("ddpm", DDPMPipeline)
        except ImportError:
            logger.debug("DDPMPipeline not available")
        
        try:
            from diffusers import StableDiffusionInstructPix2PixPipeline
            cls.register_pipeline("instruct_pix2pix", StableDiffusionInstructPix2PixPipeline)
        except ImportError:
            logger.debug("StableDiffusionInstructPix2PixPipeline not available")
        
        try:
            from diffusers import KandinskyPipeline
            cls.register_pipeline("kandinsky", KandinskyPipeline)
        except ImportError:
            logger.debug("KandinskyPipeline not available")
        
        try:
            from diffusers import WuerstchenPipeline
            cls.register_pipeline("wuerstchen", WuerstchenPipeline)
        except ImportError:
            logger.debug("WuerstchenPipeline not available")
        
        logger.info(f"Registered {len(cls.PIPELINE_MAPPING)} pipeline types")
    
    @classmethod
    def _apply_optimizations(cls, pipeline, config: DiffusionConfig):
        """Apply various optimizations to the pipeline."""
        try:
            # XFormers attention optimization
            if config.use_xformers and hasattr(pipeline, 'enable_xformers_memory_efficient_attention'):
                pipeline.enable_xformers_memory_efficient_attention()
                logger.info("Enabled XFormers memory efficient attention")
        except Exception as e:
            logger.warning(f"Failed to enable XFormers: {e}")
        
        try:
            # Gradient checkpointing
            if config.use_gradient_checkpointing and hasattr(pipeline, 'unet'):
                pipeline.unet.enable_gradient_checkpointing()
                logger.info("Enabled gradient checkpointing")
        except Exception as e:
            logger.warning(f"Failed to enable gradient checkpointing: {e}")
        
        try:
            # CPU offloading
            if config.enable_cpu_offload and hasattr(pipeline, 'enable_model_cpu_offload'):
                pipeline.enable_model_cpu_offload()
                logger.info("Enabled model CPU offload")
            elif config.enable_sequential_cpu_offload and hasattr(pipeline, 'enable_sequential_cpu_offload'):
                pipeline.enable_sequential_cpu_offload()
                logger.info("Enabled sequential CPU offload")
        except Exception as e:
            logger.warning(f"Failed to enable CPU offload: {e}")
        
        try:
            # VAE optimizations
            if config.enable_vae_slicing and hasattr(pipeline, 'enable_vae_slicing'):
                pipeline.enable_vae_slicing()
                logger.info("Enabled VAE slicing")
            
            if config.enable_vae_tiling and hasattr(pipeline, 'enable_vae_tiling'):
                pipeline.enable_vae_tiling()
                logger.info("Enabled VAE tiling")
        except Exception as e:
            logger.warning(f"Failed to enable VAE optimizations: {e}")
        
        try:
            # Attention slicing
            if config.enable_attention_slicing and hasattr(pipeline, 'enable_attention_slicing'):
                pipeline.enable_attention_slicing(config.enable_attention_slicing)
                logger.info(f"Enabled attention slicing: {config.enable_attention_slicing}")
        except Exception as e:
            logger.warning(f"Failed to enable attention slicing: {e}")
    
    @classmethod
    def get_available_pipelines(cls):
        """Get list of available pipelines."""
        return list(cls.PIPELINE_MAPPING.keys())


def timestep_embedding(timesteps: torch.Tensor, dim: int, max_period: int = 10000) -> torch.Tensor:
    """Create sinusoidal timestep embeddings."""
    half = dim // 2
    freqs = torch.exp(
        -math.log(max_period) * torch.arange(start=0, end=half, dtype=torch.float32) / half
    ).to(device=timesteps.device)
    args = timesteps[:, None].float() * freqs[None]
    embedding = torch.cat([torch.cos(args), torch.sin(args)], dim=-1)
    if dim % 2:
        embedding = torch.cat([embedding, torch.zeros_like(embedding[:, :1])], dim=-1)
    return embedding


class ResBlock(nn.Module):
    """Residual block for UNet."""
    
    def __init__(self, channels: int, emb_channels: int, dropout: float, out_channels: Optional[int] = None, use_checkpoint: bool = False):
        super().__init__()
        self.channels = channels
        self.emb_channels = emb_channels
        self.dropout = dropout
        self.out_channels = out_channels or channels
        self.use_checkpoint = use_checkpoint
        
        self.in_layers = nn.Sequential(
            nn.GroupNorm(32, channels),
            nn.SiLU(),
            nn.Conv2d(channels, self.out_channels, 3, padding=1),
        )
        
        self.emb_layers = nn.Sequential(
            nn.SiLU(),
            nn.Linear(emb_channels, self.out_channels),
        )
        
        self.out_layers = nn.Sequential(
            nn.GroupNorm(32, self.out_channels),
            nn.SiLU(),
            nn.Dropout(p=dropout),
            nn.Conv2d(self.out_channels, self.out_channels, 3, padding=1),
        )
        
        if self.out_channels == channels:
            self.skip_connection = nn.Identity()
        else:
            self.skip_connection = nn.Conv2d(channels, self.out_channels, 1)
    
    def forward(self, x: torch.Tensor, emb: torch.Tensor) -> torch.Tensor:
        h = self.in_layers(x)
        emb_out = self.emb_layers(emb).type(h.dtype)
        h = h + emb_out.view(emb_out.shape[0], -1, 1, 1)
        h = self.out_layers(h)
        return self.skip_connection(x) + h


class CrossAttention(nn.Module):
    """Cross attention module."""
    
    def __init__(self, query_dim: int, n_heads: int, d_head: int, context_dim: Optional[int] = None, use_checkpoint: bool = False):
        super().__init__()
        inner_dim = d_head * n_heads
        context_dim = context_dim if context_dim is not None else query_dim
        self.use_checkpoint = use_checkpoint
        
        self.scale = d_head ** -0.5
        self.n_heads = n_heads
        
        self.to_q = nn.Linear(query_dim, inner_dim, bias=False)
        self.to_k = nn.Linear(context_dim, inner_dim, bias=False)
        self.to_v = nn.Linear(context_dim, inner_dim, bias=False)
        
        self.to_out = nn.Sequential(
            nn.Linear(inner_dim, query_dim),
            nn.Dropout(0.0)
        )
    
    def forward(self, x: torch.Tensor, context: Optional[torch.Tensor] = None) -> torch.Tensor:
        context = context if context is not None else x
        
        q = self.to_q(x)
        k = self.to_k(context)
        v = self.to_v(context)
        
        q, k, v = map(lambda t: t.reshape(*t.shape[:2], self.n_heads, -1).transpose(1, 2), (q, k, v))
        
        sim = torch.einsum('b h i d, b h j d -> b h i j', q, k) * self.scale
        attn = sim.softmax(dim=-1)
        
        out = torch.einsum('b h i j, b h j d -> b h i d', attn, v)
        out = out.transpose(1, 2).reshape(*x.shape[:2], -1)
        
        return self.to_out(out)


class BasicTransformerBlock(nn.Module):
    """Basic transformer block with self-attention and cross-attention."""
    
    def __init__(self, dim: int, n_heads: int, d_head: int, context_dim: Optional[int] = None, use_checkpoint: bool = False):
        super().__init__()
        self.attn1 = CrossAttention(dim, n_heads, d_head, use_checkpoint=use_checkpoint)
        self.ff = FeedForward(dim, use_checkpoint=use_checkpoint)
        self.attn2 = CrossAttention(dim, n_heads, d_head, context_dim=context_dim, use_checkpoint=use_checkpoint)
        self.norm1 = nn.LayerNorm(dim)
        self.norm2 = nn.LayerNorm(dim)
        self.norm3 = nn.LayerNorm(dim)
    
    def forward(self, x: torch.Tensor, context: Optional[torch.Tensor] = None) -> torch.Tensor:
        x = self.attn1(self.norm1(x)) + x
        x = self.attn2(self.norm2(x), context=context) + x
        x = self.ff(self.norm3(x)) + x
        return x


class FeedForward(nn.Module):
    """Feed-forward network."""
    
    def __init__(self, dim: int, mult: int = 4, use_checkpoint: bool = False):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(dim, dim * mult),
            nn.GELU(),
            nn.Linear(dim * mult, dim),
        )
        self.use_checkpoint = use_checkpoint
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.net(x)


class SpatialTransformer(nn.Module):
    """Spatial transformer for cross-attention."""
    
    def __init__(self, in_channels: int, n_heads: int, d_head: int, depth: int = 1, context_dim: Optional[int] = None, use_checkpoint: bool = False):
        super().__init__()
        self.in_channels = in_channels
        inner_dim = n_heads * d_head
        self.n_heads = n_heads
        self.d_head = d_head
        self.context_dim = context_dim
        self.use_checkpoint = use_checkpoint
        
        self.norm = nn.GroupNorm(32, in_channels)
        self.proj_in = nn.Conv2d(in_channels, inner_dim, kernel_size=1, stride=1, padding=0)
        
        self.transformer_blocks = nn.ModuleList([
            BasicTransformerBlock(inner_dim, n_heads, d_head, context_dim=context_dim, use_checkpoint=use_checkpoint)
            for _ in range(depth)
        ])
        
        self.proj_out = nn.Conv2d(inner_dim, in_channels, kernel_size=1, stride=1, padding=0)
    
    def forward(self, x: torch.Tensor, context: Optional[torch.Tensor] = None) -> torch.Tensor:
        b, c, h, w = x.shape
        x_in = x
        x = self.norm(x)
        x = self.proj_in(x)
        x = x.permute(0, 2, 3, 1).reshape(b, h * w, c)
        
        for block in self.transformer_blocks:
            x = block(x, context)
        
        x = x.reshape(b, h, w, c).permute(0, 3, 1, 2)
        x = self.proj_out(x)
        return x + x_in


class Upsample(nn.Module):
    """Upsampling layer."""
    
    def __init__(self, channels: int, use_conv: bool, use_checkpoint: bool = False):
        super().__init__()
        self.channels = channels
        self.use_conv = use_conv
        self.use_checkpoint = use_checkpoint
        
        if use_conv:
            self.conv = nn.Conv2d(channels, channels, 3, padding=1)
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        x = F.interpolate(x, scale_factor=2, mode="nearest")
        if self.use_conv:
            x = self.conv(x)
        return x


class Downsample(nn.Module):
    """Downsampling layer."""
    
    def __init__(self, channels: int, use_conv: bool, use_checkpoint: bool = False):
        super().__init__()
        self.channels = channels
        self.use_conv = use_conv
        self.use_checkpoint = use_checkpoint
        
        if use_conv:
            self.op = nn.Conv2d(channels, channels, 3, stride=2, padding=1)
        else:
            self.op = nn.AvgPool2d(kernel_size=2, stride=2)
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.op(x)


class CustomUNet(nn.Module):
    """Custom UNet architecture for diffusion models."""
    
    def __init__(self, 
                 in_channels: int = 3,
                 out_channels: int = 3,
                 model_channels: int = 128,
                 num_res_blocks: int = 2,
                 attention_resolutions: Tuple[int, ...] = (8, 16),
                 dropout: float = 0.0,
                 channel_mult: Tuple[int, ...] = (1, 2, 4, 8),
                 conv_resample: bool = True,
                 num_heads: int = 8,
                 use_spatial_transformer: bool = True,
                 transformer_depth: int = 1,
                 context_dim: Optional[int] = None,
                 use_checkpoint: bool = False):
        super().__init__()
        
        self.in_channels = in_channels
        self.model_channels = model_channels
        self.num_res_blocks = num_res_blocks
        self.attention_resolutions = attention_resolutions
        self.dropout = dropout
        self.channel_mult = channel_mult
        self.conv_resample = conv_resample
        self.num_heads = num_heads
        self.use_spatial_transformer = use_spatial_transformer
        self.transformer_depth = transformer_depth
        self.context_dim = context_dim
        self.use_checkpoint = use_checkpoint
        
        # Time embedding
        time_embed_dim = model_channels * 4
        self.time_embed = nn.Sequential(
            nn.Linear(model_channels, time_embed_dim),
            nn.SiLU(),
            nn.Linear(time_embed_dim, time_embed_dim),
        )
        
        # Input projection
        self.input_blocks = nn.ModuleList([
            nn.Conv2d(in_channels, model_channels, kernel_size=3, padding=1)
        ])
        
        # Downsampling
        input_block_chans = [model_channels]
        ch = model_channels
        ds = 1
        for level, mult in enumerate(channel_mult):
            for _ in range(num_res_blocks):
                layers = [
                    ResBlock(
                        ch, time_embed_dim, dropout,
                        out_channels=mult * model_channels,
                        use_checkpoint=use_checkpoint
                    )
                ]
                ch = mult * model_channels
                if ds in attention_resolutions:
                    if use_spatial_transformer:
                        layers.append(
                            SpatialTransformer(
                                ch, num_heads, transformer_depth, context_dim,
                                use_checkpoint=use_checkpoint
                            )
                        )
                self.input_blocks.append(nn.ModuleList(layers))
                input_block_chans.append(ch)
            if level != len(channel_mult) - 1:
                self.input_blocks.append(
                    nn.ModuleList([Downsample(ch, conv_resample, use_checkpoint=use_checkpoint)])
                )
                input_block_chans.append(ch)
                ds *= 2
        
        # Middle block
        self.middle_block = nn.ModuleList([
            ResBlock(
                ch, time_embed_dim, dropout,
                use_checkpoint=use_checkpoint
            ),
            SpatialTransformer(
                ch, num_heads, transformer_depth, context_dim,
                use_checkpoint=use_checkpoint
            ) if use_spatial_transformer else nn.Identity(),
            ResBlock(
                ch, time_embed_dim, dropout,
                use_checkpoint=use_checkpoint
            ),
        ])
        
        # Upsampling
        self.output_blocks = nn.ModuleList([])
        for level, mult in list(enumerate(channel_mult))[::-1]:
            for i in range(num_res_blocks + 1):
                ich = input_block_chans.pop()
                layers = [
                    ResBlock(
                        ch + ich, time_embed_dim, dropout,
                        out_channels=model_channels * mult,
                        use_checkpoint=use_checkpoint
                    )
                ]
                ch = model_channels * mult
                if ds in attention_resolutions:
                    if use_spatial_transformer:
                        layers.append(
                            SpatialTransformer(
                                ch, num_heads, transformer_depth, context_dim,
                                use_checkpoint=use_checkpoint
                            )
                        )
                if level and i == num_res_blocks:
                    layers.append(Upsample(ch, conv_resample, use_checkpoint=use_checkpoint))
                    ds //= 2
                self.output_blocks.append(nn.ModuleList(layers))
        
        # Output projection
        self.out = nn.Sequential(
            nn.GroupNorm(32, ch),
            nn.SiLU(),
            nn.Conv2d(ch, out_channels, kernel_size=3, padding=1),
        )
    
    def forward(self, x: torch.Tensor, timesteps: torch.Tensor, context: Optional[torch.Tensor] = None) -> torch.Tensor:
        """Forward pass of the UNet."""
        # Time embedding
        emb = self.time_embed(timestep_embedding(timesteps, self.model_channels))
        
        # Input blocks
        hs = []
        h = x
        for module in self.input_blocks:
            if isinstance(module, nn.Conv2d):
                h = module(h)
            else:
                for layer in module:
                    if isinstance(layer, ResBlock):
                        h = layer(h, emb)
                    elif isinstance(layer, SpatialTransformer):
                        h = layer(h, context)
                    else:
                        h = layer(h)
            hs.append(h)
        
        # Middle block
        for module in self.middle_block:
            if isinstance(module, ResBlock):
                h = module(h, emb)
            elif isinstance(module, SpatialTransformer):
                h = module(h, context)
            else:
                h = module(h)
        
        # Output blocks
        for module in self.output_blocks:
            h = torch.cat([h, hs.pop()], dim=1)
            for layer in module:
                if isinstance(layer, ResBlock):
                    h = layer(h, emb)
                elif isinstance(layer, SpatialTransformer):
                    h = layer(h, context)
                else:
                    h = layer(h)
        
        return self.out(h)


class AdvancedDiffusionModel(nn.Module):
    """Enhanced advanced diffusion model with mathematical rigor and advanced features."""
    
    def __init__(self, config: DiffusionConfig):
        super().__init__()
        self.config = config
        self.scheduler = CustomDiffusionScheduler(config)
        
        # UNet backbone
        self.unet = CustomUNet(
            in_channels=3,
            out_channels=3,
            model_channels=128,
            num_res_blocks=2,
            attention_resolutions=(8, 16),
            dropout=0.0,
            channel_mult=(1, 2, 4, 8),
            conv_resample=True,
            num_heads=8,
            use_spatial_transformer=True,
            transformer_depth=1,
            context_dim=768,  # For text conditioning
            use_checkpoint=config.use_gradient_checkpointing
        )
        
        # Text encoder for conditioning
        self.text_encoder = nn.Sequential(
            nn.Linear(768, 512),
            nn.ReLU(),
            nn.Dropout(0.1),
            nn.Linear(512, 768)
        )
        
        # Time embedding
        self.time_embed = nn.Sequential(
            nn.Linear(1, 128),
            nn.SiLU(),
            nn.Linear(128, 128),
        )
        
        # Classifier-free guidance
        self.classifier_free_guidance = config.use_classifier_free_guidance
        
        self.to(config.device)
    
    def forward(self, x: torch.Tensor, timesteps: torch.Tensor, context: Optional[torch.Tensor] = None) -> torch.Tensor:
        """
        Forward pass predicting noise.
        
        Args:
            x: Input images [B, C, H, W]
            timesteps: Timesteps [B]
            context: Optional conditioning context [B, context_dim]
        
        Returns:
            Predicted noise [B, C, H, W]
        """
        # Time embedding
        t_emb = timesteps.float().view(-1, 1) / self.config.num_timesteps
        t_emb = self.time_embed(t_emb)
        
        # Context embedding
        if context is not None:
            context = self.text_encoder(context)
        
        return self.unet(x, t_emb, context)
    
    def sample(self, 
               batch_size: int = 1, 
               channels: int = 3, 
               height: int = 64, 
               width: int = 64,
               context: Optional[torch.Tensor] = None,
               guidance_scale: float = 7.5,
               num_inference_steps: int = None,
               clip_denoised: bool = True,
               sampling_method: str = "ddpm",
               **kwargs) -> torch.Tensor:
        """
        Generate samples using the diffusion model with advanced sampling methods.
        
        Args:
            batch_size: Number of samples to generate
            channels: Number of image channels
            height: Image height
            width: Image width
            context: Optional conditioning context
            guidance_scale: Classifier-free guidance scale
            num_inference_steps: Number of denoising steps
            clip_denoised: Whether to clip denoised images
            sampling_method: Sampling method to use ("ddpm", "ddim", "dpm_solver", "euler", "ancestral")
            **kwargs: Additional arguments for the sampling method
        
        Returns:
            Generated samples [B, C, H, W]
        """
        device = next(self.parameters()).device
        num_inference_steps = num_inference_steps or self.config.num_inference_steps
        
        # Initialize with random noise
        x = torch.randn(batch_size, channels, height, width, device=device)
        
        # Classifier-free guidance setup
        if context is not None and self.classifier_free_guidance and guidance_scale > 1.0:
            uncond_context = torch.zeros_like(context)
            context = torch.cat([uncond_context, context], dim=0)
            x = x.repeat(2, 1, 1, 1)
            batch_size *= 2
        
        # Use the enhanced sampling loop with specified method
        if sampling_method == "ddim" and "eta" in kwargs:
            # DDIM sampling with custom eta
            for i in tqdm(reversed(range(0, num_inference_steps)), desc=f"DDIM Sampling (η={kwargs['eta']})"):
                t = torch.full((batch_size,), i, device=device, dtype=torch.long)
                
                with torch.no_grad():
                    noise_pred = self(x, t, context)
                    
                    # Apply classifier-free guidance
                    if context is not None and self.classifier_free_guidance and guidance_scale > 1.0:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)
                        x = x[:batch_size // 2]
                    
                    # DDIM denoising step
                    result = self.scheduler.ddim_sample(self, x, t, i, eta=kwargs['eta'], 
                                                      clip_denoised=clip_denoised, return_dict=True)
                    x = result["prev_sample"]
        
        elif sampling_method == "dpm_solver":
            # DPM-Solver sampling
            for i in tqdm(reversed(range(0, num_inference_steps)), desc="DPM-Solver Sampling"):
                t = torch.full((batch_size,), i, device=device, dtype=torch.long)
                
                with torch.no_grad():
                    noise_pred = self(x, t, context)
                    
                    # Apply classifier-free guidance
                    if context is not None and self.classifier_free_guidance and guidance_scale > 1.0:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)
                        x = x[:batch_size // 2]
                    
                    # DPM-Solver denoising step
                    result = self.scheduler.dpm_solver_sample(self, x, t, i, 
                                                            algorithm_type=kwargs.get('algorithm_type', 'dpmsolver++'),
                                                            return_dict=True)
                    x = result["prev_sample"]
        
        else:
            # Standard sampling with specified method
            for i in tqdm(reversed(range(0, num_inference_steps)), desc=f"{sampling_method.upper()} Sampling"):
                t = torch.full((batch_size,), i, device=device, dtype=torch.long)
                
                with torch.no_grad():
                    noise_pred = self(x, t, context)
                    
                    # Apply classifier-free guidance
                    if context is not None and self.classifier_free_guidance and guidance_scale > 1.0:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)
                        x = x[:batch_size // 2]
                    
                    # Denoising step with specified method
                    result = self.scheduler.sample_with_method(sampling_method, self, x, t, i, 
                                                            clip_denoised=clip_denoised, return_dict=True, **kwargs)
                    x = result["prev_sample"]
        
        return x
    
    def sample_with_adaptive_steps(self, 
                                  batch_size: int = 1, 
                                  channels: int = 3, 
                                  height: int = 64, 
                                  width: int = 64,
                                  context: Optional[torch.Tensor] = None,
                                  guidance_scale: float = 7.5,
                                  min_steps: int = 10,
                                  max_steps: int = None,
                                  clip_denoised: bool = True) -> Dict[str, torch.Tensor]:
        """
        Generate samples with adaptive step sizing for optimal quality/speed trade-off.
        
        Args:
            batch_size: Number of samples to generate
            channels: Number of image channels
            height: Image height
            width: Image width
            context: Optional conditioning context
            guidance_scale: Classifier-free guidance scale
            min_steps: Minimum number of denoising steps
            max_steps: Maximum number of denoising steps
            clip_denoised: Whether to clip denoised images
        
        Returns:
            Dictionary with samples and convergence information
        """
        device = next(self.parameters()).device
        max_steps = max_steps or self.config.num_inference_steps
        
        # Initialize with random noise
        x = torch.randn(batch_size, channels, height, width, device=device)
        
        # Use adaptive sampling loop
        result = self.scheduler.p_sample_loop_adaptive(
            self, (batch_size, channels, height, width),
            noise=x, clip_denoised=clip_denoised,
            return_dict=True, adaptive_steps=True,
            min_steps=min_steps, max_steps=max_steps
        )
        
        return result
    
    def sample_with_guidance(self, 
                            batch_size: int = 1, 
                            channels: int = 3, 
                            height: int = 64, 
                            width: int = 64,
                            context: Optional[torch.Tensor] = None,
                            guidance_scale: float = 7.5,
                            num_inference_steps: int = None,
                            clip_denoised: bool = True) -> Dict[str, torch.Tensor]:
        """
        Generate samples with enhanced classifier-free guidance.
        
        Args:
            batch_size: Number of samples to generate
            channels: Number of image channels
            height: Image height
            width: Image width
            context: Optional conditioning context
            guidance_scale: Classifier-free guidance scale
            num_inference_steps: Number of denoising steps
            clip_denoised: Whether to clip denoised images
        
        Returns:
            Dictionary with samples and guidance information
        """
        device = next(self.parameters()).device
        num_inference_steps = num_inference_steps or self.config.num_inference_steps
        
        # Initialize with random noise
        x = torch.randn(batch_size, channels, height, width, device=device)
        
        # Use guided sampling loop
        result = self.scheduler.p_sample_loop_guided(
            self, (batch_size, channels, height, width),
            guidance_scale=guidance_scale,
            classifier_free_guidance=self.classifier_free_guidance,
            noise=x, clip_denoised=clip_denoised,
            return_dict=True
        )
        
        return result
    
    def training_step(self, batch: torch.Tensor, context: Optional[torch.Tensor] = None) -> Dict[str, torch.Tensor]:
        """
        Training step for the diffusion model.
        
        Args:
            batch: Training batch [B, C, H, W]
            context: Optional conditioning context
        
        Returns:
            Training loss dictionary
        """
        batch_size = batch.shape[0]
        device = batch.device
        
        # Sample random timesteps
        t = torch.randint(0, self.config.num_timesteps, (batch_size,), device=device)
        
        # Add noise to the batch
        noise = torch.randn_like(batch)
        noisy_batch = self.scheduler.q_sample(batch, t, noise)
        
        # Predict noise
        predicted_noise = self(noisy_batch, t, context)
        
        # Calculate loss (MSE between predicted and actual noise)
        loss = F.mse_loss(predicted_noise, noise, reduction='mean')
        
        return {
            "loss": loss,
            "predicted_noise": predicted_noise,
            "target_noise": noise,
            "timesteps": t
        }


class UltraOptimizedDiffusionModel:
    """Ultra-optimized diffusion model wrapper with comprehensive Diffusers integration."""
    
    def __init__(self, 
                 diffusion_config: DiffusionConfig = None,
                 training_config: UltraTrainingConfig = None):
        self.diffusion_config = diffusion_config or DiffusionConfig()
        self.training_config = training_config or UltraTrainingConfig()
        
        # Diffusers integration
        self.pipeline = None
        self.scheduler = None
        self.pipeline_factory = DiffusersPipelineFactory()
        self.scheduler_factory = DiffusersSchedulerFactory()
        
        # Custom models
        self.advanced_model = None
        
        # Load initial pipeline
        self._load_pipeline()
    
    def _load_pipeline(self):
        """Load diffusion pipeline using Diffusers factory."""
        try:
            # Create pipeline using factory
            self.pipeline = self.pipeline_factory.create_pipeline(self.diffusion_config)
            
            # Create and set custom scheduler if specified
            if self.diffusion_config.scheduler_type != "ddpm":
                custom_scheduler = self.scheduler_factory.create_scheduler(
                    self.diffusion_config.scheduler_type,
                    self.diffusion_config
                )
                self.pipeline.scheduler = custom_scheduler
                self.scheduler = custom_scheduler
            
            logger.info(
                "Diffusion pipeline loaded successfully",
                pipeline_type=self.diffusion_config.pipeline_type,
                model_id=self.diffusion_config.model_id,
                scheduler_type=self.diffusion_config.scheduler_type
            )
            
        except Exception as e:
            logger.error(
                "Failed to load diffusion pipeline",
                error=str(e),
                pipeline_type=self.diffusion_config.pipeline_type,
                model_id=self.diffusion_config.model_id
            )
            raise
    
    def generate_image(self, 
                     prompt: str, 
                     negative_prompt: str = None,
                     num_inference_steps: int = None, 
                     guidance_scale: float = None,
                     height: int = None,
                     width: int = None,
                     seed: int = None,
                     **kwargs):
        """Generate image using Diffusers pipeline with comprehensive options."""
        try:
            # Use config defaults if not specified
            num_inference_steps = num_inference_steps or self.diffusion_config.num_inference_steps
            guidance_scale = guidance_scale or self.diffusion_config.guidance_scale
            height = height or self.diffusion_config.height
            width = width or self.diffusion_config.width
            seed = seed or self.diffusion_config.seed
            
            # Prepare generation arguments
            generation_kwargs = {
                "prompt": prompt,
                "num_inference_steps": num_inference_steps,
                "guidance_scale": guidance_scale,
                "height": height,
                "width": width,
                **kwargs
            }
            
            # Add negative prompt if provided
            if negative_prompt:
                generation_kwargs["negative_prompt"] = negative_prompt
            
            # Set up generator for reproducibility
            if seed is not None:
                generator = torch.Generator(device=self.diffusion_config.device).manual_seed(seed)
                generation_kwargs["generator"] = generator
            
            # Add cross attention kwargs if configured
            if self.diffusion_config.cross_attention_kwargs:
                generation_kwargs["cross_attention_kwargs"] = self.diffusion_config.cross_attention_kwargs
            
            # Add clip skip if configured
            if self.diffusion_config.clip_skip:
                generation_kwargs["clip_skip"] = self.diffusion_config.clip_skip
            
            # Generate with mixed precision if enabled
            with autocast() if self.diffusion_config.use_mixed_precision else nullcontext():
                result = self.pipeline(**generation_kwargs)
            
            # Return image(s)
            if hasattr(result, 'images'):
                return result.images[0] if len(result.images) == 1 else result.images
            else:
                return result
            
        except Exception as e:
            logger.error("Image generation failed", error=str(e), prompt=prompt)
            raise
    
    def create_advanced_model(self, diffusion_config: DiffusionConfig = None):
        """Create advanced custom diffusion model."""
        if diffusion_config is None:
            diffusion_config = DiffusionConfig()
        
        self.advanced_model = AdvancedDiffusionModel(diffusion_config)
        logger.info("Advanced diffusion model created successfully")
        return self.advanced_model
    
    def train_advanced_model(self, 
                           dataloader: DataLoader, 
                           epochs: int = 100,
                           learning_rate: float = 1e-4,
                           save_path: str = "advanced_diffusion_model.pt"):
        """Train the advanced diffusion model."""
        if self.advanced_model is None:
            raise ValueError("Advanced model not created. Call create_advanced_model() first.")
        
        optimizer = torch.optim.AdamW(self.advanced_model.parameters(), lr=learning_rate)
        scheduler = torch.optim.lr_scheduler.CosineAnnealingLR(optimizer, T_max=epochs)
        
        self.advanced_model.train()
        
        for epoch in range(epochs):
            total_loss = 0
            for batch_idx, batch in enumerate(dataloader):
                images = batch['images'].to(self.config.device)
                batch_size = images.shape[0]
                
                # Sample random timesteps
                t = torch.randint(0, self.advanced_model.config.num_timesteps, (batch_size,), device=self.config.device)
                
                # Add noise
                noise = torch.randn_like(images)
                noisy_images = self.advanced_model.scheduler.q_sample(images, t, noise)
                
                # Predict noise
                predicted_noise = self.advanced_model(noisy_images, t)
                loss = F.mse_loss(predicted_noise, noise)
                
                # Backward pass
                optimizer.zero_grad()
                loss.backward()
                optimizer.step()
                
                total_loss += loss.item()
                
                if batch_idx % 10 == 0:
                    logger.info(f"Epoch {epoch}, Batch {batch_idx}, Loss: {loss.item():.4f}")
            
            scheduler.step()
            avg_loss = total_loss / len(dataloader)
            logger.info(f"Epoch {epoch} completed, Average Loss: {avg_loss:.4f}")
            
            # Save checkpoint
            if (epoch + 1) % 10 == 0:
                torch.save({
                    'epoch': epoch,
                    'model_state_dict': self.advanced_model.state_dict(),
                    'optimizer_state_dict': optimizer.state_dict(),
                    'loss': avg_loss,
                }, f"{save_path}_epoch_{epoch+1}.pt")
        
        logger.info("Training completed successfully")
    
    def generate_with_advanced_model(self, 
                                   prompt: str = None,
                                   batch_size: int = 1,
                                   height: int = 64,
                                   width: int = 64,
                                   guidance_scale: float = 7.5) -> torch.Tensor:
        """Generate images using the advanced model."""
        if self.advanced_model is None:
            raise ValueError("Advanced model not created. Call create_advanced_model() first.")
        
        # Simple text encoding (in practice, use a proper tokenizer)
        context = None
        if prompt:
            # Dummy text encoding for demonstration
            context = torch.randn(batch_size, 768, device=self.config.device)
        
        self.advanced_model.eval()
        with torch.no_grad():
            samples = self.advanced_model.sample(
                batch_size=batch_size,
                height=height,
                width=width,
                context=context,
                guidance_scale=guidance_scale
            )
        
        return samples
    
    def switch_pipeline(self, pipeline_type: str, model_id: str = None, **kwargs):
        """Switch to a different pipeline type using Diffusers factory."""
        try:
            # Update configuration
            old_config = self.diffusion_config
            new_config = DiffusionConfig(
                # Copy all existing settings
                num_timesteps=old_config.num_timesteps,
                beta_start=old_config.beta_start,
                beta_end=old_config.beta_end,
                beta_schedule=old_config.beta_schedule,
                guidance_scale=old_config.guidance_scale,
                num_inference_steps=old_config.num_inference_steps,
                scheduler_type=old_config.scheduler_type,
                scheduler_kwargs=old_config.scheduler_kwargs,
                
                # Update pipeline settings
                pipeline_type=pipeline_type,
                model_id=model_id or old_config.model_id,
                
                # Copy performance settings
                use_classifier_free_guidance=old_config.use_classifier_free_guidance,
                use_mixed_precision=old_config.use_mixed_precision,
                use_xformers=old_config.use_xformers,
                use_gradient_checkpointing=old_config.use_gradient_checkpointing,
                enable_cpu_offload=old_config.enable_cpu_offload,
                enable_sequential_cpu_offload=old_config.enable_sequential_cpu_offload,
                enable_model_cpu_offload=old_config.enable_model_cpu_offload,
                enable_vae_slicing=old_config.enable_vae_slicing,
                enable_vae_tiling=old_config.enable_vae_tiling,
                enable_attention_slicing=old_config.enable_attention_slicing,
                
                # Copy other settings
                safety_checker=old_config.safety_checker,
                requires_safety_checker=old_config.requires_safety_checker,
                height=old_config.height,
                width=old_config.width,
                device=old_config.device,
                torch_dtype=old_config.torch_dtype,
                cache_dir=old_config.cache_dir,
                **kwargs
            )
            
            self.diffusion_config = new_config
            
            # Load new pipeline
            self._load_pipeline()
            
            logger.info(
                f"Successfully switched to {pipeline_type} pipeline",
                pipeline_type=pipeline_type,
                model_id=self.diffusion_config.model_id
            )
            
        except Exception as e:
            logger.error(
                f"Failed to switch to {pipeline_type} pipeline",
                error=str(e),
                pipeline_type=pipeline_type,
                model_id=model_id
            )
            raise
    
    def switch_scheduler(self, scheduler_type: str, **kwargs):
        """Switch to a different scheduler."""
        try:
            # Update scheduler configuration
            self.diffusion_config.scheduler_type = scheduler_type
            self.diffusion_config.scheduler_kwargs.update(kwargs)
            
            # Create new scheduler
            new_scheduler = self.scheduler_factory.create_scheduler(
                scheduler_type,
                self.diffusion_config,
                **kwargs
            )
            
            # Replace scheduler in pipeline
            self.pipeline.scheduler = new_scheduler
            self.scheduler = new_scheduler
            
            logger.info(f"Successfully switched to {scheduler_type} scheduler")
            
        except Exception as e:
            logger.error(f"Failed to switch to {scheduler_type} scheduler", error=str(e))
            raise
    
    def get_available_pipelines(self):
        """Get list of available pipeline types."""
        return self.pipeline_factory.get_available_pipelines()
    
    def get_available_schedulers(self):
        """Get list of available scheduler types."""
        return self.scheduler_factory.get_available_schedulers()
    
    def get_pipeline_info(self):
        """Get information about the current pipeline."""
        return {
            "pipeline_type": self.diffusion_config.pipeline_type,
            "model_id": self.diffusion_config.model_id,
            "scheduler_type": self.diffusion_config.scheduler_type,
            "device": str(self.diffusion_config.device),
            "torch_dtype": str(self.diffusion_config.torch_dtype),
            "optimizations": {
                "xformers": self.diffusion_config.use_xformers,
                "gradient_checkpointing": self.diffusion_config.use_gradient_checkpointing,
                "cpu_offload": self.diffusion_config.enable_cpu_offload,
                "vae_slicing": self.diffusion_config.enable_vae_slicing,
                "vae_tiling": self.diffusion_config.enable_vae_tiling,
                "attention_slicing": self.diffusion_config.enable_attention_slicing,
            }
        }
    
    def benchmark_generation(self, num_runs: int = 10, prompt: str = "a beautiful landscape") -> Dict[str, float]:
        """Benchmark generation performance."""
        times = []
        memory_usage = []
        
        for i in range(num_runs):
            start_time = time.time()
            start_memory = torch.cuda.memory_allocated() if torch.cuda.is_available() else 0
            
            # Generate image
            image = self.generate_image(prompt, num_inference_steps=20)
            
            end_time = time.time()
            end_memory = torch.cuda.memory_allocated() if torch.cuda.is_available() else 0
            
            times.append(end_time - start_time)
            memory_usage.append(end_memory - start_memory)
        
        return {
            'avg_generation_time': np.mean(times),
            'std_generation_time': np.std(times),
            'avg_memory_usage': np.mean(memory_usage) / 1024**2,  # MB
            'std_memory_usage': np.std(memory_usage) / 1024**2,  # MB
        }
    
    def generate_img2img(self, 
                        prompt: str,
                        image,
                        strength: float = 0.75,
                        negative_prompt: str = None,
                        num_inference_steps: int = None,
                        guidance_scale: float = None,
                        **kwargs):
        """Generate image-to-image using Diffusers."""
        if self.diffusion_config.pipeline_type != "img2img":
            self.switch_pipeline("img2img")
        
        generation_kwargs = {
            "prompt": prompt,
            "image": image,
            "strength": strength,
            "num_inference_steps": num_inference_steps or self.diffusion_config.num_inference_steps,
            "guidance_scale": guidance_scale or self.diffusion_config.guidance_scale,
            **kwargs
        }
        
        if negative_prompt:
            generation_kwargs["negative_prompt"] = negative_prompt
        
        with autocast() if self.diffusion_config.use_mixed_precision else nullcontext():
            result = self.pipeline(**generation_kwargs)
        
        return result.images[0] if hasattr(result, 'images') else result
    
    def generate_inpaint(self,
                        prompt: str,
                        image,
                        mask_image,
                        negative_prompt: str = None,
                        num_inference_steps: int = None,
                        guidance_scale: float = None,
                        **kwargs):
        """Generate inpainting using Diffusers."""
        if self.diffusion_config.pipeline_type != "inpaint":
            self.switch_pipeline("inpaint")
        
        generation_kwargs = {
            "prompt": prompt,
            "image": image,
            "mask_image": mask_image,
            "num_inference_steps": num_inference_steps or self.diffusion_config.num_inference_steps,
            "guidance_scale": guidance_scale or self.diffusion_config.guidance_scale,
            **kwargs
        }
        
        if negative_prompt:
            generation_kwargs["negative_prompt"] = negative_prompt
        
        with autocast() if self.diffusion_config.use_mixed_precision else nullcontext():
            result = self.pipeline(**generation_kwargs)
        
        return result.images[0] if hasattr(result, 'images') else result
    
    def generate_controlnet(self,
                           prompt: str,
                           control_image,
                           controlnet_conditioning_scale: float = 1.0,
                           negative_prompt: str = None,
                           num_inference_steps: int = None,
                           guidance_scale: float = None,
                           **kwargs):
        """Generate with ControlNet using Diffusers."""
        if self.diffusion_config.pipeline_type != "controlnet":
            self.switch_pipeline("controlnet")
        
        generation_kwargs = {
            "prompt": prompt,
            "image": control_image,
            "controlnet_conditioning_scale": controlnet_conditioning_scale,
            "num_inference_steps": num_inference_steps or self.diffusion_config.num_inference_steps,
            "guidance_scale": guidance_scale or self.diffusion_config.guidance_scale,
            **kwargs
        }
        
        if negative_prompt:
            generation_kwargs["negative_prompt"] = negative_prompt
        
        with autocast() if self.diffusion_config.use_mixed_precision else nullcontext():
            result = self.pipeline(**generation_kwargs)
        
        return result.images[0] if hasattr(result, 'images') else result
    
    def generate_batch(self,
                      prompts: List[str],
                      negative_prompts: List[str] = None,
                      batch_size: int = 4,
                      **kwargs):
        """Generate multiple images in batches."""
        all_images = []
        
        for i in range(0, len(prompts), batch_size):
            batch_prompts = prompts[i:i + batch_size]
            batch_negative_prompts = negative_prompts[i:i + batch_size] if negative_prompts else None
            
            generation_kwargs = {
                "prompt": batch_prompts,
                **kwargs
            }
            
            if batch_negative_prompts:
                generation_kwargs["negative_prompt"] = batch_negative_prompts
            
            with autocast() if self.diffusion_config.use_mixed_precision else nullcontext():
                result = self.pipeline(**generation_kwargs)
            
            if hasattr(result, 'images'):
                all_images.extend(result.images)
            else:
                all_images.append(result)
        
        return all_images
    
    def enable_optimization(self, optimization_type: str):
        """Enable specific optimization."""
        if optimization_type == "xformers" and hasattr(self.pipeline, 'enable_xformers_memory_efficient_attention'):
            self.pipeline.enable_xformers_memory_efficient_attention()
            self.diffusion_config.use_xformers = True
            logger.info("Enabled XFormers memory efficient attention")
        
        elif optimization_type == "cpu_offload" and hasattr(self.pipeline, 'enable_model_cpu_offload'):
            self.pipeline.enable_model_cpu_offload()
            self.diffusion_config.enable_model_cpu_offload = True
            logger.info("Enabled model CPU offload")
        
        elif optimization_type == "sequential_cpu_offload" and hasattr(self.pipeline, 'enable_sequential_cpu_offload'):
            self.pipeline.enable_sequential_cpu_offload()
            self.diffusion_config.enable_sequential_cpu_offload = True
            logger.info("Enabled sequential CPU offload")
        
        elif optimization_type == "vae_slicing" and hasattr(self.pipeline, 'enable_vae_slicing'):
            self.pipeline.enable_vae_slicing()
            self.diffusion_config.enable_vae_slicing = True
            logger.info("Enabled VAE slicing")
        
        elif optimization_type == "vae_tiling" and hasattr(self.pipeline, 'enable_vae_tiling'):
            self.pipeline.enable_vae_tiling()
            self.diffusion_config.enable_vae_tiling = True
            logger.info("Enabled VAE tiling")
        
        elif optimization_type.startswith("attention_slicing") and hasattr(self.pipeline, 'enable_attention_slicing'):
            slice_size = optimization_type.split(":")[-1] if ":" in optimization_type else "auto"
            self.pipeline.enable_attention_slicing(slice_size)
            self.diffusion_config.enable_attention_slicing = slice_size
            logger.info(f"Enabled attention slicing: {slice_size}")
        
        else:
            logger.warning(f"Unknown or unsupported optimization: {optimization_type}")
    
    def disable_optimization(self, optimization_type: str):
        """Disable specific optimization."""
        if optimization_type == "xformers" and hasattr(self.pipeline, 'disable_xformers_memory_efficient_attention'):
            self.pipeline.disable_xformers_memory_efficient_attention()
            self.diffusion_config.use_xformers = False
            logger.info("Disabled XFormers memory efficient attention")
        
        elif optimization_type == "vae_slicing" and hasattr(self.pipeline, 'disable_vae_slicing'):
            self.pipeline.disable_vae_slicing()
            self.diffusion_config.enable_vae_slicing = False
            logger.info("Disabled VAE slicing")
        
        elif optimization_type == "vae_tiling" and hasattr(self.pipeline, 'disable_vae_tiling'):
            self.pipeline.disable_vae_tiling()
            self.diffusion_config.enable_vae_tiling = False
            logger.info("Disabled VAE tiling")
        
        elif optimization_type == "attention_slicing" and hasattr(self.pipeline, 'disable_attention_slicing'):
            self.pipeline.disable_attention_slicing()
            self.diffusion_config.enable_attention_slicing = None
            logger.info("Disabled attention slicing")
        
        else:
            logger.warning(f"Unknown or unsupported optimization: {optimization_type}")

# =============================================================================
# Ultra-Optimized Dataset and DataLoader
# =============================================================================

class UltraOptimizedDataset(Dataset):
    """Ultra-optimized dataset with pre-tokenization."""
    
    def __init__(self, texts: List[str], labels: List[int], tokenizer: PreTrainedTokenizer, max_length: int = 512):
        self.texts = texts
        self.labels = labels
        self.tokenizer = tokenizer
        self.max_length = max_length
        
        # Pre-tokenize for performance
        self.encodings = self.tokenizer(
            texts,
            truncation=True,
            padding=True,
            max_length=max_length,
            return_tensors="pt"
        )
    
    def __len__(self):
        return len(self.texts)
    
    def __getitem__(self, idx):
        item = {key: val[idx] for key, val in self.encodings.items()}
        item["labels"] = torch.tensor(self.labels[idx])
        return item

