# Advanced Data Loading System
# =============================================================================

class AdvancedDataLoaderConfig:
    """Advanced configuration for efficient data loading."""
    
    def __init__(
        self,
        batch_size: int = 32,
        num_workers: int = 4,
        pin_memory: bool = True,
        prefetch_factor: int = 2,
        persistent_workers: bool = True,
        drop_last: bool = False,
        timeout: int = 0,
        worker_init_fn: Optional[Callable] = None,
        multiprocessing_context: Optional[str] = None,
        generator: Optional[torch.Generator] = None,
        shuffle: bool = True,
        sampler: Optional[Sampler] = None,
        batch_sampler: Optional[BatchSampler] = None,
        collate_fn: Optional[Callable] = None,
        memory_format: str = "channels_last",
        enable_memory_pinning: bool = True,
        enable_prefetching: bool = True,
        enable_async_loading: bool = True,
        cache_size: int = 1000,
        compression: bool = False
    ):
        self.batch_size = batch_size
        self.num_workers = num_workers
        self.pin_memory = pin_memory
        self.prefetch_factor = prefetch_factor
        self.persistent_workers = persistent_workers
        self.drop_last = drop_last
        self.timeout = timeout
        self.worker_init_fn = worker_init_fn
        self.multiprocessing_context = multiprocessing_context
        self.generator = generator
        self.shuffle = shuffle
        self.sampler = sampler
        self.batch_sampler = batch_sampler
        self.collate_fn = collate_fn
        self.memory_format = memory_format
        self.enable_memory_pinning = enable_memory_pinning
        self.enable_prefetching = enable_prefetching
        self.enable_async_loading = enable_async_loading
        self.cache_size = cache_size
        self.compression = compression

class MemoryEfficientCollateFn:
    """Memory-efficient collate function with smart batching."""
    
    def __init__(self, max_length: int = 512, pad_token_id: int = 0):
        self.max_length = max_length
        self.pad_token_id = pad_token_id
    
    def __call__(self, batch: List[Dict[str, Any]]) -> Dict[str, torch.Tensor]:
        """Collate batch with memory optimization."""
        # Separate different types of data
        input_ids = [item['input_ids'] for item in batch]
        attention_masks = [item['attention_mask'] for item in batch]
        labels = [item['labels'] for item in batch]
        
        # Find max length in this batch (dynamic padding)
        max_len = min(max(len(ids) for ids in input_ids), self.max_length)
        
        # Pad sequences efficiently
        padded_input_ids = []
        padded_attention_masks = []
        
        for ids, mask in zip(input_ids, attention_masks):
            if len(ids) > max_len:
                # Truncate
                padded_input_ids.append(ids[:max_len])
                padded_attention_masks.append(mask[:max_len])
            else:
                # Pad
                padding_length = max_len - len(ids)
                padded_input_ids.append(torch.cat([ids, torch.full((padding_length,), self.pad_token_id, dtype=ids.dtype)]))
                padded_attention_masks.append(torch.cat([mask, torch.zeros(padding_length, dtype=mask.dtype)]))
        
        return {
            'input_ids': torch.stack(padded_input_ids),
            'attention_mask': torch.stack(padded_attention_masks),
            'labels': torch.stack(labels)
        }

class BalancedSampler(Sampler):
    """Balanced sampler for imbalanced datasets."""
    
    def __init__(self, labels: List[int], replacement: bool = True, num_samples: Optional[int] = None):
        self.labels = labels
        self.replacement = replacement
        self.num_samples = num_samples
        
        # Calculate class weights
        unique_labels, counts = torch.unique(torch.tensor(labels), return_counts=True)
        class_weights = 1.0 / counts.float()
        self.weights = class_weights[labels]
    
    def __iter__(self):
        return iter(torch.multinomial(self.weights, self.num_samples or len(self.weights), self.replacement).tolist())
    
    def __len__(self):
        return self.num_samples or len(self.weights)

class AdaptiveBatchSampler(BatchSampler):
    """Adaptive batch sampler that adjusts batch sizes based on sequence lengths."""
    
    def __init__(self, sampler: Sampler, max_tokens: int = 4096, max_batch_size: int = 32):
        self.sampler = sampler
        self.max_tokens = max_tokens
        self.max_batch_size = max_batch_size
        self.batches = self._create_batches()
    
    def _create_batches(self) -> List[List[int]]:
        """Create batches with adaptive sizing."""
        batches = []
        current_batch = []
        current_tokens = 0
        
        for idx in self.sampler:
            # Estimate tokens (assuming average length)
            estimated_tokens = 128  # Conservative estimate
            
            if current_tokens + estimated_tokens > self.max_tokens or len(current_batch) >= self.max_batch_size:
                if current_batch:
                    batches.append(current_batch)
                current_batch = [idx]
                current_tokens = estimated_tokens
            else:
                current_batch.append(idx)
                current_tokens += estimated_tokens
        
        if current_batch:
            batches.append(current_batch)
        
        return batches
    
    def __iter__(self):
        return iter(self.batches)
    
    def __len__(self):
        return len(self.batches)

class CachedDataset(Dataset):
    """Dataset with intelligent caching for memory efficiency."""
    
    def __init__(self, base_dataset: Dataset, cache_size: int = 1000, memory_threshold: float = 0.8):
        self.base_dataset = base_dataset
        self.cache_size = cache_size
        self.memory_threshold = memory_threshold
        self.cache = {}
        self.access_count = {}
    
    def __getitem__(self, idx):
        if idx in self.cache:
            self.access_count[idx] += 1
            return self.cache[idx]
        
        # Load item from base dataset
        item = self.base_dataset[idx]
        
        # Cache if we have space
        if len(self.cache) < self.cache_size:
            self.cache[idx] = item
            self.access_count[idx] = 1
        else:
            # Evict least recently used item
            self._evict_lru()
            self.cache[idx] = item
            self.access_count[idx] = 1
        
        return item
    
    def _evict_lru(self):
        """Evict least recently used item from cache."""
        if not self.cache:
            return
        
        # Find item with lowest access count
        lru_idx = min(self.access_count.keys(), key=lambda k: self.access_count[k])
        del self.cache[lru_idx]
        del self.access_count[lru_idx]
    
    def __len__(self):
        return len(self.base_dataset)

class AdvancedDataLoader:
    """Advanced DataLoader with comprehensive optimizations."""
    
    def __init__(
        self,
        dataset: Dataset,
        config: AdvancedDataLoaderConfig,
        device: torch.device = None
    ):
        self.dataset = dataset
        self.config = config
        self.device = device or torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        
        # Create optimized DataLoader
        self.dataloader = self._create_optimized_dataloader()
        
        # Performance monitoring
        self.load_times = []
        self.memory_usage = []
        self.batch_sizes = []
        
        # Initialize performance monitoring
        self._init_performance_monitoring()
    
    def _create_optimized_dataloader(self) -> DataLoader:
        """Create highly optimized DataLoader."""
        # Determine optimal number of workers
        optimal_workers = self._get_optimal_workers()
        
        # Create sampler if not provided
        sampler = self.config.sampler
        if sampler is None and not self.config.shuffle:
            sampler = SequentialSampler(self.dataset)
        elif sampler is None and self.config.shuffle:
            sampler = RandomSampler(self.dataset, generator=self.config.generator)
        
        # Create batch sampler if needed
        batch_sampler = self.config.batch_sampler
        if batch_sampler is None and self.config.enable_async_loading:
            batch_sampler = AdaptiveBatchSampler(sampler, max_tokens=4096, max_batch_size=self.config.batch_size)
        
        # Create collate function
        collate_fn = self.config.collate_fn
        if collate_fn is None:
            collate_fn = MemoryEfficientCollateFn()
        
        # Create DataLoader with optimizations
        return DataLoader(
            dataset=self.dataset,
            batch_size=None if batch_sampler else self.config.batch_size,
            sampler=None if batch_sampler else sampler,
            batch_sampler=batch_sampler,
            num_workers=optimal_workers,
            collate_fn=collate_fn,
            pin_memory=self.config.pin_memory and self.device.type == 'cuda',
            persistent_workers=self.config.persistent_workers and optimal_workers > 0,
            prefetch_factor=self.config.prefetch_factor if optimal_workers > 0 else 2,
            drop_last=self.config.drop_last,
            timeout=self.config.timeout,
            worker_init_fn=self.config.worker_init_fn,
            multiprocessing_context=self.config.multiprocessing_context,
            generator=self.config.generator
        )
    
    def _get_optimal_workers(self) -> int:
        """Calculate optimal number of workers."""
        cpu_count = mp.cpu_count()
        
        if self.device.type == 'cuda':
            # For GPU training, limit workers to avoid memory issues
            optimal = min(self.config.num_workers, cpu_count // 2, 8)
        else:
            # For CPU training, use more workers
            optimal = min(self.config.num_workers, cpu_count - 1)
        
        return max(1, optimal)
    
    def _init_performance_monitoring(self):
        """Initialize performance monitoring."""
        self.start_time = time.time()
        self.batch_count = 0
    
    def get_performance_stats(self) -> Dict[str, Any]:
        """Get performance statistics."""
        if not self.load_times:
            return {}
        
        return {
            'avg_load_time': np.mean(self.load_times),
            'total_batches': self.batch_count,
            'total_time': time.time() - self.start_time,
            'batches_per_second': self.batch_count / (time.time() - self.start_time),
            'avg_memory_usage': np.mean(self.memory_usage) if self.memory_usage else 0,
            'avg_batch_size': np.mean(self.batch_sizes) if self.batch_sizes else 0
        }
    
    def __iter__(self):
        """Iterate over dataloader with performance monitoring."""
        for batch in self.dataloader:
            start_time = time.time()
            
            # Monitor memory usage
            if torch.cuda.is_available():
                memory_used = torch.cuda.memory_allocated() / 1024**3  # GB
                self.memory_usage.append(memory_used)
            
            # Record batch size
            if hasattr(batch, 'shape'):
                self.batch_sizes.append(batch.shape[0])
            elif isinstance(batch, dict) and 'input_ids' in batch:
                self.batch_sizes.append(batch['input_ids'].shape[0])
            else:
                self.batch_sizes.append(len(batch))
            
            # Record load time
            load_time = time.time() - start_time
            self.load_times.append(load_time)
            self.batch_count += 1
            
            yield batch
    
    def __len__(self):
        return len(self.dataloader)

def create_advanced_dataloader(
    dataset: Dataset,
    config: AdvancedDataLoaderConfig,
    device: torch.device = None
) -> AdvancedDataLoader:
    """Create advanced DataLoader with comprehensive optimizations."""
    return AdvancedDataLoader(dataset, config, device)

def create_balanced_dataloader(
    dataset: Dataset,
    labels: List[int],
    config: AdvancedDataLoaderConfig,
    device: torch.device = None
) -> AdvancedDataLoader:
    """Create DataLoader with balanced sampling for imbalanced datasets."""
    balanced_sampler = BalancedSampler(labels)
    config.sampler = balanced_sampler
    return AdvancedDataLoader(dataset, config, device)

def create_cached_dataloader(
    base_dataset: Dataset,
    config: AdvancedDataLoaderConfig,
    cache_size: int = 1000,
    device: torch.device = None
) -> AdvancedDataLoader:
    """Create DataLoader with intelligent caching."""
    cached_dataset = CachedDataset(base_dataset, cache_size)
    return AdvancedDataLoader(cached_dataset, config, device)

