# Data Loading Utilities
# =============================================================================

def optimize_dataloader_performance(
    dataloader: DataLoader,
    target_device: torch.device,
    memory_limit_gb: float = 8.0
) -> DataLoader:
    """Optimize existing DataLoader for better performance."""
    # Check current memory usage
    if target_device.type == 'cuda':
        current_memory = torch.cuda.memory_allocated() / 1024**3
        if current_memory > memory_limit_gb:
            # Reduce batch size or workers
            if hasattr(dataloader, 'batch_size') and dataloader.batch_size > 1:
                dataloader.batch_size = max(1, dataloader.batch_size // 2)
                logger.warning(f"Reduced batch size to {dataloader.batch_size} due to memory constraints")
    
    return dataloader

def create_distributed_dataloader(
    dataset: Dataset,
    config: AdvancedDataLoaderConfig,
    world_size: int,
    rank: int,
    device: torch.device = None
) -> AdvancedDataLoader:
    """Create DataLoader for distributed training."""
    # Create distributed sampler
    distributed_sampler = DistributedSampler(
        dataset,
        num_replicas=world_size,
        rank=rank,
        shuffle=config.shuffle
    )
    
    # Update config
    config.sampler = distributed_sampler
    config.shuffle = False  # Sampler handles shuffling
    
    return AdvancedDataLoader(dataset, config, device)

def benchmark_dataloader_performance(
    dataloader: Union[DataLoader, AdvancedDataLoader],
    num_batches: int = 100
) -> Dict[str, float]:
    """Benchmark DataLoader performance."""
    start_time = time.time()
    batch_count = 0
    total_samples = 0
    
    try:
        for batch in dataloader:
            if batch_count >= num_batches:
                break
            
            # Count samples in batch
            if hasattr(batch, 'shape'):
                total_samples += batch.shape[0]
            elif isinstance(batch, dict) and 'input_ids' in batch:
                total_samples += batch['input_ids'].shape[0]
            else:
                total_samples += len(batch)
            
            batch_count += 1
    except Exception as e:
        logger.warning(f"Benchmark stopped early: {e}")
    
    total_time = time.time() - start_time
    
    return {
        'total_time': total_time,
        'batches_processed': batch_count,
        'samples_processed': total_samples,
        'batches_per_second': batch_count / total_time,
        'samples_per_second': total_samples / total_time,
        'avg_time_per_batch': total_time / batch_count if batch_count > 0 else 0
    }

def create_ultra_optimized_dataloader(
    dataset: Dataset,
    config: UltraTrainingConfig,
    shuffle: bool = True
) -> DataLoader:
    """Create ultra-optimized DataLoader."""
    return DataLoader(
        dataset,
        batch_size=config.batch_size,
        shuffle=shuffle,
        num_workers=config.dataloader_num_workers,
        pin_memory=config.dataloader_pin_memory,
        prefetch_factor=config.dataloader_prefetch_factor,
        persistent_workers=True if config.dataloader_num_workers > 0 else False
    )

