@dataclass
class DataSplitConfig:
    """Configuration for comprehensive data splitting and cross-validation."""
    
    # Split ratios
    train_ratio: float = 0.7
    val_ratio: float = 0.15
    test_ratio: float = 0.15
    
    # Cross-validation configuration
    use_cross_validation: bool = False
    cv_folds: int = 5
    cv_strategy: str = "stratified"  # "kfold", "stratified", "group", "time_series", "shuffle", "repeated"
    cv_repeats: int = 1
    
    # Stratification configuration
    stratify: bool = True
    stratify_labels: Optional[List] = None
    
    # Group-based splitting (for avoiding data leakage)
    group_split: bool = False
    group_labels: Optional[List] = None
    
    # Time series configuration
    time_series_split: bool = False
    time_column: Optional[str] = None
    gap: int = 0  # Gap between train and test in time series
    
    # Random state and shuffling
    random_state: int = 42
    shuffle: bool = True
    
    # Validation
    min_samples_per_split: int = 1
    ensure_minimum_samples: bool = True
    
    def __post_init__(self):
        """Validate configuration."""
        total_ratio = self.train_ratio + self.val_ratio + self.test_ratio
        if abs(total_ratio - 1.0) > 1e-6:
            raise ValueError(f"Split ratios must sum to 1.0, got {total_ratio}")
        
        if self.cv_folds < 2:
            raise ValueError(f"CV folds must be >= 2, got {self.cv_folds}")
        
        if self.cv_repeats < 1:
            raise ValueError(f"CV repeats must be >= 1, got {self.cv_repeats}")
        
        if any(ratio <= 0 for ratio in [self.train_ratio, self.val_ratio, self.test_ratio]):
            raise ValueError("All split ratios must be positive")

@dataclass
class DataSplit:
    """Container for data splits."""
    train_indices: List[int]
    val_indices: List[int]
    test_indices: List[int]
    
    # Metadata
    total_samples: int
    train_samples: int
    val_samples: int
    test_samples: int
    split_info: Dict[str, Any] = field(default_factory=dict)
    
    def get_datasets(self, base_dataset: Dataset) -> Tuple[Dataset, Dataset, Dataset]:
        """Create dataset splits from indices."""
        train_dataset = Subset(base_dataset, self.train_indices)
        val_dataset = Subset(base_dataset, self.val_indices)
        test_dataset = Subset(base_dataset, self.test_indices)
        return train_dataset, val_dataset, test_dataset
    
    def get_dataloaders(
        self, 
        base_dataset: Dataset, 
        config: AdvancedDataLoaderConfig
    ) -> Tuple[AdvancedDataLoader, AdvancedDataLoader, AdvancedDataLoader]:
        """Create DataLoader splits."""
        train_dataset, val_dataset, test_dataset = self.get_datasets(base_dataset)
        
        # Create configs for each split
        train_config = AdvancedDataLoaderConfig(**vars(config))
        train_config.shuffle = True
        
        val_config = AdvancedDataLoaderConfig(**vars(config))
        val_config.shuffle = False
        
        test_config = AdvancedDataLoaderConfig(**vars(config))
        test_config.shuffle = False
        
        train_loader = AdvancedDataLoader(train_dataset, train_config)
        val_loader = AdvancedDataLoader(val_dataset, val_config)
        test_loader = AdvancedDataLoader(test_dataset, test_config)
        
        return train_loader, val_loader, test_loader

@dataclass
class CrossValidationFold:
    """Container for a single cross-validation fold."""
    fold_index: int
    train_indices: List[int]
    val_indices: List[int]
    
    # Metadata
    train_samples: int
    val_samples: int
    fold_info: Dict[str, Any] = field(default_factory=dict)
    
    def get_datasets(self, base_dataset: Dataset) -> Tuple[Dataset, Dataset]:
        """Create train/val datasets for this fold."""
        train_dataset = Subset(base_dataset, self.train_indices)
        val_dataset = Subset(base_dataset, self.val_indices)
        return train_dataset, val_dataset
    
    def get_dataloaders(
        self, 
        base_dataset: Dataset, 
        config: AdvancedDataLoaderConfig
    ) -> Tuple[AdvancedDataLoader, AdvancedDataLoader]:
        """Create DataLoaders for this fold."""
        train_dataset, val_dataset = self.get_datasets(base_dataset)
        
        train_config = AdvancedDataLoaderConfig(**vars(config))
        train_config.shuffle = True
        
        val_config = AdvancedDataLoaderConfig(**vars(config))
        val_config.shuffle = False
        
        train_loader = AdvancedDataLoader(train_dataset, train_config)
        val_loader = AdvancedDataLoader(val_dataset, val_config)
        
        return train_loader, val_loader

@dataclass
class CrossValidationSplit:
    """Container for complete cross-validation splits."""
    folds: List[CrossValidationFold]
    cv_strategy: str
    total_samples: int
    cv_info: Dict[str, Any] = field(default_factory=dict)
    
    def __len__(self) -> int:
        return len(self.folds)
    
    def __iter__(self):
        return iter(self.folds)
    
    def get_fold_datasets(self, fold_index: int, base_dataset: Dataset) -> Tuple[Dataset, Dataset]:
        """Get datasets for a specific fold."""
        if fold_index >= len(self.folds):
            raise IndexError(f"Fold {fold_index} not found. Available folds: 0-{len(self.folds)-1}")
        return self.folds[fold_index].get_datasets(base_dataset)
    
    def get_fold_dataloaders(
        self, 
        fold_index: int, 
        base_dataset: Dataset, 
        config: AdvancedDataLoaderConfig
    ) -> Tuple[AdvancedDataLoader, AdvancedDataLoader]:
        """Get DataLoaders for a specific fold."""
        if fold_index >= len(self.folds):
            raise IndexError(f"Fold {fold_index} not found. Available folds: 0-{len(self.folds)-1}")
        return self.folds[fold_index].get_dataloaders(base_dataset, config)

class ComprehensiveDataSplitter:
    """Comprehensive data splitting and cross-validation system."""
    
    def __init__(self, config: DataSplitConfig):
        self.config = config
        self.split_results = {}
        
    def split_dataset(
        self, 
        dataset: Dataset, 
        labels: Optional[List] = None,
        groups: Optional[List] = None
    ) -> DataSplit:
        """Split dataset into train/validation/test sets."""
        dataset_size = len(dataset)
        indices = list(range(dataset_size))
        
        logger.info(f"Splitting dataset of size {dataset_size} with ratios: "
                   f"train={self.config.train_ratio}, val={self.config.val_ratio}, test={self.config.test_ratio}")
        
        if self.config.time_series_split:
            return self._time_series_split(indices, dataset_size)
        elif self.config.group_split and groups is not None:
            return self._group_based_split(indices, groups, labels)
        else:
            return self._standard_split(indices, labels)
    
    def _standard_split(self, indices: List[int], labels: Optional[List] = None) -> DataSplit:
        """Standard train/validation/test split."""
        total_size = len(indices)
        
        # Calculate split sizes
        train_size = int(self.config.train_ratio * total_size)
        val_size = int(self.config.val_ratio * total_size)
        test_size = total_size - train_size - val_size
        
        if self.config.stratify and labels is not None:
            # Stratified split
            # First split: train vs (val + test)
            train_indices, temp_indices, train_labels, temp_labels = train_test_split(
                indices, labels,
                train_size=train_size,
                stratify=labels,
                random_state=self.config.random_state,
                shuffle=self.config.shuffle
            )
            
            # Second split: val vs test
            val_size_adjusted = val_size / (val_size + test_size)
            val_indices, test_indices = train_test_split(
                temp_indices,
                test_size=1 - val_size_adjusted,
                stratify=temp_labels,
                random_state=self.config.random_state,
                shuffle=self.config.shuffle
            )
        else:
            # Random split
            if self.config.shuffle:
                np.random.seed(self.config.random_state)
                np.random.shuffle(indices)
            
            train_indices = indices[:train_size]
            val_indices = indices[train_size:train_size + val_size]
            test_indices = indices[train_size + val_size:]
        
        # Validate minimum samples
        if self.config.ensure_minimum_samples:
            for split_name, split_indices in [("train", train_indices), ("val", val_indices), ("test", test_indices)]:
                if len(split_indices) < self.config.min_samples_per_split:
                    logger.warning(f"{split_name} split has {len(split_indices)} samples, "
                                 f"which is less than minimum {self.config.min_samples_per_split}")
        
        split_info = {
            'strategy': 'stratified' if self.config.stratify and labels is not None else 'random',
            'shuffle': self.config.shuffle,
            'random_state': self.config.random_state
        }
        
        return DataSplit(
            train_indices=train_indices,
            val_indices=val_indices,
            test_indices=test_indices,
            total_samples=total_size,
            train_samples=len(train_indices),
            val_samples=len(val_indices),
            test_samples=len(test_indices),
            split_info=split_info
        )
    
    def _time_series_split(self, indices: List[int], total_size: int) -> DataSplit:
        """Time series split preserving temporal order."""
        # Calculate split points
        train_end = int(self.config.train_ratio * total_size)
        val_end = train_end + int(self.config.val_ratio * total_size)
        
        # Add gap if specified
        gap = self.config.gap
        
        train_indices = indices[:train_end]
        val_indices = indices[train_end + gap:val_end + gap]
        test_indices = indices[val_end + gap:]
        
        split_info = {
            'strategy': 'time_series',
            'gap': gap,
            'preserve_order': True
        }
        
        return DataSplit(
            train_indices=train_indices,
            val_indices=val_indices,
            test_indices=test_indices,
            total_samples=total_size,
            train_samples=len(train_indices),
            val_samples=len(val_indices),
            test_samples=len(test_indices),
            split_info=split_info
        )
    
    def _group_based_split(
        self, 
        indices: List[int], 
        groups: List, 
        labels: Optional[List] = None
    ) -> DataSplit:
        """Group-based split to prevent data leakage."""
        unique_groups = list(set(groups))
        np.random.seed(self.config.random_state)
        if self.config.shuffle:
            np.random.shuffle(unique_groups)
        
        n_groups = len(unique_groups)
        train_groups_end = int(self.config.train_ratio * n_groups)
        val_groups_end = train_groups_end + int(self.config.val_ratio * n_groups)
        
        train_groups = set(unique_groups[:train_groups_end])
        val_groups = set(unique_groups[train_groups_end:val_groups_end])
        test_groups = set(unique_groups[val_groups_end:])
        
        train_indices = [i for i in indices if groups[i] in train_groups]
        val_indices = [i for i in indices if groups[i] in val_groups]
        test_indices = [i for i in indices if groups[i] in test_groups]
        
        split_info = {
            'strategy': 'group_based',
            'n_groups': n_groups,
            'train_groups': len(train_groups),
            'val_groups': len(val_groups),
            'test_groups': len(test_groups)
        }
        
        return DataSplit(
            train_indices=train_indices,
            val_indices=val_indices,
            test_indices=test_indices,
            total_samples=len(indices),
            train_samples=len(train_indices),
            val_samples=len(val_indices),
            test_samples=len(test_indices),
            split_info=split_info
        )
    
    def create_cross_validation_splits(
        self, 
        dataset: Dataset, 
        labels: Optional[List] = None,
        groups: Optional[List] = None
    ) -> CrossValidationSplit:
        """Create cross-validation splits."""
        dataset_size = len(dataset)
        indices = list(range(dataset_size))
        
        logger.info(f"Creating {self.config.cv_folds}-fold cross-validation "
                   f"with strategy '{self.config.cv_strategy}' for dataset of size {dataset_size}")
        
        # Select appropriate cross-validation strategy
        if self.config.cv_strategy == "kfold":
            cv_splitter = KFold(
                n_splits=self.config.cv_folds,
                shuffle=self.config.shuffle,
                random_state=self.config.random_state
            )
            splits = cv_splitter.split(indices)
            
        elif self.config.cv_strategy == "stratified":
            if labels is None:
                logger.warning("Stratified CV requested but no labels provided. Using KFold instead.")
                return self.create_cross_validation_splits(dataset, labels, groups)
            
            cv_splitter = StratifiedKFold(
                n_splits=self.config.cv_folds,
                shuffle=self.config.shuffle,
                random_state=self.config.random_state
            )
            splits = cv_splitter.split(indices, labels)
            
        elif self.config.cv_strategy == "group":
            if groups is None:
                logger.warning("Group CV requested but no groups provided. Using KFold instead.")
                return self.create_cross_validation_splits(dataset, labels, groups)
            
            cv_splitter = GroupKFold(n_splits=self.config.cv_folds)
            splits = cv_splitter.split(indices, labels, groups)
            
        elif self.config.cv_strategy == "time_series":
            cv_splitter = TimeSeriesSplit(
                n_splits=self.config.cv_folds,
                gap=self.config.gap
            )
            splits = cv_splitter.split(indices)
            
        elif self.config.cv_strategy == "shuffle":
            cv_splitter = ShuffleSplit(
                n_splits=self.config.cv_folds,
                test_size=1.0 / self.config.cv_folds,
                random_state=self.config.random_state
            )
            splits = cv_splitter.split(indices)
            
        elif self.config.cv_strategy == "repeated":
            base_cv = StratifiedKFold if labels is not None else KFold
            cv_splitter = RepeatedStratifiedKFold(
                n_splits=self.config.cv_folds,
                n_repeats=self.config.cv_repeats,
                random_state=self.config.random_state
            ) if labels is not None else RepeatedKFold(
                n_splits=self.config.cv_folds,
                n_repeats=self.config.cv_repeats,
                random_state=self.config.random_state
            )
            splits = cv_splitter.split(indices, labels)
            
        else:
            raise ValueError(f"Unknown CV strategy: {self.config.cv_strategy}")
        
        # Create fold objects
        folds = []
        for fold_idx, (train_indices, val_indices) in enumerate(splits):
            fold_info = {
                'fold_index': fold_idx,
                'cv_strategy': self.config.cv_strategy,
                'total_folds': self.config.cv_folds
            }
            
            fold = CrossValidationFold(
                fold_index=fold_idx,
                train_indices=train_indices.tolist(),
                val_indices=val_indices.tolist(),
                train_samples=len(train_indices),
                val_samples=len(val_indices),
                fold_info=fold_info
            )
            folds.append(fold)
        
        cv_info = {
            'strategy': self.config.cv_strategy,
            'n_folds': len(folds),
            'total_samples': dataset_size,
            'average_train_samples': np.mean([fold.train_samples for fold in folds]),
            'average_val_samples': np.mean([fold.val_samples for fold in folds])
        }
        
        return CrossValidationSplit(
            folds=folds,
            cv_strategy=self.config.cv_strategy,
            total_samples=dataset_size,
            cv_info=cv_info
        )

class StratifiedDataSplitter:
    """Specialized data splitter for imbalanced datasets with stratification."""
    
    def __init__(self, min_samples_per_class: int = 2):
        self.min_samples_per_class = min_samples_per_class
    
    def stratified_split(
        self, 
        dataset: Dataset, 
        labels: List, 
        config: DataSplitConfig
    ) -> DataSplit:
        """Create stratified splits ensuring class balance."""
        # Analyze class distribution
        unique_labels, counts = np.unique(labels, return_counts=True)
        class_counts = dict(zip(unique_labels, counts))
        
        logger.info(f"Class distribution: {class_counts}")
        
        # Check if stratification is possible
        min_count = min(counts)
        if min_count < self.min_samples_per_class:
            logger.warning(f"Some classes have fewer than {self.min_samples_per_class} samples. "
                          f"Stratification may not be optimal.")
        
        # Use ComprehensiveDataSplitter with stratification enabled
        config.stratify = True
        splitter = ComprehensiveDataSplitter(config)
        return splitter.split_dataset(dataset, labels)
    
    def balanced_cross_validation(
        self, 
        dataset: Dataset, 
        labels: List, 
        config: DataSplitConfig
    ) -> CrossValidationSplit:
        """Create balanced cross-validation folds."""
        config.cv_strategy = "stratified"
        splitter = ComprehensiveDataSplitter(config)
        return splitter.create_cross_validation_splits(dataset, labels)

# Factory functions for easy usage
def create_train_val_test_split(
    dataset: Dataset,
    labels: Optional[List] = None,
    groups: Optional[List] = None,
    train_ratio: float = 0.7,
    val_ratio: float = 0.15,
    test_ratio: float = 0.15,
    stratify: bool = True,
    random_state: int = 42
) -> DataSplit:
    """Create train/validation/test split with sensible defaults."""
    config = DataSplitConfig(
        train_ratio=train_ratio,
        val_ratio=val_ratio,
        test_ratio=test_ratio,
        stratify=stratify,
        random_state=random_state
    )
    
    splitter = ComprehensiveDataSplitter(config)
    return splitter.split_dataset(dataset, labels, groups)

def create_cross_validation_split(
    dataset: Dataset,
    labels: Optional[List] = None,
    groups: Optional[List] = None,
    cv_folds: int = 5,
    cv_strategy: str = "stratified",
    random_state: int = 42
) -> CrossValidationSplit:
    """Create cross-validation split with sensible defaults."""
    config = DataSplitConfig(
        use_cross_validation=True,
        cv_folds=cv_folds,
        cv_strategy=cv_strategy,
        random_state=random_state
    )
    
    splitter = ComprehensiveDataSplitter(config)
    return splitter.create_cross_validation_splits(dataset, labels, groups)

def create_time_series_split(
    dataset: Dataset,
    train_ratio: float = 0.7,
    val_ratio: float = 0.15,
    test_ratio: float = 0.15,
    gap: int = 0
) -> DataSplit:
    """Create time series split preserving temporal order."""
    config = DataSplitConfig(
        train_ratio=train_ratio,
        val_ratio=val_ratio,
        test_ratio=test_ratio,
        time_series_split=True,
        gap=gap,
        shuffle=False
    )
    
    splitter = ComprehensiveDataSplitter(config)
    return splitter.split_dataset(dataset)

# =============================================================================
# Ultra-Optimized Trainer
# =============================================================================

class UltraOptimizedTrainer:
    """Ultra-optimized trainer with PyTorch best practices."""
    
    def __init__(self, model: nn.Module, config: UltraTrainingConfig):
        self.model = model
        self.config = config
        self.device = get_optimal_device(config)
        
        # Initialize comprehensive error handling
        self.error_handler = DeepLearningErrorHandler(
            enable_debug_mode=getattr(config, 'enable_debug_mode', False)
        )
        
        # Move model to device with error handling
        try:
            self.model = self.model.to(self.device)
            logger.info(f"Model moved to device: {self.device}")
        except Exception as e:
            error_info = self.error_handler.handle_error(e, "model_device_move")
            logger.error(f"Failed to move model to device: {error_info['message']}")
            raise
        
        # Multi-GPU setup with PyTorch best practices
        if config.num_gpus > 1:
            self._setup_multi_gpu()
        
        # Initialize optimizer and scheduler with PyTorch best practices
        self.optimizer = self._create_optimizer()
        self.scheduler = self._create_scheduler()
        
        # Initialize mixed precision
        self.scaler = GradScaler() if config.use_mixed_precision else None
        
        # Initialize logging
        self.writer = SummaryWriter(config.log_dir)
        
        # Initialize wandb
        if wandb.run is None:
            wandb.init(project="ultra-optimized-dl", config=vars(config))
        
        # Initialize performance monitoring
        self._init_performance_monitoring()
        
        # Initialize comprehensive performance optimization
        self.performance_manager = ComprehensivePerformanceManager()
        
        # Apply performance optimizations to the model
        self._apply_performance_optimizations()
        
        logger.info("Ultra-optimized trainer initialized", 
                   device=str(self.device), 
                   num_gpus=config.num_gpus,
                   mixed_precision=config.use_mixed_precision)
    
    def _setup_multi_gpu(self):
        """Setup multi-GPU training with PyTorch best practices."""
        if self.config.num_gpus > 1:
            # Use DataParallel for single-node multi-GPU
            self.model = DataParallel(self.model)
            logger.info(f"DataParallel initialized with {self.config.num_gpus} GPUs")
            
            # Set device for DataParallel
            self.model = self.model.to(self.device)
    
    def _create_optimizer(self):
        """Create optimizer with PyTorch best practices."""
        # Use AdamW with proper parameter grouping
        no_decay = ["bias", "LayerNorm.weight"]
        optimizer_grouped_parameters = [
            {
                "params": [p for n, p in self.model.named_parameters() 
                          if not any(nd in n for nd in no_decay)],
                "weight_decay": self.config.weight_decay,
            },
            {
                "params": [p for n, p in self.model.named_parameters() 
                          if any(nd in n for nd in no_decay)],
                "weight_decay": 0.0,
            },
        ]
        
        optimizer = torch.optim.AdamW(
            optimizer_grouped_parameters,
            lr=self.config.learning_rate,
            weight_decay=self.config.weight_decay,
            eps=1e-8,  # Better numerical stability
            betas=(0.9, 0.999)
        )
        
        return optimizer
    
    def _apply_performance_optimizations(self):
        """Apply comprehensive performance optimizations to the model and training pipeline."""
        try:
            logger.info("Applying comprehensive performance optimizations...")
            
            # Apply model-level optimizations
            self.model = self.performance_manager.performance_optimizer.optimize_model(self.model)
            
            # Apply attention optimizations
            self.model = self.performance_manager.performance_optimizer.optimize_attention(self.model)
            
            # Apply memory optimizations
            self.performance_manager.memory_manager.optimize_memory()
            
            # Setup advanced training optimizations
            if self.config.use_mixed_precision:
                self.scaler = self.performance_manager.training_optimizer.setup_mixed_precision(
                    self.model, self.optimizer
                )
            
            # Setup gradient accumulation
            if hasattr(self.config, 'gradient_accumulation_steps'):
                accumulation_steps = self.performance_manager.training_optimizer.setup_gradient_accumulation(
                    self.config.gradient_accumulation_steps
                )
                self.gradient_accumulation_steps = accumulation_steps
            else:
                self.gradient_accumulation_steps = 1
            
            # Setup dynamic batching if configured
            if hasattr(self.config, 'enable_dynamic_batching') and self.config.enable_dynamic_batching:
                batching_config = self.performance_manager.training_optimizer.setup_dynamic_batching(
                    self.config.batch_size, self.config.max_batch_size
                )
                self.dynamic_batching_config = batching_config
            
            logger.info("Performance optimizations applied successfully")
            
        except Exception as e:
            logger.warning(f"Performance optimization failed: {e}")
            # Continue without optimizations
    
    def _create_scheduler(self):
        """Create learning rate scheduler with PyTorch best practices."""
        if self.config.lr_scheduler_type == "cosine":
            return get_cosine_schedule_with_warmup(
                self.optimizer,
                num_warmup_steps=self.config.warmup_steps,
                num_training_steps=self.config.num_epochs * 1000  # Estimate
            )
        else:
            return get_linear_schedule_with_warmup(
                self.optimizer,
                num_warmup_steps=self.config.warmup_steps,
                num_training_steps=self.config.num_epochs * 1000  # Estimate
            )
    
    def _init_performance_monitoring(self):
        """Initialize performance monitoring."""
        self.training_history = {
            'loss': [],
            'learning_rate': [],
            'memory_usage': [],
            'gpu_utilization': []
        }
    
    def train_epoch(self, dataloader: DataLoader, epoch: int):
        """Train for one epoch with PyTorch optimizations and comprehensive error handling."""
        self.model.train()
        total_loss = 0
        num_batches = len(dataloader)
        failed_batches = 0
        
        progress_bar = tqdm(dataloader, desc=f"Epoch {epoch}")
        
        # Memory tracking context
        with memory_tracking_context():
            for batch_idx, batch in enumerate(progress_bar):
                try:
                    # Use error handler for safe execution
                    success, result, error_info = self.error_handler.safe_execute(
                        f"training_step_{epoch}_{batch_idx}",
                        self._execute_training_step,
                        batch, batch_idx, epoch
                    )
                    
                    if success:
                        loss = result
                        total_loss += loss * self.config.gradient_accumulation_steps
                        
                        # Update progress bar with memory info
                        memory_info = self._get_memory_info()
                        progress_bar.set_postfix({
                            "loss": f"{loss:.4f}",
                            "memory": f"{memory_info['gpu_memory_gb']:.1f}GB",
                            "errors": failed_batches
                        })
                        
                        # Logging with performance metrics
                        if batch_idx % self.config.logging_steps == 0:
                            self._log_training_step(batch_idx, loss, epoch, memory_info)
                        
                        # Memory cleanup if needed
                        if batch_idx % 100 == 0:
                            self._cleanup_memory()
                    else:
                        failed_batches += 1
                        logger.warning(f"Training step {batch_idx} failed: {error_info['message']}")
                        
                        # Update progress bar to show errors
                        progress_bar.set_postfix({
                            "loss": "ERROR",
                            "memory": "N/A",
                            "errors": failed_batches
                        })
                        
                        # Continue training instead of stopping
                        continue
                
                except Exception as e:
                    failed_batches += 1
                    error_info = self.error_handler.handle_error(e, f"training_step_{epoch}_{batch_idx}")
                    logger.error(f"Training step {batch_idx} failed: {error_info['message']}")
                    
                    # Update progress bar
                    progress_bar.set_postfix({
                        "loss": "ERROR",
                        "memory": "N/A",
                        "errors": failed_batches
                    })
                    
                    # Continue training instead of stopping
                    continue
        
        avg_loss = total_loss / max(1, num_batches - failed_batches)
        success_rate = (num_batches - failed_batches) / num_batches * 100
        
        logger.info("Epoch completed", 
                   epoch=epoch, 
                   avg_loss=avg_loss, 
                   success_rate=f"{success_rate:.1f}%",
                   failed_batches=failed_batches)
        
        return avg_loss
    
    def _execute_training_step(self, batch, batch_idx: int, epoch: int):
        """Execute a single training step with error handling."""
        try:
            # Move batch to device with proper memory management
            batch = {k: v.to(self.device, non_blocking=True) for k, v in batch.items()}
            
            # Forward pass with mixed precision and profiling
            with torch_profiler_context(self.config):
                with autocast() if self.config.use_mixed_precision else nullcontext():
                    outputs = self.model(**batch)
                    loss = outputs["loss"]
                    loss = loss / self.config.gradient_accumulation_steps
            
            # Backward pass with PyTorch best practices
            if self.config.use_mixed_precision:
                self.scaler.scale(loss).backward()
            else:
                loss.backward()
            
            # Gradient accumulation with proper handling
            if (batch_idx + 1) % self.config.gradient_accumulation_steps == 0:
                # Gradient clipping with PyTorch best practices
                if self.config.use_gradient_clipping:
                    if self.config.use_mixed_precision:
                        self.scaler.unscale_(self.optimizer)
                    torch.nn.utils.clip_grad_norm_(
                        self.model.parameters(), 
                        self.config.max_grad_norm
                    )
                
                # Optimizer step with proper error handling
                if self.config.use_mixed_precision:
                    self.scaler.step(self.optimizer)
                    self.scaler.update()
                else:
                    self.optimizer.step()
                
                # Scheduler step
                self.scheduler.step()
                
                # Zero gradients with PyTorch best practices
                self.optimizer.zero_grad(set_to_none=True)
            
            return loss.item()
            
        except Exception as e:
            # Re-raise for error handler to catch
            raise e
    
    def _get_memory_info(self) -> Dict[str, float]:
        """Get current memory usage information."""
        memory_info = {
            'gpu_memory_gb': 0.0,
            'gpu_memory_percent': 0.0,
            'cpu_memory_gb': 0.0
        }
        
        if torch.cuda.is_available():
            memory_info['gpu_memory_gb'] = torch.cuda.memory_allocated() / 1024**3
            memory_info['gpu_memory_percent'] = (
                torch.cuda.memory_allocated() / torch.cuda.max_memory_allocated()
            ) * 100
        
        return memory_info
    
    def _cleanup_memory(self):
        """Clean up memory with PyTorch best practices."""
        if torch.cuda.is_available():
            # Clear cache if memory usage is high
            if torch.cuda.memory_allocated() / torch.cuda.max_memory_allocated() > 0.8:
                torch.cuda.empty_cache()
                logger.debug("GPU cache cleared due to high memory usage")
    
    def _log_training_step(self, batch_idx: int, loss: float, epoch: int, memory_info: Dict[str, float]):
        """Log training step metrics with PyTorch performance data."""
        step = epoch * 1000 + batch_idx  # Estimate total steps
        
        # TensorBoard logging
        self.writer.add_scalar("Loss/train", loss, step)
        self.writer.add_scalar("Learning_rate", self.optimizer.param_groups[0]["lr"], step)
        self.writer.add_scalar("Memory/GPU_GB", memory_info['gpu_memory_gb'], step)
        
        # Wandb logging
        wandb.log({
            "train_loss": loss,
            "learning_rate": self.optimizer.param_groups[0]["lr"],
            "epoch": epoch,
            "step": step,
            "gpu_memory_gb": memory_info['gpu_memory_gb'],
            "gpu_memory_percent": memory_info['gpu_memory_percent']
        })
        
        # Update training history
        self.training_history['loss'].append(loss)
        self.training_history['learning_rate'].append(self.optimizer.param_groups[0]["lr"])
        self.training_history['memory_usage'].append(memory_info['gpu_memory_gb'])
    
    def get_error_statistics(self) -> Dict[str, Any]:
        """Get comprehensive error statistics from the error handler."""
        return self.error_handler.get_error_summary()
    
    def enable_debug_mode(self):
        """Enable PyTorch debug mode."""
        self.error_handler.enable_debug_mode()
        logger.info("Debug mode enabled for trainer")
    
    def disable_debug_mode(self):
        """Disable PyTorch debug mode."""
        self.error_handler.disable_debug_mode()
        logger.info("Debug mode disabled for trainer")
    
    def clear_error_logs(self):
        """Clear error logs."""
        self.error_handler.clear_error_log()
        logger.info("Error logs cleared")
    
    def evaluate(self, dataloader: DataLoader) -> Dict[str, float]:
        """Evaluate model with PyTorch optimizations and comprehensive error handling."""
        self.model.eval()
        total_loss = 0
        correct_predictions = 0
        total_predictions = 0
        failed_batches = 0
        
        # Use no_grad context for evaluation
        with torch.no_grad():
            for batch_idx, batch in enumerate(tqdm(dataloader, desc="Evaluating")):
                try:
                    # Use error handler for safe execution
                    success, result, error_info = self.error_handler.safe_execute(
                        f"evaluation_step_{batch_idx}",
                        self._execute_evaluation_step,
                        batch
                    )
                    
                    if success:
                        loss, correct, total = result
                        total_loss += loss
                        correct_predictions += correct
                        total_predictions += total
                    else:
                        failed_batches += 1
                        logger.warning(f"Evaluation step {batch_idx} failed: {error_info['message']}")
                        continue
                    
                except Exception as e:
                    failed_batches += 1
                    error_info = self.error_handler.handle_error(e, f"evaluation_step_{batch_idx}")
                    logger.error(f"Evaluation step {batch_idx} failed: {error_info['message']}")
                    continue
        
        # Calculate metrics with error handling
        num_batches = len(dataloader)
        successful_batches = num_batches - failed_batches
        
        if successful_batches > 0:
            avg_loss = total_loss / successful_batches
            accuracy = correct_predictions / total_predictions if total_predictions > 0 else 0.0
        else:
            avg_loss = float('inf')
            accuracy = 0.0
        
        success_rate = successful_batches / num_batches * 100
        
        metrics = {
            "eval_loss": avg_loss, 
            "eval_accuracy": accuracy,
            "success_rate": success_rate,
            "failed_batches": failed_batches,
            "total_batches": num_batches
        }
        
        logger.info("Evaluation completed", **metrics)
        return metrics
    
    def _execute_evaluation_step(self, batch):
        """Execute a single evaluation step with error handling."""
        try:
            # Move batch to device with non_blocking for efficiency
            batch = {k: v.to(self.device, non_blocking=True) for k, v in batch.items()}
            
            with autocast() if self.config.use_mixed_precision else nullcontext():
                outputs = self.model(**batch)
                loss = outputs["loss"]
                logits = outputs["logits"]
            
            # Calculate accuracy with proper tensor operations
            predictions = torch.argmax(logits, dim=-1)
            correct = (predictions == batch["labels"]).sum().item()
            total = batch["labels"].size(0)
            
            return loss.item(), correct, total
            
        except Exception as e:
            # Re-raise for error handler to catch
            raise e
    
    def save_checkpoint(self, path: str, epoch: int, metrics: Dict[str, float]):
        """Save model checkpoint with PyTorch best practices and error handling."""
        checkpoint = {
            'epoch': epoch,
            'model_state_dict': self.model.state_dict(),
            'optimizer_state_dict': self.optimizer.state_dict(),
            'scheduler_state_dict': self.scheduler.state_dict(),
            'scaler_state_dict': self.scaler.state_dict() if self.scaler else None,
            'config': self.config,
            'metrics': metrics,
            'training_history': self.training_history,
            'error_statistics': self.get_error_statistics()  # Include error stats
        }
        
        # Save with comprehensive error handling
        try:
            # Create directory if it doesn't exist
            os.makedirs(os.path.dirname(path), exist_ok=True)
            
            # Use error handler for safe execution
            success, result, error_info = self.error_handler.safe_execute(
                "save_checkpoint",
                torch.save,
                checkpoint, path
            )
            
            if success:
                logger.info(f"Checkpoint saved to {path}")
                return True
            else:
                logger.error(f"Failed to save checkpoint: {error_info['message']}")
                return False
                
        except Exception as e:
            error_info = self.error_handler.handle_error(e, "save_checkpoint")
            logger.error(f"Failed to save checkpoint: {error_info['message']}")
            return False
    
    def load_checkpoint(self, path: str):
        """Load model checkpoint with PyTorch best practices and error handling."""
        try:
            # Check if file exists
            if not os.path.exists(path):
                raise FileNotFoundError(f"Checkpoint file not found: {path}")
            
            # Use error handler for safe execution
            success, checkpoint, error_info = self.error_handler.safe_execute(
                "load_checkpoint",
                torch.load,
                path, map_location=self.device
            )
            
            if not success:
                logger.error(f"Failed to load checkpoint: {error_info['message']}")
                return None, {}
            
            # Load model state with error handling
            try:
                self.model.load_state_dict(checkpoint['model_state_dict'])
                self.optimizer.load_state_dict(checkpoint['optimizer_state_dict'])
                self.scheduler.load_state_dict(checkpoint['scheduler_state_dict'])
                
                if self.scaler and checkpoint.get('scaler_state_dict'):
                    self.scaler.load_state_dict(checkpoint['scaler_state_dict'])
                
                # Restore error statistics if available
                if 'error_statistics' in checkpoint:
                    logger.info("Restored error statistics from checkpoint")
                
                logger.info(f"Checkpoint loaded from {path}")
                return checkpoint['epoch'], checkpoint.get('metrics', {})
                
            except Exception as e:
                error_info = self.error_handler.handle_error(e, "load_checkpoint_state")
                logger.error(f"Failed to load checkpoint state: {error_info['message']}")
                raise
            
        except Exception as e:
            error_info = self.error_handler.handle_error(e, "load_checkpoint")
            logger.error(f"Failed to load checkpoint: {error_info['message']}")
            raise

