class AdvancedTrainingMetrics:
    """Advanced training metrics and evaluation tools."""
    
    def __init__(self):
        self.metrics_history = {
            'train_loss': [],
            'val_loss': [],
            'train_acc': [],
            'val_acc': [],
            'learning_rate': [],
            'gradient_norm': [],
            'parameter_norm': [],
            'memory_usage': [],
            'gpu_utilization': [],
            'training_time': [],
            'validation_time': []
        }
    
    def update_metrics(self, metrics: Dict[str, float]):
        """Update metrics history."""
        for key, value in metrics.items():
            if key in self.metrics_history:
                self.metrics_history[key].append(value)
    
    def get_best_metrics(self) -> Dict[str, float]:
        """Get best metrics achieved during training."""
        best_metrics = {}
        for key, values in self.metrics_history.items():
            if values:
                if 'loss' in key:
                    best_metrics[key] = min(values)
                elif 'acc' in key:
                    best_metrics[key] = max(values)
                else:
                    best_metrics[key] = values[-1]  # Latest value
        return best_metrics
    
    def plot_metrics(self, save_path: Optional[str] = None):
        """Plot training metrics."""
        try:
            import matplotlib.pyplot as plt
            
            fig, axes = plt.subplots(2, 3, figsize=(15, 10))
            fig.suptitle('Training Metrics Overview', fontsize=16)
            
            # Loss plots
            axes[0, 0].plot(self.metrics_history['train_loss'], label='Train Loss')
            axes[0, 0].plot(self.metrics_history['val_loss'], label='Val Loss')
            axes[0, 0].set_title('Loss')
            axes[0, 0].legend()
            axes[0, 0].grid(True)
            
            # Accuracy plots
            axes[0, 1].plot(self.metrics_history['train_acc'], label='Train Acc')
            axes[0, 1].plot(self.metrics_history['val_acc'], label='Val Acc')
            axes[0, 1].set_title('Accuracy')
            axes[0, 1].legend()
            axes[0, 1].grid(True)
            
            # Learning rate
            axes[0, 2].plot(self.metrics_history['learning_rate'])
            axes[0, 2].set_title('Learning Rate')
            axes[0, 2].grid(True)
            
            # Gradient norm
            axes[1, 0].plot(self.metrics_history['gradient_norm'])
            axes[1, 0].set_title('Gradient Norm')
            axes[1, 0].grid(True)
            
            # Memory usage
            axes[1, 1].plot(self.metrics_history['memory_usage'])
            axes[1, 1].set_title('GPU Memory (GB)')
            axes[1, 1].grid(True)
            
            # Training time
            axes[1, 2].plot(self.metrics_history['training_time'])
            axes[1, 2].set_title('Training Time (s)')
            axes[1, 2].grid(True)
            
            plt.tight_layout()
            
            if save_path:
                plt.savefig(save_path, dpi=300, bbox_inches='tight')
                logger.info(f"Metrics plot saved to {save_path}")
            else:
                plt.show()
                
        except ImportError:
            logger.warning("matplotlib not available for plotting")
        except Exception as e:
            logger.error(f"Failed to plot metrics: {e}")


class ModelValidator:
    """Comprehensive model validation and testing."""
    
    def __init__(self, model: nn.Module, device: torch.device):
        self.model = model
        self.device = device
        self.validation_results = {}
    
    def validate_model_architecture(self) -> Dict[str, Any]:
        """Validate model architecture and parameters."""
        try:
            total_params = sum(p.numel() for p in self.model.parameters())
            trainable_params = sum(p.numel() for p in self.model.parameters() if p.requires_grad)
            
            # Check for NaN or Inf parameters
            has_nan = any(torch.isnan(p).any() for p in self.model.parameters())
            has_inf = any(torch.isinf(p).any() for p in self.model.parameters())
            
            # Check parameter gradients
            grad_norms = []
            for name, param in self.model.named_parameters():
                if param.grad is not None:
                    grad_norms.append((name, param.grad.norm().item()))
            
            architecture_info = {
                'total_parameters': total_params,
                'trainable_parameters': trainable_params,
                'non_trainable_parameters': total_params - trainable_params,
                'has_nan_parameters': has_nan,
                'has_inf_parameters': has_inf,
                'gradient_norms': grad_norms,
                'model_size_mb': total_params * 4 / (1024 * 1024),  # Assuming float32
                'device': str(self.device)
            }
            
            self.validation_results['architecture'] = architecture_info
            logger.info("Model architecture validation completed", **architecture_info)
            return architecture_info
            
        except Exception as e:
            logger.error(f"Architecture validation failed: {e}")
            return {}
    
    def validate_training_ready(self, dataloader: DataLoader) -> Dict[str, Any]:
        """Validate that model is ready for training."""
        try:
            self.model.train()
            
            # Test forward pass
            batch = next(iter(dataloader))
            batch = {k: v.to(self.device) if torch.is_tensor(v) else v for k, v in batch.items()}
            
            with torch.no_grad():
                outputs = self.model(**batch)
                loss = outputs.get('loss', torch.tensor(0.0))
                
                # Check output shapes
                output_shapes = {}
                for key, value in outputs.items():
                    if torch.is_tensor(value):
                        output_shapes[key] = list(value.shape)
            
            # Test backward pass
            loss.backward()
            
            # Check gradients
            grad_stats = {}
            for name, param in self.model.named_parameters():
                if param.grad is not None:
                    grad_stats[name] = {
                        'grad_norm': param.grad.norm().item(),
                        'grad_mean': param.grad.mean().item(),
                        'grad_std': param.grad.std().item()
                    }
            
            training_ready = {
                'forward_pass_successful': True,
                'backward_pass_successful': True,
                'output_shapes': output_shapes,
                'loss_value': loss.item(),
                'gradient_statistics': grad_stats,
                'memory_allocated': torch.cuda.memory_allocated() / 1024**3 if torch.cuda.is_available() else 0
            }
            
            self.validation_results['training_ready'] = training_ready
            logger.info("Training readiness validation completed", **training_ready)
            return training_ready
            
        except Exception as e:
            logger.error(f"Training readiness validation failed: {e}")
            return {'error': str(e)}
    
    def validate_inference(self, test_inputs: List[Any]) -> Dict[str, Any]:
        """Validate model inference capabilities."""
        try:
            self.model.eval()
            
            inference_results = []
            inference_times = []
            
            with torch.no_grad():
                for i, test_input in enumerate(test_inputs):
                    start_time = time.time()
                    
                    if isinstance(test_input, str):
                        # Text input
                        result = self._inference_text(test_input)
                    elif isinstance(test_input, torch.Tensor):
                        # Tensor input
                        result = self._inference_tensor(test_input)
                    else:
                        result = {'error': f'Unsupported input type: {type(test_input)}'}
                    
                    inference_time = time.time() - start_time
                    inference_times.append(inference_time)
                    
                    inference_results.append({
                        'input_id': i,
                        'input_type': type(test_input).__name__,
                        'result': result,
                        'inference_time': inference_time
                    })
            
            inference_validation = {
                'total_inputs': len(test_inputs),
                'successful_inferences': len([r for r in inference_results if 'error' not in r['result']]),
                'average_inference_time': np.mean(inference_times),
                'max_inference_time': np.max(inference_times),
                'min_inference_time': np.min(inference_times),
                'detailed_results': inference_results
            }
            
            self.validation_results['inference'] = inference_validation
            logger.info("Inference validation completed", **inference_validation)
            return inference_validation
            
        except Exception as e:
            logger.error(f"Inference validation failed: {e}")
            return {'error': str(e)}
    
    def _inference_text(self, text: str) -> Dict[str, Any]:
        """Handle text inference."""
        try:
            # Mock text processing for validation
            return {
                'processed_text': text,
                'length': len(text),
                'status': 'success'
            }
        except Exception as e:
            return {'error': str(e)}
    
    def _inference_tensor(self, tensor: torch.Tensor) -> Dict[str, Any]:
        """Handle tensor inference."""
        try:
            return {
                'tensor_shape': list(tensor.shape),
                'tensor_dtype': str(tensor.dtype),
                'tensor_device': str(tensor.device),
                'status': 'success'
            }
        except Exception as e:
            return {'error': str(e)}
    
    def get_performance_optimization_report(self) -> Dict[str, Any]:
        """Get comprehensive performance optimization report."""
        try:
            return self.performance_manager.get_optimization_report()
        except Exception as e:
            logger.error(f"Failed to get performance optimization report: {e}")
            return {"error": str(e)}
    
    def benchmark_model_performance(self, dataloader: DataLoader, num_iterations: int = 100) -> Dict[str, Any]:
        """Benchmark model performance with comprehensive metrics."""
        try:
            return self.performance_manager.benchmark_performance(self.model, dataloader, num_iterations)
        except Exception as e:
            logger.error(f"Performance benchmarking failed: {e}")
            return {"error": str(e)}
    
    def apply_inference_optimizations(self) -> nn.Module:
        """Apply optimizations specifically for inference."""
        try:
            self.model = self.performance_manager.apply_inference_optimizations(self.model)
            logger.info("Inference optimizations applied successfully")
            return self.model
        except Exception as e:
            logger.error(f"Inference optimization failed: {e}")
            return self.model
    
    def optimize_data_pipeline(self, dataset: Dataset, **kwargs) -> DataLoader:
        """Optimize data pipeline for better performance."""
        try:
            optimization_result = self.performance_manager.optimize_training_pipeline(
                self.model, dataset, **kwargs
            )
            return optimization_result["optimized_dataloader"]
        except Exception as e:
            logger.error(f"Data pipeline optimization failed: {e}")
            # Return fallback dataloader
            return DataLoader(dataset, **kwargs)
    
    def reset_performance_optimizations(self):
        """Reset all performance optimizations to baseline."""
        try:
            self.performance_manager.reset_optimizations()
            logger.info("Performance optimizations reset successfully")
        except Exception as e:
            logger.error(f"Failed to reset performance optimizations: {e}")


class AdvancedModelTrainer(UltraOptimizedTrainer):
    """Advanced model trainer with comprehensive training and evaluation."""
    
    def __init__(self, model: nn.Module, config: UltraTrainingConfig):
        super().__init__(model, config)
        
        # Initialize advanced components
        self.metrics_tracker = AdvancedTrainingMetrics()
        self.model_validator = ModelValidator(model, self.device)
        
        # Initialize error handler
        self.error_handler = DeepLearningErrorHandler(
            enable_debugging=getattr(config, 'enable_debugging', False)
        )
        
        # Training state
        self.current_epoch = 0
        self.best_metrics = {}
        self.early_stopping_counter = 0
        self.early_stopping_patience = getattr(config, 'early_stopping_patience', 5)
        
        # Validation dataloader
        self.val_dataloader = None
        
        # Robust components
        self.robust_dataloader = None
        self.robust_inference = None
        
        logger.info("Advanced model trainer initialized with error handling")
    
    def set_validation_dataloader(self, val_dataloader: DataLoader):
        """Set validation dataloader."""
        self.val_dataloader = val_dataloader
        logger.info("Validation dataloader set")
    
    def validate_model(self) -> Dict[str, Any]:
        """Comprehensive model validation."""
        logger.info("Starting comprehensive model validation")
        
        # Architecture validation
        arch_validation = self.model_validator.validate_model_architecture()
        
        # Training readiness validation
        if self.val_dataloader:
            training_validation = self.model_validator.validate_training_ready(self.val_dataloader)
        else:
            training_validation = {'error': 'No validation dataloader available'}
        
        # Inference validation
        test_inputs = [
            "Sample text for validation",
            torch.randn(1, 10, 512).to(self.device)
        ]
        inference_validation = self.model_validator.validate_inference(test_inputs)
        
        validation_summary = {
            'architecture': arch_validation,
            'training_ready': training_validation,
            'inference': inference_validation,
            'validation_timestamp': time.time()
        }
        
        logger.info("Model validation completed", validation_summary=validation_summary)
        return validation_summary
    
    def train_with_validation(self, 
                            train_dataloader: DataLoader, 
                            num_epochs: int,
                            save_dir: str = "./checkpoints") -> Dict[str, Any]:
        """Train model with comprehensive validation and monitoring."""
        logger.info(f"Starting training with validation for {num_epochs} epochs")
        
        # Create save directory
        os.makedirs(save_dir, exist_ok=True)
        
        # Initial model validation
        initial_validation = self.validate_model()
        
        # Training loop with validation
        for epoch in range(num_epochs):
            self.current_epoch = epoch
            epoch_start_time = time.time()
            
            logger.info(f"Starting epoch {epoch + 1}/{num_epochs}")
            
            # Training phase
            train_metrics = self._train_epoch_advanced(train_dataloader, epoch)
            
            # Validation phase
            if self.val_dataloader:
                val_metrics = self._validate_epoch_advanced(epoch)
            else:
                val_metrics = {'val_loss': float('inf'), 'val_accuracy': 0.0}
            
            # Update metrics tracker
            combined_metrics = {**train_metrics, **val_metrics}
            self.metrics_tracker.update_metrics(combined_metrics)
            
            # Check for best model
            if self._is_best_model(val_metrics):
                self._save_best_model(save_dir, epoch, val_metrics)
                self.best_metrics = val_metrics
                self.early_stopping_counter = 0
            else:
                self.early_stopping_counter += 1
            
            # Early stopping check
            if self.early_stopping_counter >= self.early_stopping_patience:
                logger.info(f"Early stopping triggered after {epoch + 1} epochs")
                break
            
            # Regular checkpoint
            if (epoch + 1) % self.config.checkpoint_frequency == 0:
                self.save_checkpoint(
                    os.path.join(save_dir, f"checkpoint_epoch_{epoch + 1}.pt"),
                    epoch + 1,
                    combined_metrics
                )
            
            epoch_time = time.time() - epoch_start_time
            logger.info(f"Epoch {epoch + 1} completed", 
                       epoch_time=epoch_time,
                       train_loss=train_metrics.get('train_loss', 0),
                       val_loss=val_metrics.get('val_loss', 0))
        
        # Final validation and summary
        final_validation = self.validate_model()
        training_summary = self._generate_training_summary()
        
        # Save final model and metrics
        self._save_final_model(save_dir, training_summary)
        
        # Generate plots
        self.metrics_tracker.plot_metrics(os.path.join(save_dir, 'training_metrics.png'))
        
        logger.info("Training completed successfully", training_summary=training_summary)
        return training_summary
    
    def _train_epoch_advanced(self, dataloader: DataLoader, epoch: int) -> Dict[str, float]:
        """Advanced training for one epoch with detailed metrics."""
        self.model.train()
        total_loss = 0
        num_batches = len(dataloader)
        
        progress_bar = tqdm(dataloader, desc=f"Training Epoch {epoch + 1}")
        
        # Performance monitoring
        epoch_start_time = time.time()
        memory_usage = []
        gradient_norms = []
        
        for batch_idx, batch in enumerate(progress_bar):
            try:
                # Move batch to device
                batch = {k: v.to(self.device, non_blocking=True) for k, v in batch.items()}
                
                # Forward pass
                with torch_profiler_context(self.config):
                    with autocast() if self.config.use_mixed_precision else nullcontext():
                        outputs = self.model(**batch)
                        loss = outputs["loss"]
                        loss = loss / self.config.gradient_accumulation_steps
                
                # Backward pass
                if self.config.use_mixed_precision:
                    self.scaler.scale(loss).backward()
                else:
                    loss.backward()
                
                # Gradient accumulation
                if (batch_idx + 1) % self.config.gradient_accumulation_steps == 0:
                    # Gradient clipping
                    if self.config.use_gradient_clipping:
                        if self.config.use_mixed_precision:
                            self.scaler.unscale_(self.optimizer)
                        torch.nn.utils.clip_grad_norm_(
                            self.model.parameters(), 
                            self.config.max_grad_norm
                        )
                    
                    # Compute gradient norm
                    total_norm = torch.nn.utils.clip_grad_norm_(
                        self.model.parameters(), float('inf')
                    )
                    gradient_norms.append(total_norm.item())
                    
                    # Optimizer step
                    if self.config.use_mixed_precision:
                        self.scaler.step(self.optimizer)
                        self.scaler.update()
                    else:
                        self.optimizer.step()
                    
                    # Scheduler step
                    self.scheduler.step()
                    
                    # Zero gradients
                    self.optimizer.zero_grad(set_to_none=True)
                
                total_loss += loss.item() * self.config.gradient_accumulation_steps
                
                # Memory tracking
                if torch.cuda.is_available():
                    memory_usage.append(torch.cuda.memory_allocated() / 1024**3)
                
                # Update progress bar
                progress_bar.set_postfix({
                    "loss": f"{loss.item():.4f}",
                    "lr": f"{self.optimizer.param_groups[0]['lr']:.6f}",
                    "memory": f"{memory_usage[-1] if memory_usage else 0:.1f}GB"
                })
                
            except Exception as e:
                error_info = self.error_handler.handle_error(
                    e, "training", "batch_processing",
                    batch_index=batch_idx,
                    epoch=epoch
                )
                
                logger.error("Training step failed", 
                            error_info=error_info, 
                            batch_idx=batch_idx, 
                            epoch=epoch)
                
                # Try to recover or skip batch
                if self._should_skip_batch(error_info):
                    logger.warning(f"Skipping problematic batch {batch_idx}")
                    continue
                else:
                    # Critical error - log and continue
                    logger.error(f"Critical error in batch {batch_idx}, continuing with next batch")
                    continue
        
        epoch_time = time.time() - epoch_start_time
        avg_loss = total_loss / num_batches
        avg_gradient_norm = np.mean(gradient_norms) if gradient_norms else 0
        avg_memory = np.mean(memory_usage) if memory_usage else 0
        
        train_metrics = {
            'train_loss': avg_loss,
            'train_accuracy': 0.0,  # Would need to compute based on task
            'learning_rate': self.optimizer.param_groups[0]['lr'],
            'gradient_norm': avg_gradient_norm,
            'memory_usage': avg_memory,
            'training_time': epoch_time
        }
        
        return train_metrics
    
    def _should_skip_batch(self, error_info: Dict[str, Any]) -> bool:
        """Determine if batch should be skipped based on error."""
        # Skip for non-critical errors
        skip_errors = ['OSError', 'FileNotFoundError', 'PermissionError', 'ValueError']
        return error_info.get('error_type') in skip_errors
    
    def _validate_training_inputs(self, inputs, targets):
        """Validate training inputs with error handling."""
        try:
            if inputs is None or targets is None:
                raise ValueError("Inputs and targets cannot be None")
            
            # Check for NaN/Inf values
            if torch.is_tensor(inputs):
                if torch.isnan(inputs).any():
                    raise ValueError("Input contains NaN values")
                if torch.isinf(inputs).any():
                    raise ValueError("Input contains Inf values")
            
            if torch.is_tensor(targets):
                if torch.isnan(targets).any():
                    raise ValueError("Targets contain NaN values")
                if torch.isinf(targets).any():
                    raise ValueError("Targets contain Inf values")
                    
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "training", "input_validation"
            )
            logger.error(f"Input validation failed: {error_info}")
            raise
    
    def _safe_move_to_device(self, data, data_name: str):
        """Safely move data to device with error handling."""
        try:
            if torch.is_tensor(data):
                return data.to(self.device, non_blocking=True)
            elif isinstance(data, dict):
                return {k: self._safe_move_to_device(v, f"{data_name}.{k}") for k, v in data.items()}
            elif isinstance(data, (list, tuple)):
                return type(data)(self._safe_move_to_device(item, f"{data_name}[{i}]") 
                                for i, item in enumerate(data))
            else:
                return data
                
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "training", "device_transfer",
                data_name=data_name,
                data_type=str(type(data))
            )
            logger.error(f"Device transfer failed for {data_name}: {error_info}")
            raise
    
    def _safe_forward_pass(self, inputs):
        """Safely perform forward pass with error handling."""
        try:
            return self.model(**inputs)
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "training", "forward_pass",
                input_shape=str(inputs.shape) if hasattr(inputs, 'shape') else str(type(inputs))
            )
            logger.error(f"Forward pass failed: {error_info}")
            raise
    
    def _safe_loss_calculation(self, outputs, targets):
        """Safely calculate loss with error handling."""
        try:
            if isinstance(outputs, dict) and "loss" in outputs:
                return outputs["loss"]
            else:
                # Fallback to default loss calculation
                return self.criterion(outputs, targets)
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "training", "loss_calculation"
            )
            logger.error(f"Loss calculation failed: {error_info}")
            raise
    
    def _safe_backward_pass(self, loss):
        """Safely perform backward pass with error handling."""
        try:
            if self.config.use_mixed_precision:
                self.scaler.scale(loss).backward()
            else:
                loss.backward()
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "training", "backward_pass"
            )
            logger.error(f"Backward pass failed: {error_info}")
            raise
    
    def _validate_epoch_advanced(self, epoch: int) -> Dict[str, float]:
        """Advanced validation for one epoch."""
        if not self.val_dataloader:
            return {'val_loss': float('inf'), 'val_accuracy': 0.0}
        
        self.model.eval()
        total_loss = 0
        correct_predictions = 0
        total_predictions = 0
        
        validation_start_time = time.time()
        
        with torch.no_grad():
            for batch in tqdm(self.val_dataloader, desc=f"Validation Epoch {epoch + 1}"):
                try:
                    # Move batch to device
                    batch = {k: v.to(self.device, non_blocking=True) for k, v in batch.items()}
                    
                    # Forward pass
                    with autocast() if self.config.use_mixed_precision else nullcontext():
                        outputs = self.model(**batch)
                        loss = outputs["loss"]
                        logits = outputs["logits"]
                    
                    total_loss += loss.item()
                    
                    # Calculate accuracy
                    predictions = torch.argmax(logits, dim=-1)
                    correct_predictions += (predictions == batch["labels"]).sum().item()
                    total_predictions += batch["labels"].size(0)
                    
                except Exception as e:
                    error_info = self.error_handler.handle_error(
                        e, "validation", "batch_processing",
                        batch_index=getattr(self, '_val_batch_count', 0),
                        epoch=epoch
                    )
                    
                    logger.error("Validation step failed", 
                                error_info=error_info,
                                batch_index=getattr(self, '_val_batch_count', 0),
                                epoch=epoch)
                    
                    # Try to recover or skip batch
                    if self._should_skip_batch(error_info):
                        logger.warning(f"Skipping problematic validation batch")
                        continue
                    else:
                        # Critical error - log and continue
                        logger.error(f"Critical error in validation batch, continuing with next batch")
                        continue
        
        validation_time = time.time() - validation_start_time
        avg_loss = total_loss / len(self.val_dataloader)
        accuracy = correct_predictions / total_predictions if total_predictions > 0 else 0
        
        val_metrics = {
            'val_loss': avg_loss,
            'val_accuracy': accuracy,
            'validation_time': validation_time
        }
        
        return val_metrics
    
    def _is_best_model(self, val_metrics: Dict[str, float]) -> bool:
        """Check if current model is the best so far."""
        if not self.best_metrics:
            return True
        
        # Compare validation loss (lower is better)
        current_val_loss = val_metrics.get('val_loss', float('inf'))
        best_val_loss = self.best_metrics.get('val_loss', float('inf'))
        
        return current_val_loss < best_val_loss
    
    def _save_best_model(self, save_dir: str, epoch: int, metrics: Dict[str, float]):
        """Save the best model."""
        best_model_path = os.path.join(save_dir, 'best_model.pt')
        
        checkpoint = {
            'epoch': epoch,
            'model_state_dict': self.model.state_dict(),
            'optimizer_state_dict': self.optimizer.state_dict(),
            'scheduler_state_dict': self.scheduler.state_dict(),
            'scaler_state_dict': self.scaler.state_dict() if self.scaler else None,
            'config': self.config,
            'metrics': metrics,
            'best_metrics': self.best_metrics
        }
        
        try:
            torch.save(checkpoint, best_model_path)
            logger.info(f"Best model saved to {best_model_path}")
        except Exception as e:
            error_info = self.error_handler.handle_error(
                e, "model_saving", "best_model_save",
                save_path=best_model_path,
                epoch=epoch
            )
            logger.error(f"Failed to save best model: {error_info}")
    
    def _generate_training_summary(self) -> Dict[str, Any]:
        """Generate comprehensive training summary."""
        best_metrics = self.metrics_tracker.get_best_metrics()
        
        summary = {
            'total_epochs': self.current_epoch + 1,
            'best_metrics': best_metrics,
            'final_metrics': self.metrics_tracker.metrics_history,
            'training_config': vars(self.config),
            'model_parameters': sum(p.numel() for p in self.model.parameters()),
            'completion_timestamp': time.time()
        }
        
        return summary
    
    def _save_final_model(self, save_dir: str, training_summary: Dict[str, Any]):
        """Save final model and training summary."""
        # Save final model
        final_model_path = os.path.join(save_dir, 'final_model.pt')
        checkpoint = {
            'model_state_dict': self.model.state_dict(),
            'config': self.config,
            'training_summary': training_summary
        }
        
        try:
            torch.save(checkpoint, final_model_path)
            logger.info(f"Final model saved to {final_model_path}")
        except Exception as e:
            logger.error(f"Failed to save final model: {e}")
        
        # Save training summary as JSON
        summary_path = os.path.join(save_dir, 'training_summary.json')
        try:
            import json
            with open(summary_path, 'w') as f:
                json.dump(training_summary, f, indent=2, default=str)
            logger.info(f"Training summary saved to {summary_path}")
        except Exception as e:
            logger.error(f"Failed to save training summary: {e}")


class ModelEvaluator:
    """Comprehensive model evaluation and analysis."""
    
    def __init__(self, model: nn.Module, device: torch.device):
        self.model = model
        self.device = device
        self.evaluation_results = {}
    
    def evaluate_model_performance(self, 
                                 test_dataloader: DataLoader,
                                 metrics: List[str] = None) -> Dict[str, float]:
        """Evaluate model performance on test data."""
        if metrics is None:
            metrics = ['accuracy', 'precision', 'recall', 'f1', 'loss']
        
        logger.info(f"Starting model evaluation with metrics: {metrics}")
        
        self.model.eval()
        all_predictions = []
        all_labels = []
        total_loss = 0
        
        with torch.no_grad():
            for batch in tqdm(test_dataloader, desc="Evaluating"):
                try:
                    # Move batch to device
                    batch = {k: v.to(self.device, non_blocking=True) for k, v in batch.items()}
                    
                    # Forward pass
                    outputs = self.model(**batch)
                    loss = outputs["loss"]
                    logits = outputs["logits"]
                    
                    total_loss += loss.item()
                    
                    # Store predictions and labels
                    predictions = torch.argmax(logits, dim=-1)
                    all_predictions.extend(predictions.cpu().numpy())
                    all_labels.extend(batch["labels"].cpu().numpy())
                    
                except Exception as e:
                    logger.error("Evaluation step failed", error=str(e))
                    continue
        
        # Calculate metrics
        evaluation_metrics = self._calculate_metrics(
            all_predictions, all_labels, total_loss, len(test_dataloader), metrics
        )
        
        self.evaluation_results['performance'] = evaluation_metrics
        logger.info("Model performance evaluation completed", **evaluation_metrics)
        return evaluation_metrics
    
    def _calculate_metrics(self, 
                          predictions: List[int], 
                          labels: List[int], 
                          total_loss: float, 
                          num_batches: int,
                          metrics: List[str]) -> Dict[str, float]:
        """Calculate specified evaluation metrics."""
        results = {}
        
        if 'loss' in metrics:
            results['loss'] = total_loss / num_batches
        
        if 'accuracy' in metrics:
            correct = sum(1 for p, l in zip(predictions, labels) if p == l)
            results['accuracy'] = correct / len(predictions) if predictions else 0
        
        # For classification tasks, calculate precision, recall, F1
        if any(metric in metrics for metric in ['precision', 'recall', 'f1']):
            try:
                from sklearn.metrics import precision_recall_fscore_support
                precision, recall, f1, _ = precision_recall_fscore_support(
                    labels, predictions, average='weighted', zero_division=0
                )
                
                if 'precision' in metrics:
                    results['precision'] = precision
                if 'recall' in metrics:
                    results['recall'] = recall
                if 'f1' in metrics:
                    results['f1'] = f1
                    
            except ImportError:
                logger.warning("scikit-learn not available for precision/recall/F1 calculation")
        
        return results
    
    def analyze_model_complexity(self) -> Dict[str, Any]:
        """Analyze model complexity and efficiency."""
        try:
            total_params = sum(p.numel() for p in self.model.parameters())
            trainable_params = sum(p.numel() for p in self.model.parameters() if p.requires_grad)
            
            # Model size estimation
            param_size = 0
            buffer_size = 0
            
            for param in self.model.parameters():
                param_size += param.nelement() * param.element_size()
            
            for buffer in self.model.buffers():
                buffer_size += buffer.nelement() * buffer.element_size()
            
            size_mb = (param_size + buffer_size) / 1024**2
            
            # Layer analysis
            layer_info = {}
            for name, module in self.model.named_modules():
                if len(list(module.children())) == 0:  # Leaf module
                    layer_info[name] = {
                        'type': module.__class__.__name__,
                        'parameters': sum(p.numel() for p in module.parameters()),
                        'trainable': any(p.requires_grad for p in module.parameters())
                    }
            
            complexity_analysis = {
                'total_parameters': total_params,
                'trainable_parameters': trainable_params,
                'non_trainable_parameters': total_params - trainable_params,
                'model_size_mb': size_mb,
                'parameter_size_bytes': param_size,
                'buffer_size_bytes': buffer_size,
                'layer_breakdown': layer_info,
                'memory_efficiency': trainable_params / total_params if total_params > 0 else 0
            }
            
            self.evaluation_results['complexity'] = complexity_analysis
            logger.info("Model complexity analysis completed", **complexity_analysis)
            return complexity_analysis
            
        except Exception as e:
            logger.error(f"Complexity analysis failed: {e}")
            return {'error': str(e)}
    
    def benchmark_inference_speed(self, 
                                test_inputs: List[Any], 
                                num_runs: int = 100) -> Dict[str, Any]:
        """Benchmark model inference speed."""
        logger.info(f"Starting inference speed benchmark with {num_runs} runs")
        
        self.model.eval()
        inference_times = []
        memory_usage = []
        
        # Warmup runs
        for _ in range(10):
            with torch.no_grad():
                _ = self._run_inference(test_inputs[0])
        
        # Benchmark runs
        with torch.no_grad():
            for _ in tqdm(range(num_runs), desc="Benchmarking"):
                start_time = time.time()
                
                # Record memory before
                if torch.cuda.is_available():
                    torch.cuda.reset_peak_memory_stats()
                    memory_before = torch.cuda.memory_allocated()
                
                # Run inference
                _ = self._run_inference(test_inputs[0])
                
                # Record memory after
                if torch.cuda.is_available():
                    memory_after = torch.cuda.memory_allocated()
                    peak_memory = torch.cuda.max_memory_allocated()
                    memory_usage.append({
                        'allocated': memory_after / 1024**3,
                        'peak': peak_memory / 1024**3
                    })
                
                inference_time = time.time() - start_time
                inference_times.append(inference_time)
        
        # Calculate statistics
        avg_time = np.mean(inference_times)
        std_time = np.std(inference_times)
        min_time = np.min(inference_times)
        max_time = np.max(inference_times)
        
        # Throughput (inferences per second)
        throughput = 1.0 / avg_time if avg_time > 0 else 0
        
        benchmark_results = {
            'num_runs': num_runs,
            'average_inference_time_ms': avg_time * 1000,
            'std_inference_time_ms': std_time * 1000,
            'min_inference_time_ms': min_time * 1000,
            'max_inference_time_ms': max_time * 1000,
            'throughput_inferences_per_second': throughput,
            'memory_usage_gb': {
                'average_allocated': np.mean([m['allocated'] for m in memory_usage]) if memory_usage else 0,
                'average_peak': np.mean([m['peak'] for m in memory_usage]) if memory_usage else 0
            } if memory_usage else {}
        }
        
        self.evaluation_results['benchmark'] = benchmark_results
        logger.info("Inference speed benchmark completed", **benchmark_results)
        return benchmark_results
    
    def _run_inference(self, test_input: Any) -> Any:
        """Run single inference for benchmarking."""
        try:
            if isinstance(test_input, str):
                # Mock text processing
                return {'processed': test_input}
            elif isinstance(test_input, torch.Tensor):
                # Mock tensor processing
                return {'processed': test_input.shape}
            else:
                return {'processed': str(test_input)}
        except Exception as e:
            return {'error': str(e)}
    
    def generate_evaluation_report(self, save_path: Optional[str] = None) -> str:
        """Generate comprehensive evaluation report."""
        report_lines = []
        report_lines.append("=" * 80)
        report_lines.append("COMPREHENSIVE MODEL EVALUATION REPORT")
        report_lines.append("=" * 80)
        report_lines.append("")
        
        # Performance metrics
        if 'performance' in self.evaluation_results:
            report_lines.append("PERFORMANCE METRICS:")
            report_lines.append("-" * 40)
            for metric, value in self.evaluation_results['performance'].items():
                report_lines.append(f"{metric.upper()}: {value:.4f}")
            report_lines.append("")
        
        # Complexity analysis
        if 'complexity' in self.evaluation_results:
            complexity = self.evaluation_results['complexity']
            report_lines.append("MODEL COMPLEXITY:")
            report_lines.append("-" * 40)
            report_lines.append(f"Total Parameters: {complexity['total_parameters']:,}")
            report_lines.append(f"Trainable Parameters: {complexity['trainable_parameters']:,}")
            report_lines.append(f"Model Size: {complexity['model_size_mb']:.2f} MB")
            report_lines.append(f"Memory Efficiency: {complexity['memory_efficiency']:.2%}")
            report_lines.append("")
        
        # Benchmark results
        if 'benchmark' in self.evaluation_results:
            benchmark = self.evaluation_results['benchmark']
            report_lines.append("INFERENCE SPEED BENCHMARK:")
            report_lines.append("-" * 40)
            report_lines.append(f"Average Time: {benchmark['average_inference_time_ms']:.2f} ms")
            report_lines.append(f"Throughput: {benchmark['throughput_inferences_per_second']:.2f} inf/sec")
            report_lines.append(f"Memory Usage: {benchmark['memory_usage_gb']['average_allocated']:.2f} GB")
            report_lines.append("")
        
        # Summary
        report_lines.append("EVALUATION SUMMARY:")
        report_lines.append("-" * 40)
        report_lines.append(f"Total Evaluations: {len(self.evaluation_results)}")
        report_lines.append(f"Report Generated: {time.strftime('%Y-%m-%d %H:%M:%S')}")
        report_lines.append("=" * 80)
        
        report = "\n".join(report_lines)
        
        if save_path:
            try:
                with open(save_path, 'w') as f:
                    f.write(report)
                logger.info(f"Evaluation report saved to {save_path}")
            except Exception as e:
                logger.error(f"Failed to save evaluation report: {e}")
        
        return report


# =============================================================================
# Custom nn.Module Architectures
# =============================================================================

class CustomTransformerBlock(nn.Module):
    """Custom transformer block with configurable attention and feed-forward layers."""
    
    def __init__(self, d_model: int, n_heads: int, d_ff: int, dropout: float = 0.1):
        super().__init__()
        self.d_model = d_model
        self.n_heads = n_heads
        self.d_ff = d_ff
        
        # Multi-head self-attention
        self.attention = nn.MultiheadAttention(
            d_model, n_heads, dropout=dropout, batch_first=True
        )
        
        # Feed-forward network
        self.feed_forward = nn.Sequential(
            nn.Linear(d_model, d_ff),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(d_ff, d_model),
            nn.Dropout(dropout)
        )
        
        # Layer normalization
        self.norm1 = nn.LayerNorm(d_model)
        self.norm2 = nn.LayerNorm(d_model)
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
    
    def forward(self, x: torch.Tensor, mask: Optional[torch.Tensor] = None, 
                key_padding_mask: Optional[torch.Tensor] = None) -> torch.Tensor:
        """Forward pass with residual connections and layer normalization."""
        # Self-attention with residual connection
        # Use key_padding_mask if provided, otherwise use mask (for backward compatibility)
        if key_padding_mask is not None:
            attn_output, _ = self.attention(x, x, x, key_padding_mask=key_padding_mask)
        else:
            # Handle mask properly for PyTorch MultiheadAttention
            if mask is not None:
                # Ensure mask has correct shape [seq_len, seq_len]
                if mask.dim() == 2 and mask.shape[0] != mask.shape[1]:
                    # If mask is [batch_size, seq_len], convert to proper attention mask
                    seq_len = mask.shape[1]
                    attn_mask = torch.zeros(seq_len, seq_len, device=mask.device)
                    # Set causal mask (lower triangular)
                    attn_mask = torch.triu(attn_mask, diagonal=1)
                    attn_mask = attn_mask.masked_fill(attn_mask == 1, float('-inf'))
                else:
                    attn_mask = mask
            else:
                attn_mask = None
            
            attn_output, _ = self.attention(x, x, x, attn_mask=attn_mask)
        x = self.norm1(x + self.dropout(attn_output))
        
        # Feed-forward with residual connection
        ff_output = self.feed_forward(x)
        x = self.norm2(x + ff_output)
        
        return x


class CustomTransformerModel(nn.Module):
    """Custom transformer model with configurable architecture."""
    
    def __init__(self, 
                 vocab_size: int, 
                 d_model: int = 512, 
                 n_layers: int = 6, 
                 n_heads: int = 8, 
                 d_ff: int = 2048, 
                 max_seq_len: int = 512, 
                 dropout: float = 0.1,
                 num_labels: int = 2,
                 **kwargs):
        super().__init__()
        self.d_model = d_model
        self.n_layers = n_layers
        self.max_seq_len = max_seq_len
        
        # Token embedding
        self.token_embedding = nn.Embedding(vocab_size, d_model)
        
        # Positional encoding
        self.pos_encoding = nn.Parameter(torch.randn(1, max_seq_len, d_model))
        
        # Transformer blocks
        self.transformer_blocks = nn.ModuleList([
            CustomTransformerBlock(d_model, n_heads, d_ff, dropout)
            for _ in range(n_layers)
        ])
        
        # Output head
        self.classifier = nn.Linear(d_model, num_labels)
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Initialize weights
        self._init_weights()
    
    def _init_weights(self):
        """Initialize weights with proper initialization."""
        for module in self.modules():
            if isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
            elif isinstance(module, nn.Embedding):
                nn.init.normal_(module.weight, mean=0.0, std=0.02)
            elif isinstance(module, nn.LayerNorm):
                nn.init.ones_(module.weight)
                nn.init.zeros_(module.bias)
    
    def forward(self, input_ids: torch.Tensor, attention_mask: Optional[torch.Tensor] = None, 
                labels: Optional[torch.Tensor] = None) -> Dict[str, torch.Tensor]:
        """Forward pass through the transformer model."""
        batch_size, seq_len = input_ids.shape
        
        # Token embeddings
        x = self.token_embedding(input_ids) * math.sqrt(self.d_model)
        
        # Add positional encoding
        x = x + self.pos_encoding[:, :seq_len, :]
        x = self.dropout(x)
        
        # Create attention mask if not provided
        if attention_mask is None:
            attention_mask = torch.ones(batch_size, seq_len, device=input_ids.device)
        
        # Convert attention mask to PyTorch MultiheadAttention format
        # PyTorch expects mask to be True for positions to ignore
        # Create key padding mask (True for padding positions)
        key_padding_mask = (attention_mask == 0)  # [batch_size, seq_len]
        
        # Apply transformer blocks
        for transformer_block in self.transformer_blocks:
            x = transformer_block(x, key_padding_mask=key_padding_mask)
        
        # Global average pooling
        x = x.mean(dim=1)
        
        # Classification head
        logits = self.classifier(x)
        
        # Calculate loss if labels are provided
        loss = None
        if labels is not None:
            loss_fct = nn.CrossEntropyLoss()
            loss = loss_fct(logits.view(-1, logits.size(-1)), labels.view(-1))
        
        return {"loss": loss, "logits": logits} if loss is not None else {"logits": logits}


class CustomCNNModel(nn.Module):
    """Custom CNN model for sequence classification."""
    
    def __init__(self, vocab_size: int, embed_dim: int = 128, num_filters: int = 128, 
                 filter_sizes: List[int] = [3, 4, 5], num_labels: int = 2, dropout: float = 0.5):
        super().__init__()
        self.embed_dim = embed_dim
        self.num_filters = num_filters
        self.filter_sizes = filter_sizes
        
        # Embedding layer
        self.embedding = nn.Embedding(vocab_size, embed_dim)
        
        # Convolutional layers
        self.convs = nn.ModuleList([
            nn.Conv1d(embed_dim, num_filters, kernel_size=k, padding=k//2)
            for k in filter_sizes
        ])
        
        # Global max pooling and average pooling
        self.global_max_pool = nn.AdaptiveMaxPool1d(1)
        self.global_avg_pool = nn.AdaptiveAvgPool1d(1)
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Classification head
        self.classifier = nn.Linear(num_filters * len(filter_sizes) * 2, num_labels)
        
        # Initialize weights
        self._init_weights()
    
    def _init_weights(self):
        """Initialize weights with proper initialization."""
        for module in self.modules():
            if isinstance(module, nn.Conv1d):
                nn.init.kaiming_normal_(module.weight, mode='fan_out', nonlinearity='relu')
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
            elif isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
            elif isinstance(module, nn.Embedding):
                nn.init.normal_(module.weight, mean=0.0, std=0.02)
    
    def forward(self, input_ids: torch.Tensor, attention_mask: Optional[torch.Tensor] = None,
                labels: Optional[torch.Tensor] = None) -> Dict[str, torch.Tensor]:
        """Forward pass through the CNN model."""
        # Embedding
        x = self.embedding(input_ids)  # [batch_size, seq_len, embed_dim]
        
        # Transpose for convolution
        x = x.transpose(1, 2)  # [batch_size, embed_dim, seq_len]
        
        # Apply convolutions and pooling
        conv_outputs = []
        for conv in self.convs:
            conv_out = F.relu(conv(x))
            
            # Global max pooling
            max_pool = self.global_max_pool(conv_out).squeeze(-1)
            
            # Global average pooling
            avg_pool = self.global_avg_pool(conv_out).squeeze(-1)
            
            # Concatenate both pooling results
            pool_out = torch.cat([max_pool, avg_pool], dim=1)
            conv_outputs.append(pool_out)
        
        # Concatenate all convolution outputs
        x = torch.cat(conv_outputs, dim=1)
        
        # Dropout
        x = self.dropout(x)
        
        # Classification
        logits = self.classifier(x)
        
        # Calculate loss if labels are provided
        loss = None
        if labels is not None:
            loss_fct = nn.CrossEntropyLoss()
            loss = loss_fct(logits.view(-1, logits.size(-1)), labels.view(-1))
        
        return {"loss": loss, "logits": logits} if loss is not None else {"logits": logits}


class CustomRNNModel(nn.Module):
    """Custom RNN model with LSTM/GRU support."""
    
    def __init__(self, vocab_size: int, embed_dim: int = 128, hidden_dim: int = 256, 
                 num_layers: int = 2, rnn_type: str = "lstm", bidirectional: bool = True,
                 num_labels: int = 2, dropout: float = 0.5):
        super().__init__()
        self.embed_dim = embed_dim
        self.hidden_dim = hidden_dim
        self.num_layers = num_layers
        self.rnn_type = rnn_type.lower()
        self.bidirectional = bidirectional
        
        # Embedding layer
        self.embedding = nn.Embedding(vocab_size, embed_dim)
        
        # RNN layer
        if self.rnn_type == "lstm":
            self.rnn = nn.LSTM(
                embed_dim, hidden_dim, num_layers, 
                bidirectional=bidirectional, dropout=dropout if num_layers > 1 else 0,
                batch_first=True
            )
        elif self.rnn_type == "gru":
            self.rnn = nn.GRU(
                embed_dim, hidden_dim, num_layers,
                bidirectional=bidirectional, dropout=dropout if num_layers > 1 else 0,
                batch_first=True
            )
        else:
            raise ValueError(f"Unsupported RNN type: {rnn_type}")
        
        # Calculate output dimension
        self.output_dim = hidden_dim * (2 if bidirectional else 1)
        
        # Attention mechanism
        self.attention = nn.MultiheadAttention(
            self.output_dim, num_heads=8, batch_first=True
        )
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Classification head
        self.classifier = nn.Linear(self.output_dim, num_labels)
        
        # Initialize weights
        self._init_weights()
    
    def _init_weights(self):
        """Initialize weights with proper initialization."""
        for module in self.modules():
            if isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
            elif isinstance(module, nn.Embedding):
                nn.init.normal_(module.weight, mean=0.0, std=0.02)
            elif isinstance(module, (nn.LSTM, nn.GRU)):
                for name, param in module.named_parameters():
                    if 'weight' in name:
                        nn.init.orthogonal_(param)
                    elif 'bias' in name:
                        nn.init.zeros_(param)
    
    def forward(self, input_ids: torch.Tensor, attention_mask: Optional[torch.Tensor] = None,
                labels: Optional[torch.Tensor] = None) -> Dict[str, torch.Tensor]:
        """Forward pass through the RNN model."""
        # Embedding
        x = self.embedding(input_ids)  # [batch_size, seq_len, embed_dim]
        
        # RNN forward pass
        rnn_output, _ = self.rnn(x)  # [batch_size, seq_len, output_dim]
        
        # Apply attention
        attn_output, _ = self.attention(rnn_output, rnn_output, rnn_output)
        
        # Global average pooling
        x = attn_output.mean(dim=1)
        
        # Dropout
        x = self.dropout(x)
        
        # Classification
        logits = self.classifier(x)
        
        # Calculate loss if labels are provided
        loss = None
        if labels is not None:
            loss_fct = nn.CrossEntropyLoss()
            loss = loss_fct(logits.view(-1, logits.size(-1)), labels.view(-1))
        
        return {"loss": loss, "logits": logits} if loss is not None else {"logits": logits}


class CustomHybridModel(nn.Module):
    """Custom hybrid model combining CNN, RNN, and Transformer components."""
    
    def __init__(self, vocab_size: int, embed_dim: int = 128, hidden_dim: int = 256,
                 num_filters: int = 128, filter_sizes: List[int] = [3, 4, 5],
                 num_layers: int = 2, num_heads: int = 8, num_labels: int = 2, 
                 dropout: float = 0.5):
        super().__init__()
        self.embed_dim = embed_dim
        self.hidden_dim = hidden_dim
        self.num_filters = num_filters
        self.filter_sizes = filter_sizes
        
        # Shared embedding layer
        self.embedding = nn.Embedding(vocab_size, embed_dim)
        
        # CNN branch
        self.cnn_convs = nn.ModuleList([
            nn.Conv1d(embed_dim, num_filters, kernel_size=k, padding=k//2)
            for k in filter_sizes
        ])
        
        # RNN branch
        self.rnn = nn.LSTM(
            embed_dim, hidden_dim, num_layers, 
            bidirectional=True, dropout=dropout if num_layers > 1 else 0,
            batch_first=True
        )
        
        # Transformer branch
        self.transformer_block = CustomTransformerBlock(
            embed_dim, num_heads, hidden_dim, dropout
        )
        
        # Feature fusion
        cnn_output_dim = num_filters * len(filter_sizes)
        rnn_output_dim = hidden_dim * 2  # bidirectional
        transformer_output_dim = embed_dim
        
        total_features = cnn_output_dim + rnn_output_dim + transformer_output_dim
        
        # Feature fusion layer
        self.fusion = nn.Sequential(
            nn.Linear(total_features, hidden_dim),
            nn.ReLU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, hidden_dim // 2),
            nn.ReLU(),
            nn.Dropout(dropout)
        )
        
        # Classification head
        self.classifier = nn.Linear(hidden_dim // 2, num_labels)
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Initialize weights
        self._init_weights()
    
    def _init_weights(self):
        """Initialize weights with proper initialization."""
        for module in self.modules():
            if isinstance(module, nn.Conv1d):
                nn.init.kaiming_normal_(module.weight, mode='fan_out', nonlinearity='relu')
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
            elif isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
            elif isinstance(module, nn.Embedding):
                nn.init.normal_(module.weight, mean=0.0, std=0.02)
            elif isinstance(module, nn.LSTM):
                for name, param in module.named_parameters():
                    if 'weight' in name:
                        nn.init.orthogonal_(param)
                    elif 'bias' in name:
                        nn.init.zeros_(param)
    
    def forward(self, input_ids: torch.Tensor, attention_mask: Optional[torch.Tensor] = None,
                labels: Optional[torch.Tensor] = None) -> Dict[str, torch.Tensor]:
        """Forward pass through the hybrid model."""
        # Embedding
        x = self.embedding(input_ids)  # [batch_size, seq_len, embed_dim]
        
        # CNN branch
        x_cnn = x.transpose(1, 2)  # [batch_size, embed_dim, seq_len]
        cnn_outputs = []
        for conv in self.cnn_convs:
            conv_out = F.relu(conv(x_cnn))
            pool_out = F.adaptive_max_pool1d(conv_out, 1).squeeze(-1)
            cnn_outputs.append(pool_out)
        cnn_features = torch.cat(cnn_outputs, dim=1)
        
        # RNN branch
        rnn_output, _ = self.rnn(x)
        rnn_features = rnn_output.mean(dim=1)  # Global average pooling
        
        # Transformer branch
        transformer_features = self.transformer_block(x)
        transformer_features = transformer_features.mean(dim=1)  # Global average pooling
        
        # Feature fusion
        combined_features = torch.cat([cnn_features, rnn_features, transformer_features], dim=1)
        fused_features = self.fusion(combined_features)
        
        # Dropout
        fused_features = self.dropout(fused_features)
        
        # Classification
        logits = self.classifier(fused_features)
        
        # Calculate loss if labels are provided
        loss = None
        if labels is not None:
            loss_fct = nn.CrossEntropyLoss()
            loss = loss_fct(logits.view(-1, logits.size(-1)), labels.view(-1))
        
        return {"loss": loss, "logits": logits} if loss is not None else {"logits": logits}


class CustomAttentionMechanism(nn.Module):
    """Custom attention mechanism for sequence modeling."""
    
    def __init__(self, d_model: int, num_heads: int = 8, dropout: float = 0.1):
        super().__init__()
        self.d_model = d_model
        self.num_heads = num_heads
        self.d_k = d_model // num_heads
        
        # Linear transformations
        self.w_q = nn.Linear(d_model, d_model)
        self.w_k = nn.Linear(d_model, d_model)
        self.w_v = nn.Linear(d_model, d_model)
        self.w_o = nn.Linear(d_model, d_model)
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Layer normalization
        self.norm = nn.LayerNorm(d_model)
        
        # Initialize weights
        self._init_weights()
    
    def _init_weights(self):
        """Initialize weights with proper initialization."""
        for module in self.modules():
            if isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
    
    def scaled_dot_product_attention(self, Q: torch.Tensor, K: torch.Tensor, 
                                   V: torch.Tensor, mask: Optional[torch.Tensor] = None) -> torch.Tensor:
        """Scaled dot-product attention."""
        # Calculate attention scores
        scores = torch.matmul(Q, K.transpose(-2, -1)) / math.sqrt(self.d_k)
        
        # Apply mask if provided
        if mask is not None:
            scores = scores.masked_fill(mask == 0, -1e9)
        
        # Apply softmax
        attention_weights = F.softmax(scores, dim=-1)
        attention_weights = self.dropout(attention_weights)
        
        # Apply attention to values
        output = torch.matmul(attention_weights, V)
        
        return output
    
    def forward(self, x: torch.Tensor, mask: Optional[torch.Tensor] = None) -> torch.Tensor:
        """Forward pass through the attention mechanism."""
        batch_size, seq_len, d_model = x.shape
        
        # Linear transformations
        Q = self.w_q(x).view(batch_size, seq_len, self.num_heads, self.d_k).transpose(1, 2)
        K = self.w_k(x).view(batch_size, seq_len, self.num_heads, self.d_k).transpose(1, 2)
        V = self.w_v(x).view(batch_size, seq_len, self.num_heads, self.d_k).transpose(1, 2)
        
        # Apply attention
        attention_output = self.scaled_dot_product_attention(Q, K, V, mask)
        
        # Reshape and apply output projection
        attention_output = attention_output.transpose(1, 2).contiguous().view(
            batch_size, seq_len, d_model
        )
        output = self.w_o(attention_output)
        
        # Residual connection and layer normalization
        output = self.norm(x + output)
        
        return output


class CustomResidualBlock(nn.Module):
    """Custom residual block for deep networks."""
    
    def __init__(self, d_model: int, dropout: float = 0.1):
        super().__init__()
        self.d_model = d_model
        
        # Two linear layers with activation
        self.linear1 = nn.Linear(d_model, d_model)
        self.linear2 = nn.Linear(d_model, d_model)
        
        # Layer normalization
        self.norm1 = nn.LayerNorm(d_model)
        self.norm2 = nn.LayerNorm(d_model)
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Initialize weights
        self._init_weights()
    
    def _init_weights(self):
        """Initialize weights with proper initialization."""
        for module in self.modules():
            if isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.zeros_(module.bias)
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """Forward pass with residual connections."""
        # First sub-layer
        residual = x
        x = self.norm1(x)
        x = F.relu(self.linear1(x))
        x = self.dropout(x)
        x = self.linear2(x)
        x = self.dropout(x)
        x = x + residual
        
        # Second sub-layer
        residual = x
        x = self.norm2(x)
        x = F.relu(self.linear1(x))
        x = self.dropout(x)
        x = self.linear2(x)
        x = self.dropout(x)
        x = x + residual
        
        return x


class CustomModelFactory:
    """Factory class for creating custom model architectures."""
    
    @staticmethod
    def create_model(model_type: str, config: UltraTrainingConfig, **kwargs) -> nn.Module:
        """Create a model based on the specified type."""
        if model_type == "transformer":
            return CustomTransformerModel(
                vocab_size=kwargs.get('vocab_size', 50000),
                d_model=kwargs.get('d_model', 512),
                n_layers=kwargs.get('n_layers', 6),
                n_heads=kwargs.get('n_heads', 8),
                d_ff=kwargs.get('d_ff', 2048),
                max_seq_len=config.max_length,
                dropout=kwargs.get('dropout', 0.1),
                num_labels=kwargs.get('num_labels', 2)
            )
        
        elif model_type == "cnn":
            return CustomCNNModel(
                vocab_size=kwargs.get('vocab_size', 50000),
                embed_dim=kwargs.get('embed_dim', 128),
                num_filters=kwargs.get('num_filters', 128),
                filter_sizes=kwargs.get('filter_sizes', [3, 4, 5]),
                num_labels=kwargs.get('num_labels', 2),
                dropout=kwargs.get('dropout', 0.5)
            )
        
        elif model_type == "rnn":
            return CustomRNNModel(
                vocab_size=kwargs.get('vocab_size', 50000),
                embed_dim=kwargs.get('embed_dim', 128),
                hidden_dim=kwargs.get('hidden_dim', 256),
                num_layers=kwargs.get('num_layers', 2),
                rnn_type=kwargs.get('rnn_type', 'lstm'),
                bidirectional=kwargs.get('bidirectional', True),
                num_labels=kwargs.get('num_labels', 2),
                dropout=kwargs.get('dropout', 0.5)
            )
        
        elif model_type == "hybrid":
            return CustomHybridModel(
                vocab_size=kwargs.get('vocab_size', 50000),
                embed_dim=kwargs.get('embed_dim', 128),
                hidden_dim=kwargs.get('hidden_dim', 256),
                num_filters=kwargs.get('num_filters', 128),
                filter_sizes=kwargs.get('filter_sizes', [3, 4, 5]),
                num_layers=kwargs.get('num_layers', 2),
                num_heads=kwargs.get('num_heads', 8),
                num_labels=kwargs.get('num_labels', 2),
                dropout=kwargs.get('dropout', 0.5)
            )
        
        else:
            raise ValueError(f"Unsupported model type: {model_type}")


