def create_pytorch_dataloader(
    dataset: Dataset,
    config: UltraTrainingConfig,
    shuffle: bool = True
) -> DataLoader:
    """Create PyTorch DataLoader with best practices."""
    return DataLoader(
        dataset,
        batch_size=config.batch_size,
        shuffle=shuffle,
        num_workers=config.dataloader_num_workers,
        pin_memory=config.dataloader_pin_memory,
        prefetch_factor=config.dataloader_prefetch_factor,
        persistent_workers=True if config.dataloader_num_workers > 0 else False,
        drop_last=False,  # Keep all data
        generator=torch.Generator(device='cpu') if shuffle else None  # Reproducible shuffling
    )


def setup_pytorch_distributed_training(config: UltraTrainingConfig):
    """Setup distributed training with PyTorch best practices."""
    if config.num_gpus > 1:
        try:
            import torch.distributed as dist
            dist.init_process_group(backend=config.ddp_backend)
            logger.info("Distributed training initialized")
            return True
        except Exception as e:
            logger.warning(f"Distributed training failed: {e}, falling back to DataParallel")
            return False
    return False


def get_pytorch_model_info(model: nn.Module) -> Dict[str, Any]:
    """Get comprehensive PyTorch model information."""
    total_params = sum(p.numel() for p in model.parameters())
    trainable_params = sum(p.numel() for p in model.parameters() if p.requires_grad)
    
    model_info = {
        'total_parameters': total_params,
        'trainable_parameters': trainable_params,
        'non_trainable_parameters': total_params - trainable_params,
        'model_size_mb': sum(p.numel() * p.element_size() for p in model.parameters()) / 1024**2,
        'layers': len(list(model.modules())),
        'device': next(model.parameters()).device,
        'dtype': next(model.parameters()).dtype
    }
    
    return model_info


def validate_pytorch_model(model: nn.Module, sample_input: torch.Tensor) -> bool:
    """Validate PyTorch model with sample input."""
    try:
        model.eval()
        with torch.no_grad():
            # Test forward pass
            if hasattr(model, 'forward'):
                output = model(sample_input)
                logger.info("Model validation successful", output_shape=output.shape if hasattr(output, 'shape') else str(type(output)))
                return True
            else:
                logger.error("Model does not have forward method")
                return False
    except Exception as e:
        logger.error("Model validation failed", error=str(e))
        return False


