class EnhancedUltraOptimizedTrainer(UltraOptimizedTrainer):
    """Enhanced trainer with advanced autograd features."""
    
    def __init__(self, model: nn.Module, config: UltraTrainingConfig):
        super().__init__(model, config)
        
        # Initialize autograd optimizer
        self.autograd_optimizer = AutogradOptimizer(model, config)
        
        # Gradient monitoring
        self.gradient_monitor = GradientMonitor(model)
        
        logger.info("Enhanced trainer with autograd features initialized")
    
    def train_epoch(self, dataloader: DataLoader, epoch: int):
        """Train for one epoch with enhanced autograd features."""
        self.model.train()
        total_loss = 0
        num_batches = len(dataloader)
        
        progress_bar = tqdm(dataloader, desc=f"Epoch {epoch}")
        
        # Memory tracking context
        with memory_tracking_context():
            for batch_idx, batch in enumerate(progress_bar):
                try:
                    # Move batch to device
                    batch = {k: v.to(self.device, non_blocking=True) for k, v in batch.items()}
                    
                    # Compute loss with autograd features
                    loss = self.autograd_optimizer.compute_loss_with_autograd(batch)
                    
                    # Backward step with autograd optimizations
                    self.autograd_optimizer.backward_step(loss)
                    
                    total_loss += loss.item()
                    
                    # Update progress bar
                    memory_info = self._get_memory_info()
                    progress_bar.set_postfix({
                        "loss": f"{loss.item():.4f}",
                        "memory": f"{memory_info['gpu_memory_gb']:.1f}GB"
                    })
                    
                    # Logging with gradient information
                    if batch_idx % self.config.logging_steps == 0:
                        self._log_training_step_with_gradients(batch_idx, loss.item(), epoch, memory_info)
                    
                    # Memory cleanup
                    if batch_idx % 100 == 0:
                        self._cleanup_memory()
                
                except Exception as e:
                    logger.error("Training step failed", 
                                error=str(e), 
                                batch_idx=batch_idx, 
                                epoch=epoch)
                    continue
        
        avg_loss = total_loss / num_batches
        logger.info("Epoch completed", epoch=epoch, avg_loss=avg_loss)
        
        # Log gradient statistics
        gradient_info = self.autograd_optimizer.get_gradient_info()
        logger.info("Gradient statistics", **gradient_info)
        
        return avg_loss
    
    def _log_training_step_with_gradients(self, batch_idx: int, loss: float, epoch: int, memory_info: Dict[str, float]):
        """Log training step with gradient information."""
        step = epoch * 1000 + batch_idx
        
        # Get gradient information
        gradient_info = self.autograd_optimizer.get_gradient_info()
        
        # TensorBoard logging
        self.writer.add_scalar("Loss/train", loss, step)
        self.writer.add_scalar("Learning_rate", gradient_info['learning_rate'], step)
        self.writer.add_scalar("Memory/GPU_GB", memory_info['gpu_memory_gb'], step)
        
        # Log gradient statistics
        for name, stats in gradient_info['gradient_statistics'].items():
            self.writer.add_scalar(f"Gradients/{name}/mean_norm", stats['mean_norm'], step)
            self.writer.add_scalar(f"Gradients/{name}/std_norm", stats['std_norm'], step)
        
        # Wandb logging
        wandb.log({
            "train_loss": loss,
            "learning_rate": gradient_info['learning_rate'],
            "epoch": epoch,
            "step": step,
            "gpu_memory_gb": memory_info['gpu_memory_gb'],
            "gradient_anomalies": len(gradient_info['gradient_anomalies'])
        })
        
        # Update training history
        self.training_history['loss'].append(loss)
        self.training_history['learning_rate'].append(gradient_info['learning_rate'])
        self.training_history['memory_usage'].append(memory_info['gpu_memory_gb'])


