# Comprehensive Early Stopping and Learning Rate Scheduling
# =============================================================================

class EarlyStoppingConfig:
    """Configuration for early stopping strategies."""
    
    def __init__(self,
                 patience: int = 10,
                 min_delta: float = 0.0,
                 min_epochs: int = 0,
                 max_epochs: int = None,
                 mode: str = 'min',
                 monitor: str = 'val_loss',
                 baseline: float = None,
                 restore_best_weights: bool = True,
                 cooldown: int = 0,
                 min_lr: float = 1e-8,
                 verbose: bool = True):
        self.patience = patience
        self.min_delta = min_delta
        self.min_epochs = min_epochs
        self.max_epochs = max_epochs
        self.mode = mode
        self.monitor = monitor
        self.baseline = baseline
        self.restore_best_weights = restore_best_weights
        self.cooldown = cooldown
        self.min_lr = min_lr
        self.verbose = verbose
        
        # Validation
        if mode not in ['min', 'max']:
            raise ValueError("mode must be 'min' or 'max'")
        if patience < 0:
            raise ValueError("patience must be non-negative")
        if min_epochs < 0:
            raise ValueError("min_epochs must be non-negative")
        if cooldown < 0:
            raise ValueError("cooldown must be non-negative")


class EarlyStopping:
    """Advanced early stopping with multiple criteria and monitoring."""
    
    def __init__(self, config: EarlyStoppingConfig):
        self.config = config
        self.best_score = None
        self.best_epoch = 0
        self.counter = 0
        self.cooldown_counter = 0
        self.best_weights = None
        self.history = []
        
        # Initialize baseline
        if self.config.baseline is not None:
            self.best_score = self.config.baseline
            if self.config.mode == 'min':
                self.best_score = float('inf')
            else:
                self.best_score = float('-inf')
    
    def __call__(self, epoch: int, metrics: Dict[str, float], model: nn.Module) -> bool:
        """Check if training should stop early."""
        current_score = metrics.get(self.config.monitor)
        
        if current_score is None:
            if self.config.verbose:
                logger.warning(f"Monitor metric '{self.config.monitor}' not found in metrics")
            return False
        
        # Check minimum epochs
        if epoch < self.config.min_epochs:
            return False
        
        # Check maximum epochs
        if self.config.max_epochs and epoch >= self.config.max_epochs:
            if self.config.verbose:
                logger.info(f"Maximum epochs ({self.config.max_epochs}) reached")
            return True
        
        # Cooldown period
        if self.cooldown_counter > 0:
            self.cooldown_counter -= 1
            return False
        
        # Check if current score is better
        is_better = False
        if self.config.mode == 'min':
            is_better = current_score < self.best_score - self.config.min_delta
        else:
            is_better = current_score > self.best_score + self.config.min_delta
        
        if is_better:
            self.best_score = current_score
            self.best_epoch = epoch
            self.counter = 0
            
            # Save best weights
            if self.config.restore_best_weights:
                self.best_weights = {name: param.clone().detach() 
                                   for name, param in model.state_dict().items()}
            
            if self.config.verbose:
                logger.info(f"New best {self.config.monitor}: {current_score:.6f} at epoch {epoch}")
        else:
            self.counter += 1
            if self.config.verbose and self.counter == 1:
                logger.info(f"EarlyStopping counter: {self.counter} out of {self.config.patience}")
        
        # Record history
        self.history.append({
            'epoch': epoch,
            'score': current_score,
            'best_score': self.best_score,
            'counter': self.counter,
            'is_better': is_better
        })
        
        # Check if patience exceeded
        if self.counter >= self.config.patience:
            if self.config.verbose:
                logger.info(f"Early stopping triggered at epoch {epoch}")
                logger.info(f"Best {self.config.monitor}: {self.best_score:.6f} at epoch {self.best_epoch}")
            
            # Start cooldown
            self.cooldown_counter = self.config.cooldown
            
            return True
        
        return False
    
    def restore_best_weights(self, model: nn.Module):
        """Restore the best weights to the model."""
        if self.best_weights is not None:
            model.load_state_dict(self.best_weights)
            if self.config.verbose:
                logger.info("Best weights restored to model")
    
    def get_summary(self) -> Dict[str, Any]:
        """Get early stopping summary."""
        return {
            'best_score': self.best_score,
            'best_epoch': self.best_epoch,
            'counter': self.counter,
            'cooldown_counter': self.cooldown_counter,
            'history': self.history,
            'stopped_early': self.counter >= self.config.patience
        }


class AdvancedLearningRateScheduler:
    """Advanced learning rate scheduler with multiple strategies and monitoring."""
    
    def __init__(self, 
                 optimizer: torch.optim.Optimizer,
                 scheduler_type: str = 'cosine',
                 config: Dict[str, Any] = None):
        self.optimizer = optimizer
        self.scheduler_type = scheduler_type
        self.config = config or {}
        self.scheduler = None
        self.history = []
        self.current_epoch = 0
        
        self._create_scheduler()
    
    def _create_scheduler(self):
        """Create the appropriate scheduler."""
        if self.scheduler_type == 'cosine':
            self.scheduler = torch.optim.lr_scheduler.CosineAnnealingLR(
                self.optimizer,
                T_max=self.config.get('T_max', 100),
                eta_min=self.config.get('eta_min', 0)
            )
        elif self.scheduler_type == 'cosine_warmup':
            self.scheduler = torch.optim.lr_scheduler.CosineAnnealingWarmRestarts(
                self.optimizer,
                T_0=self.config.get('T_0', 10),
                T_mult=self.config.get('T_mult', 2),
                eta_min=self.config.get('eta_min', 0)
            )
        elif self.scheduler_type == 'linear_warmup':
            self.scheduler = torch.optim.lr_scheduler.LinearLR(
                self.optimizer,
                start_factor=self.config.get('start_factor', 0.1),
                total_iters=self.config.get('total_iters', 10)
            )
        elif self.scheduler_type == 'step':
            self.scheduler = torch.optim.lr_scheduler.StepLR(
                self.optimizer,
                step_size=self.config.get('step_size', 30),
                gamma=self.config.get('gamma', 0.1)
            )
        elif self.scheduler_type == 'plateau':
            self.scheduler = torch.optim.lr_scheduler.ReduceLROnPlateau(
                self.optimizer,
                mode=self.config.get('mode', 'min'),
                factor=self.config.get('factor', 0.1),
                patience=self.config.get('patience', 10),
                min_lr=self.config.get('min_lr', 1e-8),
                verbose=self.config.get('verbose', True)
            )
        elif self.scheduler_type == 'exponential':
            self.scheduler = torch.optim.lr_scheduler.ExponentialLR(
                self.optimizer,
                gamma=self.config.get('gamma', 0.95)
            )
        elif self.scheduler_type == 'one_cycle':
            self.scheduler = torch.optim.lr_scheduler.OneCycleLR(
                self.optimizer,
                max_lr=self.config.get('max_lr', 1e-3),
                total_steps=self.config.get('total_steps', 100),
                pct_start=self.config.get('pct_start', 0.3),
                anneal_strategy=self.config.get('anneal_strategy', 'cos')
            )
        elif self.scheduler_type == 'cyclic':
            self.scheduler = torch.optim.lr_scheduler.CyclicLR(
                self.optimizer,
                base_lr=self.config.get('base_lr', 1e-6),
                max_lr=self.config.get('max_lr', 1e-3),
                step_size_up=self.config.get('step_size_up', 2000),
                step_size_down=self.config.get('step_size_down', 2000),
                mode=self.config.get('cyclic_mode', 'triangular')
            )
        elif self.scheduler_type == 'custom':
            # Custom scheduler function
            custom_func = self.config.get('custom_func')
            if custom_func and callable(custom_func):
                self.scheduler = custom_func(self.optimizer, **self.config)
            else:
                raise ValueError("custom_func must be provided for custom scheduler type")
        else:
            raise ValueError(f"Unsupported scheduler type: {self.scheduler_type}")
    
    def step(self, metrics: float = None, epoch: int = None):
        """Step the scheduler."""
        if epoch is not None:
            self.current_epoch = epoch
        
        # Step the scheduler
        if self.scheduler_type == 'plateau' and metrics is not None:
            self.scheduler.step(metrics)
        else:
            self.scheduler.step()
        
        # Record history
        current_lr = self.get_last_lr()
        self.history.append({
            'epoch': self.current_epoch,
            'learning_rate': current_lr,
            'metrics': metrics
        })
    
    def get_last_lr(self) -> List[float]:
        """Get current learning rates."""
        return self.scheduler.get_last_lr()
    
    def get_learning_rate(self) -> float:
        """Get current learning rate (first parameter group)."""
        lrs = self.get_last_lr()
        return lrs[0] if lrs else 0.0
    
    def set_learning_rate(self, lr: float):
        """Set learning rate for all parameter groups."""
        for param_group in self.optimizer.param_groups:
            param_group['lr'] = lr
    
    def get_scheduler_info(self) -> Dict[str, Any]:
        """Get comprehensive scheduler information."""
        return {
            'type': self.scheduler_type,
            'current_lr': self.get_learning_rate(),
            'current_epoch': self.current_epoch,
            'config': self.config,
            'history_length': len(self.history)
        }
    
    def plot_learning_rate_schedule(self, save_path: str = None):
        """Plot learning rate schedule."""
        if not self.history:
            logger.warning("No learning rate history to plot")
            return
        
        epochs = [h['epoch'] for h in self.history]
        lrs = [h['learning_rate'][0] if isinstance(h['learning_rate'], list) else h['learning_rate'] 
               for h in self.history]
        
        plt.figure(figsize=(10, 6))
        plt.plot(epochs, lrs, 'b-', linewidth=2)
        plt.xlabel('Epoch')
        plt.ylabel('Learning Rate')
        plt.title(f'{self.scheduler_type.title()} Learning Rate Schedule')
        plt.grid(True, alpha=0.3)
        plt.yscale('log')
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
        
        plt.show()
    
    def state_dict(self):
        """Get scheduler state dict."""
        return self.scheduler.state_dict()
    
    def load_state_dict(self, state_dict):
        """Load scheduler state dict."""
        self.scheduler.load_state_dict(state_dict)


class LearningRateSchedulerFactory:
    """Factory for creating learning rate schedulers."""
    
    @staticmethod
    def create_scheduler(optimizer: torch.optim.Optimizer,
                        scheduler_type: str = 'cosine',
                        **kwargs) -> AdvancedLearningRateScheduler:
        """Create a learning rate scheduler."""
        return AdvancedLearningRateScheduler(optimizer, scheduler_type, kwargs)
    
    @staticmethod
    def get_scheduler_config(scheduler_type: str) -> Dict[str, Any]:
        """Get default configuration for a scheduler type."""
        configs = {
            'cosine': {'T_max': 100, 'eta_min': 0},
            'cosine_warmup': {'T_0': 10, 'T_mult': 2, 'eta_min': 0},
            'linear_warmup': {'start_factor': 0.1, 'total_iters': 10},
            'step': {'step_size': 30, 'gamma': 0.1},
            'plateau': {'mode': 'min', 'factor': 0.1, 'patience': 10, 'min_lr': 1e-8},
            'exponential': {'gamma': 0.95},
            'one_cycle': {'max_lr': 1e-3, 'total_steps': 100, 'pct_start': 0.3},
            'cyclic': {'base_lr': 1e-6, 'max_lr': 1e-3, 'step_size_up': 2000}
        }
        return configs.get(scheduler_type, {})
    
    @staticmethod
    def create_adaptive_scheduler(optimizer: torch.optim.Optimizer,
                                train_dataloader: DataLoader,
                                num_epochs: int,
                                warmup_ratio: float = 0.1) -> AdvancedLearningRateScheduler:
        """Create an adaptive scheduler with automatic configuration."""
        total_steps = len(train_dataloader) * num_epochs
        warmup_steps = int(total_steps * warmup_ratio)
        
        config = {
            'T_max': total_steps,
            'warmup_steps': warmup_steps,
            'eta_min': 1e-8
        }
        
        return AdvancedLearningRateScheduler(optimizer, 'cosine_warmup', config)


class TrainingManager:
    """Comprehensive training manager with early stopping, LR scheduling, gradient clipping, and NaN/Inf handling."""
    
    def __init__(self,
                 model: nn.Module,
                 optimizer: torch.optim.Optimizer,
                 scheduler: AdvancedLearningRateScheduler = None,
                 early_stopping: EarlyStopping = None,
                 device: str = 'cuda' if torch.cuda.is_available() else 'cpu',
                 max_grad_norm: float = 1.0,
                 enable_gradient_clipping: bool = True,
                 enable_nan_inf_checking: bool = True,
                 nan_inf_threshold: float = 1e6):
        self.model = model
        self.optimizer = optimizer
        self.scheduler = scheduler
        self.early_stopping = early_stopping
        self.device = device
        
        # Gradient clipping and NaN/Inf handling configuration
        self.max_grad_norm = max_grad_norm
        self.enable_gradient_clipping = enable_gradient_clipping
        self.enable_nan_inf_checking = enable_nan_inf_checking
        self.nan_inf_threshold = nan_inf_threshold
        
        self.current_epoch = 0
        self.training_history = []
        self.best_metrics = {}
        
        # Move model to device
        self.model.to(self.device)
        
        logger.info("Training manager initialized with gradient clipping and NaN/Inf handling")
    
    def check_nan_inf(self, tensor: torch.Tensor, name: str = "tensor") -> bool:
        """Check if tensor contains NaN or Inf values."""
        if not self.enable_nan_inf_checking:
            return False
        
        has_nan = torch.isnan(tensor).any()
        has_inf = torch.isinf(tensor).any()
        
        if has_nan or has_inf:
            logger.warning(f"NaN/Inf detected in {name}: NaN={has_nan}, Inf={has_inf}")
            return True
        
        return False
    
    def check_gradients_nan_inf(self) -> bool:
        """Check if any gradients contain NaN or Inf values."""
        if not self.enable_nan_inf_checking:
            return False
        
        has_nan_inf = False
        for name, param in self.model.named_parameters():
            if param.grad is not None:
                if self.check_nan_inf(param.grad, f"gradient of {name}"):
                    has_nan_inf = True
        
        return has_nan_inf
    
    def clip_gradients(self) -> float:
        """Clip gradients to prevent exploding gradients."""
        if not self.enable_gradient_clipping:
            return 0.0
        
        # Calculate total gradient norm
        total_norm = 0.0
        param_count = 0
        
        for p in self.model.parameters():
            if p.grad is not None:
                param_norm = p.grad.data.norm(2)
                total_norm += param_norm.item() ** 2
                param_count += 1
        
        if param_count == 0:
            return 0.0
        
        total_norm = total_norm ** (1. / 2)
        
        # Clip gradients if norm exceeds threshold
        if total_norm > self.max_grad_norm:
            clip_coef = self.max_grad_norm / (total_norm + 1e-6)
            for p in self.model.parameters():
                if p.grad is not None:
                    p.grad.data.mul_(clip_coef)
            
            logger.info(f"Gradients clipped: {total_norm:.4f} -> {self.max_grad_norm:.4f}")
        
        return total_norm
    
    def safe_backward_pass(self, loss: torch.Tensor, epoch: int = 0, batch_idx: int = 0) -> bool:
        """Perform backward pass with safety checks and recovery mechanisms."""
        try:
            # Check loss for NaN/Inf before backward pass
            if self.check_nan_inf(loss, "loss"):
                logger.error("Loss contains NaN/Inf values, skipping backward pass")
                return False
            
            # Perform backward pass
            loss.backward()
            
            # Check gradients for NaN/Inf after backward pass
            if self.check_gradients_nan_inf():
                logger.error("Gradients contain NaN/Inf values after backward pass")
                self.optimizer.zero_grad()
                return False
            
            # Clip gradients if enabled
            grad_norm = self.clip_gradients()
            
            # Check gradients again after clipping
            if self.check_gradients_nan_inf():
                logger.error("Gradients still contain NaN/Inf values after clipping")
                self.optimizer.zero_grad()
                return False
            
            return True
            
        except Exception as e:
            logger.error(f"Error during backward pass: {e}")
            self.optimizer.zero_grad()
            return False
    
    def get_gradient_statistics(self) -> Dict[str, Any]:
        """Get comprehensive gradient statistics."""
        total_norm = 0.0
        param_count = 0
        clipped_count = 0
        nan_inf_detected = False
        
        for p in self.model.parameters():
            if p.grad is not None:
                param_norm = p.grad.data.norm(2)
                total_norm += param_norm.item() ** 2
                param_count += 1
                
                # Check if this parameter was clipped
                if param_norm > self.max_grad_norm:
                    clipped_count += 1
                
                # Check for NaN/Inf
                if torch.isnan(p.grad).any() or torch.isinf(p.grad).any():
                    nan_inf_detected = True
        
        if param_count > 0:
            total_norm = total_norm ** (1. / 2)
        
        return {
            'total_norm': total_norm,
            'param_count': param_count,
            'clipped_count': clipped_count,
            'nan_inf_detected': nan_inf_detected,
            'max_grad_norm': self.max_grad_norm
        }
    
    def handle_training_recovery(self, epoch: int, batch_idx: int) -> bool:
        """Handle training recovery when NaN/Inf values are detected."""
        logger.warning(f"Training recovery triggered at epoch {epoch}, batch {batch_idx}")
        
        # Clear gradients
        self.optimizer.zero_grad()
        
        # Optionally reduce learning rate
        if self.scheduler:
            current_lr = self.scheduler.get_learning_rate()
            if current_lr > 1e-6:  # Don't reduce below minimum threshold
                # Reduce learning rate by factor of 2
                for param_group in self.optimizer.param_groups:
                    param_group['lr'] = param_group['lr'] * 0.5
                logger.info(f"Learning rate reduced to {self.optimizer.param_groups[0]['lr']:.2e}")
        
        # Check if we should continue training
        recovery_attempts = getattr(self, '_recovery_attempts', 0)
        self._recovery_attempts = recovery_attempts + 1
        
        if recovery_attempts >= 3:
            logger.error("Maximum recovery attempts reached, stopping training")
            return False
        
        return True
    
    def log_training_stability(self, epoch: int, batch_idx: int, loss: torch.Tensor, grad_stats: Dict[str, Any]):
        """Log training stability metrics."""
        if batch_idx % 100 == 0:  # Log every 100 batches
            logger.info(f"Epoch {epoch}, Batch {batch_idx}: "
                       f"Loss={loss.item():.4f}, "
                       f"GradNorm={grad_stats['total_norm']:.4f}, "
                       f"Clipped={grad_stats['clipped_count']}, "
                       f"NaN/Inf={grad_stats['nan_inf_detected']}")
    
    def train_epoch(self, train_dataloader: DataLoader, epoch: int) -> Dict[str, float]:
        """Train for one epoch."""
        self.model.train()
        total_loss = 0.0
        num_batches = len(train_dataloader)
        
        for batch_idx, batch in enumerate(train_dataloader):
            # Move batch to device
            batch = {k: v.to(self.device) if isinstance(v, torch.Tensor) else v 
                    for k, v in batch.items()}
            
            # Forward pass
            self.optimizer.zero_grad()
            outputs = self.model(**batch)
            loss = outputs['loss'] if isinstance(outputs, dict) else outputs
            
            # Safe backward pass with gradient clipping and NaN/Inf handling
            if self.safe_backward_pass(loss, epoch, batch_idx):
                self.optimizer.step()
                
                # Log training stability
                grad_stats = self.get_gradient_statistics()
                self.log_training_stability(epoch, batch_idx, loss, grad_stats)
            else:
                logger.warning(f"Backward pass failed for batch {batch_idx}, skipping optimizer step")
                continue
            
            total_loss += loss.item()
            
            # Update scheduler if step-based
            if self.scheduler and self.scheduler.scheduler_type in ['one_cycle', 'cyclic']:
                self.scheduler.step()
        
        # Update scheduler if epoch-based
        if self.scheduler and self.scheduler.scheduler_type not in ['one_cycle', 'cyclic']:
            self.scheduler.step(epoch=epoch)
        
        avg_loss = total_loss / num_batches
        
        # Get current learning rate
        current_lr = self.scheduler.get_learning_rate() if self.scheduler else 0.0
        
        # Get gradient statistics
        grad_stats = self.get_gradient_statistics()
        
        return {
            'train_loss': avg_loss, 
            'learning_rate': current_lr,
            'grad_norm': grad_stats['total_norm'],
            'grad_norm_clipped': grad_stats['clipped_count'] > 0,
            'nan_inf_detected': grad_stats['nan_inf_detected']
        }
    
    def validate_epoch(self, val_dataloader: DataLoader, epoch: int) -> Dict[str, float]:
        """Validate for one epoch."""
        self.model.eval()
        total_loss = 0.0
        num_batches = len(val_dataloader)
        
        with torch.no_grad():
            for batch in val_dataloader:
                # Move batch to device
                batch = {k: v.to(self.device) if isinstance(v, torch.Tensor) else v 
                        for k, v in batch.items()}
                
                # Forward pass
                outputs = self.model(**batch)
                loss = outputs['loss'] if isinstance(outputs, dict) else outputs
                
                total_loss += loss.item()
        
        avg_loss = total_loss / num_batches
        return {'val_loss': avg_loss}
    
    def train(self, 
              train_dataloader: DataLoader,
              val_dataloader: DataLoader,
              num_epochs: int,
              save_dir: str = "./checkpoints") -> Dict[str, Any]:
        """Complete training loop with early stopping and LR scheduling."""
        logger.info(f"Starting training for {num_epochs} epochs")
        
        # Create save directory
        os.makedirs(save_dir, exist_ok=True)
        
        best_val_loss = float('inf')
        
        for epoch in range(num_epochs):
            self.current_epoch = epoch
            
            # Training
            train_metrics = self.train_epoch(train_dataloader, epoch)
            
            # Validation
            val_metrics = self.validate_epoch(val_dataloader, epoch)
            
            # Combine metrics
            epoch_metrics = {**train_metrics, **val_metrics}
            self.training_history.append(epoch_metrics)
            
            # Update best metrics
            if val_metrics['val_loss'] < best_val_loss:
                best_val_loss = val_metrics['val_loss']
                self.best_metrics = epoch_metrics
                
                # Save best model
                best_model_path = os.path.join(save_dir, 'best_model.pt')
                torch.save({
                    'epoch': epoch,
                    'model_state_dict': self.model.state_dict(),
                    'optimizer_state_dict': self.optimizer.state_dict(),
                    'scheduler_state_dict': self.scheduler.state_dict() if self.scheduler else None,
                    'metrics': epoch_metrics
                }, best_model_path)
                
                logger.info(f"New best model saved at epoch {epoch + 1}")
            
            # Log progress
            logger.info(f"Epoch {epoch + 1}/{num_epochs} - "
                       f"Train Loss: {train_metrics['train_loss']:.4f}, "
                       f"Val Loss: {val_metrics['val_loss']:.4f}, "
                       f"LR: {epoch_metrics.get('learning_rate', 0.0):.2e}")
            
            # Check early stopping
            if self.early_stopping:
                should_stop = self.early_stopping(epoch, epoch_metrics, self.model)
                if should_stop:
                    logger.info("Early stopping triggered")
                    break
        
        # Restore best weights if early stopping was used
        if self.early_stopping and self.early_stopping.config.restore_best_weights:
            self.early_stopping.restore_best_weights(self.model)
        
        # Final summary
        training_summary = {
            'total_epochs': self.current_epoch + 1,
            'best_metrics': self.best_metrics,
            'training_history': self.training_history,
            'early_stopping_summary': self.early_stopping.get_summary() if self.early_stopping else None,
            'scheduler_info': self.scheduler.get_scheduler_info() if self.scheduler else None
        }
        
        logger.info("Training completed successfully")
        return training_summary
    
    def plot_training_history(self, save_path: str = None):
        """Plot training history."""
        if not self.training_history:
            logger.warning("No training history to plot")
            return
        
        epochs = list(range(1, len(self.training_history) + 1))
        train_losses = [h['train_loss'] for h in self.training_history]
        val_losses = [h['val_loss'] for h in self.training_history]
        lrs = [h.get('learning_rate', 0.0) for h in self.training_history]
        
        fig, (ax1, ax2) = plt.subplots(2, 1, figsize=(12, 8))
        
        # Loss plot
        ax1.plot(epochs, train_losses, 'b-', label='Train Loss', linewidth=2)
        ax1.plot(epochs, val_losses, 'r-', label='Validation Loss', linewidth=2)
        ax1.set_xlabel('Epoch')
        ax1.set_ylabel('Loss')
        ax1.set_title('Training and Validation Loss')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        
        # Learning rate plot
        ax2.plot(epochs, lrs, 'g-', label='Learning Rate', linewidth=2)
        ax2.set_xlabel('Epoch')
        ax2.set_ylabel('Learning Rate')
        ax2.set_title('Learning Rate Schedule')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.set_yscale('log')
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
        
        plt.show()


