# =============================================================================
# Enhanced Trainer with Advanced Loss and Optimization
# =============================================================================

class EnhancedUltraOptimizedTrainer(UltraOptimizedTrainer):
    """Enhanced trainer with advanced loss functions and optimization algorithms."""
    
    def __init__(self, model: nn.Module, config: UltraTrainingConfig):
        super().__init__(model, config)
        
        # Initialize loss function
        self.loss_function = self._create_loss_function()
        
        # Initialize optimizer with parameter grouping
        if config.use_parameter_grouping:
            self.parameter_groups = ParameterGrouper.group_parameters(
                model, config.weight_decay, config.no_decay_keywords
            )
            self.optimizer = self._create_optimizer_with_groups()
        else:
            self.optimizer = self._create_optimizer()
            
        # Initialize scheduler
        self.scheduler = self._create_scheduler()
        
        # Initialize gradient monitor
        self.gradient_monitor = GradientMonitor(model)
        
        logger.info("Enhanced trainer initialized with advanced loss and optimization")
        
    def _create_loss_function(self) -> nn.Module:
        """Create loss function based on configuration."""
        if self.config.auxiliary_losses:
            return CustomLossFunction(
                primary_loss=self.config.loss_function,
                auxiliary_losses=self.config.auxiliary_losses,
                loss_weights=self.config.loss_weights
            )
        else:
            return LossFunctionFactory.create_loss_function(self.config.loss_function)
    
    def _create_optimizer_with_groups(self) -> torch.optim.Optimizer:
        """Create optimizer with parameter grouping."""
        if self.config.optimizer_type == 'adamw':
            return torch.optim.AdamW(
                self.parameter_groups,
                lr=self.config.learning_rate,
                weight_decay=self.config.weight_decay
            )
        elif self.config.optimizer_type == 'adam':
            return torch.optim.Adam(
                self.parameter_groups,
                lr=self.config.learning_rate,
                weight_decay=self.config.weight_decay
            )
        else:
            return torch.optim.AdamW(
                self.parameter_groups,
                lr=self.config.learning_rate,
                weight_decay=self.config.weight_decay
            )
    
    def _create_optimizer(self) -> torch.optim.Optimizer:
        """Create standard optimizer."""
        return OptimizerFactory.create_optimizer(
            self.model,
            self.config.optimizer_type,
            self.config.learning_rate,
            self.config.weight_decay
        )
    
    def _create_scheduler(self) -> LearningRateScheduler:
        """Create learning rate scheduler."""
        scheduler_kwargs = {}
        
        if self.config.scheduler_type == 'cosine':
            scheduler_kwargs = {'T_max': self.config.num_epochs}
        elif self.config.scheduler_type == 'cosine_warmup':
            scheduler_kwargs = {'T_0': self.config.warmup_steps}
        elif self.config.scheduler_type == 'one_cycle':
            scheduler_kwargs = {
                'max_lr': self.config.max_lr,
                'total_steps': self.config.num_epochs
            }
            
        return OptimizerFactory.create_scheduler(
            self.optimizer,
            self.config.scheduler_type,
            **scheduler_kwargs
        )
    
    def compute_loss(self, predictions: torch.Tensor, targets: torch.Tensor, 
                    additional_data: Dict[str, torch.Tensor] = None) -> torch.Tensor:
        """Compute loss with support for auxiliary losses."""
        if isinstance(self.loss_function, CustomLossFunction):
            # Prepare predictions and targets for custom loss
            loss_inputs = {'primary': predictions}
            loss_targets = {'primary': targets}
            
            if additional_data:
                loss_inputs.update(additional_data.get('predictions', {}))
                loss_targets.update(additional_data.get('targets', {}))
                
            return self.loss_function(loss_inputs, loss_targets)
        else:
            # Standard loss computation
            return self.loss_function(predictions, targets)
    
    def train_epoch(self, dataloader: DataLoader, epoch: int) -> float:
        """Enhanced training epoch with advanced loss and optimization."""
        self.model.train()
        total_loss = 0.0
        num_batches = len(dataloader)
        
        # Clear gradient monitor
        self.gradient_monitor.clear_gradients()
        
        for batch_idx, batch in enumerate(dataloader):
            try:
                # Move batch to device
                input_ids = batch['input_ids'].to(self.device, non_blocking=True)
                attention_mask = batch['attention_mask'].to(self.device, non_blocking=True)
                labels = batch['labels'].to(self.device, non_blocking=True)
                
                # Forward pass with autograd profiling
                with autograd_profiler_context(self.config, enabled=True):
                    predictions = self.model(input_ids=input_ids, attention_mask=attention_mask)
                    
                    # Compute loss
                    loss = self.compute_loss(predictions, labels)
                
                # Backward pass
                loss.backward()
                
                # Apply gradient clipping
                apply_gradient_clipping(self.model, self.config)
                
                # Apply gradient accumulation
                apply_gradient_accumulation(self.optimizer, self.config, batch_idx)
                
                # Log training step
                self._log_training_step(batch_idx, num_batches, loss, epoch)
                
                total_loss += loss.item()
                
                # Cleanup memory
                self._cleanup_memory()
                
            except Exception as e:
                logger.error(f"Error in training step {batch_idx}", error=str(e))
                continue
        
        # Step scheduler
        if hasattr(self.scheduler, 'step'):
            self.scheduler.step()
        
        avg_loss = total_loss / num_batches
        logger.info(f"Epoch {epoch} completed", avg_loss=avg_loss)
        
        return avg_loss
    
    def _log_training_step(self, batch_idx: int, num_batches: int, loss: torch.Tensor, epoch: int):
        """Enhanced logging with gradient statistics."""
        if batch_idx % self.config.logging_steps == 0:
            # Get gradient statistics
            grad_stats = self.gradient_monitor.get_gradient_statistics()
            
            # Get learning rate
            current_lr = self.optimizer.param_groups[0]['lr']
            
            logger.info(
                f"Training step {batch_idx}/{num_batches}",
                epoch=epoch,
                loss=loss.item(),
                learning_rate=current_lr,
                grad_stats=grad_stats
            )
            
            # Log to wandb if available
            if wandb.run is not None:
                wandb.log({
                    'train_loss': loss.item(),
                    'learning_rate': current_lr,
                    'epoch': epoch,
                    'batch': batch_idx,
                    **{f'grad_{k}_{stat}': v for k, v in grad_stats.items() for stat, v2 in v.items()}
                })


