def test_loss_functions():
    """Test various loss functions with proper tensor shapes."""
    logger.info("Testing loss functions...")
    
    # Create sample data with proper shapes
    batch_size, num_classes = 32, 10
    
    # For classification losses: [batch_size, num_classes] vs [batch_size]
    predictions = torch.randn(batch_size, num_classes)
    targets = torch.randint(0, num_classes, (batch_size,))
    
    # For regression losses: [batch_size, 1] vs [batch_size, 1]
    regression_pred = torch.randn(batch_size, 1)
    regression_targets = torch.randn(batch_size, 1)
    
    # Test different loss functions
    loss_functions = {
        'cross_entropy': nn.CrossEntropyLoss(),
        'focal': FocalLoss(alpha=1.0, gamma=2.0),
        'label_smoothing': LabelSmoothingLoss(classes=num_classes, smoothing=0.1),
        'mse': nn.MSELoss(),
        'l1': nn.L1Loss()
    }
    
    results = {}
    for name, loss_fn in loss_functions.items():
        try:
            if name in ['cross_entropy', 'focal', 'label_smoothing']:
                # Classification losses
                loss = loss_fn(predictions, targets)
            else:
                # Regression losses
                loss = loss_fn(regression_pred, regression_targets)
            
            results[name] = loss.item()
            logger.info(f"{name} loss: {loss.item():.4f}")
        except Exception as e:
            logger.error(f"Error testing {name} loss", error=str(e))
            results[name] = None
    
    return results


def test_optimizers():
    """Test various optimizers."""
    logger.info("Testing optimizers...")
    
    # Create a simple model
    model = nn.Sequential(
        nn.Linear(10, 20),
        nn.ReLU(),
        nn.Linear(20, 5)
    )
    
    # Test different optimizers
    optimizers = {
        'adamw': torch.optim.AdamW(model.parameters(), lr=1e-4),
        'adam': torch.optim.Adam(model.parameters(), lr=1e-4),
        'sgd': torch.optim.SGD(model.parameters(), lr=1e-3, momentum=0.9),
        'radam': torch.optim.RAdam(model.parameters(), lr=1e-4)
    }
    
    # Test parameter access
    results = {}
    for name, optimizer in optimizers.items():
        try:
            lr = optimizer.param_groups[0]['lr']
            param_count = sum(p.numel() for p in model.parameters())
            results[name] = {'lr': lr, 'param_count': param_count}
            logger.info(f"{name}: lr={lr}, params={param_count}")
        except Exception as e:
            logger.error(f"Error testing {name} optimizer", error=str(e))
            results[name] = None
    
    return results


def test_schedulers():
    """Test various learning rate schedulers."""
    logger.info("Testing schedulers...")
    
    # Create a simple model and optimizer
    model = nn.Sequential(nn.Linear(10, 5))
    optimizer = torch.optim.Adam(model.parameters(), lr=1e-3)
    
    # Test different schedulers
    schedulers = {
        'cosine': torch.optim.lr_scheduler.CosineAnnealingLR(optimizer, T_max=10),
        'step': torch.optim.lr_scheduler.StepLR(optimizer, step_size=2, gamma=0.5),
        'exponential': torch.optim.lr_scheduler.ExponentialLR(optimizer, gamma=0.95)
    }
    
    results = {}
    for name, scheduler in schedulers.items():
        try:
            initial_lr = optimizer.param_groups[0]['lr']
            scheduler.step()
            final_lr = optimizer.param_groups[0]['lr']
            results[name] = {'initial_lr': initial_lr, 'final_lr': final_lr}
            logger.info(f"{name}: {initial_lr:.6f} -> {final_lr:.6f}")
        except Exception as e:
            logger.error(f"Error testing {name} scheduler", error=str(e))
            results[name] = None
    
    return results


def demonstrate_loss_optimization_integration():
    """Demonstrate integration of loss functions and optimization algorithms."""
    logger.info("Demonstrating loss and optimization integration...")
    
    # Create sample data
    batch_size, seq_len, hidden_dim = 32, 100, 128
    input_ids = torch.randint(0, 50000, (batch_size, seq_len))
    attention_mask = torch.ones(batch_size, seq_len)
    labels = torch.randint(0, 2, (batch_size,))
    
    # Create model
    model = CustomTransformerModel(
        vocab_size=50000,
        d_model=hidden_dim,
        n_layers=4,
        n_heads=8,
        d_ff=512,
        max_seq_len=seq_len,
        dropout=0.1,
        num_labels=2
    )
    
    # Test different loss functions
    loss_functions = [
        ('cross_entropy', nn.CrossEntropyLoss()),
        ('focal', FocalLoss(alpha=1.0, gamma=2.0)),
        ('label_smoothing', LabelSmoothingLoss(classes=2, smoothing=0.1))
    ]
    
    # Test different optimizers
    optimizers = [
        ('adamw', torch.optim.AdamW(model.parameters(), lr=1e-4)),
        ('adam', torch.optim.Adam(model.parameters(), lr=1e-4)),
        ('sgd', torch.optim.SGD(model.parameters(), lr=1e-3, momentum=0.9))
    ]
    
    results = {}
    
    for loss_name, loss_fn in loss_functions:
        for opt_name, optimizer in optimizers:
            try:
                # Reset model
                for param in model.parameters():
                    param.data.normal_(0, 0.02)
                
                # Forward pass
                predictions = model(input_ids=input_ids, attention_mask=attention_mask)
                
                # Compute loss
                loss = loss_fn(predictions, labels)
                
                # Backward pass
                optimizer.zero_grad()
                loss.backward()
                
                # Get gradient norm
                grad_norm = torch.nn.utils.clip_grad_norm_(model.parameters(), max_norm=1.0)
                
                # Optimizer step
                optimizer.step()
                
                results[f"{loss_name}_{opt_name}"] = {
                    'loss': loss.item(),
                    'grad_norm': grad_norm.item()
                }
                
                logger.info(f"{loss_name} + {opt_name}: loss={loss.item():.4f}, grad_norm={grad_norm.item():.4f}")
                
            except Exception as e:
                logger.error(f"Error testing {loss_name} + {opt_name}", error=str(e))
                results[f"{loss_name}_{opt_name}"] = None
    
    return results


