# =============================================================================
# Advanced Attention Mechanisms
# =============================================================================

class MultiHeadAttention(nn.Module):
    """Multi-head attention mechanism with modern optimizations."""
    
    def __init__(self, d_model: int, num_heads: int, dropout: float = 0.1,
                 use_flash_attention: bool = True, use_xformers: bool = True,
                 use_grouped_query: bool = False, num_kv_heads: int = None):
        super().__init__()
        assert d_model % num_heads == 0
        
        self.d_model = d_model
        self.num_heads = num_heads
        self.num_kv_heads = num_kv_heads or num_heads
        self.head_dim = d_model // num_heads
        self.scale = self.head_dim ** -0.5
        
        # Linear projections
        self.q_proj = nn.Linear(d_model, d_model, bias=False)
        self.k_proj = nn.Linear(d_model, d_model, bias=False)
        self.v_proj = nn.Linear(d_model, d_model, bias=False)
        self.out_proj = nn.Linear(d_model, d_model, bias=False)
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Optimization flags
        self.use_flash_attention = use_flash_attention and FLASH_ATTENTION_AVAILABLE
        self.use_xformers = use_xformers and XFORMERS_AVAILABLE
        self.use_grouped_query = use_grouped_query
        
        # KV cache for inference
        self.k_cache = None
        self.v_cache = None
        
    def forward(self, query: torch.Tensor, key: torch.Tensor, value: torch.Tensor,
                attention_mask: Optional[torch.Tensor] = None,
                use_cache: bool = False) -> torch.Tensor:
        """Forward pass with optimized attention."""
        batch_size, seq_len, _ = query.shape
        
        # Project queries, keys, and values
        q = self.q_proj(query).view(batch_size, seq_len, self.num_heads, self.head_dim).transpose(1, 2)
        k = self.k_proj(key).view(batch_size, seq_len, self.num_kv_heads, self.head_dim).transpose(1, 2)
        v = self.v_proj(value).view(batch_size, seq_len, self.num_kv_heads, self.head_dim).transpose(1, 2)
        
        # Handle grouped query attention
        if self.use_grouped_query and self.num_kv_heads < self.num_heads:
            k = k.repeat_interleave(self.num_heads // self.num_kv_heads, dim=2)
            v = v.repeat_interleave(self.num_heads // self.num_kv_heads, dim=2)
        
        # Use optimized attention if available
        if self.use_flash_attention and attention_mask is None:
            # Flash Attention (no attention mask)
            output = flash_attn_func(q, k, v, dropout_p=self.dropout.p if self.training else 0.0)
            output = output.transpose(1, 2).contiguous().view(batch_size, seq_len, self.d_model)
        elif self.use_xformers and attention_mask is None:
            # XFormers memory efficient attention
            output = memory_efficient_attention(q, k, v, dropout_p=self.dropout.p if self.training else 0.0)
            output = output.transpose(1, 2).contiguous().view(batch_size, seq_len, self.d_model)
        else:
            # Standard scaled dot-product attention
            scores = torch.matmul(q, k.transpose(-2, -1)) * self.scale
            
            if attention_mask is not None:
                scores = scores + attention_mask
            
            attn_weights = F.softmax(scores, dim=-1)
            attn_weights = self.dropout(attn_weights)
            
            output = torch.matmul(attn_weights, v)
            output = output.transpose(1, 2).contiguous().view(batch_size, seq_len, self.d_model)
        
        # Final projection
        output = self.out_proj(output)
        
        # Update KV cache if requested
        if use_cache:
            if self.k_cache is None:
                self.k_cache = k
                self.v_cache = v
            else:
                self.k_cache = torch.cat([self.k_cache, k], dim=2)
                self.v_cache = torch.cat([self.v_cache, v], dim=2)
        
        return output
    
    def clear_cache(self):
        """Clear the KV cache."""
        self.k_cache = None
        self.v_cache = None


class RotaryPositionalEmbedding(nn.Module):
    """Rotary Positional Embedding (RoPE) for transformers."""
    
    def __init__(self, dim: int, max_position_embeddings: int = 2048, base: int = 10000):
        super().__init__()
        self.dim = dim
        self.max_position_embeddings = max_position_embeddings
        self.base = base
        
        # Generate rotation matrix
        inv_freq = 1.0 / (self.base ** (torch.arange(0, self.dim, 2).float() / self.dim))
        self.register_buffer('inv_freq', inv_freq)
        
    def forward(self, x: torch.Tensor, seq_len: int) -> torch.Tensor:
        """Apply rotary positional embeddings."""
        t = torch.arange(seq_len, device=x.device).type_as(self.inv_freq)
        freqs = torch.outer(t, self.inv_freq)
        emb = torch.cat((freqs, freqs), dim=-1)
        
        # Apply rotation
        cos = emb.cos()
        sin = emb.sin()
        
        # Reshape for broadcasting
        cos = cos.view(1, seq_len, 1, -1)
        sin = sin.view(1, seq_len, 1, -1)
        
        # Split input into even and odd dimensions
        x_even = x[..., ::2]
        x_odd = x[..., 1::2]
        
        # Apply rotation
        rotated = torch.cat([
            x_even * cos - x_odd * sin,
            x_even * sin + x_odd * cos
        ], dim=-1)
        
        return rotated


class ALiBiPositionalEmbedding(nn.Module):
    """Attention with Linear Biases (ALiBi) positional embedding."""
    
    def __init__(self, num_heads: int, max_position_embeddings: int = 2048):
        super().__init__()
        self.num_heads = num_heads
        self.max_position_embeddings = max_position_embeddings
        
        # Generate ALiBi slopes
        slopes = torch.Tensor(self._get_slopes(num_heads))
        self.register_buffer('slopes', slopes)
        
    def _get_slopes(self, n: int) -> List[float]:
        """Get ALiBi slopes for n heads."""
        def get_slopes_power_of_2(n):
            start = (2**(-2**-(math.log2(n)-3)))
            ratio = start
            return [start*ratio**i for i in range(n)]
        
        if math.log2(n).is_integer():
            return get_slopes_power_of_2(n)
        else:
            closest_power_of_2 = 2**math.floor(math.log2(n))
            return (get_slopes_power_of_2(closest_power_of_2) + 
                   self._get_slopes(2*closest_power_of_2)[0::2][:n-closest_power_of_2])
    
    def forward(self, attention_scores: torch.Tensor, seq_len: int) -> torch.Tensor:
        """Add ALiBi biases to attention scores."""
        # Generate position indices
        pos_indices = torch.arange(seq_len, device=attention_scores.device)
        
        # Create ALiBi matrix
        alibi = pos_indices.unsqueeze(0) - pos_indices.unsqueeze(1)
        alibi = alibi.unsqueeze(0).expand(self.num_heads, -1, -1)
        
        # Apply slopes
        alibi = alibi * self.slopes.unsqueeze(-1).unsqueeze(-1)
        
        # Add to attention scores
        return attention_scores + alibi


class SwiGLU(nn.Module):
    """SwiGLU activation function for modern transformers."""
    
    def __init__(self, hidden_size: int, intermediate_size: int, bias: bool = True):
        super().__init__()
        self.w1 = nn.Linear(hidden_size, intermediate_size, bias=bias)
        self.w2 = nn.Linear(hidden_size, intermediate_size, bias=bias)
        self.w3 = nn.Linear(intermediate_size, hidden_size, bias=bias)
        
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """Forward pass with SwiGLU activation."""
        return self.w3(F.silu(self.w1(x)) * self.w2(x))


class RMSNorm(nn.Module):
    """Root Mean Square Layer Normalization."""
    
    def __init__(self, hidden_size: int, eps: float = 1e-6):
        super().__init__()
        self.weight = nn.Parameter(torch.ones(hidden_size))
        self.variance_epsilon = eps
        
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """Apply RMS normalization."""
        variance = x.pow(2).mean(-1, keepdim=True)
        x = x * torch.rsqrt(variance + self.variance_epsilon)
        return self.weight * x


