# Multi-Modal LLM Support
# =============================================================================

class VisionLanguageModel(nn.Module):
    """Vision-Language Model for multi-modal understanding."""
    
    def __init__(self, config: AdvancedLLMConfig):
        super().__init__()
        self.config = config
        
        # Vision encoder (CLIP-like)
        self.vision_encoder = self._create_vision_encoder()
        
        # Language model
        self.language_model = AdvancedLLMModel(config)
        
        # Vision-language projection
        self.vision_projection = nn.Linear(
            self.vision_encoder.config.hidden_size,
            config.hidden_size
        )
        
        # Multi-modal fusion
        self.multimodal_fusion = nn.TransformerEncoderLayer(
            d_model=config.hidden_size,
            nhead=config.num_attention_heads,
            dim_feedforward=config.intermediate_size,
            dropout=0.1
        )
    
    def _create_vision_encoder(self):
        """Create vision encoder (placeholder for CLIP integration)."""
        # This would integrate with CLIP or similar vision models
        return nn.Identity()  # Placeholder
    
    def forward(self, images: torch.Tensor, text_input_ids: torch.Tensor,
                attention_mask: Optional[torch.Tensor] = None) -> Dict[str, torch.Tensor]:
        """Forward pass for vision-language understanding."""
        # Encode images
        vision_features = self.vision_encoder(images)
        vision_features = self.vision_projection(vision_features)
        
        # Encode text
        text_features = self.language_model.embed_tokens(text_input_ids)
        
        # Concatenate vision and text features
        multimodal_features = torch.cat([vision_features, text_features], dim=1)
        
        # Apply multimodal fusion
        multimodal_features = self.multimodal_fusion(multimodal_features)
        
        # Generate language model output
        outputs = self.language_model(
            input_ids=text_input_ids,
            attention_mask=attention_mask
        )
        
        return {
            "logits": outputs["logits"],
            "multimodal_features": multimodal_features
        }


# =============================================================================
# LLM Training and Fine-tuning
# =============================================================================

class LLMTrainer:
    """Advanced trainer for LLM fine-tuning."""
    
    def __init__(self, model: nn.Module, tokenizer: PreTrainedTokenizer, config: AdvancedLLMConfig):
        self.model = model
        self.tokenizer = tokenizer
        self.config = config
        
        # Training configuration
        self.training_args = TrainingArguments(
            output_dir="./llm_output",
            num_train_epochs=3,
            per_device_train_batch_size=4,
            per_device_eval_batch_size=4,
            gradient_accumulation_steps=4,
            learning_rate=2e-5,
            weight_decay=0.01,
            warmup_steps=100,
            logging_steps=10,
            save_steps=500,
            eval_steps=500,
            evaluation_strategy="steps",
            save_strategy="steps",
            load_best_model_at_end=True,
            metric_for_best_model="eval_loss",
            greater_is_better=False,
            fp16=self.config.use_mixed_precision,
            dataloader_pin_memory=True,
            dataloader_num_workers=4,
            remove_unused_columns=False,
            report_to=["wandb"] if wandb.run else None
        )
        
        # Data collator
        self.data_collator = DataCollatorForLanguageModeling(
            tokenizer=self.tokenizer,
            mlm=False,  # Causal language modeling
            return_tensors="pt"
        )
    
    def train(self, train_dataset: Dataset, eval_dataset: Optional[Dataset] = None):
        """Train the LLM."""
        # Initialize trainer
        trainer = Trainer(
            model=self.model,
            args=self.training_args,
            train_dataset=train_dataset,
            eval_dataset=eval_dataset,
            data_collator=self.data_collator,
            tokenizer=self.tokenizer
        )
        
        # Train
        trainer.train()
        
        # Save model
        trainer.save_model()
        self.tokenizer.save_pretrained(self.training_args.output_dir)
        
        return trainer


# =============================================================================
# Efficient Fine-tuning Techniques (LoRA, P-tuning, etc.)
# =============================================================================

class LoRAConfig:
    """Configuration for LoRA (Low-Rank Adaptation) fine-tuning."""
    
    def __init__(self):
        # LoRA parameters
        self.lora_rank = 16  # Rank of adaptation matrices
        self.lora_alpha = 32  # Scaling factor
        self.lora_dropout = 0.1  # Dropout for LoRA layers
        self.target_modules = ["q_proj", "v_proj", "k_proj", "o_proj", "gate_proj", "up_proj", "down_proj"]
        
        # Advanced LoRA options
        self.use_rslora = False  # Rank-Stabilized LoRA
        self.use_adalora = False  # Adaptive LoRA
        self.use_qlora = False  # Quantized LoRA
        
        # Quantization settings for QLoRA
        self.bnb_4bit_compute_dtype = torch.float16
        self.bnb_4bit_use_double_quant = True
        self.bnb_4bit_quant_type = "nf4"
        
        # Task type
        self.task_type = "CAUSAL_LM"  # CAUSAL_LM, SEQ_2_SEQ_LM, TOKEN_CLS, SEQ_CLS
        
        # Bias handling
        self.bias = "none"  # none, all, lora_only


class LoRALayer(nn.Module):
    """Custom LoRA layer implementation."""
    
    def __init__(self, in_features: int, out_features: int, rank: int = 16, 
                 alpha: float = 32.0, dropout: float = 0.1):
        super().__init__()
        self.rank = rank
        self.alpha = alpha
        self.scaling = alpha / rank
        
        # LoRA matrices
        self.lora_A = nn.Parameter(torch.randn(rank, in_features) * 0.02)
        self.lora_B = nn.Parameter(torch.zeros(out_features, rank))
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        # Initialize weights
        self._init_weights()
    
    def _init_weights(self):
        """Initialize LoRA weights."""
        nn.init.kaiming_uniform_(self.lora_A, a=math.sqrt(5))
        nn.init.zeros_(self.lora_B)
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """Forward pass through LoRA layer."""
        # LoRA computation: x @ (B @ A) * scaling
        lora_output = F.linear(x, self.lora_B @ self.lora_A) * self.scaling
        return self.dropout(lora_output)


class LoRALinear(nn.Module):
    """Linear layer with LoRA adaptation."""
    
    def __init__(self, base_layer: nn.Linear, rank: int = 16, alpha: float = 32.0, 
                 dropout: float = 0.1, trainable_base: bool = False):
        super().__init__()
        self.base_layer = base_layer
        self.trainable_base = trainable_base
        
        # Freeze base layer if not trainable
        if not trainable_base:
            for param in self.base_layer.parameters():
                param.requires_grad = False
        
        # LoRA adaptation
        self.lora = LoRALayer(
            base_layer.in_features, 
            base_layer.out_features, 
            rank, alpha, dropout
        )
        
        # Track if LoRA is enabled
        self.lora_enabled = True
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """Forward pass combining base layer and LoRA."""
        base_output = self.base_layer(x)
        
        if self.lora_enabled:
            lora_output = self.lora(x)
            return base_output + lora_output
        
        return base_output
    
    def enable_lora(self):
        """Enable LoRA adaptation."""
        self.lora_enabled = True
    
    def disable_lora(self):
        """Disable LoRA adaptation."""
        self.lora_enabled = False
    
    def merge_lora(self):
        """Merge LoRA weights into base layer."""
        if self.lora_enabled:
            # Merge LoRA weights: W = W_base + (B @ A) * scaling
            lora_weight = self.lora.lora_B @ self.lora.lora_A * self.lora.scaling
            self.base_layer.weight.data += lora_weight
            
            # Reset LoRA weights
            nn.init.zeros_(self.lora.lora_B)
            self.lora_enabled = False


class AdaLoRALayer(nn.Module):
    """Adaptive LoRA layer with dynamic rank adjustment."""
    
    def __init__(self, in_features: int, out_features: int, init_rank: int = 16,
                 target_rank: int = 8, alpha: float = 32.0, dropout: float = 0.1):
        super().__init__()
        self.init_rank = init_rank
        self.target_rank = target_rank
        self.current_rank = init_rank
        self.alpha = alpha
        
        # Initialize with full rank
        self.lora_A = nn.Parameter(torch.randn(init_rank, in_features) * 0.02)
        self.lora_B = nn.Parameter(torch.zeros(out_features, init_rank))
        
        # Importance scores for rank pruning
        self.importance_scores = nn.Parameter(torch.ones(init_rank))
        
        # Dropout
        self.dropout = nn.Dropout(dropout)
        
        self._init_weights()
    
    def _init_weights(self):
        """Initialize AdaLoRA weights."""
        nn.init.kaiming_uniform_(self.lora_A, a=math.sqrt(5))
        nn.init.zeros_(self.lora_B)
        nn.init.ones_(self.importance_scores)
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """Forward pass with adaptive rank."""
        # Apply importance masking
        if self.training:
            mask = torch.sigmoid(self.importance_scores)
            masked_A = self.lora_A * mask.unsqueeze(1)
            masked_B = self.lora_B * mask.unsqueeze(0)
        else:
            # Use top-k important dimensions
            _, top_indices = torch.topk(self.importance_scores, self.current_rank)
            masked_A = self.lora_A[top_indices]
            masked_B = self.lora_B[:, top_indices]
        
        # LoRA computation
        scaling = self.alpha / self.current_rank
        lora_output = F.linear(x, masked_B @ masked_A) * scaling
        return self.dropout(lora_output)
    
    def prune_to_target_rank(self):
        """Prune to target rank based on importance scores."""
        if self.current_rank > self.target_rank:
            _, top_indices = torch.topk(self.importance_scores, self.target_rank)
            
            # Update parameters
            self.lora_A.data = self.lora_A.data[top_indices]
            self.lora_B.data = self.lora_B.data[:, top_indices]
            self.importance_scores.data = self.importance_scores.data[top_indices]
            
            self.current_rank = self.target_rank
            logger.info(f"Pruned AdaLoRA rank to {self.current_rank}")


class PrefixTuningLayer(nn.Module):
    """Prefix tuning layer for efficient fine-tuning."""
    
    def __init__(self, config: AdvancedLLMConfig, prefix_length: int = 10):
        super().__init__()
        self.config = config
        self.prefix_length = prefix_length
        self.hidden_size = config.hidden_size
        self.num_layers = config.num_hidden_layers
        self.num_heads = config.num_attention_heads
        self.head_dim = self.hidden_size // self.num_heads
        
        # Prefix parameters for each layer
        self.prefix_keys = nn.Parameter(
            torch.randn(self.num_layers, self.num_heads, prefix_length, self.head_dim)
        )
        self.prefix_values = nn.Parameter(
            torch.randn(self.num_layers, self.num_heads, prefix_length, self.head_dim)
        )
        
        # Reparameterization MLP
        self.prefix_mlp = nn.Sequential(
            nn.Linear(self.hidden_size, self.hidden_size),
            nn.Tanh(),
            nn.Linear(self.hidden_size, self.num_layers * 2 * self.hidden_size)
        )
        
        self._init_weights()
    
    def _init_weights(self):
        """Initialize prefix tuning weights."""
        nn.init.normal_(self.prefix_keys, std=0.02)
        nn.init.normal_(self.prefix_values, std=0.02)
        
        for module in self.prefix_mlp:
            if isinstance(module, nn.Linear):
                nn.init.normal_(module.weight, std=0.02)
                nn.init.zeros_(module.bias)
    
    def get_prefix_states(self, batch_size: int) -> Tuple[torch.Tensor, torch.Tensor]:
        """Get prefix key and value states for all layers."""
        # Expand for batch size
        prefix_keys = self.prefix_keys.unsqueeze(0).expand(
            batch_size, self.num_layers, self.num_heads, self.prefix_length, self.head_dim
        )
        prefix_values = self.prefix_values.unsqueeze(0).expand(
            batch_size, self.num_layers, self.num_heads, self.prefix_length, self.head_dim
        )
        
        return prefix_keys, prefix_values


class PromptTuningLayer(nn.Module):
    """Prompt tuning layer for efficient fine-tuning."""
    
    def __init__(self, config: AdvancedLLMConfig, num_virtual_tokens: int = 10,
                 init_method: str = "random"):
        super().__init__()
        self.config = config
        self.num_virtual_tokens = num_virtual_tokens
        self.hidden_size = config.hidden_size
        self.init_method = init_method
        
        # Virtual token embeddings
        self.virtual_tokens = nn.Parameter(
            torch.randn(num_virtual_tokens, self.hidden_size)
        )
        
        self._init_weights()
    
    def _init_weights(self):
        """Initialize prompt tuning weights."""
        if self.init_method == "random":
            nn.init.normal_(self.virtual_tokens, std=0.02)
        elif self.init_method == "vocab_sample":
            # Initialize from vocabulary distribution (would need tokenizer)
            nn.init.normal_(self.virtual_tokens, std=0.02)
    
    def forward(self, input_embeddings: torch.Tensor) -> torch.Tensor:
        """Prepend virtual tokens to input embeddings."""
        batch_size = input_embeddings.size(0)
        
        # Expand virtual tokens for batch
        virtual_tokens = self.virtual_tokens.unsqueeze(0).expand(
            batch_size, self.num_virtual_tokens, self.hidden_size
        )
        
        # Concatenate with input embeddings
        return torch.cat([virtual_tokens, input_embeddings], dim=1)


class PEFTModelWrapper(nn.Module):
    """Wrapper for applying PEFT methods to existing models."""
    
    def __init__(self, base_model: nn.Module, peft_config: LoRAConfig):
        super().__init__()
        self.base_model = base_model
        self.peft_config = peft_config
        self.peft_type = self._determine_peft_type()
        
        # Apply PEFT method
        if self.peft_type == "lora":
            self._apply_lora()
        elif self.peft_type == "adalora":
            self._apply_adalora()
        elif self.peft_type == "prefix_tuning":
            self._apply_prefix_tuning()
        elif self.peft_type == "prompt_tuning":
            self._apply_prompt_tuning()
        
        # Track trainable parameters
        self._update_trainable_params()
    
    def _determine_peft_type(self) -> str:
        """Determine PEFT type from config."""
        if self.peft_config.use_adalora:
            return "adalora"
        elif hasattr(self.peft_config, "prefix_length"):
            return "prefix_tuning"
        elif hasattr(self.peft_config, "num_virtual_tokens"):
            return "prompt_tuning"
        else:
            return "lora"
    
    def _apply_lora(self):
        """Apply LoRA to target modules."""
        target_modules = self.peft_config.target_modules
        
        for name, module in self.base_model.named_modules():
            if any(target in name for target in target_modules):
                if isinstance(module, nn.Linear):
                    # Replace with LoRA linear layer
                    lora_layer = LoRALinear(
                        module,
                        rank=self.peft_config.lora_rank,
                        alpha=self.peft_config.lora_alpha,
                        dropout=self.peft_config.lora_dropout
                    )
                    
                    # Replace in parent module
                    parent_name = ".".join(name.split(".")[:-1])
                    child_name = name.split(".")[-1]
                    
                    if parent_name:
                        parent = dict(self.base_model.named_modules())[parent_name]
                        setattr(parent, child_name, lora_layer)
                    else:
                        setattr(self.base_model, child_name, lora_layer)
        
        logger.info(f"Applied LoRA to {len(target_modules)} module types")
    
    def _apply_adalora(self):
        """Apply AdaLoRA to target modules."""
        # Similar to LoRA but with AdaLoRA layers
        target_modules = self.peft_config.target_modules
        
        for name, module in self.base_model.named_modules():
            if any(target in name for target in target_modules):
                if isinstance(module, nn.Linear):
                    # Create AdaLoRA linear layer
                    adalora_layer = self._create_adalora_linear(module)
                    
                    # Replace in parent module
                    parent_name = ".".join(name.split(".")[:-1])
                    child_name = name.split(".")[-1]
                    
                    if parent_name:
                        parent = dict(self.base_model.named_modules())[parent_name]
                        setattr(parent, child_name, adalora_layer)
                    else:
                        setattr(self.base_model, child_name, adalora_layer)
        
        logger.info("Applied AdaLoRA to target modules")
    
    def _create_adalora_linear(self, base_layer: nn.Linear) -> nn.Module:
        """Create AdaLoRA linear layer."""
        class AdaLoRALinear(nn.Module):
            def __init__(self, base_layer, config):
                super().__init__()
                self.base_layer = base_layer
                
                # Freeze base layer
                for param in base_layer.parameters():
                    param.requires_grad = False
                
                # AdaLoRA adaptation
                self.adalora = AdaLoRALayer(
                    base_layer.in_features,
                    base_layer.out_features,
                    init_rank=config.lora_rank,
                    target_rank=config.lora_rank // 2,
                    alpha=config.lora_alpha,
                    dropout=config.lora_dropout
                )
            
            def forward(self, x):
                base_output = self.base_layer(x)
                adalora_output = self.adalora(x)
                return base_output + adalora_output
        
        return AdaLoRALinear(base_layer, self.peft_config)
    
    def _apply_prefix_tuning(self):
        """Apply prefix tuning."""
        # Add prefix tuning layer
        if hasattr(self.base_model, 'config'):
            config = self.base_model.config
        else:
            config = self.peft_config
        
        self.prefix_tuning = PrefixTuningLayer(config)
        logger.info("Applied Prefix Tuning")
    
    def _apply_prompt_tuning(self):
        """Apply prompt tuning."""
        if hasattr(self.base_model, 'config'):
            config = self.base_model.config
        else:
            config = self.peft_config
        
        self.prompt_tuning = PromptTuningLayer(config)
        logger.info("Applied Prompt Tuning")
    
    def _update_trainable_params(self):
        """Update trainable parameters count."""
        total_params = sum(p.numel() for p in self.base_model.parameters())
        trainable_params = sum(p.numel() for p in self.base_model.parameters() if p.requires_grad)
        
        self.total_params = total_params
        self.trainable_params = trainable_params
        self.trainable_ratio = trainable_params / total_params * 100
        
        logger.info(f"Total parameters: {total_params:,}")
        logger.info(f"Trainable parameters: {trainable_params:,}")
        logger.info(f"Trainable ratio: {self.trainable_ratio:.2f}%")
    
    def forward(self, *args, **kwargs):
        """Forward pass through PEFT model."""
        if self.peft_type == "prompt_tuning":
            # Handle prompt tuning
            input_ids = kwargs.get('input_ids') or args[0]
            if hasattr(self.base_model, 'embed_tokens'):
                input_embeddings = self.base_model.embed_tokens(input_ids)
                augmented_embeddings = self.prompt_tuning(input_embeddings)
                # Update kwargs or args for model
                kwargs['inputs_embeds'] = augmented_embeddings
                if 'input_ids' in kwargs:
                    del kwargs['input_ids']
        
        return self.base_model(*args, **kwargs)
    
    def print_trainable_parameters(self):
        """Print summary of trainable parameters."""
        print(f"Total parameters: {self.total_params:,}")
        print(f"Trainable parameters: {self.trainable_params:,}")
        print(f"Trainable ratio: {self.trainable_ratio:.2f}%")
    
    def merge_and_unload(self):
        """Merge PEFT weights and return base model."""
        if self.peft_type == "lora":
            for module in self.base_model.modules():
                if isinstance(module, LoRALinear):
                    module.merge_lora()
        
        return self.base_model


class PEFTTrainer:
    """Specialized trainer for PEFT methods."""
    
    def __init__(self, model: PEFTModelWrapper, tokenizer, config: LoRAConfig):
        self.model = model
        self.tokenizer = tokenizer
        self.config = config
        
        # Training configuration
        self.training_args = self._create_training_args()
        
        # Optimizer (only train PEFT parameters)
        self.optimizer = self._create_optimizer()
        
        # Scheduler
        self.scheduler = self._create_scheduler()
        
        # Tracking
        self.global_step = 0
        self.best_loss = float('inf')
    
    def _create_training_args(self):
        """Create training arguments for PEFT."""
        return {
            "learning_rate": 2e-4,  # Higher LR for PEFT
            "per_device_train_batch_size": 4,
            "per_device_eval_batch_size": 4,
            "gradient_accumulation_steps": 4,
            "num_train_epochs": 3,
            "warmup_steps": 100,
            "logging_steps": 10,
            "save_steps": 500,
            "eval_steps": 500,
            "fp16": True,
            "dataloader_pin_memory": True,
            "remove_unused_columns": False,
            "report_to": ["wandb"] if wandb.run else None
        }
    
    def _create_optimizer(self):
        """Create optimizer for PEFT parameters only."""
        # Only optimize trainable parameters
        trainable_params = [p for p in self.model.parameters() if p.requires_grad]
        
        optimizer = torch.optim.AdamW(
            trainable_params,
            lr=self.training_args["learning_rate"],
            weight_decay=0.01,
            betas=(0.9, 0.999),
            eps=1e-8
        )
        
        return optimizer
    
    def _create_scheduler(self):
        """Create learning rate scheduler."""
        from torch.optim.lr_scheduler import CosineAnnealingLR
        
        scheduler = CosineAnnealingLR(
            self.optimizer,
            T_max=1000,  # Will be updated based on dataset size
            eta_min=1e-6
        )
        
        return scheduler
    
    def train(self, train_dataset, eval_dataset=None):
        """Train the PEFT model."""
        logger.info("Starting PEFT training...")
        
        # Print trainable parameters
        self.model.print_trainable_parameters()
        
        # Create data loader
        train_loader = DataLoader(
            train_dataset,
            batch_size=self.training_args["per_device_train_batch_size"],
            shuffle=True,
            pin_memory=self.training_args["dataloader_pin_memory"]
        )
        
        # Training loop
        self.model.train()
        total_loss = 0.0
        
        for epoch in range(self.training_args["num_train_epochs"]):
            epoch_loss = 0.0
            
            progress_bar = tqdm(train_loader, desc=f"Epoch {epoch+1}")
            
            for batch_idx, batch in enumerate(progress_bar):
                # Move batch to device
                batch = {k: v.to(next(self.model.parameters()).device) 
                        for k, v in batch.items() if isinstance(v, torch.Tensor)}
                
                # Forward pass
                outputs = self.model(**batch)
                loss = outputs.get('loss') or self._compute_loss(outputs, batch)
                
                # Gradient accumulation
                loss = loss / self.training_args["gradient_accumulation_steps"]
                loss.backward()
                
                # Update weights
                if (batch_idx + 1) % self.training_args["gradient_accumulation_steps"] == 0:
                    # Gradient clipping
                    torch.nn.utils.clip_grad_norm_(self.model.parameters(), 1.0)
                    
                    self.optimizer.step()
                    self.scheduler.step()
                    self.optimizer.zero_grad()
                    
                    self.global_step += 1
                
                # Logging
                epoch_loss += loss.item()
                total_loss += loss.item()
                
                # Update progress bar
                progress_bar.set_postfix({
                    'loss': f'{loss.item():.4f}',
                    'lr': f'{self.optimizer.param_groups[0]["lr"]:.2e}'
                })
                
                # Log to wandb
                if wandb.run and self.global_step % self.training_args["logging_steps"] == 0:
                    wandb.log({
                        "train/loss": loss.item(),
                        "train/learning_rate": self.optimizer.param_groups[0]["lr"],
                        "train/global_step": self.global_step
                    })
            
            # Epoch summary
            avg_epoch_loss = epoch_loss / len(train_loader)
            logger.info(f"Epoch {epoch+1} - Average Loss: {avg_epoch_loss:.4f}")
            
            # Evaluation
            if eval_dataset and (epoch + 1) % 1 == 0:
                eval_loss = self.evaluate(eval_dataset)
                logger.info(f"Epoch {epoch+1} - Eval Loss: {eval_loss:.4f}")
                
                # Save best model
                if eval_loss < self.best_loss:
                    self.best_loss = eval_loss
                    self.save_model(f"best_peft_model_epoch_{epoch+1}")
        
        # Save final model
        self.save_model("final_peft_model")
        
        logger.info("PEFT training completed!")
        return total_loss / (len(train_loader) * self.training_args["num_train_epochs"])
    
    def _compute_loss(self, outputs, batch):
        """Compute loss for PEFT training."""
        logits = outputs.get('logits')
        labels = batch.get('labels')
        
        if logits is not None and labels is not None:
            loss_fct = nn.CrossEntropyLoss()
            shift_logits = logits[..., :-1, :].contiguous()
            shift_labels = labels[..., 1:].contiguous()
            loss = loss_fct(shift_logits.view(-1, shift_logits.size(-1)), shift_labels.view(-1))
            return loss
        
        return torch.tensor(0.0, requires_grad=True)
    
    def evaluate(self, eval_dataset):
        """Evaluate the PEFT model."""
        self.model.eval()
        
        eval_loader = DataLoader(
            eval_dataset,
            batch_size=self.training_args["per_device_eval_batch_size"],
            shuffle=False
        )
        
        total_loss = 0.0
        total_samples = 0
        
        with torch.no_grad():
            for batch in eval_loader:
                batch = {k: v.to(next(self.model.parameters()).device) 
                        for k, v in batch.items() if isinstance(v, torch.Tensor)}
                
                outputs = self.model(**batch)
                loss = outputs.get('loss') or self._compute_loss(outputs, batch)
                
                total_loss += loss.item() * batch['input_ids'].size(0)
                total_samples += batch['input_ids'].size(0)
        
        self.model.train()
        return total_loss / total_samples
    
    def save_model(self, output_dir: str):
        """Save PEFT model."""
        os.makedirs(output_dir, exist_ok=True)
        
        # Save only PEFT parameters
        peft_state_dict = {}
        for name, param in self.model.named_parameters():
            if param.requires_grad:
                peft_state_dict[name] = param
        
        torch.save(peft_state_dict, os.path.join(output_dir, "peft_weights.pt"))
        
        # Save config
        config_path = os.path.join(output_dir, "peft_config.json")
        with open(config_path, 'w') as f:
            json.dump(vars(self.config), f, indent=2)
        
        logger.info(f"PEFT model saved to {output_dir}")


class QLoRAIntegration:
    """QLoRA (Quantized LoRA) integration for memory-efficient fine-tuning."""
    
    def __init__(self, config: LoRAConfig):
        self.config = config
        self.quantization_config = self._create_bnb_config()
    
    def _create_bnb_config(self):
        """Create BitsAndBytes quantization config."""
        if not ADVANCED_TRANSFORMERS_AVAILABLE:
            logger.warning("BitsAndBytes not available for QLoRA")
            return None
        
        try:
            from transformers import BitsAndBytesConfig
            
            bnb_config = BitsAndBytesConfig(
                load_in_4bit=True,
                bnb_4bit_compute_dtype=self.config.bnb_4bit_compute_dtype,
                bnb_4bit_use_double_quant=self.config.bnb_4bit_use_double_quant,
                bnb_4bit_quant_type=self.config.bnb_4bit_quant_type
            )
            
            return bnb_config
        except ImportError:
            logger.warning("BitsAndBytes not available for QLoRA")
            return None
    
    def prepare_model_for_qlora(self, model):
        """Prepare model for QLoRA training."""
        if not PEFT_AVAILABLE:
            logger.warning("PEFT not available for QLoRA")
            return model
        
        try:
            from peft import prepare_model_for_kbit_training
            
            # Prepare model for k-bit training
            model = prepare_model_for_kbit_training(model)
            
            logger.info("Model prepared for QLoRA training")
            return model
        except ImportError:
            logger.warning("PEFT prepare_model_for_kbit_training not available")
            return model


