def test_advanced_attention_mechanisms():
    """Test advanced attention mechanisms."""
    logger.info("Testing advanced attention mechanisms...")
    
    try:
        # Test MultiHeadAttention
        d_model = 512
        num_heads = 8
        seq_len = 128
        batch_size = 4
        
        attention = MultiHeadAttention(
            d_model=d_model,
            num_heads=num_heads,
            use_flash_attention=FLASH_ATTENTION_AVAILABLE,
            use_xformers=XFORMERS_AVAILABLE
        )
        
        # Create test inputs
        query = torch.randn(batch_size, seq_len, d_model)
        key = torch.randn(batch_size, seq_len, d_model)
        value = torch.randn(batch_size, seq_len, d_model)
        
        # Test forward pass
        output = attention(query, key, value)
        assert output.shape == (batch_size, seq_len, d_model)
        logger.info("✓ MultiHeadAttention forward pass successful")
        
        # Test with attention mask
        attention_mask = torch.ones(batch_size, seq_len, seq_len)
        output_with_mask = attention(query, key, value, attention_mask=attention_mask)
        assert output_with_mask.shape == (batch_size, seq_len, d_model)
        logger.info("✓ MultiHeadAttention with mask successful")
        
        # Test KV cache
        output_cache = attention(query, key, value, use_cache=True)
        assert attention.k_cache is not None
        assert attention.v_cache is not None
        logger.info("✓ KV cache functionality successful")
        
        # Clear cache
        attention.clear_cache()
        assert attention.k_cache is None
        assert attention.v_cache is None
        logger.info("✓ Cache clearing successful")
        
    except Exception as e:
        logger.error(f"Advanced attention mechanisms test failed: {e}")
        raise


