def test_lora_implementation():
    """Test LoRA implementation."""
    logger.info("Testing LoRA implementation...")
    
    try:
        # Test basic LoRA layer
        lora_layer = LoRALayer(512, 256, rank=16, alpha=32.0)
        x = torch.randn(4, 10, 512)
        output = lora_layer(x)
        assert output.shape == (4, 10, 256)
        logger.info("✓ LoRA layer forward pass successful")
        
        # Test LoRA linear layer
        base_linear = nn.Linear(512, 256)
        lora_linear = LoRALinear(base_linear, rank=16, alpha=32.0)
        
        output = lora_linear(x)
        assert output.shape == (4, 10, 256)
        logger.info("✓ LoRA linear layer forward pass successful")
        
        # Test enable/disable LoRA
        lora_linear.disable_lora()
        output_disabled = lora_linear(x)
        lora_linear.enable_lora()
        output_enabled = lora_linear(x)
        
        # Should be different when LoRA is enabled vs disabled
        assert not torch.allclose(output_disabled, output_enabled)
        logger.info("✓ LoRA enable/disable functionality successful")
        
        # Test merge LoRA
        original_weight = base_linear.weight.clone()
        lora_linear.merge_lora()
        # Weight should be different after merging
        assert not torch.allclose(original_weight, base_linear.weight)
        logger.info("✓ LoRA merge functionality successful")
        
    except Exception as e:
        logger.error(f"LoRA implementation test failed: {e}")
        raise


