def main():
    """Main training function with PyTorch best practices."""
    try:
        # Initialize configuration
        config = UltraTrainingConfig()
        
        # Create output directories
        os.makedirs(config.output_dir, exist_ok=True)
        os.makedirs(config.cache_dir, exist_ok=True)
        os.makedirs(config.log_dir, exist_ok=True)
        
        # Load tokenizer
        tokenizer = AutoTokenizer.from_pretrained(
            config.model_name, 
            cache_dir=config.cache_dir
        )
        if tokenizer.pad_token is None:
            tokenizer.pad_token = tokenizer.eos_token
        
        # Initialize model
        model = UltraOptimizedTransformerModel(config.model_name, config=config)
        
        # Get model information
        model_info = get_pytorch_model_info(model)
        logger.info("Model information", **model_info)
        
        # Create sample data
        texts = ["This is a positive review", "This is a negative review"] * 100
        labels = [1, 0] * 100
        
        # Create dataset and dataloader
        dataset = UltraOptimizedDataset(texts, labels, tokenizer, config.max_length)
        dataloader = create_pytorch_dataloader(dataset, config)
        
        # Validate model with sample data
        sample_batch = next(iter(dataloader))
        if not validate_pytorch_model(model, sample_batch['input_ids']):
            raise ValueError("Model validation failed")
        
        # Initialize trainer
        trainer = UltraOptimizedTrainer(model, config)
        
        # Training loop with PyTorch best practices
        best_metrics = {'eval_loss': float('inf')}
        
        for epoch in range(config.num_epochs):
            logger.info(f"Starting epoch {epoch + 1}/{config.num_epochs}")
            
            # Train epoch
            avg_loss = trainer.train_epoch(dataloader, epoch)
            
            # Evaluation
            if epoch % 1 == 0:
                metrics = trainer.evaluate(dataloader)
                logger.info("Epoch evaluation", epoch=epoch, **metrics)
                
                # Save best model
                if metrics['eval_loss'] < best_metrics['eval_loss']:
                    best_metrics = metrics
                    checkpoint_path = os.path.join(config.output_dir, f"best_model_epoch_{epoch}.pt")
                    trainer.save_checkpoint(checkpoint_path, epoch, metrics)
                    logger.info("New best model saved", checkpoint_path=checkpoint_path)
            
            # Save regular checkpoint
            if epoch % 2 == 0:
                checkpoint_path = os.path.join(config.output_dir, f"checkpoint_epoch_{epoch}.pt")
                trainer.save_checkpoint(checkpoint_path, epoch, metrics)
        
        # Save final model
        final_checkpoint_path = os.path.join(config.output_dir, "final_model.pt")
        trainer.save_checkpoint(final_checkpoint_path, config.num_epochs - 1, metrics)
        
        # Initialize inference
        inference = UltraOptimizedInference(model, tokenizer, config)
        
        # Test inference
        result = inference.predict("This is a test review")
        logger.info("Inference test completed", result=result)
        
        logger.info("Training completed successfully", best_metrics=best_metrics)
        
    except Exception as e:
        logger.error("Training failed", error=str(e))
        raise


def train_with_resume(checkpoint_path: str):
    """Resume training from checkpoint with PyTorch best practices."""
    try:
        # Load checkpoint
        checkpoint = torch.load(checkpoint_path, map_location='cpu')
        config = checkpoint['config']
        
        # Initialize model and trainer
        model = UltraOptimizedTransformerModel(config.model_name, config=config)
        trainer = UltraOptimizedTrainer(model, config)
        
        # Load checkpoint state
        start_epoch, metrics = trainer.load_checkpoint(checkpoint_path)
        logger.info(f"Resuming training from epoch {start_epoch}", metrics=metrics)
        
        # Continue training
        for epoch in range(start_epoch + 1, config.num_epochs):
            # ... training logic ...
            pass
            
    except Exception as e:
        logger.error("Resume training failed", error=str(e))
        raise


