class AdvancedTokenizer:
    """
    Advanced tokenizer with support for multiple tokenization strategies,
    vocabulary management, and sequence processing.
    """
    
    def __init__(self, vocab_size=50000, max_length=512, padding_side='right', 
                 truncation_side='right', special_tokens=None):
        self.vocab_size = vocab_size
        self.max_length = max_length
        self.padding_side = padding_side
        self.truncation_side = truncation_side
        
        # Initialize special tokens
        self.special_tokens = special_tokens or {
            'pad_token': '[PAD]',
            'unk_token': '[UNK]',
            'cls_token': '[CLS]',
            'sep_token': '[SEP]',
            'mask_token': '[MASK]',
            'bos_token': '[BOS]',
            'eos_token': '[EOS]'
        }
        
        # Initialize vocabulary
        self.word2idx = {token: idx for idx, token in enumerate(self.special_tokens.values())}
        self.idx2word = {idx: token for token, idx in self.word2idx.items()}
        self.vocab = list(self.special_tokens.values())
        
        # Tokenization statistics
        self.tokenization_stats = {
            'total_tokens': 0,
            'unique_tokens': 0,
            'vocab_coverage': 0.0
        }
    
    def build_vocabulary(self, texts, min_freq=2, max_vocab_size=None):
        """Build vocabulary from text corpus."""
        if max_vocab_size is None:
            max_vocab_size = self.vocab_size
        
        # Count word frequencies
        word_freq = {}
        for text in texts:
            words = self._tokenize_text(text)
            for word in words:
                word_freq[word] = word_freq.get(word, 0) + 1
        
        # Filter by minimum frequency
        filtered_words = {word: freq for word, freq in word_freq.items() 
                         if freq >= min_freq}
        
        # Sort by frequency and limit vocabulary size
        sorted_words = sorted(filtered_words.items(), key=lambda x: x[1], reverse=True)
        vocab_words = [word for word, _ in sorted_words[:max_vocab_size - len(self.special_tokens)]]
        
        # Update vocabulary
        for word in vocab_words:
            if word not in self.word2idx:
                idx = len(self.word2idx)
                self.word2idx[word] = idx
                self.idx2word[idx] = word
                self.vocab.append(word)
        
        # Update statistics
        self.tokenization_stats['unique_tokens'] = len(self.word2idx)
        self.tokenization_stats['vocab_coverage'] = len(self.word2idx) / max_vocab_size
        
        return self.word2idx
    
    def _tokenize_text(self, text):
        """Basic text tokenization (word-level)."""
        # Simple word tokenization - can be enhanced with more sophisticated methods
        return text.lower().split()
    
    def encode(self, text, add_special_tokens=True, return_tensors=None):
        """Encode text to token IDs."""
        # Tokenize text
        tokens = self._tokenize_text(text)
        
        # Convert to IDs
        token_ids = []
        for token in tokens:
            if token in self.word2idx:
                token_ids.append(self.word2idx[token])
            else:
                token_ids.append(self.word2idx[self.special_tokens['unk_token']])
        
        # Add special tokens
        if add_special_tokens:
            token_ids = ([self.word2idx[self.special_tokens['cls_token']]] + 
                        token_ids + 
                        [self.word2idx[self.special_tokens['sep_token']]])
        
        # Truncate if necessary
        if len(token_ids) > self.max_length:
            if self.truncation_side == 'right':
                token_ids = token_ids[:self.max_length]
            else:
                token_ids = token_ids[-self.max_length:]
        
        # Pad if necessary
        if len(token_ids) < self.max_length:
            pad_id = self.word2idx[self.special_tokens['pad_token']]
            if self.padding_side == 'right':
                token_ids = token_ids + [pad_id] * (self.max_length - len(token_ids))
            else:
                token_ids = [pad_id] * (self.max_length - len(token_ids)) + token_ids
        
        # Convert to tensor if requested
        if return_tensors == 'pt':
            return torch.tensor(token_ids, dtype=torch.long)
        elif return_tensors == 'np':
            return np.array(token_ids, dtype=np.int64)
        
        return token_ids
    
    def decode(self, token_ids, skip_special_tokens=True):
        """Decode token IDs back to text."""
        if isinstance(token_ids, torch.Tensor):
            token_ids = token_ids.tolist()
        elif isinstance(token_ids, np.ndarray):
            token_ids = token_ids.tolist()
        
        # Convert IDs to tokens
        tokens = []
        for token_id in token_ids:
            if token_id in self.idx2word:
                token = self.idx2word[token_id]
                if skip_special_tokens and token in self.special_tokens.values():
                    continue
                tokens.append(token)
        
        return ' '.join(tokens)
    
    def get_vocabulary_info(self):
        """Get information about the vocabulary."""
        return {
            'vocab_size': len(self.word2idx),
            'special_tokens': self.special_tokens,
            'stats': self.tokenization_stats
        }


class SubwordTokenizer:
    """
    Subword tokenizer using Byte Pair Encoding (BPE) algorithm.
    """
    
    def __init__(self, vocab_size=30000, min_freq=2, max_length=512):
        self.vocab_size = vocab_size
        self.min_freq = min_freq
        self.max_length = max_length
        self.merges = {}
        self.vocab = {}
        self.reverse_vocab = {}
        
    def train(self, texts):
        """Train the BPE tokenizer on a corpus of texts."""
        # Initialize vocabulary with characters
        word_freq = {}
        for text in texts:
            words = text.split()
            for word in words:
                word_freq[word] = word_freq.get(word, 0) + 1
        
        # Initialize vocabulary with individual characters
        char_vocab = set()
        for word in word_freq.keys():
            char_vocab.update(word)
        
        self.vocab = {char: i for i, char in enumerate(char_vocab)}
        self.reverse_vocab = {i: char for char, i in self.vocab.items()}
        
        # BPE training
        for _ in range(self.vocab_size - len(self.vocab)):
            # Find most frequent pair
            pair_freq = {}
            for word, freq in word_freq.items():
                if freq < self.min_freq:
                    continue
                
                # Split word into subword units
                subwords = self._word_to_subwords(word)
                
                # Count adjacent pairs
                for i in range(len(subwords) - 1):
                    pair = (subwords[i], subwords[i + 1])
                    pair_freq[pair] = pair_freq.get(pair, 0) + freq
            
            if not pair_freq:
                break
            
            # Merge most frequent pair
            best_pair = max(pair_freq.items(), key=lambda x: x[1])[0]
            new_token = ''.join(best_pair)
            
            # Add to vocabulary
            if new_token not in self.vocab:
                self.vocab[new_token] = len(self.vocab)
                self.reverse_vocab[len(self.vocab) - 1] = new_token
                self.merges[best_pair] = new_token
    
    def _word_to_subwords(self, word):
        """Convert word to list of subword units."""
        subwords = list(word)
        
        # Apply merges
        for (a, b), merged in self.merges.items():
            i = 0
            while i < len(subwords) - 1:
                if subwords[i] == a and subwords[i + 1] == b:
                    subwords[i:i + 2] = [merged]
                else:
                    i += 1
        
        return subwords
    
    def encode(self, text, add_special_tokens=True):
        """Encode text using trained BPE vocabulary."""
        words = text.split()
        token_ids = []
        
        for word in words:
            subwords = self._word_to_subwords(word)
            for subword in subwords:
                if subword in self.vocab:
                    token_ids.append(self.vocab[subword])
                else:
                    # Handle unknown subwords
                    token_ids.append(self.vocab.get('<unk>', 0))
        
        # Truncate if necessary
        if len(token_ids) > self.max_length:
            token_ids = token_ids[:self.max_length]
        
        return token_ids
    
    def decode(self, token_ids):
        """Decode token IDs back to text."""
        if isinstance(token_ids, torch.Tensor):
            token_ids = token_ids.tolist()
        
        tokens = []
        for token_id in token_ids:
            if token_id in self.reverse_vocab:
                tokens.append(self.reverse_vocab[token_id])
        
        return ' '.join(tokens)


class SequenceProcessor:
    """
    Advanced sequence processor for handling variable-length sequences,
    batching, and data augmentation.
    """
    
    def __init__(self, max_length=512, padding_strategy='longest', 
                 truncation_strategy='longest_first', return_tensors='pt'):
        self.max_length = max_length
        self.padding_strategy = padding_strategy
        self.truncation_strategy = truncation_strategy
        self.return_tensors = return_tensors
    
    def process_batch(self, texts, tokenizer):
        """Process a batch of texts with consistent padding and truncation."""
        # Tokenize all texts
        tokenized = [tokenizer.encode(text, add_special_tokens=True) for text in texts]
        
        # Determine padding length
        if self.padding_strategy == 'longest':
            max_len = min(max(len(seq) for seq in tokenized), self.max_length)
        else:
            max_len = self.max_length
        
        # Pad and truncate sequences
        processed_sequences = []
        attention_masks = []
        
        for seq in tokenized:
            # Truncate if necessary
            if len(seq) > max_len:
                if self.truncation_strategy == 'longest_first':
                    seq = seq[:max_len]
                else:
                    seq = seq[-max_len:]
            
            # Create attention mask
            attention_mask = [1] * len(seq)
            
            # Pad if necessary
            if len(seq) < max_len:
                pad_length = max_len - len(seq)
                seq = seq + [0] * pad_length  # Assuming 0 is pad token ID
                attention_mask = attention_mask + [0] * pad_length
            
            processed_sequences.append(seq)
            attention_masks.append(attention_mask)
        
        # Convert to tensors
        if self.return_tensors == 'pt':
            input_ids = torch.tensor(processed_sequences, dtype=torch.long)
            attention_mask = torch.tensor(attention_masks, dtype=torch.long)
            return {
                'input_ids': input_ids,
                'attention_mask': attention_mask
            }
        else:
            return {
                'input_ids': processed_sequences,
                'attention_mask': attention_masks
            }
    
    def create_sliding_windows(self, text, tokenizer, window_size=512, stride=256):
        """Create sliding windows for long sequences."""
        tokens = tokenizer.encode(text, add_special_tokens=True)
        
        windows = []
        for i in range(0, len(tokens), stride):
            window = tokens[i:i + window_size]
            if len(window) >= window_size // 2:  # Only keep windows with sufficient content
                windows.append(window)
        
        return windows
    
    def apply_data_augmentation(self, text, augmentation_type='random'):
        """Apply data augmentation techniques."""
        if augmentation_type == 'random':
            # Random character substitution
            chars = list(text)
            if len(chars) > 10:
                num_substitutions = max(1, len(chars) // 100)  # 1% substitution rate
                for _ in range(num_substitutions):
                    idx = random.randint(0, len(chars) - 1)
                    chars[idx] = random.choice('abcdefghijklmnopqrstuvwxyz')
                return ''.join(chars)
        
        return text


class TextDataset(torch.utils.data.Dataset):
    """
    PyTorch Dataset for text data with advanced preprocessing.
    """
    
    def __init__(self, texts, labels=None, tokenizer=None, processor=None,
                 max_length=512, augmentation=False):
        self.texts = texts
        self.labels = labels
        self.tokenizer = tokenizer
        self.processor = processor or SequenceProcessor(max_length=max_length)
        self.augmentation = augmentation
        
        # Preprocess all texts
        self.processed_data = []
        for i, text in enumerate(texts):
            if self.augmentation:
                text = self.processor.apply_data_augmentation(text)
            
            if self.tokenizer:
                tokens = self.tokenizer.encode(text, add_special_tokens=True)
            else:
                tokens = text.split()  # Simple word-level tokenization
            
            self.processed_data.append({
                'text': text,
                'tokens': tokens,
                'label': labels[i] if labels is not None else None
            })
    
    def __len__(self):
        return len(self.processed_data)
    
    def __getitem__(self, idx):
        item = self.processed_data[idx]
        
        if self.tokenizer:
            # Use tokenizer for encoding
            input_ids = self.tokenizer.encode(item['text'], add_special_tokens=True)
        else:
            # Use preprocessed tokens
            input_ids = item['tokens']
        
        # Truncate if necessary
        if len(input_ids) > self.processor.max_length:
            input_ids = input_ids[:self.processor.max_length]
        
        # Create attention mask
        attention_mask = [1] * len(input_ids)
        
        # Pad if necessary
        if len(input_ids) < self.processor.max_length:
            pad_length = self.processor.max_length - len(input_ids)
            input_ids = input_ids + [0] * pad_length
            attention_mask = attention_mask + [0] * pad_length
        
        result = {
            'input_ids': torch.tensor(input_ids, dtype=torch.long),
            'attention_mask': torch.tensor(attention_mask, dtype=torch.long)
        }
        
        if item['label'] is not None:
            result['labels'] = torch.tensor(item['label'], dtype=torch.long)
        
        return result


class TextDataLoader:
    """
    Advanced data loader for text data with batching, shuffling, and caching.
    """
    
    def __init__(self, dataset, batch_size=32, shuffle=True, num_workers=4,
                 pin_memory=True, drop_last=False, collate_fn=None):
        self.dataset = dataset
        self.batch_size = batch_size
        self.shuffle = shuffle
        self.num_workers = num_workers
        self.pin_memory = pin_memory
        self.drop_last = drop_last
        
        # Custom collate function for variable-length sequences
        if collate_fn is None:
            collate_fn = self._collate_fn
        
        self.dataloader = torch.utils.data.DataLoader(
            dataset,
            batch_size=batch_size,
            shuffle=shuffle,
            num_workers=num_workers,
            pin_memory=pin_memory,
            drop_last=drop_last,
            collate_fn=collate_fn
        )
    
    def _collate_fn(self, batch):
        """Custom collate function for handling variable-length sequences."""
        # Separate different types of data
        input_ids = [item['input_ids'] for item in batch]
        attention_masks = [item['attention_mask'] for item in batch]
        labels = [item.get('labels', None) for item in batch]
        
        # Pad sequences to the same length
        max_len = max(len(seq) for seq in input_ids)
        
        padded_input_ids = []
        padded_attention_masks = []
        
        for seq, mask in zip(input_ids, attention_masks):
            pad_length = max_len - len(seq)
            if pad_length > 0:
                seq = torch.cat([seq, torch.zeros(pad_length, dtype=seq.dtype)])
                mask = torch.cat([mask, torch.zeros(pad_length, dtype=mask.dtype)])
            padded_input_ids.append(seq)
            padded_attention_masks.append(mask)
        
        result = {
            'input_ids': torch.stack(padded_input_ids),
            'attention_mask': torch.stack(padded_attention_masks)
        }
        
        # Handle labels if present
        if any(label is not None for label in labels):
            valid_labels = [label for label in labels if label is not None]
            if valid_labels:
                result['labels'] = torch.stack(valid_labels)
        
        return result
    
    def __iter__(self):
        return iter(self.dataloader)
    
    def __len__(self):
        return len(self.dataloader)


