def test_diffusion_training():
    """Test diffusion model training with dummy data."""
    print("\n🏋️ Testing Diffusion Model Training...")
    
    try:
        # Create dummy dataset
        print("1. Creating dummy dataset...")
        dummy_images = torch.randn(10, 3, 32, 32)
        dummy_dataset = torch.utils.data.TensorDataset(dummy_images)
        dataloader = DataLoader(dummy_dataset, batch_size=2, shuffle=True)
        
        # Create diffusion model
        print("2. Creating diffusion model...")
        config = UltraTrainingConfig(device="cpu")
        diffusion_model = UltraOptimizedDiffusionModel(config=config)
        
        # Create advanced model
        diffusion_config = DiffusionConfig(num_timesteps=50, device="cpu")
        advanced_model = diffusion_model.create_advanced_model(diffusion_config)
        
        # Test training loop (just a few steps)
        print("3. Testing training loop...")
        optimizer = torch.optim.AdamW(advanced_model.parameters(), lr=1e-4)
        
        advanced_model.train()
        for batch_idx, (images,) in enumerate(dataloader):
            if batch_idx >= 2:  # Just test 2 batches
                break
                
            batch_size = images.shape[0]
            
            # Sample random timesteps
            t = torch.randint(0, diffusion_config.num_timesteps, (batch_size,))
            
            # Add noise
            noise = torch.randn_like(images)
            noisy_images = advanced_model.scheduler.q_sample(images, t, noise)
            
            # Predict noise
            predicted_noise = advanced_model(noisy_images, t)
            loss = F.mse_loss(predicted_noise, noise)
            
            # Backward pass
            optimizer.zero_grad()
            loss.backward()
            optimizer.step()
            
            print(f"   Batch {batch_idx + 1}, Loss: {loss.item():.4f}")
        
        print("✅ Diffusion model training test completed!")
        return True
        
    except Exception as e:
        print(f"\n❌ Diffusion training test failed: {e}")
        import traceback
        traceback.print_exc()
        return False


