            # Analyze the schedule
            betas = scheduler.betas
            alphas_cumprod = scheduler.alphas_cumprod
            
            print(f"   {schedule_type.upper():12}: β range [{betas.min():.6f}, {betas.max():.6f}], "
                  f"ᾱ range [{alphas_cumprod.min():.6f}, {alphas_cumprod.max():.6f}]")
        
