    print(f"  Trainable Parameters: {complexity_analysis['trainable_parameters']:,}")
    print(f"  Model Size: {complexity_analysis['model_size_mb']:.2f} MB")
    print(f"  Memory Efficiency: {complexity_analysis['memory_efficiency']:.2%}")
    
