def demonstrate_pytorch_data_loading_optimizations():
    """Demonstrate PyTorch-specific data loading optimizations."""
    print("\n🚀 PYTORCH DATA LOADING OPTIMIZATIONS")
    print("=" * 80)
    
    print("\n📊 PyTorch DataLoader Best Practices:")
    print("-" * 40)
    
    # Create sample dataset
    class SampleDataset(torch.utils.data.Dataset):
        def __init__(self, size=1000):
            self.size = size
            self.data = torch.randn(size, 64)
            self.targets = torch.randint(0, 10, (size,))
        
        def __len__(self):
            return self.size
        
        def __getitem__(self, idx):
            return self.data[idx], self.targets[idx]
    
    dataset = SampleDataset(1000)
    print(f"  • Dataset size: {len(dataset)}")
    print(f"  • Data shape: {dataset.data.shape}")
    print(f"  • Target shape: {dataset.targets.shape}")
    
    print("\n🔧 Optimized DataLoader Configurations:")
    print("-" * 40)
    
    # Test different DataLoader configurations
    configs = [
        {
            'name': 'Basic (No Optimization)',
            'batch_size': 32,
            'num_workers': 0,
            'pin_memory': False,
            'persistent_workers': False,
            'prefetch_factor': None
        },
        {
            'name': 'CPU Optimized',
            'batch_size': 32,
            'num_workers': min(4, os.cpu_count()) if os.cpu_count() else 0,
            'pin_memory': False,
            'persistent_workers': True,
            'prefetch_factor': 2
        },
        {
            'name': 'GPU Optimized',
            'batch_size': 64,
            'num_workers': min(4, os.cpu_count()) if os.cpu_count() else 0,
            'pin_memory': torch.cuda.is_available(),
            'persistent_workers': True,
            'prefetch_factor': 2
        }
    ]
    
    for i, config in enumerate(configs):
        print(f"\n  --- {config['name']} ---")
        print(f"    • Batch size: {config['batch_size']}")
        print(f"    • Workers: {config['num_workers']}")
        print(f"    • Pin memory: {config['pin_memory']}")
        print(f"    • Persistent workers: {config['persistent_workers']}")
        print(f"    • Prefetch factor: {config['prefetch_factor']}")
        
        try:
            # Create DataLoader
            dataloader = torch.utils.data.DataLoader(
                dataset,
                batch_size=config['batch_size'],
                shuffle=True,
                num_workers=config['num_workers'],
                pin_memory=config['pin_memory'],
                persistent_workers=config['persistent_workers'],
                prefetch_factor=config['prefetch_factor'] if config['prefetch_factor'] else 2
            )
            
            # Test basic functionality
            batch = next(iter(dataloader))
            print(f"    ✅ Created successfully - Batch shape: {batch[0].shape}")
            
        except Exception as e:
            print(f"    ❌ Failed: {str(e)}")
    
    print("\n⚡ Performance Monitoring:")
    print("-" * 40)
    
    try:
        # Create optimized dataloader for profiling
        optimized_loader = torch.utils.data.DataLoader(
            dataset,
            batch_size=32,
            shuffle=True,
            num_workers=min(2, os.cpu_count()) if os.cpu_count() else 0,
            pin_memory=torch.cuda.is_available(),
            persistent_workers=True,
            prefetch_factor=2
        )
        
        # Profile performance
        print("  • Profiling DataLoader performance...")
        start_time = time.time()
        batch_count = 0
        total_samples = 0
        
        for batch in optimized_loader:
            if batch_count >= 10:  # Profile first 10 batches
                break
            
            batch_size = batch[0].shape[0]
            total_samples += batch_size
            batch_count += 1
        
        total_time = time.time() - start_time
        throughput = total_samples / total_time
        
        print(f"    • Processed {total_samples} samples in {total_time:.3f}s")
        print(f"    • Throughput: {throughput:.1f} samples/second")
        print(f"    • Average batch time: {total_time/batch_count:.3f}s")
        print("  ✅ Performance profiling completed")
        
    except Exception as e:
        print(f"  ❌ Performance profiling failed: {str(e)}")
    
    print("\n🎯 Memory Optimization Features:")
    print("-" * 40)
    
    print("  • Pin Memory: Faster GPU transfer when available")
    print("  • Persistent Workers: Keep workers alive between epochs")
    print("  • Prefetch Factor: Preload batches in background")
    print("  • Optimal Worker Count: Based on CPU cores")
    print("  • Drop Last: Handle incomplete batches efficiently")
    
    print("\n✅ PyTorch Data Loading Optimizations demonstration completed!")
    print("=" * 80)


def demonstrate_data_splitting_and_cross_validation():
    """Demonstrate comprehensive data splitting and cross-validation features."""
    print("\n🚀 DATA SPLITTING AND CROSS-VALIDATION DEMONSTRATION")
    print("=" * 80)
    
    print("\n📊 Creating Mock Dataset:")
    print("-" * 40)
    
    # Create a mock dataset with labels and groups for demonstration
    class MockClassificationDataset(Dataset):
        def __init__(self, size=1000):
            self.size = size
            self.data = [f"sample_{i}" for i in range(size)]
            
            # Create imbalanced labels
            self.labels = []
            for i in range(size):
                if i < 500:
                    self.labels.append(0)  # Class 0: 50%
                elif i < 800:
                    self.labels.append(1)  # Class 1: 30%
                else:
                    self.labels.append(2)  # Class 2: 20%
            
            # Create groups (e.g., for group-based splitting)
            self.groups = [i // 50 for i in range(size)]  # 20 groups
        
        def __len__(self):
            return self.size
        
        def __getitem__(self, idx):
            return {
                'data': self.data[idx],
                'label': self.labels[idx],
                'group': self.groups[idx]
            }
    
    dataset = MockClassificationDataset(1000)
    print(f"  • Dataset size: {len(dataset)}")
    print(f"  • Number of groups: {len(set(dataset.groups))}")
    
