class TaskSpecificMetrics:
    """Task-specific evaluation metrics for different ML tasks."""
    
    def __init__(self, task_type: str = 'classification'):
        self.task_type = task_type
        self.logger = structlog.get_logger()
    
    def compute_classification_metrics(self, 
                                    y_true: torch.Tensor, 
                                    y_pred: torch.Tensor,
                                    y_pred_proba: Optional[torch.Tensor] = None,
                                    average: str = 'weighted') -> Dict[str, float]:
        """Compute comprehensive classification metrics."""
        try:
            # Convert to numpy for sklearn compatibility
            y_true_np = y_true.cpu().numpy()
            y_pred_np = y_pred.cpu().numpy()
            
            metrics = {}
            
            # Basic classification metrics
            from sklearn.metrics import (
                accuracy_score, precision_score, recall_score, f1_score,
                roc_auc_score, average_precision_score, confusion_matrix,
                classification_report, cohen_kappa_score, matthews_corrcoef,
                balanced_accuracy_score, hamming_loss, jaccard_score
            )
            
            # Accuracy metrics
            metrics['accuracy'] = accuracy_score(y_true_np, y_pred_np)
            metrics['balanced_accuracy'] = balanced_accuracy_score(y_true_np, y_pred_np)
            
            # Precision, Recall, F1
            metrics['precision'] = precision_score(y_true_np, y_pred_np, average=average, zero_division=0)
            metrics['recall'] = recall_score(y_true_np, y_pred_np, average=average, zero_division=0)
            metrics['f1'] = f1_score(y_true_np, y_pred_np, average=average, zero_division=0)
            
            # F-beta scores
            metrics['f2'] = f1_score(y_true_np, y_pred_np, average=average, beta=2.0, zero_division=0)
            metrics['f0_5'] = f1_score(y_true_np, y_pred_np, average=average, beta=0.5, zero_division=0)
            
            # Advanced classification metrics
            metrics['cohen_kappa'] = cohen_kappa_score(y_true_np, y_pred_np)
            metrics['matthews_correlation'] = matthews_corrcoef(y_true_np, y_pred_np)
            metrics['hamming_loss'] = hamming_loss(y_true_np, y_pred_np)
            metrics['jaccard'] = jaccard_score(y_true_np, y_pred_np, average=average, zero_division=0)
            
            # Confusion matrix metrics
            cm = confusion_matrix(y_true_np, y_pred_np)
            if cm.shape == (2, 2):  # Binary classification
                tn, fp, fn, tp = cm.ravel()
                metrics['true_negatives'] = int(tn)
                metrics['false_positives'] = int(fp)
                metrics['false_negatives'] = int(fn)
                metrics['true_positives'] = int(tp)
                metrics['sensitivity'] = tp / (tp + fn) if (tp + fn) > 0 else 0
                metrics['specificity'] = tn / (tn + fp) if (tn + fp) > 0 else 0
                metrics['positive_predictive_value'] = tp / (tp + fp) if (tp + fp) > 0 else 0
                metrics['negative_predictive_value'] = tn / (tn + fn) if (tn + fn) > 0 else 0
            
            # Probability-based metrics (if available)
            if y_pred_proba is not None:
                y_pred_proba_np = y_pred_proba.cpu().numpy()
                
                # Handle binary vs multi-class
                if len(np.unique(y_true_np)) == 2:
                    # Binary classification
                    metrics['roc_auc'] = roc_auc_score(y_true_np, y_pred_proba_np[:, 1])
                    metrics['pr_auc'] = average_precision_score(y_true_np, y_pred_proba_np[:, 1])
                else:
                    # Multi-class classification
                    metrics['roc_auc'] = roc_auc_score(y_true_np, y_pred_proba_np, multi_class='ovr', average='weighted')
                    metrics['pr_auc'] = average_precision_score(y_true_np, y_pred_proba_np, average='weighted')
            
            # Store confusion matrix for visualization
            metrics['confusion_matrix'] = cm.tolist()
            
            return metrics
            
        except Exception as e:
            self.logger.error(f"Classification metrics computation failed: {e}")
            return {'error': str(e)}
    
    def compute_regression_metrics(self, 
                                 y_true: torch.Tensor, 
                                 y_pred: torch.Tensor) -> Dict[str, float]:
        """Compute comprehensive regression metrics."""
        try:
            # Convert to numpy
            y_true_np = y_true.cpu().numpy()
            y_pred_np = y_pred.cpu().numpy()
            
            metrics = {}
            
            from sklearn.metrics import (
                mean_squared_error, mean_absolute_error, r2_score,
                mean_absolute_percentage_error, mean_squared_log_error,
                median_absolute_error, max_error, explained_variance_score
            )
            
            # Basic regression metrics
            metrics['mse'] = mean_squared_error(y_true_np, y_pred_np)
            metrics['rmse'] = np.sqrt(metrics['mse'])
            metrics['mae'] = mean_absolute_error(y_true_np, y_pred_np)
            metrics['r2'] = r2_score(y_true_np, y_pred_np)
            
            # Advanced regression metrics
            metrics['mape'] = mean_absolute_percentage_error(y_true_np, y_pred_np)
            metrics['msle'] = mean_squared_log_error(y_true_np, y_pred_np)
            metrics['median_ae'] = median_absolute_error(y_true_np, y_pred_np)
            metrics['max_error'] = max_error(y_true_np, y_pred_np)
            metrics['explained_variance'] = explained_variance_score(y_true_np, y_pred_np)
            
            # Custom metrics
            metrics['smape'] = 2.0 * np.mean(np.abs(y_pred_np - y_true_np) / (np.abs(y_pred_np) + np.abs(y_true_np)))
            
            # Residual analysis
            residuals = y_true_np - y_pred_np
            metrics['residual_mean'] = np.mean(residuals)
            metrics['residual_std'] = np.std(residuals)
            
            # Import scipy.stats for skewness and kurtosis
            try:
                from scipy import stats
                metrics['residual_skewness'] = float(stats.skew(residuals)) if len(residuals) > 2 else 0
                metrics['residual_kurtosis'] = float(stats.kurtosis(residuals)) if len(residuals) > 2 else 0
            except ImportError:
                metrics['residual_skewness'] = 0.0
                metrics['residual_kurtosis'] = 0.0
            
            return metrics
            
        except Exception as e:
            self.logger.error(f"Regression metrics computation failed: {e}")
            return {'error': str(e)}
    
    def compute_object_detection_metrics(self,
                                       predictions: List[Dict],
                                       ground_truth: List[Dict],
                                       iou_threshold: float = 0.5) -> Dict[str, float]:
        """Compute object detection metrics (mAP, IoU, etc.)."""
        try:
            metrics = {}
            
            # This is a simplified implementation
            # In practice, you'd use libraries like pycocotools or similar
            
            total_predictions = sum(len(pred['boxes']) for pred in predictions)
            total_ground_truth = sum(len(gt['boxes']) for gt in ground_truth)
            
            metrics['total_predictions'] = total_predictions
            metrics['total_ground_truth'] = total_ground_truth
            
            # Placeholder for actual IoU calculations
            metrics['mean_iou'] = 0.0  # Would calculate actual IoU values
            metrics['precision_at_iou'] = 0.0  # Would calculate precision at given IoU threshold
            metrics['recall_at_iou'] = 0.0  # Would calculate recall at given IoU threshold
            
            return metrics
            
        except Exception as e:
            self.logger.error(f"Object detection metrics computation failed: {e}")
            return {'error': str(e)}
    
    def compute_segmentation_metrics(self,
                                   y_true: torch.Tensor,
                                   y_pred: torch.Tensor) -> Dict[str, float]:
        """Compute segmentation metrics (Dice, IoU, pixel accuracy)."""
        try:
            metrics = {}
            
            # Convert to numpy
            y_true_np = y_true.cpu().numpy()
            y_pred_np = y_pred.cpu().numpy()
            
            # Dice coefficient (F1 score for segmentation)
            intersection = np.sum(y_true_np * y_pred_np)
            union = np.sum(y_true_np) + np.sum(y_pred_np)
            metrics['dice_coefficient'] = (2.0 * intersection) / union if union > 0 else 0
            
            # IoU (Jaccard index)
            metrics['iou'] = intersection / (union - intersection) if (union - intersection) > 0 else 0
            
            # Pixel accuracy
            metrics['pixel_accuracy'] = np.mean(y_true_np == y_pred_np)
            
            # Per-class metrics
            unique_classes = np.unique(np.concatenate([y_true_np, y_pred_np]))
            per_class_metrics = {}
            
            for cls in unique_classes:
                if cls == 0:  # Skip background class
                    continue
                    
                y_true_cls = (y_true_np == cls).astype(int)
                y_pred_cls = (y_pred_np == cls).astype(int)
                
                intersection_cls = np.sum(y_true_cls * y_pred_cls)
                union_cls = np.sum(y_true_cls) + np.sum(y_pred_cls)
                
                per_class_metrics[f'class_{cls}_dice'] = (2.0 * intersection_cls) / union_cls if union_cls > 0 else 0
                per_class_metrics[f'class_{cls}_iou'] = intersection_cls / (union_cls - intersection_cls) if (union_cls - intersection_cls) > 0 else 0
            
            metrics['per_class_metrics'] = per_class_metrics
            
            return metrics
            
        except Exception as e:
            self.logger.error(f"Segmentation metrics computation failed: {e}")
            return {'error': str(e)}
    
    def compute_time_series_metrics(self,
                                   y_true: torch.Tensor,
                                   y_pred: torch.Tensor) -> Dict[str, float]:
        """Compute time series specific metrics."""
        try:
            # Convert to numpy
            y_true_np = y_true.cpu().numpy()
            y_pred_np = y_pred.cpu().numpy()
            
            metrics = {}
            
            # Basic regression metrics
            metrics['mse'] = np.mean((y_true_np - y_pred_np) ** 2)
            metrics['mae'] = np.mean(np.abs(y_true_np - y_pred_np))
            metrics['rmse'] = np.sqrt(metrics['mse'])
            
            # Time series specific metrics
            # Directional accuracy
            if len(y_true_np) > 1:
                true_direction = np.diff(y_true_np) > 0
                pred_direction = np.diff(y_pred_np) > 0
                metrics['directional_accuracy'] = np.mean(true_direction == pred_direction)
            
            # Mean absolute percentage error
            metrics['mape'] = np.mean(np.abs((y_true_np - y_pred_np) / y_true_np)) * 100
            
            # Symmetric mean absolute percentage error
            metrics['smape'] = 2.0 * np.mean(np.abs(y_pred_np - y_true_np) / (np.abs(y_pred_np) + np.abs(y_true_np))) * 100
            
            return metrics
            
        except Exception as e:
            self.logger.error(f"Time series metrics computation failed: {e}")
            return {'error': str(e)}


class AdvancedEvaluationMetrics:
    """Advanced evaluation metrics with statistical analysis and visualization."""
    
    def __init__(self, task_type: str = 'classification'):
        self.task_type = task_type
        self.task_metrics = TaskSpecificMetrics(task_type)
        self.logger = structlog.get_logger()
        self.metrics_history = defaultdict(list)
    
    def evaluate_model(self,
                      model: nn.Module,
                      dataloader: DataLoader,
                      device: torch.device,
                      task_type: str = None,
                      additional_metrics: List[str] = None) -> Dict[str, Any]:
        """Comprehensive model evaluation."""
        if task_type:
            self.task_type = task_type
            self.task_metrics = TaskSpecificMetrics(task_type)
        
        model.eval()
        all_predictions = []
        all_labels = []
        all_probabilities = []
        total_loss = 0
        
        # Collect predictions and labels
        with torch.no_grad():
            for batch in tqdm(dataloader, desc="Evaluating"):
                try:
                    # Move batch to device
                    batch = {k: v.to(device, non_blocking=True) for k, v in batch.items()}
                    
                    # Forward pass
                    outputs = model(**batch)
                    loss = outputs.get("loss", torch.tensor(0.0))
                    logits = outputs.get("logits", torch.tensor([]))
                    
                    total_loss += loss.item()
                    
                    # Store predictions and labels
                    if logits.numel() > 0:
                        predictions = torch.argmax(logits, dim=-1)
                        probabilities = torch.softmax(logits, dim=-1)
                        
                        all_predictions.extend(predictions.cpu())
                        all_labels.extend(batch["labels"].cpu())
                        all_probabilities.extend(probabilities.cpu())
                    
                except Exception as e:
                    self.logger.error(f"Evaluation step failed: {e}")
                    continue
        
        # Convert to tensors
        all_predictions = torch.stack(all_predictions) if all_predictions else torch.tensor([])
        all_labels = torch.stack(all_labels) if all_labels else torch.tensor([])
        all_probabilities = torch.stack(all_probabilities) if all_probabilities else torch.tensor([])
        
        # Calculate task-specific metrics
        if self.task_type == 'classification':
            metrics = self.task_metrics.compute_classification_metrics(
                all_labels, all_predictions, all_probabilities
            )
        elif self.task_type == 'regression':
            metrics = self.task_metrics.compute_regression_metrics(
                all_labels, all_predictions
            )
        elif self.task_type == 'segmentation':
            metrics = self.task_metrics.compute_segmentation_metrics(
                all_labels, all_predictions
            )
        elif self.task_type == 'object_detection':
            # This would need actual detection predictions and ground truth
            metrics = {'error': 'Object detection evaluation not implemented yet'}
        elif self.task_type == 'time_series':
            metrics = self.task_metrics.compute_time_series_metrics(
                all_labels, all_predictions
            )
        else:
            metrics = {'error': f'Unknown task type: {self.task_type}'}
        
        # Add basic metrics
        if all_predictions.numel() > 0:
            metrics['total_samples'] = len(all_predictions)
            metrics['avg_loss'] = total_loss / len(dataloader)
        
        # Store metrics history
        for key, value in metrics.items():
            if isinstance(value, (int, float)) and key != 'total_samples':
                self.metrics_history[key].append(value)
        
        return metrics
    
    def get_metrics_summary(self) -> Dict[str, Any]:
        """Get summary statistics of metrics history."""
        summary = {}
        
        for metric_name, values in self.metrics_history.items():
            if values:
                summary[f'{metric_name}_mean'] = np.mean(values)
                summary[f'{metric_name}_std'] = np.std(values)
                summary[f'{metric_name}_min'] = np.min(values)
                summary[f'{metric_name}_max'] = np.max(values)
                summary[f'{metric_name}_latest'] = values[-1]
        
        return summary
    
    def plot_metrics_history(self, save_path: Optional[str] = None):
        """Plot metrics history over time."""
        if not self.metrics_history:
            self.logger.warning("No metrics history to plot")
            return
        
        try:
            import matplotlib.pyplot as plt
            
            # Determine subplot layout
            n_metrics = len(self.metrics_history)
            n_cols = min(3, n_metrics)
            n_rows = (n_metrics + n_cols - 1) // n_cols
            
            fig, axes = plt.subplots(n_rows, n_cols, figsize=(5*n_cols, 4*n_rows))
            if n_metrics == 1:
                axes = [axes]
            elif n_rows == 1:
                axes = axes.reshape(1, -1)
            
            for idx, (metric_name, values) in enumerate(self.metrics_history.items()):
                row = idx // n_cols
                col = idx % n_cols
                ax = axes[row, col]
                
                ax.plot(values, 'b-', linewidth=2)
                ax.set_title(f'{metric_name.replace("_", " ").title()}')
                ax.set_xlabel('Evaluation Step')
                ax.set_ylabel('Value')
                ax.grid(True, alpha=0.3)
            
            # Hide empty subplots
            for idx in range(n_metrics, n_rows * n_cols):
                row = idx // n_cols
                col = idx % n_cols
                axes[row, col].set_visible(False)
            
            plt.tight_layout()
            
            if save_path:
                plt.savefig(save_path, dpi=300, bbox_inches='tight')
            
            plt.show()
            
        except ImportError:
            self.logger.warning("matplotlib not available for plotting")
        except Exception as e:
            self.logger.error(f"Plotting failed: {e}")


class EvaluationMetricsFactory:
    """Factory for creating evaluation metrics based on task type."""
    
    @staticmethod
    def create_evaluator(task_type: str, **kwargs) -> AdvancedEvaluationMetrics:
        """Create an evaluation metrics instance for the specified task."""
        return AdvancedEvaluationMetrics(task_type, **kwargs)
    
    @staticmethod
    def get_supported_tasks() -> List[str]:
        """Get list of supported task types."""
        return ['classification', 'regression', 'segmentation', 'object_detection', 'time_series']
    
    @staticmethod
    def get_default_metrics(task_type: str) -> List[str]:
        """Get default metrics for a task type."""
        default_metrics = {
            'classification': ['accuracy', 'precision', 'recall', 'f1', 'roc_auc', 'confusion_matrix'],
            'regression': ['mse', 'rmse', 'mae', 'r2', 'mape'],
            'segmentation': ['dice_coefficient', 'iou', 'pixel_accuracy'],
            'object_detection': ['mean_iou', 'precision_at_iou', 'recall_at_iou'],
            'time_series': ['mse', 'mae', 'directional_accuracy', 'mape']
        }
        return default_metrics.get(task_type, [])


