@dataclass
class GradientClippingConfig:
    """Configuration for advanced gradient clipping strategies."""
    # Basic gradient clipping
    max_grad_norm: float = 1.0
    max_grad_value: Optional[float] = None
    
    # Adaptive gradient clipping
    enable_adaptive_clipping: bool = True
    adaptive_clip_factor: float = 0.1
    adaptive_clip_window: int = 100
    
    # Layer-wise gradient clipping
    enable_layer_wise_clipping: bool = False
    layer_clip_ratios: Dict[str, float] = field(default_factory=dict)
    
    # Gradient clipping strategies
    clipping_strategy: str = "norm"  # "norm", "value", "adaptive", "layer_wise"
    
    # Monitoring and logging
    enable_gradient_monitoring: bool = True
    gradient_monitoring_frequency: int = 10
    log_gradient_histograms: bool = False

@dataclass
class NumericalStabilityConfig:
    """Configuration for numerical stability monitoring and handling."""
    # NaN/Inf detection
    enable_nan_inf_checking: bool = True
    nan_inf_threshold: float = 1e6
    check_frequency: int = 1  # Check every N batches
    
    # Recovery strategies
    recovery_strategy: str = "reduce_lr"  # "reduce_lr", "skip_batch", "restart_training"
    max_recovery_attempts: int = 3
    recovery_lr_factor: float = 0.5
    
    # Advanced monitoring
    enable_loss_monitoring: bool = True
    enable_gradient_monitoring: bool = True
    enable_parameter_monitoring: bool = True
    
    # Alert thresholds
    loss_spike_threshold: float = 10.0
    gradient_explosion_threshold: float = 1e3
    parameter_drift_threshold: float = 1e2

class AdvancedGradientClipper:
    """Advanced gradient clipping with multiple strategies and adaptive mechanisms."""
    
    def __init__(self, config: GradientClippingConfig):
        self.config = config
        self.gradient_history = []
        self.clipping_stats = {
            'total_clips': 0,
            'norm_clips': 0,
            'value_clips': 0,
            'adaptive_clips': 0,
            'layer_clips': 0
        }
    
    def clip_gradients(self, model: nn.Module) -> Dict[str, Any]:
        """Apply gradient clipping based on configured strategy."""
        if self.config.clipping_strategy == "norm":
            return self._clip_by_norm(model)
        elif self.config.clipping_strategy == "value":
            return self._clip_by_value(model)
        elif self.config.clipping_strategy == "adaptive":
            return self._clip_adaptively(model)
        elif self.config.clipping_strategy == "layer_wise":
            return self._clip_layer_wise(model)
        else:
            return self._clip_by_norm(model)  # Default
    
    def _clip_by_norm(self, model: nn.Module) -> Dict[str, Any]:
        """Clip gradients by norm."""
        total_norm = 0.0
        param_count = 0
        
        for p in model.parameters():
            if p.grad is not None:
                param_norm = p.grad.data.norm(2)
                total_norm += param_norm.item() ** 2
                param_count += 1
        
        if param_count == 0:
            return {'total_norm': 0.0, 'clipped': False, 'clip_ratio': 0.0}
        
        total_norm = total_norm ** (1. / 2)
        clip_ratio = 1.0
        
        if total_norm > self.config.max_grad_norm:
            clip_ratio = self.config.max_grad_norm / (total_norm + 1e-6)
            for p in model.parameters():
                if p.grad is not None:
                    p.grad.data.mul_(clip_ratio)
            
            self.clipping_stats['norm_clips'] += 1
            self.clipping_stats['total_clips'] += 1
        
        return {
            'total_norm': total_norm,
            'clipped': clip_ratio < 1.0,
            'clip_ratio': clip_ratio,
            'max_norm': self.config.max_grad_norm
        }
    
    def _clip_by_value(self, model: nn.Module) -> Dict[str, Any]:
        """Clip gradients by value."""
        if self.config.max_grad_value is None:
            return self._clip_by_norm(model)
        
        total_clipped = 0
        total_params = 0
        
        for p in model.parameters():
            if p.grad is not None:
                total_params += 1
                if torch.abs(p.grad).max() > self.config.max_grad_value:
                    p.grad.data.clamp_(-self.config.max_grad_value, self.config.max_grad_value)
                    total_clipped += 1
        
        self.clipping_stats['value_clips'] += 1 if total_clipped > 0 else 0
        self.clipping_stats['total_clips'] += 1 if total_clipped > 0 else 0
        
        return {
            'total_clipped': total_clipped,
            'total_params': total_params,
            'clipped': total_clipped > 0,
            'max_value': self.config.max_grad_value
        }
    
    def _clip_adaptively(self, model: nn.Module) -> Dict[str, Any]:
        """Apply adaptive gradient clipping based on gradient history."""
        if not self.config.enable_adaptive_clipping:
            return self._clip_by_norm(model)
        
        # Get current gradient norm
        current_norm = 0.0
        for p in model.parameters():
            if p.grad is not None:
                current_norm += p.grad.data.norm(2).item() ** 2
        current_norm = current_norm ** (1. / 2)
        
        # Update gradient history
        self.gradient_history.append(current_norm)
        if len(self.gradient_history) > self.config.adaptive_clip_window:
            self.gradient_history.pop(0)
        
        # Calculate adaptive threshold
        if len(self.gradient_history) >= 10:
            mean_norm = np.mean(self.gradient_history[:-1])  # Exclude current
            adaptive_threshold = mean_norm * (1 + self.config.adaptive_clip_factor)
        else:
            adaptive_threshold = self.config.max_grad_norm
        
        # Apply clipping
        clip_ratio = 1.0
        if current_norm > adaptive_threshold:
            clip_ratio = adaptive_threshold / (current_norm + 1e-6)
            for p in model.parameters():
                if p.grad is not None:
                    p.grad.data.mul_(clip_ratio)
            
            self.clipping_stats['adaptive_clips'] += 1
            self.clipping_stats['total_clips'] += 1
        
        return {
            'total_norm': current_norm,
            'adaptive_threshold': adaptive_threshold,
            'clipped': clip_ratio < 1.0,
            'clip_ratio': clip_ratio,
            'history_size': len(self.gradient_history)
        }
    
    def _clip_layer_wise(self, model: nn.Module) -> Dict[str, Any]:
        """Apply layer-wise gradient clipping."""
        if not self.config.enable_layer_wise_clipping:
            return self._clip_by_norm(model)
        
        layer_stats = {}
        total_clipped_layers = 0
        
        for name, module in model.named_modules():
            if hasattr(module, 'weight') and module.weight.grad is not None:
                layer_norm = module.weight.grad.data.norm(2)
                layer_ratio = self.config.layer_clip_ratios.get(name, 1.0)
                layer_threshold = self.config.max_grad_norm * layer_ratio
                
                if layer_norm > layer_threshold:
                    clip_ratio = layer_threshold / (layer_norm + 1e-6)
                    module.weight.grad.data.mul_(clip_ratio)
                    total_clipped_layers += 1
                
                layer_stats[name] = {
                    'norm': layer_norm.item(),
                    'threshold': layer_threshold,
                    'clipped': layer_norm > layer_threshold
                }
        
        if total_clipped_layers > 0:
            self.clipping_stats['layer_clips'] += 1
            self.clipping_stats['total_clips'] += 1
        
        return {
            'layer_stats': layer_stats,
            'total_clipped_layers': total_clipped_layers,
            'clipped': total_clipped_layers > 0
        }
    
    def get_clipping_statistics(self) -> Dict[str, Any]:
        """Get comprehensive clipping statistics."""
        return {
            'clipping_stats': self.clipping_stats.copy(),
            'gradient_history': self.gradient_history[-10:] if self.gradient_history else [],
            'config': {
                'max_grad_norm': self.config.max_grad_norm,
                'max_grad_value': self.config.max_grad_value,
                'clipping_strategy': self.config.clipping_strategy,
                'enable_adaptive_clipping': self.config.enable_adaptive_clipping
            }
        }

class AdvancedNumericalStabilityMonitor:
    """Advanced numerical stability monitoring and handling."""
    
    def __init__(self, config: NumericalStabilityConfig):
        self.config = config
        self.stability_history = []
        self.recovery_attempts = 0
        self.last_check_batch = 0
        
        # Monitoring state
        self.loss_history = []
        self.gradient_history = []
        self.parameter_history = []
    
    def check_numerical_stability(self, 
                                 model: nn.Module, 
                                 loss: Optional[torch.Tensor] = None,
                                 batch_idx: int = 0) -> Dict[str, Any]:
        """Comprehensive numerical stability check."""
        if batch_idx % self.config.check_frequency != 0:
            return {'stable': True, 'checks_performed': 0}
        
        stability_report = {
            'stable': True,
            'checks_performed': 0,
            'loss_stable': True,
            'gradients_stable': True,
            'parameters_stable': True,
            'issues': []
        }
        
        # Check loss stability
        if self.config.enable_loss_monitoring and loss is not None:
            stability_report['loss_stable'] = self._check_loss_stability(loss)
            stability_report['checks_performed'] += 1
            if not stability_report['loss_stable']:
                stability_report['stable'] = False
                stability_report['issues'].append('loss_unstable')
        
        # Check gradient stability
        if self.config.enable_gradient_monitoring:
            stability_report['gradients_stable'] = self._check_gradient_stability(model)
            stability_report['checks_performed'] += 1
            if not stability_report['gradients_stable']:
                stability_report['stable'] = False
                stability_report['issues'].append('gradients_unstable')
        
        # Check parameter stability
        if self.config.enable_parameter_monitoring:
            stability_report['parameters_stable'] = self._check_parameter_stability(model)
            stability_report['checks_performed'] += 1
            if not stability_report['parameters_stable']:
                stability_report['stable'] = False
                stability_report['issues'].append('parameters_unstable')
        
        # Update history
        self.stability_history.append({
            'batch_idx': batch_idx,
            'timestamp': time.time(),
            'report': stability_report
        })
        
        # Keep only recent history
        if len(self.stability_history) > 1000:
            self.stability_history = self.stability_history[-500:]
        
        return stability_report
    
    def _check_loss_stability(self, loss: torch.Tensor) -> bool:
        """Check if loss is numerically stable."""
        loss_value = loss.item()
        
        # Check for NaN/Inf
        if torch.isnan(loss) or torch.isinf(loss):
            return False
        
        # Check for extreme values
        if abs(loss_value) > self.config.nan_inf_threshold:
            return False
        
        # Check for loss spikes
        self.loss_history.append(loss_value)
        if len(self.loss_history) > 10:
            recent_losses = self.loss_history[-10:]
            mean_loss = np.mean(recent_losses[:-1])
            if abs(loss_value - mean_loss) > self.config.loss_spike_threshold * mean_loss:
                return False
        
        return True
    
    def _check_gradient_stability(self, model: nn.Module) -> bool:
        """Check if gradients are numerically stable."""
        total_norm = 0.0
        has_nan_inf = False
        
        for name, param in model.named_parameters():
            if param.grad is not None:
                # Check for NaN/Inf
                if torch.isnan(param.grad).any() or torch.isinf(param.grad).any():
                    has_nan_inf = True
                
                # Calculate norm
                param_norm = param.grad.data.norm(2)
                total_norm += param_norm.item() ** 2
        
        if has_nan_inf:
            return False
        
        total_norm = total_norm ** (1. / 2)
        
        # Check for gradient explosion
        if total_norm > self.config.gradient_explosion_threshold:
            return False
        
        # Update gradient history
        self.gradient_history.append(total_norm)
        if len(self.gradient_history) > 100:
            self.gradient_history = self.gradient_history[-50:]
        
        return True
    
    def _check_parameter_stability(self, model: nn.Module) -> bool:
        """Check if model parameters are numerically stable."""
        total_drift = 0.0
        param_count = 0
        
        for name, param in model.named_parameters():
            if param.data is not None:
                # Check for NaN/Inf
                if torch.isnan(param.data).any() or torch.isinf(param.data).any():
                    return False
                
                # Calculate parameter drift
                param_norm = param.data.norm(2)
                total_drift += param_norm.item()
                param_count += 1
        
        if param_count > 0:
            avg_drift = total_drift / param_count
            if avg_drift > self.config.parameter_drift_threshold:
                return False
        
        return True
    
    def handle_instability(self, model: nn.Module, optimizer: torch.optim.Optimizer, 
                          epoch: int, batch_idx: int) -> bool:
        """Handle numerical instability with recovery strategies."""
        self.recovery_attempts += 1
        
        if self.recovery_attempts > self.config.max_recovery_attempts:
            logger.error(f"Maximum recovery attempts ({self.config.max_recovery_attempts}) reached")
            return False
        
        logger.warning(f"Numerical instability detected at epoch {epoch}, batch {batch_idx}. "
                      f"Recovery attempt {self.recovery_attempts}/{self.config.max_recovery_attempts}")
        
        if self.config.recovery_strategy == "reduce_lr":
            return self._reduce_learning_rate(optimizer)
        elif self.config.recovery_strategy == "skip_batch":
            return self._skip_batch(model, optimizer)
        elif self.config.recovery_strategy == "restart_training":
            return self._restart_training(model, optimizer)
        else:
            return self._reduce_learning_rate(optimizer)  # Default
    
    def _reduce_learning_rate(self, optimizer: torch.optim.Optimizer) -> bool:
        """Reduce learning rate as recovery strategy."""
        current_lr = optimizer.param_groups[0]['lr']
        new_lr = current_lr * self.config.recovery_lr_factor
        
        for param_group in optimizer.param_groups:
            param_group['lr'] = new_lr
        
        logger.info(f"Learning rate reduced: {current_lr:.2e} -> {new_lr:.2e}")
        return True
    
    def _skip_batch(self, model: nn.Module, optimizer: torch.optim.Optimizer) -> bool:
        """Skip current batch as recovery strategy."""
        optimizer.zero_grad()
        logger.info("Current batch skipped due to numerical instability")
        return True
    
    def _restart_training(self, model: nn.Module, optimizer: torch.optim.Optimizer) -> bool:
        """Restart training as recovery strategy."""
        # Reset optimizer
        optimizer.zero_grad()
        
        # Reset learning rate to initial value
        for param_group in optimizer.param_groups:
            param_group['lr'] = param_group['lr'] / (self.config.recovery_lr_factor ** self.recovery_attempts)
        
        logger.info("Training restarted with reset learning rate")
        return True
    
    def get_stability_statistics(self) -> Dict[str, Any]:
        """Get comprehensive stability statistics."""
        recent_reports = self.stability_history[-100:] if self.stability_history else []
        
        stability_rate = 0.0
        if recent_reports:
            stable_count = sum(1 for report in recent_reports if report['report']['stable'])
            stability_rate = stable_count / len(recent_reports)
        
        return {
            'stability_rate': stability_rate,
            'recovery_attempts': self.recovery_attempts,
            'total_checks': len(self.stability_history),
            'recent_issues': [report['report']['issues'] for report in recent_reports[-10:] if report['report']['issues']],
            'loss_history': self.loss_history[-20:] if self.loss_history else [],
            'gradient_history': self.gradient_history[-20:] if self.gradient_history else []
        }

class EnhancedTrainingManager(TrainingManager):
    """Enhanced training manager with advanced gradient clipping and numerical stability monitoring."""
    
    def __init__(self,
                 model: nn.Module,
                 optimizer: torch.optim.Optimizer,
                 scheduler: AdvancedLearningRateScheduler = None,
                 early_stopping: EarlyStopping = None,
                 device: str = 'cuda' if torch.cuda.is_available() else 'cpu',
                 gradient_clipping_config: GradientClippingConfig = None,
                 numerical_stability_config: NumericalStabilityConfig = None):
        
        # Initialize base training manager
        super().__init__(
            model=model,
            optimizer=optimizer,
            scheduler=scheduler,
            early_stopping=early_stopping,
            device=device,
            max_grad_norm=gradient_clipping_config.max_grad_norm if gradient_clipping_config else 1.0,
            enable_gradient_clipping=True,
            enable_nan_inf_checking=True,
            nan_inf_threshold=1e6
        )
        
        # Initialize enhanced components
        self.gradient_clipper = AdvancedGradientClipper(
            gradient_clipping_config or GradientClippingConfig()
        )
        self.stability_monitor = AdvancedNumericalStabilityMonitor(
            numerical_stability_config or NumericalStabilityConfig()
        )
        
        logger.info("Enhanced training manager initialized with advanced gradient clipping and stability monitoring")
    
    def enhanced_train_step(self, batch: Any, epoch: int, batch_idx: int) -> Dict[str, Any]:
        """Enhanced training step with comprehensive stability monitoring."""
        try:
            # Forward pass
            loss = self._forward_pass(batch)
            
            # Check numerical stability
            stability_report = self.stability_monitor.check_numerical_stability(
                self.model, loss, batch_idx
            )
            
            if not stability_report['stable']:
                logger.warning(f"Numerical instability detected: {stability_report['issues']}")
                if not self.stability_monitor.handle_instability(self.model, self.optimizer, epoch, batch_idx):
                    return {
                        'loss': None,
                        'gradient_stats': None,
                        'stability_report': stability_report,
                        'training_continued': False
                    }
            
            # Safe backward pass
            if not self.safe_backward_pass(loss, epoch, batch_idx):
                return {
                    'loss': loss.item(),
                    'gradient_stats': None,
                    'stability_report': stability_report,
                    'training_continued': False
                }
            
            # Apply enhanced gradient clipping
            clipping_result = self.gradient_clipper.clip_gradients(self.model)
            
            # Optimizer step
            self.optimizer.step()
            self.optimizer.zero_grad()
            
            # Get comprehensive statistics
            gradient_stats = self.get_gradient_statistics()
            gradient_stats.update(clipping_result)
            
            # Log training stability
            self.log_training_stability(epoch, batch_idx, loss, gradient_stats)
            
            return {
                'loss': loss.item(),
                'gradient_stats': gradient_stats,
                'stability_report': stability_report,
                'training_continued': True
            }
            
        except Exception as e:
            logger.error(f"Error in enhanced training step: {e}")
            return {
                'loss': None,
                'gradient_stats': None,
                'stability_report': {'stable': False, 'issues': ['exception']},
                'training_continued': False
            }
    
    def _forward_pass(self, batch: Any) -> torch.Tensor:
        """Perform forward pass with error handling."""
        # This is a placeholder - implement based on your specific model
        if hasattr(self.model, 'forward'):
            return self.model(batch)
        else:
            raise NotImplementedError("Model must implement forward method")
    
    def get_enhanced_statistics(self) -> Dict[str, Any]:
        """Get comprehensive training statistics."""
        base_stats = {
            'current_epoch': self.current_epoch,
            'training_history': self.training_history[-10:] if self.training_history else [],
            'best_metrics': self.best_metrics
        }
        
        # Add gradient clipping statistics
        clipping_stats = self.gradient_clipper.get_clipping_statistics()
        
        # Add stability statistics
        stability_stats = self.stability_monitor.get_stability_statistics()
        
        return {
            **base_stats,
            'gradient_clipping': clipping_stats,
            'numerical_stability': stability_stats
        }

