class GradioConfig:
    """Configuration class for Gradio integration with enhanced UI/UX and error handling."""
    
    def __init__(self,
                 title: str = "Deep Learning Model Demo",
                 description: str = "Interactive demo for deep learning models",
                 theme: str = "default",
                 server_name: str = "127.0.0.1",
                 server_port: int = 7860,
                 share: bool = False,
                 debug: bool = False,
                 enable_queue: bool = True,
                 max_threads: int = 4,
                 auth: tuple = None,
                 favicon_path: str = None,
                 css: str = None,
                 js: str = None,
                 head: str = None,
                 analytics_enabled: bool = False,
                 allow_flagging: str = "manual",
                 show_error: bool = True,
                 show_tips: bool = True,
                 height: int = 500,
                 width: str = "100%",
                 encrypt: bool = False,
                 show_progress: bool = True,
                 # Enhanced UI/UX options
                 enable_loading_states: bool = True,
                 show_confidence_scores: bool = True,
                 enable_batch_processing: bool = True,
                 max_file_size_mb: int = 50,
                 allowed_file_types: list = None,
                 enable_help_tooltips: bool = True,
                 enable_example_inputs: bool = True,
                 enable_result_download: bool = True,
                 # Error handling options
                 enable_input_validation: bool = True,
                 enable_error_recovery: bool = True,
                 max_retry_attempts: int = 3,
                 error_message_style: str = "user_friendly",
                 # Performance options
                 enable_caching: bool = True,
                 cache_ttl_seconds: int = 3600,
                 enable_progress_bars: bool = True,
                 enable_async_processing: bool = True):
        """
        Initialize Gradio configuration.
        
        Args:
            title: Demo title
            description: Demo description
            theme: UI theme (default, soft, monochrome, glass, etc.)
            server_name: Server hostname
            server_port: Server port
            share: Create public link
            debug: Enable debug mode
            enable_queue: Enable request queuing
            max_threads: Maximum concurrent threads
            auth: Authentication tuple (username, password)
            favicon_path: Custom favicon path
            css: Custom CSS
            js: Custom JavaScript
            head: Custom HTML head content
            analytics_enabled: Enable analytics
            allow_flagging: Flagging behavior
            show_error: Show error messages
            show_tips: Show usage tips
            height: Interface height
            width: Interface width
            encrypt: Enable encryption
            show_progress: Show progress indicators
        """
        self.title = title
        self.description = description
        self.theme = theme
        self.server_name = server_name
        self.server_port = server_port
        self.share = share
        self.debug = debug
        self.enable_queue = enable_queue
        self.max_threads = max_threads
        self.auth = auth
        self.favicon_path = favicon_path
        self.css = css
        self.js = js
        self.head = head
        self.analytics_enabled = analytics_enabled
        self.allow_flagging = allow_flagging
        self.show_error = show_error
        self.show_tips = show_tips
        self.height = height
        self.width = width
        self.encrypt = encrypt
        self.show_progress = show_progress
        
        # Enhanced UI/UX options
        self.enable_loading_states = enable_loading_states
        self.show_confidence_scores = show_confidence_scores
        self.enable_batch_processing = enable_batch_processing
        self.max_file_size_mb = max_file_size_mb
        self.allowed_file_types = allowed_file_types or ['.jpg', '.jpeg', '.png', '.gif', '.bmp', '.tiff', '.txt', '.pdf']
        self.enable_help_tooltips = enable_help_tooltips
        self.enable_example_inputs = enable_example_inputs
        self.enable_result_download = enable_result_download
        
        # Error handling options
        self.enable_input_validation = enable_input_validation
        self.enable_error_recovery = enable_error_recovery
        self.max_retry_attempts = max_retry_attempts
        self.error_message_style = error_message_style
        
        # Performance options
        self.enable_caching = enable_caching
        self.cache_ttl_seconds = cache_ttl_seconds
        self.enable_progress_bars = enable_progress_bars
        self.enable_async_processing = enable_async_processing
        
        logger.info(f"Gradio config initialized: {title} with enhanced UI/UX and error handling")


class GradioModelInterface:
    """Base class for creating Gradio interfaces for different model types with enhanced error handling and UI/UX."""
    
    def __init__(self, 
                 model: nn.Module, 
                 config: GradioConfig,
                 device: str = 'cuda' if torch.cuda.is_available() else 'cpu'):
        """
        Initialize Gradio model interface.
        
        Args:
            model: PyTorch model
            config: Gradio configuration
            device: Computing device
        """
        self.model = model
        self.config = config
        self.device = device
        self.model.to(device)
        self.model.eval()
        
        # Initialize error handling and validation
        self.error_handler = GradioErrorHandler(config)
        self.error_count = 0
        self.success_count = 0
        self.cache = {} if config.enable_caching else None
        self.last_error = None
        self._start_time = time.time()
        
        logger.info(f"Gradio interface initialized for model on {device}")
    
    def validate_input(self, *args, **kwargs):
        """Validate input data before processing."""
        try:
            if not self.config.enable_input_validation:
                return True, None
            
            # Basic validation
            if not args and not kwargs:
                return False, "No input provided"
            
            # Use error handler for validation
            for arg in args:
                if hasattr(arg, 'name'):  # File object
                    is_valid, error_msg = self.error_handler.validate_file(arg)
                    if not is_valid:
                        return False, error_msg
                elif isinstance(arg, str):  # Text input
                    is_valid, error_msg = self.error_handler.validate_text(arg)
                    if not is_valid:
                        return False, error_msg
            
            return True, None
            
        except Exception as e:
            logger.error(f"Input validation error: {e}")
            return False, f"Input validation failed: {str(e)}"
    
    def handle_error(self, error: Exception, context: str = "prediction"):
        """Handle errors gracefully with user-friendly messages."""
        try:
            self.error_count += 1
            self.last_error = error
            
            # Use error handler for user-friendly messages
            error_response = self.error_handler.create_user_friendly_error(error, context)
            
            return error_response
            
        except Exception as e:
            logger.error(f"Error in error handler: {e}")
            return {
                "error": True,
                "message": "An error occurred while processing your request.",
                "error_type": "Unknown",
                "context": context,
                "timestamp": time.time()
            }
    
    def retry_with_recovery(self, func, *args, max_attempts=None, **kwargs):
        """Retry function with error recovery."""
        max_attempts = max_attempts or self.config.max_retry_attempts
        
        for attempt in range(max_attempts):
            try:
                result = func(*args, **kwargs)
                self.success_count += 1
                return result
                
            except Exception as e:
                logger.warning(f"Attempt {attempt + 1} failed: {e}")
                
                if attempt < max_attempts - 1:
                    # Try to recover
                    if self.config.enable_error_recovery:
                        try:
                            self._attempt_recovery()
                            time.sleep(0.5 * (attempt + 1))  # Exponential backoff
                        except Exception as recovery_error:
                            logger.error(f"Recovery attempt failed: {recovery_error}")
                
                if attempt == max_attempts - 1:
                    # Final attempt failed
                    return self.handle_error(e, "retry_recovery")
        
        return self.handle_error(Exception("Max retry attempts exceeded"), "retry_recovery")
    
    def _attempt_recovery(self):
        """Attempt to recover from errors."""
        try:
            # Clear GPU cache if available
            if torch.cuda.is_available():
                torch.cuda.empty_cache()
            
            # Reset model to eval mode
            self.model.eval()
            
            logger.info("Recovery attempt completed")
            
        except Exception as e:
            logger.error(f"Recovery attempt failed: {e}")
    
    def get_cache_key(self, *args, **kwargs):
        """Generate cache key for input data."""
        if not self.config.enable_caching:
            return None
        
        try:
            # Create a hash of input data
            input_str = str(args) + str(sorted(kwargs.items()))
            return hashlib.md5(input_str.encode()).hexdigest()
        except Exception:
            return None
    
    def check_cache(self, cache_key):
        """Check if result exists in cache."""
        if not self.config.enable_caching or not cache_key or not self.cache:
            return None
        
        try:
            cached_result = self.cache.get(cache_key)
            if cached_result and time.time() - cached_result.get('timestamp', 0) < self.config.cache_ttl_seconds:
                logger.info("Cache hit")
                return cached_result['result']
        except Exception as e:
            logger.warning(f"Cache check failed: {e}")
        
        return None
    
    def update_cache(self, cache_key, result):
        """Update cache with new result."""
        if not self.config.enable_caching or not cache_key or not self.cache:
            return
        
        try:
            self.cache[cache_key] = {
                'result': result,
                'timestamp': time.time()
            }
            
            # Clean old entries
            current_time = time.time()
            self.cache = {k: v for k, v in self.cache.items() 
                         if current_time - v.get('timestamp', 0) < self.config.cache_ttl_seconds}
            
        except Exception as e:
            logger.warning(f"Cache update failed: {e}")
    
    def preprocess_input(self, *args, **kwargs):
        """Preprocess input data for model inference."""
        raise NotImplementedError("Subclasses must implement preprocess_input")
    
    def predict(self, *args, **kwargs):
        """Run model inference with error handling and caching."""
        try:
            # Input validation
            is_valid, error_msg = self.validate_input(*args, **kwargs)
            if not is_valid:
                return self.handle_error(ValueError(error_msg), "input_validation")
            
            # Check cache
            cache_key = self.get_cache_key(*args, **kwargs)
            cached_result = self.check_cache(cache_key)
            if cached_result is not None:
                return cached_result
            
            # Run prediction with retry logic
            result = self.retry_with_recovery(self._predict_impl, *args, **kwargs)
            
            # Update cache if successful
            if not result.get('error', False) and cache_key:
                self.update_cache(cache_key, result)
            
            return result
            
        except Exception as e:
            return self.handle_error(e, "prediction")
    
    def _predict_impl(self, *args, **kwargs):
        """Internal prediction implementation."""
        raise NotImplementedError("Subclasses must implement _predict_impl")
    
    def postprocess_output(self, output):
        """Postprocess model output for display."""
        return output
    
    def create_interface(self):
        """Create Gradio interface."""
        raise NotImplementedError("Subclasses must implement create_interface")
    
    def get_interface_stats(self):
        """Get interface statistics."""
        error_summary = self.error_handler.get_error_summary()
        
        return {
            "total_requests": self.success_count + self.error_count,
            "success_count": self.success_count,
            "error_count": self.error_count,
            "success_rate": self.success_count / max(1, self.success_count + self.error_count),
            "last_error": self.last_error,
            "cache_size": len(self.cache) if self.cache else 0,
            "error_summary": error_summary,
            "uptime": time.time() - getattr(self, '_start_time', time.time())
        }


class ClassificationDemo(GradioModelInterface):
    """Gradio interface for image classification models."""
    
    def __init__(self, 
                 model: nn.Module, 
                 config: GradioConfig,
                 class_names: List[str],
                 transforms=None,
                 device: str = 'cuda' if torch.cuda.is_available() else 'cpu'):
        """
        Initialize classification demo.
        
        Args:
            model: Classification model
            config: Gradio configuration
            class_names: List of class names
            transforms: Image transforms
            device: Computing device
        """
        super().__init__(model, config, device)
        self.class_names = class_names
        self.transforms = transforms or self._default_transforms()
        
        logger.info(f"Classification demo initialized with {len(class_names)} classes")
    
    def _default_transforms(self):
        """Default image transforms."""
        try:
            import torchvision.transforms as transforms
            return transforms.Compose([
                transforms.Resize((224, 224)),
                transforms.ToTensor(),
                transforms.Normalize(mean=[0.485, 0.456, 0.406], 
                                   std=[0.229, 0.224, 0.225])
            ])
        except ImportError:
            logger.warning("torchvision not available, using identity transform")
            return lambda x: x
    
    def preprocess_input(self, image):
        """Preprocess input image."""
        try:
            if isinstance(image, str):
                from PIL import Image
                image = Image.open(image).convert('RGB')
            
            if self.transforms:
                image = self.transforms(image)
            
            if isinstance(image, torch.Tensor):
                if image.dim() == 3:
                    image = image.unsqueeze(0)  # Add batch dimension
                
            return image.to(self.device)
        except Exception as e:
            logger.error(f"Error preprocessing image: {e}")
            return None
    
    def _predict_impl(self, image):
        """Internal classification implementation."""
        try:
            processed_image = self.preprocess_input(image)
            if processed_image is None:
                raise ValueError("Failed to process image")
            
            with torch.no_grad():
                outputs = self.model(processed_image)
                probabilities = torch.softmax(outputs, dim=1)
                
            # Convert to CPU for further processing
            probabilities = probabilities.cpu().numpy()[0]
            
            # Create results dictionary
            results = {}
            for i, class_name in enumerate(self.class_names):
                results[class_name] = float(probabilities[i])
            
            # Sort by probability
            results = dict(sorted(results.items(), key=lambda x: x[1], reverse=True))
            
            # Add metadata for enhanced UI
            top_prediction = list(results.keys())[0]
            top_confidence = results[top_prediction]
            
            enhanced_results = {
                "predictions": results,
                "top_prediction": top_prediction,
                "top_confidence": top_confidence,
                "confidence_level": self._get_confidence_level(top_confidence),
                "processing_time": time.time(),
                "model_confidence": "high" if top_confidence > 0.8 else "medium" if top_confidence > 0.6 else "low"
            }
            
            logger.info(f"Classification completed, top prediction: {top_prediction} ({top_confidence:.3f})")
            return enhanced_results
            
        except Exception as e:
            logger.error(f"Error during classification: {e}")
            raise e
    
    def _get_confidence_level(self, confidence):
        """Get human-readable confidence level."""
        if confidence >= 0.9:
            return "Very High"
        elif confidence >= 0.8:
            return "High"
        elif confidence >= 0.6:
            return "Medium"
        elif confidence >= 0.4:
            return "Low"
        else:
            return "Very Low"
    
    def create_interface(self):
        """Create enhanced Gradio interface for classification with better UI/UX."""
        try:
            import gradio as gr
            
            # Enhanced CSS for better UI
            custom_css = """
            .gradio-container {
                font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            }
            .confidence-high { color: #28a745; font-weight: bold; }
            .confidence-medium { color: #ffc107; font-weight: bold; }
            .confidence-low { color: #dc3545; font-weight: bold; }
            .error-message { 
                background-color: #f8d7da; 
                border: 1px solid #f5c6cb; 
                color: #721c24; 
                padding: 10px; 
                border-radius: 5px; 
                margin: 10px 0; 
            }
            .success-message { 
                background-color: #d4edda; 
                border: 1px solid #c3e6cb; 
                color: #155724; 
                padding: 10px; 
                border-radius: 5px; 
                margin: 10px 0; 
            }
            .stats-container {
                background-color: #f8f9fa;
                border: 1px solid #dee2e6;
                border-radius: 5px;
                padding: 15px;
                margin: 10px 0;
            }
            """
            
            # Create enhanced interface with Blocks
            with gr.Blocks(
                title=self.config.title,
                theme=self.config.theme,
                css=custom_css
            ) as interface:
                
                # Header
                gr.Markdown(f"# {self.config.title}")
                gr.Markdown(self.config.description)
                
                with gr.Row():
                    with gr.Column(scale=2):
                        # Input section
                        gr.Markdown("## 📸 Upload Image")
                        image_input = gr.Image(
                            type="pil", 
                            label="Upload Image",
                            height=300,
                            tooltip="Upload an image to classify. Supported formats: JPG, PNG, GIF, BMP, TIFF"
                        )
                        
                        # Example images
                        if self.config.enable_example_inputs:
                            gr.Markdown("### 💡 Example Images")
                            gr.Examples(
                                examples=[
                                    ["https://images.unsplash.com/photo-1543852786-1cf6624b998d?w=300&h=300&fit=crop"],
                                    ["https://images.unsplash.com/photo-1552053831-71594a27632d?w=300&h=300&fit=crop"],
                                    ["https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=300&h=300&fit=crop"]
                                ],
                                inputs=image_input,
                                label="Try these examples"
                            )
                        
                        # Processing options
                        with gr.Accordion("⚙️ Advanced Options", open=False):
                            confidence_threshold = gr.Slider(
                                minimum=0.1, 
                                maximum=1.0, 
                                value=0.5, 
                                step=0.1,
                                label="Confidence Threshold",
                                tooltip="Only show predictions above this confidence level"
                            )
                            show_all_classes = gr.Checkbox(
                                label="Show All Classes", 
                                value=True,
                                tooltip="Display all class predictions or only top ones"
                            )
                        
                        # Process button
                        process_btn = gr.Button(
                            "🔍 Classify Image", 
                            variant="primary",
                            size="lg"
                        )
                        
                        # Progress bar
                        if self.config.enable_progress_bars:
                            progress_bar = gr.Progress()
                    
                    with gr.Column(scale=2):
                        # Output section
                        gr.Markdown("## 🎯 Classification Results")
                        
                        # Main results
                        results_output = gr.JSON(
                            label="Raw Results",
                            visible=False
                        )
                        
                        # Enhanced display
                        top_prediction = gr.Markdown("### Top Prediction")
                        confidence_display = gr.Markdown("### Confidence Level")
                        
                        # Detailed results
                        predictions_table = gr.DataFrame(
                            headers=["Class", "Confidence", "Confidence Level"],
                            label="All Predictions",
                            interactive=False
                        )
                        
                        # Error display
                        error_display = gr.HTML(
                            label="Error Messages",
                            visible=False
                        )
                        
                        # Success message
                        success_display = gr.HTML(
                            label="Success Messages",
                            visible=False
                        )
                        
                        # Download results
                        if self.config.enable_result_download:
                            download_btn = gr.DownloadButton(
                                label="📥 Download Results",
                                visible=False
                            )
                
                # Statistics section
                with gr.Accordion("📊 Interface Statistics", open=False):
                    stats_display = gr.JSON(label="Performance Metrics")
                    refresh_stats_btn = gr.Button("🔄 Refresh Stats")
                
                # Help section
                if self.config.enable_help_tooltips:
                    with gr.Accordion("❓ Help & Tips", open=False):
                        gr.Markdown("""
                        ### How to use:
                        1. **Upload an image** using the file picker or drag & drop
                        2. **Adjust settings** in Advanced Options if needed
                        3. **Click Classify** to process the image
                        4. **View results** in the right panel
                        5. **Download results** as JSON if needed
                        
                        ### Tips:
                        - Use clear, well-lit images for best results
                        - Supported formats: JPG, PNG, GIF, BMP, TIFF
                        - Maximum file size: 50MB
                        - Results are cached for faster repeat queries
                        """)
                
                # Event handlers
                def process_image(image, confidence_threshold, show_all_classes, progress=gr.Progress()):
                    """Process image with enhanced error handling and UI feedback."""
                    try:
                        if image is None:
                            return {
                                error_display: gr.HTML.update(
                                    value='<div class="error-message">❌ Please upload an image first.</div>',
                                    visible=True
                                ),
                                success_display: gr.HTML.update(visible=False),
                                results_output: gr.JSON.update(visible=False),
                                top_prediction: gr.Markdown.update(value="### No prediction"),
                                confidence_display: gr.Markdown.update(value="### No confidence data"),
                                predictions_table: gr.DataFrame.update(value=None),
                                download_btn: gr.DownloadButton.update(visible=False)
                            }
                        
                        # Update progress
                        progress(0.2, desc="Validating input...")
                        
                        # Process image
                        progress(0.4, desc="Processing image...")
                        result = self.predict(image)
                        
                        progress(0.8, desc="Formatting results...")
                        
                        # Check for errors
                        if result.get('error', False):
                            return {
                                error_display: gr.HTML.update(
                                    value=f'<div class="error-message">❌ {result["message"]}</div>',
                                    visible=True
                                ),
                                success_display: gr.HTML.update(visible=False),
                                results_output: gr.JSON.update(visible=False),
                                top_prediction: gr.Markdown.update(value="### Error occurred"),
                                confidence_display: gr.Markdown.update(value="### No confidence data"),
                                predictions_table: gr.DataFrame.update(value=None),
                                download_btn: gr.DownloadButton.update(visible=False)
                            }
                        
                        # Filter by confidence threshold
                        filtered_predictions = {
                            k: v for k, v in result['predictions'].items() 
                            if v >= confidence_threshold
                        }
                        
                        # Prepare table data
                        table_data = []
                        for class_name, confidence in filtered_predictions.items():
                            confidence_level = self._get_confidence_level(confidence)
                            table_data.append([class_name, f"{confidence:.3f}", confidence_level])
                        
                        # Update outputs
                        progress(1.0, desc="Complete!")
                        
                        return {
                            error_display: gr.HTML.update(visible=False),
                            success_display: gr.HTML.update(
                                value=f'<div class="success-message">✅ Classification completed successfully!</div>',
                                visible=True
                            ),
                            results_output: gr.JSON.update(value=result, visible=True),
                            top_prediction: gr.Markdown.update(
                                value=f"### 🏆 {result['top_prediction']}"
                            ),
                            confidence_display: gr.Markdown.update(
                                value=f"### 📊 {result['confidence_level']} ({result['top_confidence']:.1%})"
                            ),
                            predictions_table: gr.DataFrame.update(value=table_data),
                            download_btn: gr.DownloadButton.update(
                                value=json.dumps(result, indent=2),
                                label=f"📥 Download Results ({len(table_data)} classes)",
                                visible=True
                            )
                        }
                        
                    except Exception as e:
                        error_msg = self.handle_error(e, "interface_processing")
                        return {
                            error_display: gr.HTML.update(
                                value=f'<div class="error-message">❌ {error_msg["message"]}</div>',
                                visible=True
                            ),
                            success_display: gr.HTML.update(visible=False),
                            results_output: gr.JSON.update(visible=False),
                            top_prediction: gr.Markdown.update(value="### Error occurred"),
                            confidence_display: gr.Markdown.update(value="### No confidence data"),
                            predictions_table: gr.DataFrame.update(value=None),
                            download_btn: gr.DownloadButton.update(visible=False)
                        }
                
                def refresh_statistics():
                    """Refresh interface statistics."""
                    stats = self.get_interface_stats()
                    return gr.JSON.update(value=stats)
                
                # Connect events
                process_btn.click(
                    fn=process_image,
                    inputs=[image_input, confidence_threshold, show_all_classes],
                    outputs=[
                        error_display, success_display, results_output,
                        top_prediction, confidence_display, predictions_table, download_btn
                    ]
                )
                
                refresh_stats_btn.click(
                    fn=refresh_statistics,
                    outputs=[stats_display]
                )
                
                # Initial stats load
                interface.load(fn=refresh_statistics, outputs=[stats_display])
            
            logger.info("Enhanced classification interface created successfully")
            return interface
            
        except ImportError:
            logger.error("Gradio not available, cannot create interface")
            return None
        except Exception as e:
            logger.error(f"Error creating classification interface: {e}")
            return None


class TextGenerationDemo(GradioModelInterface):
    """Gradio interface for text generation models."""
    
    def __init__(self, 
                 model: nn.Module, 
                 tokenizer,
                 config: GradioConfig,
                 max_length: int = 100,
                 temperature: float = 0.7,
                 top_p: float = 0.9,
                 top_k: int = 50,
                 device: str = 'cuda' if torch.cuda.is_available() else 'cpu'):
        """
        Initialize text generation demo.
        
        Args:
            model: Text generation model
            tokenizer: Tokenizer
            config: Gradio configuration
            max_length: Maximum generation length
            temperature: Sampling temperature
            top_p: Nucleus sampling parameter
            top_k: Top-k sampling parameter
            device: Computing device
        """
        super().__init__(model, config, device)
        self.tokenizer = tokenizer
        self.max_length = max_length
        self.temperature = temperature
        self.top_p = top_p
        self.top_k = top_k
        
        logger.info("Text generation demo initialized")
    
    def preprocess_input(self, text: str):
        """Preprocess input text."""
        try:
            if hasattr(self.tokenizer, 'encode'):
                tokens = self.tokenizer.encode(text, return_tensors='pt')
            else:
                # Fallback for custom tokenizer
                tokens = torch.tensor([self.tokenizer.word_to_idx.get(word, 0) 
                                     for word in text.split()]).unsqueeze(0)
            
            return tokens.to(self.device)
        except Exception as e:
            logger.error(f"Error preprocessing text: {e}")
            return None
    
    def predict(self, prompt: str, max_length: int = None, temperature: float = None):
        """Generate text from prompt."""
        try:
            max_length = max_length or self.max_length
            temperature = temperature or self.temperature
            
            input_ids = self.preprocess_input(prompt)
            if input_ids is None:
                return "Error: Failed to process input text"
            
            with torch.no_grad():
                generated_ids = self._generate_text(
                    input_ids, max_length, temperature
                )
            
            if hasattr(self.tokenizer, 'decode'):
                generated_text = self.tokenizer.decode(
                    generated_ids[0], skip_special_tokens=True
                )
            else:
                # Fallback for custom tokenizer
                generated_text = ' '.join([
                    self.tokenizer.idx_to_word.get(idx.item(), '<UNK>')
                    for idx in generated_ids[0]
                ])
            
            logger.info(f"Text generation completed, length: {len(generated_text)}")
            return generated_text
            
        except Exception as e:
            logger.error(f"Error during text generation: {e}")
            return f"Error: {str(e)}"
    
    def _generate_text(self, input_ids: torch.Tensor, max_length: int, temperature: float):
        """Internal text generation method."""
        generated = input_ids.clone()
        
        for _ in range(max_length):
            with torch.no_grad():
                outputs = self.model(generated)
                
                if isinstance(outputs, dict):
                    logits = outputs.get('logits', outputs.get('prediction_scores', outputs))
                else:
                    logits = outputs
                
                if logits.dim() > 2:
                    logits = logits[:, -1, :]  # Get last token logits
                
                # Apply temperature
                logits = logits / temperature
                
                # Sample next token
                probs = torch.softmax(logits, dim=-1)
                next_token = torch.multinomial(probs, num_samples=1)
                
                # Append to generated sequence
                generated = torch.cat([generated, next_token], dim=-1)
                
                # Check for stopping criteria (simplified)
                if next_token.item() == 0:  # Assuming 0 is end token
                    break
        
        return generated
    
    def create_interface(self):
        """Create Gradio interface for text generation."""
        try:
            import gradio as gr
            
            interface = gr.Interface(
                fn=self.predict,
                inputs=[
                    gr.Textbox(label="Input Prompt", placeholder="Enter your prompt here..."),
                    gr.Slider(minimum=10, maximum=500, value=self.max_length, 
                             label="Max Length"),
                    gr.Slider(minimum=0.1, maximum=2.0, value=self.temperature, 
                             label="Temperature")
                ],
                outputs=gr.Textbox(label="Generated Text"),
                title=self.config.title,
                description=self.config.description,
                theme=self.config.theme,
                allow_flagging=self.config.allow_flagging,
                analytics_enabled=self.config.analytics_enabled
            )
            
            logger.info("Text generation interface created successfully")
            return interface
            
        except ImportError:
            logger.error("Gradio not available, cannot create interface")
            return None
        except Exception as e:
            logger.error(f"Error creating text generation interface: {e}")
            return None


class ImageGenerationDemo(GradioModelInterface):
    """Gradio interface for image generation models (including diffusion models)."""
    
    def __init__(self, 
                 model, 
                 config: GradioConfig,
                 model_type: str = "diffusion",
                 image_size: int = 512,
                 num_inference_steps: int = 50,
                 guidance_scale: float = 7.5,
                 device: str = 'cuda' if torch.cuda.is_available() else 'cpu'):
        """
        Initialize image generation demo.
        
        Args:
            model: Image generation model or pipeline
            config: Gradio configuration
            model_type: Type of model (diffusion, gan, vae)
            image_size: Generated image size
            num_inference_steps: Number of diffusion steps
            guidance_scale: Guidance scale for diffusion
            device: Computing device
        """
        super().__init__(model, config, device)
        self.model_type = model_type
        self.image_size = image_size
        self.num_inference_steps = num_inference_steps
        self.guidance_scale = guidance_scale
        
        logger.info(f"Image generation demo initialized: {model_type}")
    
    def predict(self, prompt: str, num_steps: int = None, guidance: float = None, 
                seed: int = None):
        """Generate image from text prompt."""
        try:
            num_steps = num_steps or self.num_inference_steps
            guidance = guidance or self.guidance_scale
            
            if seed is not None:
                torch.manual_seed(seed)
                if torch.cuda.is_available():
                    torch.cuda.manual_seed(seed)
            
            if self.model_type == "diffusion":
                return self._generate_diffusion_image(prompt, num_steps, guidance)
            elif self.model_type == "gan":
                return self._generate_gan_image(prompt)
            else:
                return self._generate_generic_image(prompt)
                
        except Exception as e:
            logger.error(f"Error during image generation: {e}")
            return None
    
    def _generate_diffusion_image(self, prompt: str, num_steps: int, guidance: float):
        """Generate image using diffusion model."""
        try:
            # Check if it's a diffusers pipeline
            if hasattr(self.model, '__call__') and hasattr(self.model, 'scheduler'):
                result = self.model(
                    prompt=prompt,
                    num_inference_steps=num_steps,
                    guidance_scale=guidance,
                    height=self.image_size,
                    width=self.image_size
                )
                
                if hasattr(result, 'images'):
                    image = result.images[0]
                else:
                    image = result
                    
                logger.info("Diffusion image generation completed")
                return image
            else:
                # Custom diffusion model
                return self._generate_custom_diffusion_image(prompt, num_steps)
                
        except Exception as e:
            logger.error(f"Error in diffusion generation: {e}")
            return None
    
    def _generate_custom_diffusion_image(self, prompt: str, num_steps: int):
        """Generate image using custom diffusion model."""
        try:
            # This is a simplified version - actual implementation would depend on model architecture
            batch_size = 1
            channels = 3
            height = width = self.image_size
            
            # Generate random noise
            noise = torch.randn(batch_size, channels, height, width).to(self.device)
            
            # Simple denoising process (placeholder)
            with torch.no_grad():
                for step in range(num_steps):
                    model_output = self.model(noise)
                    if isinstance(model_output, dict):
                        noise = model_output.get('sample', model_output.get('prediction', noise))
                    else:
                        noise = model_output
            
            # Convert to PIL Image
            image = noise.cpu().clamp(0, 1)
            image = (image * 255).byte().permute(0, 2, 3, 1).numpy()[0]
            
            try:
                from PIL import Image
                pil_image = Image.fromarray(image)
                logger.info("Custom diffusion image generation completed")
                return pil_image
            except ImportError:
                logger.warning("PIL not available, returning tensor")
                return image
                
        except Exception as e:
            logger.error(f"Error in custom diffusion generation: {e}")
            return None
    
    def _generate_gan_image(self, prompt: str):
        """Generate image using GAN model."""
        try:
            # Simple GAN generation (placeholder)
            batch_size = 1
            latent_dim = 100
            
            # Generate random latent vector
            latent = torch.randn(batch_size, latent_dim).to(self.device)
            
            with torch.no_grad():
                generated = self.model(latent)
            
            # Convert to PIL Image
            image = generated.cpu().clamp(0, 1)
            image = (image * 255).byte().permute(0, 2, 3, 1).numpy()[0]
            
            try:
                from PIL import Image
                pil_image = Image.fromarray(image)
                logger.info("GAN image generation completed")
                return pil_image
            except ImportError:
                logger.warning("PIL not available, returning tensor")
                return image
                
        except Exception as e:
            logger.error(f"Error in GAN generation: {e}")
            return None
    
    def _generate_generic_image(self, prompt: str):
        """Generate image using generic model."""
        try:
            # Placeholder for generic image generation
            batch_size = 1
            channels = 3
            height = width = self.image_size
            
            with torch.no_grad():
                generated = self.model(torch.randn(batch_size, channels, height, width).to(self.device))
            
            # Convert to PIL Image
            image = generated.cpu().clamp(0, 1)
            image = (image * 255).byte().permute(0, 2, 3, 1).numpy()[0]
            
            try:
                from PIL import Image
                pil_image = Image.fromarray(image)
                logger.info("Generic image generation completed")
                return pil_image
            except ImportError:
                logger.warning("PIL not available, returning tensor")
                return image
                
        except Exception as e:
            logger.error(f"Error in generic generation: {e}")
            return None
    
    def create_interface(self):
        """Create Gradio interface for image generation."""
        try:
            import gradio as gr
            
            interface = gr.Interface(
                fn=self.predict,
                inputs=[
                    gr.Textbox(label="Text Prompt", 
                              placeholder="Describe the image you want to generate..."),
                    gr.Slider(minimum=10, maximum=150, value=self.num_inference_steps, 
                             label="Number of Steps"),
                    gr.Slider(minimum=1.0, maximum=20.0, value=self.guidance_scale, 
                             label="Guidance Scale"),
                    gr.Number(label="Seed (optional)", precision=0)
                ],
                outputs=gr.Image(label="Generated Image"),
                title=self.config.title,
                description=self.config.description,
                theme=self.config.theme,
                allow_flagging=self.config.allow_flagging,
                analytics_enabled=self.config.analytics_enabled
            )
            
            logger.info("Image generation interface created successfully")
            return interface
            
        except ImportError:
            logger.error("Gradio not available, cannot create interface")
            return None
        except Exception as e:
            logger.error(f"Error creating image generation interface: {e}")
            return None


class TrainingVisualizationDemo:
    """Gradio interface for visualizing training metrics and model architecture."""
    
    def __init__(self, config: GradioConfig):
        """
        Initialize training visualization demo.
        
        Args:
            config: Gradio configuration
        """
        self.config = config
        logger.info("Training visualization demo initialized")
    
    def plot_training_metrics(self, metrics_data: dict):
        """Plot training metrics."""
        try:
            import matplotlib.pyplot as plt
            import io
            import base64
            
            fig, axes = plt.subplots(2, 2, figsize=(12, 10))
            fig.suptitle('Training Metrics', fontsize=16)
            
            # Loss plot
            if 'train_loss' in metrics_data and 'val_loss' in metrics_data:
                axes[0, 0].plot(metrics_data['train_loss'], label='Train Loss')
                axes[0, 0].plot(metrics_data['val_loss'], label='Validation Loss')
                axes[0, 0].set_title('Loss')
                axes[0, 0].set_xlabel('Epoch')
                axes[0, 0].set_ylabel('Loss')
                axes[0, 0].legend()
                axes[0, 0].grid(True)
            
            # Accuracy plot
            if 'train_acc' in metrics_data and 'val_acc' in metrics_data:
                axes[0, 1].plot(metrics_data['train_acc'], label='Train Accuracy')
                axes[0, 1].plot(metrics_data['val_acc'], label='Validation Accuracy')
                axes[0, 1].set_title('Accuracy')
                axes[0, 1].set_xlabel('Epoch')
                axes[0, 1].set_ylabel('Accuracy')
                axes[0, 1].legend()
                axes[0, 1].grid(True)
            
            # Learning rate plot
            if 'learning_rate' in metrics_data:
                axes[1, 0].plot(metrics_data['learning_rate'])
                axes[1, 0].set_title('Learning Rate')
                axes[1, 0].set_xlabel('Epoch')
                axes[1, 0].set_ylabel('Learning Rate')
                axes[1, 0].grid(True)
            
            # Gradient norm plot
            if 'grad_norm' in metrics_data:
                axes[1, 1].plot(metrics_data['grad_norm'])
                axes[1, 1].set_title('Gradient Norm')
                axes[1, 1].set_xlabel('Epoch')
                axes[1, 1].set_ylabel('Gradient Norm')
                axes[1, 1].grid(True)
            
            plt.tight_layout()
            
            # Convert to base64 for display
            buffer = io.BytesIO()
            plt.savefig(buffer, format='png', dpi=150, bbox_inches='tight')
            buffer.seek(0)
            
            plt.close(fig)
            
            return buffer.getvalue()
            
        except Exception as e:
            logger.error(f"Error plotting training metrics: {e}")
            return None
    
    def visualize_model_architecture(self, model: nn.Module):
        """Visualize model architecture."""
        try:
            # Create a text representation of the model
            model_str = str(model)
            
            # Count parameters
            total_params = sum(p.numel() for p in model.parameters())
            trainable_params = sum(p.numel() for p in model.parameters() if p.requires_grad)
            
            # Create summary
            summary = f"""
Model Architecture Summary
{'='*50}

Total Parameters: {total_params:,}
Trainable Parameters: {trainable_params:,}
Non-trainable Parameters: {total_params - trainable_params:,}

Model Structure:
{'-'*50}
{model_str}
            """
            
            logger.info("Model architecture visualization completed")
            return summary
            
        except Exception as e:
            logger.error(f"Error visualizing model architecture: {e}")
            return f"Error: {str(e)}"
    
    def create_interface(self):
        """Create Gradio interface for training visualization."""
        try:
            import gradio as gr
            
            with gr.Blocks(title=self.config.title, theme=self.config.theme) as demo:
                gr.Markdown(f"# {self.config.title}")
                gr.Markdown(self.config.description)
                
                with gr.Tab("Training Metrics"):
                    metrics_input = gr.File(label="Upload Metrics JSON")
                    plot_button = gr.Button("Plot Metrics")
                    metrics_output = gr.Image(label="Training Metrics Plot")
                    
                    plot_button.click(
                        fn=self._plot_from_file,
                        inputs=metrics_input,
                        outputs=metrics_output
                    )
                
                with gr.Tab("Model Architecture"):
                    model_input = gr.File(label="Upload Model State Dict")
                    visualize_button = gr.Button("Visualize Architecture")
                    arch_output = gr.Textbox(label="Model Architecture", lines=20)
                    
                    visualize_button.click(
                        fn=self._visualize_from_file,
                        inputs=model_input,
                        outputs=arch_output
                    )
            
            logger.info("Training visualization interface created successfully")
            return demo
            
        except ImportError:
            logger.error("Gradio not available, cannot create interface")
            return None
        except Exception as e:
            logger.error(f"Error creating visualization interface: {e}")
            return None
    
    def _plot_from_file(self, file_path: str):
        """Plot metrics from uploaded file."""
        try:
            import json
            
            if file_path is None:
                return None
            
            with open(file_path.name, 'r') as f:
                metrics_data = json.load(f)
            
            return self.plot_training_metrics(metrics_data)
            
        except Exception as e:
            logger.error(f"Error plotting from file: {e}")
            return None
    
    def _visualize_from_file(self, file_path: str):
        """Visualize model from uploaded file."""
        try:
            if file_path is None:
                return "Please upload a model file"
            
            # Load model state dict
            state_dict = torch.load(file_path.name, map_location='cpu')
            
            # Create a summary of the state dict
            summary = "Model State Dictionary Summary\n"
            summary += "=" * 50 + "\n\n"
            
            total_params = 0
            for name, param in state_dict.items():
                param_count = param.numel() if hasattr(param, 'numel') else 0
                total_params += param_count
                summary += f"{name}: {list(param.shape)} ({param_count:,} params)\n"
            
            summary += f"\nTotal Parameters: {total_params:,}"
            
            return summary
            
        except Exception as e:
            logger.error(f"Error visualizing from file: {e}")
            return f"Error: {str(e)}"


class BatchProcessingDemo:
    """Gradio interface for batch processing multiple inputs."""
    
    def __init__(self, model_interface: GradioModelInterface, config: GradioConfig):
        """
        Initialize batch processing demo.
        
        Args:
            model_interface: Base model interface
            config: Gradio configuration
        """
        self.model_interface = model_interface
        self.config = config
        logger.info("Batch processing demo initialized")
    
    def process_batch(self, file_list):
        """Process multiple files in batch."""
        try:
            if not file_list:
                return "No files uploaded"
            
            results = []
            
            for file_info in file_list:
                try:
                    # Process individual file
                    if hasattr(self.model_interface, 'predict'):
                        result = self.model_interface.predict(file_info.name)
                        results.append({
                            'file': file_info.name,
                            'result': result
                        })
                except Exception as e:
                    results.append({
                        'file': file_info.name,
                        'error': str(e)
                    })
            
            # Format results
            output = "Batch Processing Results\n"
            output += "=" * 50 + "\n\n"
            
            for i, result in enumerate(results, 1):
                output += f"File {i}: {result['file']}\n"
                if 'error' in result:
                    output += f"Error: {result['error']}\n"
                else:
                    output += f"Result: {result['result']}\n"
                output += "-" * 30 + "\n"
            
            logger.info(f"Batch processing completed for {len(results)} files")
            return output
            
        except Exception as e:
            logger.error(f"Error in batch processing: {e}")
            return f"Error: {str(e)}"
    
    def create_interface(self):
        """Create Gradio interface for batch processing."""
        try:
            import gradio as gr
            
            interface = gr.Interface(
                fn=self.process_batch,
                inputs=gr.File(file_count="multiple", label="Upload Multiple Files"),
                outputs=gr.Textbox(label="Batch Results", lines=20),
                title=f"{self.config.title} - Batch Processing",
                description="Upload multiple files for batch processing",
                theme=self.config.theme,
                allow_flagging=self.config.allow_flagging,
                analytics_enabled=self.config.analytics_enabled
            )
            
            logger.info("Batch processing interface created successfully")
            return interface
            
        except ImportError:
            logger.error("Gradio not available, cannot create interface")
            return None
        except Exception as e:
            logger.error(f"Error creating batch processing interface: {e}")
            return None


class GradioInterfaceFactory:
    """Factory class for creating different types of Gradio interfaces."""
    
    @staticmethod
    def create_classification_demo(model: nn.Module, 
                                 class_names: List[str],
                                 config: GradioConfig = None,
                                 transforms=None) -> ClassificationDemo:
        """
        Create classification demo interface.
        
        Args:
            model: Classification model
            class_names: List of class names
            config: Gradio configuration
            transforms: Image transforms
            
        Returns:
            ClassificationDemo instance
        """
        if config is None:
            config = GradioConfig(
                title="Image Classification Demo",
                description="Upload an image to classify it using a deep learning model."
            )
        
        return ClassificationDemo(model, config, class_names, transforms)
    
    @staticmethod
    def create_text_generation_demo(model: nn.Module,
                                  tokenizer,
                                  config: GradioConfig = None) -> TextGenerationDemo:
        """
        Create text generation demo interface.
        
        Args:
            model: Text generation model
            tokenizer: Tokenizer
            config: Gradio configuration
            
        Returns:
            TextGenerationDemo instance
        """
        if config is None:
            config = GradioConfig(
                title="Text Generation Demo",
                description="Enter a prompt to generate text using a language model."
            )
        
        return TextGenerationDemo(model, tokenizer, config)
    
    @staticmethod
    def create_image_generation_demo(model,
                                   config: GradioConfig = None,
                                   model_type: str = "diffusion") -> ImageGenerationDemo:
        """
        Create image generation demo interface.
        
        Args:
            model: Image generation model
            config: Gradio configuration
            model_type: Type of model
            
        Returns:
            ImageGenerationDemo instance
        """
        if config is None:
            config = GradioConfig(
                title="Image Generation Demo",
                description="Enter a text prompt to generate images using AI."
            )
        
        return ImageGenerationDemo(model, config, model_type)
    
    @staticmethod
    def create_training_visualization_demo(config: GradioConfig = None) -> TrainingVisualizationDemo:
        """
        Create training visualization demo interface.
        
        Args:
            config: Gradio configuration
            
        Returns:
            TrainingVisualizationDemo instance
        """
        if config is None:
            config = GradioConfig(
                title="Training Visualization Demo",
                description="Visualize training metrics and model architecture."
            )
        
        return TrainingVisualizationDemo(config)
    
    @staticmethod
    def create_batch_processing_demo(model_interface: GradioModelInterface,
                                   config: GradioConfig = None) -> BatchProcessingDemo:
        """
        Create batch processing demo interface.
        
        Args:
            model_interface: Base model interface
            config: Gradio configuration
            
        Returns:
            BatchProcessingDemo instance
        """
        if config is None:
            config = GradioConfig(
                title="Batch Processing Demo",
                description="Process multiple files in batch using AI models."
            )
        
        return BatchProcessingDemo(model_interface, config)
    
    @staticmethod
    def create_multi_tab_demo(interfaces: List[GradioModelInterface],
                            config: GradioConfig = None):
        """
        Create multi-tab demo with multiple interfaces.
        
        Args:
            interfaces: List of interface instances
            config: Gradio configuration
            
        Returns:
            Gradio Blocks interface
        """
        try:
            import gradio as gr
            
            if config is None:
                config = GradioConfig(
                    title="Multi-Model Demo",
                    description="Comprehensive AI model demonstration platform."
                )
            
            with gr.Blocks(title=config.title, theme=config.theme) as demo:
                gr.Markdown(f"# {config.title}")
                gr.Markdown(config.description)
                
                for i, interface in enumerate(interfaces):
                    with gr.Tab(f"Model {i+1}"):
                        if hasattr(interface, 'create_interface'):
                            sub_interface = interface.create_interface()
                            if sub_interface:
                                # Extract components from interface
                                if hasattr(sub_interface, 'input_components'):
                                    for component in sub_interface.input_components:
                                        component.render()
                
            logger.info(f"Multi-tab demo created with {len(interfaces)} interfaces")
            return demo
            
        except ImportError:
            logger.error("Gradio not available, cannot create multi-tab demo")
            return None
        except Exception as e:
            logger.error(f"Error creating multi-tab demo: {e}")
            return None


class GradioLauncher:
    """Utility class for launching Gradio interfaces."""
    
    @staticmethod
    def launch_interface(interface, config: GradioConfig):
        """
        Launch Gradio interface with specified configuration.
        
        Args:
            interface: Gradio interface
            config: Launch configuration
        """
        try:
            if interface is None:
                logger.error("Cannot launch None interface")
                return False
            
            launch_kwargs = {
                'server_name': config.server_name,
                'server_port': config.server_port,
                'share': config.share,
                'debug': config.debug,
                'auth': config.auth,
                'favicon_path': config.favicon_path,
                'show_error': config.show_error,
                'height': config.height,
                'width': config.width,
                'enable_queue': config.enable_queue,
                'max_threads': config.max_threads
            }
            
            # Remove None values
            launch_kwargs = {k: v for k, v in launch_kwargs.items() if v is not None}
            
            logger.info(f"Launching Gradio interface on {config.server_name}:{config.server_port}")
            interface.launch(**launch_kwargs)
            
            return True
            
        except Exception as e:
            logger.error(f"Error launching interface: {e}")
            return False
    
    @staticmethod
    def launch_demo_suite(models: dict, config: GradioConfig = None):
        """
        Launch a comprehensive demo suite with multiple models.
        
        Args:
            models: Dictionary of model configurations
            config: Global configuration
        """
        try:
            if config is None:
                config = GradioConfig(
                    title="AI Model Demo Suite",
                    description="Comprehensive demonstration of AI models"
                )
            
            interfaces = []
            
            # Create interfaces for each model type
            for model_type, model_config in models.items():
                if model_type == "classification" and 'model' in model_config:
                    demo = GradioInterfaceFactory.create_classification_demo(
                        model_config['model'],
                        model_config.get('class_names', ['Class 1', 'Class 2']),
                        config
                    )
                    interfaces.append(demo)
                
                elif model_type == "text_generation" and 'model' in model_config:
                    demo = GradioInterfaceFactory.create_text_generation_demo(
                        model_config['model'],
                        model_config.get('tokenizer'),
                        config
                    )
                    interfaces.append(demo)
                
                elif model_type == "image_generation" and 'model' in model_config:
                    demo = GradioInterfaceFactory.create_image_generation_demo(
                        model_config['model'],
                        config,
                        model_config.get('model_type', 'diffusion')
                    )
                    interfaces.append(demo)
            
            # Add training visualization
            viz_demo = GradioInterfaceFactory.create_training_visualization_demo(config)
            interfaces.append(viz_demo)
            
            # Create multi-tab interface
            multi_demo = GradioInterfaceFactory.create_multi_tab_demo(interfaces, config)
            
            if multi_demo:
                return GradioLauncher.launch_interface(multi_demo, config)
            else:
                logger.error("Failed to create multi-tab demo")
                return False
                
        except Exception as e:
            logger.error(f"Error launching demo suite: {e}")
            return False


