@dataclass
class ExperimentMetadata:
    """Comprehensive metadata for experiment tracking"""
    
    # Basic experiment information
    experiment_name: str
    experiment_id: str
    description: str = ""
    tags: List[str] = field(default_factory=list)
    version: str = "1.0.0"
    
    # Timestamp information
    created_at: str = field(default_factory=lambda: datetime.now().isoformat())
    started_at: Optional[str] = None
    completed_at: Optional[str] = None
    
    # Status tracking
    status: str = "created"  # created, running, completed, failed, paused
    
    # System information
    python_version: str = field(default_factory=lambda: sys.version)
    torch_version: str = field(default_factory=lambda: torch.__version__)
    cuda_version: Optional[str] = None
    platform: str = field(default_factory=lambda: sys.platform)
    
    # Configuration hash for reproducibility
    config_hash: Optional[str] = None
    
    # Git information (if available)
    git_commit: Optional[str] = None
    git_branch: Optional[str] = None
    git_dirty: bool = False
    
    def __post_init__(self):
        """Set default values after initialization"""
        if self.started_at is None:
            self.started_at = self.created_at
        
        # Try to get CUDA version
        if torch.cuda.is_available():
            self.cuda_version = torch.version.cuda
        
        # Try to get git information
        try:
            import subprocess
            result = subprocess.run(['git', 'rev-parse', 'HEAD'], 
                                  capture_output=True, text=True, cwd=Path.cwd())
            if result.returncode == 0:
                self.git_commit = result.stdout.strip()
            
            result = subprocess.run(['git', 'branch', '--show-current'], 
                                  capture_output=True, text=True, cwd=Path.cwd())
            if result.returncode == 0:
                self.git_branch = result.stdout.strip()
            
            result = subprocess.run(['git', 'status', '--porcelain'], 
                                  capture_output=True, text=True, cwd=Path.cwd())
            self.git_dirty = bool(result.stdout.strip())
        except Exception:
            pass  # Git not available or not a git repository


@dataclass
class CheckpointMetadata:
    """Metadata for model checkpoints"""
    
    # Checkpoint identification
    checkpoint_id: str
    experiment_id: str
    checkpoint_name: str
    
    # Training state
    epoch: int
    step: int
    global_step: int
    
    # Performance metrics at checkpoint time
    train_loss: Optional[float] = None
    val_loss: Optional[float] = None
    train_accuracy: Optional[float] = None
    val_accuracy: Optional[float] = None
    custom_metrics: Dict[str, float] = field(default_factory=dict)
    
    # Model information
    model_size_mb: Optional[float] = None
    num_parameters: Optional[int] = None
    
    # File information
    file_path: Optional[str] = None
    file_size_bytes: Optional[int] = None
    compression_ratio: Optional[float] = None
    
    # Timestamp
    created_at: str = field(default_factory=lambda: datetime.now().isoformat())
    
    # Checkpoint type
    is_best: bool = False
    is_latest: bool = False
    checkpoint_type: str = "regular"  # regular, best, latest, emergency
    
    # Training context
    learning_rate: Optional[float] = None
    optimizer_state: bool = False
    scheduler_state: bool = False
    gradient_norm: Optional[float] = None
    
    # System state
    gpu_memory_used: Optional[float] = None
    cpu_memory_used: Optional[float] = None


class ModelCheckpointer:
    """Robust model checkpointing system with metadata management"""
    
    def __init__(self, checkpoint_dir: str = "checkpoints", max_checkpoints: int = 10):
        """Initialize the model checkpointer"""
        self.checkpoint_dir = Path(checkpoint_dir)
        self.max_checkpoints = max_checkpoints
        self.checkpoint_dir.mkdir(parents=True, exist_ok=True)
        
        # Registry for tracking checkpoints
        self.checkpoint_registry: Dict[str, CheckpointMetadata] = {}
        self.best_checkpoint: Optional[str] = None
        self.latest_checkpoint: Optional[str] = None
        
        # Load existing registry
        self._load_registry()
        
        logger.info(f"Model checkpointer initialized: {checkpoint_dir}")
    
    def _load_registry(self):
        """Load existing checkpoint registry from disk"""
        registry_file = self.checkpoint_dir / "registry.json"
        if registry_file.exists():
            try:
                with open(registry_file, 'r') as f:
                    registry_data = json.load(f)
                    for checkpoint_id, metadata_dict in registry_data.items():
                        metadata = CheckpointMetadata(**metadata_dict)
                        self.checkpoint_registry[checkpoint_id] = metadata
                        
                        if metadata.is_best:
                            self.best_checkpoint = checkpoint_id
                        if metadata.is_latest:
                            self.latest_checkpoint = checkpoint_id
                
                logger.info(f"Loaded {len(self.checkpoint_registry)} existing checkpoints")
            except Exception as e:
                logger.warning(f"Failed to load checkpoint registry: {e}")
    
    def _save_registry(self):
        """Save checkpoint registry to disk"""
        registry_file = self.checkpoint_dir / "registry.json"
        try:
            registry_data = {
                checkpoint_id: asdict(metadata)
                for checkpoint_id, metadata in self.checkpoint_registry.items()
            }
            with open(registry_file, 'w') as f:
                json.dump(registry_data, f, indent=2)
        except Exception as e:
            logger.error(f"Failed to save checkpoint registry: {e}")
    
    def _generate_checkpoint_id(self, experiment_id: str, epoch: int, step: int) -> str:
        """Generate unique checkpoint ID"""
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        return f"{experiment_id}_epoch_{epoch}_step_{step}_{timestamp}"
    
    def _calculate_model_size(self, model: nn.Module) -> Tuple[float, int]:
        """Calculate model size in MB and number of parameters"""
        param_size = 0
        num_params = 0
        
        for param in model.parameters():
            param_size += param.nelement() * param.element_size()
            num_params += param.nelement()
        
        size_mb = param_size / (1024 * 1024)
        return size_mb, num_params
    
    def _compress_checkpoint(self, checkpoint_data: Dict[str, Any], 
                           compression: str = "gzip") -> Tuple[bytes, float]:
        """Compress checkpoint data"""
        if compression == "gzip":
            import gzip
            data_bytes = pickle.dumps(checkpoint_data)
            compressed_data = gzip.compress(data_bytes)
            compression_ratio = len(compressed_data) / len(data_bytes)
            return compressed_data, compression_ratio
        else:
            # No compression
            data_bytes = pickle.dumps(checkpoint_data)
            return data_bytes, 1.0
    
    def save_checkpoint(self, experiment_id: str, model: nn.Module, 
                       epoch: int, step: int, global_step: int = 0,
                       optimizer: Optional[torch.optim.Optimizer] = None,
                       scheduler: Optional[Any] = None,
                       train_loss: Optional[float] = None,
                       val_loss: Optional[float] = None,
                       train_accuracy: Optional[float] = None,
                       val_accuracy: Optional[float] = None,
                       custom_metrics: Optional[Dict[str, float]] = None,
                       is_best: bool = False,
                       checkpoint_type: str = "regular",
                       compression: str = "gzip") -> str:
        """Save a comprehensive model checkpoint"""
        
        # Generate checkpoint ID
        checkpoint_id = self._generate_checkpoint_id(experiment_id, epoch, step)
        
        # Calculate model size
        model_size_mb, num_parameters = self._calculate_model_size(model)
        
        # Prepare checkpoint data
        checkpoint_data = {
            'checkpoint_id': checkpoint_id,
            'experiment_id': experiment_id,
            'epoch': epoch,
            'step': step,
            'global_step': global_step,
            'model_state_dict': model.state_dict(),
            'model_config': getattr(model, 'config', {}),
            'timestamp': datetime.now().isoformat()
        }
        
        # Add optimizer state
        if optimizer:
            checkpoint_data['optimizer_state_dict'] = optimizer.state_dict()
        
        # Add scheduler state
        if scheduler:
            checkpoint_data['scheduler_state_dict'] = scheduler.state_dict()
        
        # Add metrics
        if train_loss is not None:
            checkpoint_data['train_loss'] = train_loss
        if val_loss is not None:
            checkpoint_data['val_loss'] = val_loss
        if train_accuracy is not None:
            checkpoint_data['train_accuracy'] = train_accuracy
        if val_accuracy is not None:
            checkpoint_data['val_accuracy'] = val_accuracy
        if custom_metrics:
            checkpoint_data['custom_metrics'] = custom_metrics
        
        # Compress checkpoint
        compressed_data, compression_ratio = self._compress_checkpoint(
            checkpoint_data, compression
        )
        
        # Save checkpoint file
        checkpoint_path = self.checkpoint_dir / f"{checkpoint_id}.pt"
        with open(checkpoint_path, 'wb') as f:
            f.write(compressed_data)
        
        # Create metadata
        metadata = CheckpointMetadata(
            checkpoint_id=checkpoint_id,
            experiment_id=experiment_id,
            checkpoint_name=f"Epoch {epoch}, Step {step}",
            epoch=epoch,
            step=step,
            global_step=global_step,
            train_loss=train_loss,
            val_loss=val_loss,
            train_accuracy=train_accuracy,
            val_accuracy=val_accuracy,
            custom_metrics=custom_metrics or {},
            model_size_mb=model_size_mb,
            num_parameters=num_parameters,
            file_path=str(checkpoint_path),
            file_size_bytes=len(compressed_data),
            compression_ratio=compression_ratio,
            is_best=is_best,
            checkpoint_type=checkpoint_type,
            optimizer_state=optimizer is not None,
            scheduler_state=scheduler is not None
        )
        
        # Update registry
        self.checkpoint_registry[checkpoint_id] = metadata
        
        # Update best and latest checkpoints
        if is_best:
            if self.best_checkpoint:
                self.checkpoint_registry[self.best_checkpoint].is_best = False
            self.best_checkpoint = checkpoint_id
        
        if self.latest_checkpoint:
            self.checkpoint_registry[self.latest_checkpoint].is_latest = False
        self.latest_checkpoint = checkpoint_id
        
        # Save registry
        self._save_registry()
        
        # Cleanup old checkpoints
        self._cleanup_old_checkpoints()
        
        logger.info(f"Checkpoint saved: {checkpoint_path} (Size: {model_size_mb:.2f} MB)")
        return str(checkpoint_path)
    
    def load_checkpoint(self, checkpoint_path: str, model: nn.Module,
                       optimizer: Optional[torch.optim.Optimizer] = None,
                       scheduler: Optional[Any] = None,
                       device: Optional[torch.device] = None) -> Tuple[Dict[str, Any], int, int]:
        """Load a model checkpoint"""
        
        checkpoint_path = Path(checkpoint_path)
        if not checkpoint_path.exists():
            raise FileNotFoundError(f"Checkpoint not found: {checkpoint_path}")
        
        try:
            # Load checkpoint data
            with open(checkpoint_path, 'rb') as f:
                compressed_data = f.read()
            
            # Try to decompress (assume gzip if it fails)
            try:
                import gzip
                data_bytes = gzip.decompress(compressed_data)
            except Exception:
                data_bytes = compressed_data
            
            checkpoint_data = pickle.loads(data_bytes)
            
            # Load model state
            model.load_state_dict(checkpoint_data['model_state_dict'])
            
            # Load optimizer state
            if optimizer and 'optimizer_state_dict' in checkpoint_data:
                optimizer.load_state_dict(checkpoint_data['optimizer_state_dict'])
            
            # Load scheduler state
            if scheduler and 'scheduler_state_dict' in checkpoint_data:
                scheduler.load_state_dict(checkpoint_data['scheduler_state_dict'])
            
            # Move model to device if specified
            if device:
                model.to(device)
            
            epoch = checkpoint_data.get('epoch', 0)
            step = checkpoint_data.get('step', 0)
            
            logger.info(f"Checkpoint loaded: {checkpoint_path}")
            logger.info(f"Resuming from epoch {epoch}, step {step}")
            
            return checkpoint_data, epoch, step
            
        except Exception as e:
            logger.error(f"Failed to load checkpoint: {e}")
            raise
    
    def get_best_checkpoint(self) -> Optional[str]:
        """Get the path to the best checkpoint"""
        if self.best_checkpoint:
            return self.checkpoint_registry[self.best_checkpoint].file_path
        return None
    
    def get_latest_checkpoint(self) -> Optional[str]:
        """Get the path to the latest checkpoint"""
        if self.latest_checkpoint:
            return self.checkpoint_registry[self.latest_checkpoint].file_path
        return None
    
    def list_checkpoints(self, experiment_id: Optional[str] = None) -> List[CheckpointMetadata]:
        """List all checkpoints, optionally filtered by experiment"""
        if experiment_id:
            return [
                metadata for metadata in self.checkpoint_registry.values()
                if metadata.experiment_id == experiment_id
            ]
        return list(self.checkpoint_registry.values())
    
    def _cleanup_old_checkpoints(self):
        """Remove old checkpoints to stay within max_checkpoints limit"""
        if len(self.checkpoint_registry) <= self.max_checkpoints:
            return
        
        # Sort checkpoints by creation time (oldest first)
        sorted_checkpoints = sorted(
            self.checkpoint_registry.items(),
            key=lambda x: x[1].created_at
        )
        
        # Keep best and latest checkpoints
        checkpoints_to_remove = []
        for checkpoint_id, metadata in sorted_checkpoints[:-self.max_checkpoints]:
            if not metadata.is_best and not metadata.is_latest:
                checkpoints_to_remove.append(checkpoint_id)
        
        # Remove old checkpoints
        for checkpoint_id in checkpoints_to_remove:
            metadata = self.checkpoint_registry[checkpoint_id]
            if metadata.file_path and Path(metadata.file_path).exists():
                Path(metadata.file_path).unlink()
            del self.checkpoint_registry[checkpoint_id]
        
        if checkpoints_to_remove:
            logger.info(f"Removed {len(checkpoints_to_remove)} old checkpoints")
            self._save_registry()


class ExperimentTracker:
    """Comprehensive experiment tracking system with multiple backends"""
    
    def __init__(self, experiment_name: str, config: Optional[Dict[str, Any]] = None):
        """Initialize experiment tracker"""
        self.experiment_name = experiment_name
        self.config = config or {}
        
        # Generate experiment ID
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        self.experiment_id = f"{experiment_name}_{timestamp}"
        
        # Initialize metadata
        self.metadata = ExperimentMetadata(
            experiment_name=experiment_name,
            experiment_id=self.experiment_id,
            description=self.config.get('description', ''),
            tags=self.config.get('tags', []),
            version=self.config.get('version', '1.0.0')
        )
        
        # Initialize tracking backends
        self.wandb_run = None
        self.tensorboard_writer = None
        self.mlflow_run = None
        
        # Initialize checkpointer
        checkpoint_dir = self.config.get('checkpoint_dir', f"checkpoints/{experiment_name}")
        max_checkpoints = self.config.get('max_checkpoints', 10)
        self.checkpointer = ModelCheckpointer(checkpoint_dir, max_checkpoints)
        
        # Metrics tracking
        self.metrics_history: Dict[str, List[float]] = defaultdict(list)
        self.current_step = 0
        self.current_epoch = 0
        
        # Initialize tracking backends
        self._initialize_tracking()
        
        # Update metadata status
        self.metadata.status = "running"
        self.metadata.started_at = datetime.now().isoformat()
        
        logger.info(f"Experiment tracker initialized: {experiment_name} ({self.experiment_id})")
    
    def _initialize_tracking(self):
        """Initialize all tracking backends"""
        
        # Initialize Weights & Biases
        if self.config.get('use_wandb', False):
            self._init_wandb()
        
        # Initialize TensorBoard
        if self.config.get('use_tensorboard', True):
            self._init_tensorboard()
        
        # Initialize MLflow
        if self.config.get('use_mlflow', False):
            self._init_mlflow()
    
    def _init_wandb(self):
        """Initialize Weights & Biases tracking"""
        try:
            wandb.init(
                project=self.config.get('wandb_project', 'deep-learning-project'),
                name=self.experiment_name,
                id=self.experiment_id,
                config=self.config,
                tags=self.metadata.tags,
                notes=self.metadata.description,
                entity=self.config.get('wandb_entity'),
                group=self.config.get('wandb_group'),
                job_type=self.config.get('wandb_job_type', 'training'),
                resume=False
            )
            self.wandb_run = wandb.run
            
            # Log experiment metadata
            wandb.run.summary.update({
                'experiment_id': self.experiment_id,
                'python_version': self.metadata.python_version,
                'torch_version': self.metadata.torch_version,
                'cuda_version': self.metadata.cuda_version,
                'platform': self.metadata.platform,
                'git_commit': self.metadata.git_commit,
                'git_branch': self.metadata.git_branch,
                'git_dirty': self.metadata.git_dirty
            })
            
            logger.info("Weights & Biases tracking initialized")
            
        except Exception as e:
            logger.warning(f"Failed to initialize WandB: {e}")
    
    def _init_tensorboard(self):
        """Initialize TensorBoard tracking"""
        try:
            log_dir = self.config.get('tensorboard_log_dir', f"runs/tensorboard/{self.experiment_name}")
            Path(log_dir).mkdir(parents=True, exist_ok=True)
            
            self.tensorboard_writer = SummaryWriter(
                log_dir=log_dir,
                comment=f"_{self.experiment_id}"
            )
            
            # Log experiment metadata
            self.tensorboard_writer.add_text(
                'experiment/metadata',
                f"Experiment ID: {self.experiment_id}\n"
                f"Description: {self.metadata.description}\n"
                f"Tags: {', '.join(self.metadata.tags)}\n"
                f"Python Version: {self.metadata.python_version}\n"
                f"PyTorch Version: {self.metadata.torch_version}\n"
                f"CUDA Version: {self.metadata.cuda_version}\n"
                f"Platform: {self.metadata.platform}",
                global_step=0
            )
            
            logger.info(f"TensorBoard tracking initialized: {log_dir}")
            
        except Exception as e:
            logger.warning(f"Failed to initialize TensorBoard: {e}")
    
    def _init_mlflow(self):
        """Initialize MLflow tracking"""
        try:
            import mlflow
            
            tracking_uri = self.config.get('mlflow_tracking_uri', 'file:./mlruns')
            mlflow.set_tracking_uri(tracking_uri)
            
            experiment_name = self.config.get('mlflow_experiment_name', 'deep-learning-project')
            mlflow.set_experiment(experiment_name)
            
            self.mlflow_run = mlflow.start_run(
                run_name=self.experiment_name,
                tags={
                    'experiment_id': self.experiment_id,
                    'description': self.metadata.description,
                    'tags': ','.join(self.metadata.tags)
                }
            )
            
            # Log experiment metadata
            mlflow.log_params({
                'experiment_id': self.experiment_id,
                'python_version': self.metadata.python_version,
                'torch_version': self.metadata.torch_version,
                'cuda_version': self.metadata.cuda_version,
                'platform': self.metadata.platform
            })
            
            logger.info("MLflow tracking initialized")
            
        except Exception as e:
            logger.warning(f"Failed to initialize MLflow: {e}")
    
    def log_metrics(self, metrics: Dict[str, float], step: Optional[int] = None, 
                   epoch: Optional[int] = None, prefix: str = ""):
        """Log metrics to all tracking backends"""
        
        current_step = step if step is not None else self.current_step
        current_epoch = epoch if epoch is not None else self.current_epoch
        
        # Add prefix to metric names
        prefixed_metrics = {}
        for key, value in metrics.items():
            if prefix:
                prefixed_metrics[f"{prefix}/{key}"] = value
            else:
                prefixed_metrics[key] = value
        
        # Store in history
        for key, value in prefixed_metrics.items():
            self.metrics_history[key].append(value)
        
        # Log to WandB
        if self.wandb_run:
            try:
                wandb.log(prefixed_metrics, step=current_step)
            except Exception as e:
                logger.warning(f"Failed to log to WandB: {e}")
        
        # Log to TensorBoard
        if self.tensorboard_writer:
            try:
                for key, value in prefixed_metrics.items():
                    self.tensorboard_writer.add_scalar(key, value, current_step)
            except Exception as e:
                logger.warning(f"Failed to log to TensorBoard: {e}")
        
        # Log to MLflow
        if self.mlflow_run:
            try:
                import mlflow
                mlflow.log_metrics(prefixed_metrics, step=current_step)
            except Exception as e:
                logger.warning(f"Failed to log to MLflow: {e}")
        
        logger.debug(f"Logged metrics at step {current_step}: {prefixed_metrics}")
    
    def log_hyperparameters(self, hyperparameters: Dict[str, Any]):
        """Log hyperparameters to all tracking backends"""
        
        # Log to WandB
        if self.wandb_run:
            try:
                wandb.config.update(hyperparameters)
            except Exception as e:
                logger.warning(f"Failed to log hyperparameters to WandB: {e}")
        
        # Log to TensorBoard
        if self.tensorboard_writer:
            try:
                for key, value in hyperparameters.items():
                    self.tensorboard_writer.add_text(f'hyperparameters/{key}', str(value), 0)
            except Exception as e:
                logger.warning(f"Failed to log hyperparameters to TensorBoard: {e}")
        
        # Log to MLflow
        if self.mlflow_run:
            try:
                import mlflow
                mlflow.log_params(hyperparameters)
            except Exception as e:
                logger.warning(f"Failed to log hyperparameters to MLflow: {e}")
        
        logger.info(f"Logged hyperparameters: {list(hyperparameters.keys())}")
    
    def log_model(self, model: nn.Module, model_name: str = "model"):
        """Log model architecture and parameters to tracking backends"""
        
        # Log to WandB
        if self.wandb_run:
            try:
                # Log model summary
                model_summary = str(model)
                wandb.run.summary[f"{model_name}_architecture"] = model_summary
                
                # Log model parameters
                total_params = sum(p.numel() for p in model.parameters())
                trainable_params = sum(p.numel() for p in model.parameters() if p.requires_grad)
                wandb.run.summary[f"{model_name}_total_parameters"] = total_params
                wandb.run.summary[f"{model_name}_trainable_parameters"] = trainable_params
                
            except Exception as e:
                logger.warning(f"Failed to log model to WandB: {e}")
        
        # Log to TensorBoard
        if self.tensorboard_writer:
            try:
                # Log model graph
                dummy_input = torch.randn(1, 3, 224, 224)  # Adjust based on your model
                self.tensorboard_writer.add_graph(model, dummy_input)
                
                # Log model parameters
                for name, param in model.named_parameters():
                    self.tensorboard_writer.add_histogram(f"{model_name}/{name}", param.data, 0)
                    
            except Exception as e:
                logger.warning(f"Failed to log model to TensorBoard: {e}")
        
        # Log to MLflow
        if self.mlflow_run:
            try:
                import mlflow
                # Log model as artifact
                model_path = f"models/{model_name}"
                torch.save(model.state_dict(), model_path)
                mlflow.log_artifact(model_path)
                
            except Exception as e:
                logger.warning(f"Failed to log model to MLflow: {e}")
        
        logger.info(f"Logged model: {model_name}")
    
    def save_checkpoint(self, model: nn.Module, epoch: int, step: int, 
                       optimizer: Optional[torch.optim.Optimizer] = None,
                       scheduler: Optional[Any] = None,
                       train_loss: Optional[float] = None,
                       val_loss: Optional[float] = None,
                       train_accuracy: Optional[float] = None,
                       val_accuracy: Optional[float] = None,
                       custom_metrics: Optional[Dict[str, float]] = None,
                       is_best: bool = False) -> str:
        """Save model checkpoint using the checkpointer"""
        
        checkpoint_path = self.checkpointer.save_checkpoint(
            experiment_id=self.experiment_id,
            model=model,
            epoch=epoch,
            step=step,
            global_step=self.current_step,
            optimizer=optimizer,
            scheduler=scheduler,
            train_loss=train_loss,
            val_loss=val_loss,
            train_accuracy=train_accuracy,
            val_accuracy=val_accuracy,
                    custom_metrics=custom_metrics,
            is_best=is_best
        )
        
        # Log checkpoint to tracking backends
        if self.wandb_run:
            try:
                wandb.save(checkpoint_path)
                wandb.run.summary['best_checkpoint'] = checkpoint_path if is_best else None
            except Exception as e:
                logger.warning(f"Failed to log checkpoint to WandB: {e}")
        
        if self.mlflow_run:
            try:
                import mlflow
                mlflow.log_artifact(checkpoint_path, artifact_path="checkpoints")
            except Exception as e:
                logger.warning(f"Failed to log checkpoint to MLflow: {e}")
        
        return checkpoint_path
    
    def load_checkpoint(self, checkpoint_path: str, model: nn.Module,
                       optimizer: Optional[torch.optim.Optimizer] = None,
                       scheduler: Optional[Any] = None) -> Tuple[int, int]:
        """Load model checkpoint using the checkpointer"""
        
        checkpoint_data, epoch, step = self.checkpointer.load_checkpoint(
            checkpoint_path, model, optimizer, scheduler
        )
        
        # Update current state
        self.current_epoch = epoch
        self.current_step = step
        
        logger.info(f"Resumed training from epoch {epoch}, step {step}")
        return epoch, step
    
    def log_system_metrics(self, gpu_memory: Optional[float] = None,
                          gpu_utilization: Optional[float] = None,
                          cpu_usage: Optional[float] = None,
                          memory_usage: Optional[float] = None):
        """Log system performance metrics"""
        
        system_metrics = {}
        
        if gpu_memory is not None:
            system_metrics['system/gpu_memory_mb'] = gpu_memory
        
        if gpu_utilization is not None:
            system_metrics['system/gpu_utilization_percent'] = gpu_utilization
        
        if cpu_usage is not None:
            system_metrics['system/cpu_usage_percent'] = cpu_usage
        
        if memory_usage is not None:
            system_metrics['system/memory_usage_percent'] = memory_usage
        
        if system_metrics:
            self.log_metrics(system_metrics, prefix="system")
    
    def create_performance_plots(self, output_dir: str = "plots"):
        """Create performance visualization plots"""
        
        output_path = Path(output_dir)
        output_path.mkdir(parents=True, exist_ok=True)
        
        try:
            import matplotlib.pyplot as plt
            import seaborn as sns
            
            # Set style
            plt.style.use('seaborn-v0_8')
            sns.set_palette("husl")
            
            # Create subplots
            fig, axes = plt.subplots(2, 2, figsize=(15, 10))
            fig.suptitle(f'Training Performance: {self.experiment_name}', fontsize=16)
            
            # Plot training loss
            if 'train/loss' in self.metrics_history:
                axes[0, 0].plot(self.metrics_history['train/loss'], label='Training Loss')
                axes[0, 0].set_title('Training Loss')
                axes[0, 0].set_xlabel('Step')
                axes[0, 0].set_ylabel('Loss')
                axes[0, 0].set_legend()
                axes[0, 0].grid(True)
            
            # Plot validation loss
            if 'val/loss' in self.metrics_history:
                axes[0, 1].plot(self.metrics_history['val/loss'], label='Validation Loss', color='orange')
                axes[0, 1].set_title('Validation Loss')
                axes[0, 1].set_xlabel('Step')
                axes[0, 1].set_ylabel('Loss')
                axes[0, 1].set_legend()
                axes[0, 1].grid(True)
            
            # Plot accuracy
            if 'train/accuracy' in self.metrics_history or 'val/accuracy' in self.metrics_history:
                if 'train/accuracy' in self.metrics_history:
                    axes[1, 0].plot(self.metrics_history['train/accuracy'], label='Training Accuracy')
                if 'val/accuracy' in self.metrics_history:
                    axes[1, 0].plot(self.metrics_history['val/accuracy'], label='Validation Accuracy')
                axes[1, 0].set_title('Accuracy')
                axes[1, 0].set_xlabel('Step')
                axes[1, 0].set_ylabel('Accuracy')
                axes[1, 0].set_legend()
                axes[1, 0].grid(True)
            
            # Plot learning rate (if available)
            if 'train/learning_rate' in self.metrics_history:
                axes[1, 1].plot(self.metrics_history['train/learning_rate'], label='Learning Rate', color='green')
                axes[1, 1].set_title('Learning Rate')
                axes[1, 1].set_xlabel('Step')
                axes[1, 1].set_ylabel('Learning Rate')
                axes[1, 1].set_legend()
                axes[1, 1].grid(True)
                axes[1, 1].set_yscale('log')
            
            # Adjust layout
            plt.tight_layout()
            
            # Save plot
            plot_path = output_path / f"{self.experiment_name}_performance.png"
            plt.savefig(plot_path, dpi=300, bbox_inches='tight')
            plt.close()
            
            logger.info(f"Performance plots saved: {plot_path}")
            
            # Log plot to tracking backends
            if self.wandb_run:
                try:
                    wandb.log({"performance_plot": wandb.Image(str(plot_path))})
                except Exception as e:
                    logger.warning(f"Failed to log plot to WandB: {e}")
            
            if self.mlflow_run:
                try:
                    import mlflow
                    mlflow.log_artifact(str(plot_path), artifact_path="plots")
                except Exception as e:
                    logger.warning(f"Failed to log plot to MLflow: {e}")
            
        except Exception as e:
            logger.warning(f"Failed to create performance plots: {e}")
    
    def finish(self, status: str = "completed"):
        """Finish the experiment and clean up"""
        
        self.metadata.status = status
        self.metadata.completed_at = datetime.now().isoformat()
        
        # Create final performance plots
        self.create_performance_plots()
        
        # Close tracking backends
        if self.tensorboard_writer:
            self.tensorboard_writer.close()
        
        if self.wandb_run:
            try:
                wandb.finish()
            except Exception as e:
                logger.warning(f"Failed to finish WandB run: {e}")
        
        if self.mlflow_run:
            try:
                import mlflow
                mlflow.end_run()
            except Exception as e:
                logger.warning(f"Failed to end MLflow run: {e}")
        
        logger.info(f"Experiment finished: {self.experiment_name} (Status: {status})")
    
    def __enter__(self):
        """Context manager entry"""
        return self
    
    def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit"""
        status = "completed" if exc_type is None else "failed"
        self.finish(status)


# Context manager for easy experiment tracking
@contextmanager
def experiment_tracking(experiment_name: str, config: Optional[Dict[str, Any]] = None):
    """Context manager for experiment tracking"""
    tracker = ExperimentTracker(experiment_name, config)
    try:
        yield tracker
    finally:
        tracker.finish()


# =============================================================================
# VERSION CONTROL INTEGRATION SYSTEM
# =============================================================================

@dataclass
class GitInfo:
    """Git repository information"""
    
    # Repository information
    repo_path: str
    is_git_repo: bool = False
    
    # Branch and commit information
    current_branch: Optional[str] = None
    current_commit: Optional[str] = None
    commit_message: Optional[str] = None
    commit_author: Optional[str] = None
    commit_date: Optional[str] = None
    
    # Repository status
    is_dirty: bool = False
    untracked_files: List[str] = field(default_factory=list)
    modified_files: List[str] = field(default_factory=list)
    staged_files: List[str] = field(default_factory=list)
    
    # Remote information
    remote_url: Optional[str] = None
    remote_branch: Optional[str] = None
    ahead_count: int = 0
    behind_count: int = 0
    
    # Tags and releases
    latest_tag: Optional[str] = None
    tag_count: int = 0
    
    # Timestamp
    last_updated: str = field(default_factory=lambda: datetime.now().isoformat())


class VersionControlManager:
    """Comprehensive version control management system"""
    
    def __init__(self, repo_path: Optional[str] = None):
        """Initialize version control manager"""
        self.repo_path = Path(repo_path) if repo_path else Path.cwd()
        self.git_info = GitInfo(repo_path=str(self.repo_path))
        
        # Initialize git information
        self._initialize_git_info()
        
        logger.info(f"Version control manager initialized: {self.repo_path}")
    
    def _initialize_git_info(self):
        """Initialize git repository information"""
        try:
            import subprocess
            
            # Check if this is a git repository
            result = subprocess.run(['git', 'rev-parse', '--git-dir'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.is_git_repo = True
                self._update_git_info()
            else:
                logger.info(f"Not a git repository: {self.repo_path}")
                
        except Exception as e:
            logger.warning(f"Failed to initialize git info: {e}")
    
    def _update_git_info(self):
        """Update git repository information"""
        if not self.git_info.is_git_repo:
            return
        
        try:
            import subprocess
            
            # Get current branch
            result = subprocess.run(['git', 'branch', '--show-current'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.current_branch = result.stdout.strip()
            
            # Get current commit
            result = subprocess.run(['git', 'rev-parse', 'HEAD'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.current_commit = result.stdout.strip()
            
            # Get commit message
            result = subprocess.run(['git', 'log', '-1', '--pretty=format:%s'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.commit_message = result.stdout.strip()
            
            # Get commit author
            result = subprocess.run(['git', 'log', '-1', '--pretty=format:%an'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.commit_author = result.stdout.strip()
            
            # Get commit date
            result = subprocess.run(['git', 'log', '-1', '--pretty=format:%ai'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.commit_date = result.stdout.strip()
            
            # Check repository status
            result = subprocess.run(['git', 'status', '--porcelain'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                status_lines = result.stdout.strip().split('\n') if result.stdout.strip() else []
                self.git_info.is_dirty = bool(status_lines)
                
                for line in status_lines:
                    if line:
                        status = line[:2]
                        filename = line[3:]
                        
                        if status == '??':
                            self.git_info.untracked_files.append(filename)
                        elif status in ['M ', 'MM', 'A ', 'D ', 'R ']:
                            self.git_info.modified_files.append(filename)
                        elif status in ['M ', 'A ', 'D ', 'R ']:
                            self.git_info.staged_files.append(filename)
            
            # Get remote information
            result = subprocess.run(['git', 'remote', 'get-url', 'origin'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.remote_url = result.stdout.strip()
            
            # Get remote branch
            if self.git_info.current_branch:
                result = subprocess.run(['git', 'rev-list', '--count', 'origin/' + self.git_info.current_branch + '..HEAD'], 
                                      capture_output=True, text=True, cwd=self.repo_path)
                if result.returncode == 0:
                    self.git_info.ahead_count = int(result.stdout.strip() or 0)
                
                result = subprocess.run(['git', 'rev-list', '--count', 'HEAD..origin/' + self.git_info.current_branch], 
                                      capture_output=True, text=True, cwd=self.repo_path)
                if result.returncode == 0:
                    self.git_info.behind_count = int(result.stdout.strip() or 0)
            
            # Get latest tag
            result = subprocess.run(['git', 'describe', '--tags', '--abbrev=0'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.latest_tag = result.stdout.strip()
            
            # Get tag count
            result = subprocess.run(['git', 'tag', '--list'], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                self.git_info.tag_count = len([tag for tag in result.stdout.strip().split('\n') if tag])
            
            # Update timestamp
            self.git_info.last_updated = datetime.now().isoformat()
            
        except Exception as e:
            logger.warning(f"Failed to update git info: {e}")
    
    def get_repository_status(self) -> Dict[str, Any]:
        """Get comprehensive repository status"""
        self._update_git_info()
        return asdict(self.git_info)
    
    def create_tag(self, tag_name: str, message: str = "", force: bool = False) -> bool:
        """Create a new git tag"""
        if not self.git_info.is_git_repo:
            logger.error("Not a git repository")
            return False
        
        try:
            import subprocess
            
            cmd = ['git', 'tag']
            if force:
                cmd.append('-f')
            if message:
                cmd.extend(['-m', message])
            cmd.append(tag_name)
            
            result = subprocess.run(cmd, capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                logger.info(f"Tag '{tag_name}' created successfully")
                self._update_git_info()
                return True
            else:
                logger.error(f"Failed to create tag: {result.stderr}")
                return False
                
        except Exception as e:
            logger.error(f"Failed to create tag: {e}")
            return False
    
    def create_commit(self, message: str, add_all: bool = True) -> bool:
        """Create a new git commit"""
        if not self.git_info.is_git_repo:
            logger.error("Not a git repository")
            return False
        
        try:
            import subprocess
            
            # Add all files if requested
            if add_all:
                result = subprocess.run(['git', 'add', '.'], 
                                      capture_output=True, text=True, cwd=self.repo_path)
                if result.returncode != 0:
                    logger.error(f"Failed to add files: {result.stderr}")
                    return False
            
            # Create commit
            result = subprocess.run(['git', 'commit', '-m', message], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                logger.info(f"Commit created successfully: {message}")
                self._update_git_info()
                return True
            else:
                logger.error(f"Failed to create commit: {result.stderr}")
                return False
                
        except Exception as e:
            logger.error(f"Failed to create commit: {e}")
            return False
    
    def push_changes(self, remote: str = "origin", branch: Optional[str] = None) -> bool:
        """Push changes to remote repository"""
        if not self.git_info.is_git_repo:
            logger.error("Not a git repository")
            return False
        
        try:
            import subprocess
            
            cmd = ['git', 'push', remote]
            if branch:
                cmd.append(branch)
            
            result = subprocess.run(cmd, capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                logger.info("Changes pushed successfully")
                self._update_git_info()
                return True
            else:
                logger.error(f"Failed to push changes: {result.stderr}")
                return False
                
        except Exception as e:
            logger.error(f"Failed to push changes: {e}")
            return False
    
    def pull_changes(self, remote: str = "origin", branch: Optional[str] = None) -> bool:
        """Pull changes from remote repository"""
        if not self.git_info.is_git_repo:
            logger.error("Not a git repository")
            return False
        
        try:
            import subprocess
            
            cmd = ['git', 'pull', remote]
            if branch:
                cmd.append(branch)
            
            result = subprocess.run(cmd, capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                logger.info("Changes pulled successfully")
                self._update_git_info()
                return True
            else:
                logger.error(f"Failed to pull changes: {result.stderr}")
                return False
                
        except Exception as e:
            logger.error(f"Failed to pull changes: {e}")
            return False
    
    def get_file_history(self, file_path: str, max_commits: int = 10) -> List[Dict[str, Any]]:
        """Get commit history for a specific file"""
        if not self.git_info.is_git_repo:
            logger.error("Not a git repository")
            return []
        
        try:
            import subprocess
            
            result = subprocess.run([
                'git', 'log', f'--max-count={max_commits}',
                '--pretty=format:%H|%an|%ai|%s',
                '--', file_path
            ], capture_output=True, text=True, cwd=self.repo_path)
            
            if result.returncode == 0:
                history = []
                for line in result.stdout.strip().split('\n'):
                    if line:
                        parts = line.split('|')
                        if len(parts) == 4:
                            history.append({
                                'commit': parts[0],
                                'author': parts[1],
                                'date': parts[2],
                                'message': parts[3]
                            })
                return history
            else:
                logger.error(f"Failed to get file history: {result.stderr}")
                return []
                
        except Exception as e:
            logger.error(f"Failed to get file history: {e}")
            return []
    
    def get_diff_summary(self, file_path: Optional[str] = None) -> Dict[str, Any]:
        """Get summary of current changes"""
        if not self.git_info.is_git_repo:
            logger.error("Not a git repository")
            return {}
        
        try:
            import subprocess
            
            cmd = ['git', 'diff', '--stat']
            if file_path:
                cmd.append(file_path)
            
            result = subprocess.run(cmd, capture_output=True, text=True, cwd=self.repo_path)
            
            if result.returncode == 0:
                diff_output = result.stdout.strip()
                return {
                    'diff_summary': diff_output,
                    'has_changes': bool(diff_output),
                    'file_path': file_path
                }
            else:
                logger.error(f"Failed to get diff summary: {result.stderr}")
                return {}
                
        except Exception as e:
            logger.error(f"Failed to get diff summary: {e}")
            return {}
    
    def create_experiment_branch(self, experiment_name: str, base_branch: str = "main") -> bool:
        """Create a new branch for an experiment"""
        if not self.git_info.is_git_repo:
            logger.error("Not a git repository")
            return False
        
        try:
            import subprocess
            
            # Create and checkout new branch
            branch_name = f"experiment/{experiment_name}_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
            
            # Checkout base branch first
            result = subprocess.run(['git', 'checkout', base_branch], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode != 0:
                logger.error(f"Failed to checkout base branch: {result.stderr}")
                return False
            
            # Pull latest changes
            result = subprocess.run(['git', 'pull', 'origin', base_branch], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode != 0:
                logger.warning(f"Failed to pull latest changes: {result.stderr}")
            
            # Create and checkout new branch
            result = subprocess.run(['git', 'checkout', '-b', branch_name], 
                                  capture_output=True, text=True, cwd=self.repo_path)
            if result.returncode == 0:
                logger.info(f"Experiment branch '{branch_name}' created successfully")
                self._update_git_info()
                return True
            else:
                logger.error(f"Failed to create experiment branch: {result.stderr}")
                return False
                
        except Exception as e:
            logger.error(f"Failed to create experiment branch: {e}")
            return False
    
    def get_repository_health(self) -> Dict[str, Any]:
        """Get repository health metrics"""
        if not self.git_info.is_git_repo:
            return {'status': 'not_git_repo'}
        
        self._update_git_info()
        
        health_score = 100
        
        # Deduct points for various issues
        if self.git_info.is_dirty:
            health_score -= 20
        
        if self.git_info.ahead_count > 10:
            health_score -= 15
        
        if self.git_info.behind_count > 5:
            health_score -= 15
        
        if len(self.git_info.untracked_files) > 20:
            health_score -= 10
        
        if len(self.git_info.modified_files) > 10:
            health_score -= 10
        
        health_status = "excellent"
        if health_score < 50:
            health_status = "poor"
        elif health_score < 75:
            health_status = "fair"
        elif health_score < 90:
            health_status = "good"
        
        return {
            'status': 'healthy',
            'health_score': health_score,
            'health_status': health_status,
            'issues': {
                'has_uncommitted_changes': self.git_info.is_dirty,
                'ahead_of_remote': self.git_info.ahead_count,
                'behind_remote': self.git_info.behind_count,
                'untracked_files_count': len(self.git_info.untracked_files),
                'modified_files_count': len(self.git_info.modified_files)
            },
            'recommendations': self._get_health_recommendations(health_score)
        }
    
    def _get_health_recommendations(self, health_score: int) -> List[str]:
        """Get recommendations for improving repository health"""
        recommendations = []
        
        if self.git_info.is_dirty:
            recommendations.append("Commit or stash uncommitted changes")
        
        if self.git_info.ahead_count > 10:
            recommendations.append("Push local commits to remote repository")
        
        if self.git_info.behind_count > 5:
            recommendations.append("Pull latest changes from remote repository")
        
        if len(self.git_info.untracked_files) > 20:
            recommendations.append("Review and add/ignore untracked files")
        
        if len(self.git_info.modified_files) > 10:
            recommendations.append("Review and commit modified files")
        
        if health_score < 50:
            recommendations.append("Repository needs immediate attention")
        
        return recommendations


