def demonstrate_experiment_tracking_and_checkpointing():
    """Demonstrate the comprehensive experiment tracking and checkpointing system"""
    
    print("\n" + "="*80)
    print("🔬 EXPERIMENT TRACKING AND MODEL CHECKPOINTING SYSTEM DEMONSTRATION")
    print("="*80)
    
    # Create a simple model for demonstration
    class SimpleModel(nn.Module):
        def __init__(self, input_dim: int = 10, hidden_dim: int = 20, output_dim: int = 2):
            super().__init__()
            self.fc1 = nn.Linear(input_dim, hidden_dim)
            self.fc2 = nn.Linear(hidden_dim, hidden_dim)
            self.fc3 = nn.Linear(hidden_dim, output_dim)
            self.relu = nn.ReLU()
            self.dropout = nn.Dropout(0.1)
        
        def forward(self, x):
            x = self.relu(self.fc1(x))
            x = self.dropout(x)
            x = self.relu(self.fc2(x))
            x = self.dropout(x)
            x = self.fc3(x)
            return x
    
    # Configuration for experiment tracking
    config = {
        'description': 'Demonstration of experiment tracking and checkpointing system',
        'tags': ['demo', 'experiment-tracking', 'checkpointing'],
        'version': '1.0.0',
        'use_wandb': False,  # Set to True if you have WandB configured
        'use_tensorboard': True,
        'use_mlflow': False,  # Set to True if you have MLflow configured
        'checkpoint_dir': 'checkpoints/demo_experiment',
        'max_checkpoints': 5,
        'tensorboard_log_dir': 'runs/tensorboard/demo_experiment'
    }
    
    print("\n📋 Configuration:")
    for key, value in config.items():
        print(f"  {key}: {value}")
    
    # Initialize model, optimizer, and scheduler
    model = SimpleModel()
    optimizer = torch.optim.AdamW(model.parameters(), lr=0.001)
    scheduler = torch.optim.lr_scheduler.CosineAnnealingLR(optimizer, T_max=100)
    
    print(f"\n🏗️ Model initialized:")
    print(f"  Total parameters: {sum(p.numel() for p in model.parameters()):,}")
    print(f"  Trainable parameters: {sum(p.numel() for p in model.parameters() if p.requires_grad):,}")
    
    # Demonstrate experiment tracking
    print("\n🚀 Starting experiment tracking demonstration...")
    
    with experiment_tracking("demo_experiment", config) as tracker:
        
        # Log hyperparameters
        hyperparameters = {
            'learning_rate': 0.001,
            'batch_size': 32,
            'epochs': 10,
            'hidden_dim': 20,
            'dropout': 0.1,
            'optimizer': 'AdamW',
            'scheduler': 'CosineAnnealingLR'
        }
        tracker.log_hyperparameters(hyperparameters)
        
        # Log model architecture
        tracker.log_model(model, "simple_model")
        
        # Simulate training loop
        print("\n📊 Simulating training loop with metrics logging...")
        
        for epoch in range(5):
            for step in range(10):
                # Simulate training metrics
                train_loss = 1.0 - (epoch * 10 + step) * 0.01
                val_loss = train_loss + 0.1 + random.uniform(-0.05, 0.05)
                train_accuracy = 0.5 + (epoch * 10 + step) * 0.01
                val_accuracy = train_accuracy - 0.05 + random.uniform(-0.02, 0.02)
                learning_rate = optimizer.param_groups[0]['lr']
                
                # Log metrics
                metrics = {
                    'loss': train_loss,
                    'val_loss': val_loss,
                    'accuracy': train_accuracy,
                    'val_accuracy': val_accuracy,
                    'learning_rate': learning_rate
                }
                tracker.log_metrics(metrics, step=step, epoch=epoch, prefix="train")
                
                # Log system metrics (simulated)
                if step % 5 == 0:
                    system_metrics = {
                        'gpu_memory': random.uniform(2.0, 8.0),
                        'gpu_utilization': random.uniform(60, 95),
                        'cpu_usage': random.uniform(20, 80),
                        'memory_usage': random.uniform(30, 70)
                    }
                    tracker.log_system_metrics(**system_metrics)
                
                # Update step counter
                tracker.current_step += 1
                
                # Simulate some training steps
                dummy_input = torch.randn(1, 10)
                output = model(dummy_input)
                loss = F.cross_entropy(output, torch.randint(0, 2, (1,)))
                loss.backward()
                optimizer.step()
                scheduler.step()
                
                # Save checkpoint every few steps
                if step % 3 == 0:
                    is_best = val_loss < 0.5  # Simple best model criterion
                    checkpoint_path = tracker.save_checkpoint(
                        model=model,
                        epoch=epoch,
                        step=step,
                        optimizer=optimizer,
                        scheduler=scheduler,
                        train_loss=train_loss,
                        val_loss=val_loss,
                        train_accuracy=train_accuracy,
                        val_accuracy=val_accuracy,
                        is_best=is_best
                    )
                    print(f"  Epoch {epoch}, Step {step}: Checkpoint saved to {Path(checkpoint_path).name}")
            
            tracker.current_epoch += 1
            print(f"  Epoch {epoch} completed")
        
        print("\n✅ Training simulation completed!")
        
        # Demonstrate checkpoint management
        print("\n💾 Checkpoint Management:")
        checkpoints = tracker.checkpointer.list_checkpoints(tracker.experiment_id)
        print(f"  Total checkpoints: {len(checkpoints)}")
        
        for checkpoint in checkpoints:
            status = []
            if checkpoint.is_best:
                status.append("BEST")
            if checkpoint.is_latest:
                status.append("LATEST")
            status_str = f" ({', '.join(status)})" if status else ""
            
            print(f"  - {checkpoint.checkpoint_name}{status_str}")
            print(f"    Epoch {checkpoint.epoch}, Step {checkpoint.step}")
            print(f"  Train Loss: {checkpoint.train_loss:.4f}, Val Loss: {checkpoint.val_loss:.4f}")
            print(f"    Size: {checkpoint.model_size_mb:.2f} MB")
        
        # Demonstrate checkpoint loading
        if checkpoints:
            print("\n🔄 Demonstrating checkpoint loading...")
            best_checkpoint = tracker.checkpointer.get_best_checkpoint()
            if best_checkpoint:
                print(f"  Loading best checkpoint: {Path(best_checkpoint).name}")
                
                # Create a new model instance
                new_model = SimpleModel()
                new_optimizer = torch.optim.AdamW(new_model.parameters(), lr=0.001)
                new_scheduler = torch.optim.lr_scheduler.CosineAnnealingLR(new_optimizer, T_max=100)
                
                # Load checkpoint
                epoch, step = tracker.load_checkpoint(
                    best_checkpoint, new_model, new_optimizer, new_scheduler
                )
                print(f"  Successfully loaded checkpoint from epoch {epoch}, step {step}")
                
                # Verify model state
                with torch.no_grad():
                    dummy_input = torch.randn(1, 10)
                    original_output = model(dummy_input)
                    loaded_output = new_model(dummy_input)
                    
                    output_diff = torch.abs(original_output - loaded_output).max().item()
                    print(f"  Model output difference: {output_diff:.6f}")
        
        # Create performance plots
        print("\n📈 Creating performance plots...")
        tracker.create_performance_plots("plots/demo_experiment")
        
        print("\n🎯 Experiment tracking demonstration completed successfully!")
    
    print("\n" + "="*80)
    print("✅ EXPERIMENT TRACKING AND MODEL CHECKPOINTING SYSTEM SUCCESSFULLY DEMONSTRATED!")
    print("="*80)
    
    print("\n🔑 Key Features Demonstrated:")
    print("• Multi-backend experiment tracking (TensorBoard, WandB, MLflow)")
    print("• Comprehensive model checkpointing with metadata")
    print("• Automatic checkpoint management and cleanup")
    print("• Performance metrics logging and visualization")
    print("• System resource monitoring")
    print("• Reproducibility through configuration hashing")
    print("• Git integration for version control")
    print("• Context manager for easy experiment management")
    
    print("\n📁 Generated Files:")
    print("• Checkpoints with full metadata")
    print("• TensorBoard logs for visualization")
    print("• Performance plots and charts")
    print("• Experiment registry and metadata")
    
    print("\n🚀 Ready for Production Use:")
    print("• Robust error handling and recovery")
    print("• Configurable tracking backends")
    print("• Efficient checkpoint compression")
    print("• Automatic cleanup and management")
    print("• Integration with existing training loops")


